# Vision tier-2 module (shadow-eval today, tier-2 promotion per hotspot
# after telemetry proves agreement). Wrapped in try/except so a vision.py
# import error never breaks the pipeline — shadow mode is opt-in via
# DG_VISION_TIER=shadow and default-off.
try:
    import vision as _vision  # type: ignore
except Exception as _ve:
    _vision = None  # noqa: N816 — fallthrough; shadow path no-ops below.
    # Guard print: under pythonw.exe (Scheduled Task supervisor path),
    # sys.stdout is None and any unguarded write raises AttributeError at
    # import time, killing the daemon-loop before main() runs.
    if sys.stdout is not None:
        print(f"[vision] import failed (shadow disabled): {_ve}", flush=True)

# Phoenix self-heal SELECTOR engine (PX-0 foundation — SHADOW-ONLY, flag
# DG_SELFHEAL_ENABLED default OFF). Wrapped like the vision import so an import
# error can never break the pipeline; when the module is absent or the flag is
# off, every selfheal entry point is inert. NB: namespaced `selfheal` to avoid
# the unrelated restart/resume "Phoenix" in this file.
try:
    import selfheal  # type: ignore
except Exception as _she:
    selfheal = None  # noqa: N816 — fallthrough; the flag-gated shadow path no-ops.
    if sys.stdout is not None:
        print(f"[selfheal] import failed (self-heal shadow disabled): {_she}", flush=True)

# UTF-8 + errors="replace" reconfigure for stdout/stderr on every platform.
# Windows needs it for the cp1252 default; Linux/macOS need it when LANG=C
# or POSIX is in effect (Crostini's penguin shell pre-`dpkg-reconfigure
# locales`, slim Docker images, CI runners). Without this, any Unicode
# sigil (◆, spinner frames ⠋⠙, box-drawing chars) raises UnicodeEncodeError
# and crashes the whole subcommand before the user sees the banner.
# Guarded for pythonw.exe (sys.stdout/stderr are None under the no-console
# interpreter, so .reconfigure would crash at import).
if sys.stdout is not None:
    try:
        sys.stdout.reconfigure(encoding="utf-8", errors="replace", line_buffering=True)
    except Exception:
        pass  # Older Python or wrapped stream; ignore silently.
if sys.stderr is not None:
    try:
        sys.stderr.reconfigure(encoding="utf-8", errors="replace", line_buffering=True)
    except Exception:
        pass

