def _setup_step(n: int, total: int, title: str):
    """Section header for each step inside a subcommand (pair / resurrect /
    retire / unpair). Dim underline gives a consistent visual rhythm between
    phases without requiring each caller to track its own state."""
    print()
    print(f"  {_c(_ACCENT + _BOLD, f'[{n}/{total}]')} {_c(_BOLD, title)}")
    print(f"  {_rule(max_width=58)}")


def _bat_glyph(pct_int: int) -> str:
    """Quarter-phase moon glyph by remaining charge — shared across
    Windows/macOS/Linux battery-state branches."""
    if pct_int <= 25:  return "◓"
    if pct_int <= 50:  return "◒"
    if pct_int <= 75:  return "◑"
    return "◐"


def _battery_state() -> str:
    """Return a short display string for the machine's power state.
    "On AC" / "On battery (N%)" / "Plugged in (no battery)" / ""
    Empty string = caller should skip the row (unsupported platform or
    probe failure). Cached for ~10s so multiple context-strip renders
    in the same command don't re-probe.

    Cross-platform via per-OS probes:
      Windows  — PowerShell + Get-CimInstance Win32_Battery
      macOS    — `pmset -g batt` text parse
      Linux    — /sys/class/power_supply/BAT*/{capacity,status} sysfs
    Returns "" on any unsupported OS or probe error so callers can
    silently skip the context-strip row (F6 of the CLI audit)."""
    import platform as _platform
    import time as _time
    cache_key = "_battery_state_cache"
    g = globals()
    cached = g.get(cache_key)
    if cached and (_time.time() - cached[0]) < 10:
        return cached[1]

    sys_name = _platform.system()
    result = ""

    if sys_name == "Windows":
        try:
            ps = subprocess.run(
                ["powershell", "-NoProfile", "-NonInteractive", "-Command",
                 "$b = Get-CimInstance Win32_Battery -ErrorAction SilentlyContinue | Select-Object -First 1; "
                 "if ($b -eq $null) { 'NONE' } else { \"$($b.BatteryStatus):$($b.EstimatedChargeRemaining)\" }"],
                capture_output=True, text=True, timeout=8,
                creationflags=_PS_NO_WINDOW,
            )
            out = (ps.stdout or "").strip()
        except Exception:
            out = ""
        if out == "NONE":
            result = "▰ Plugged in (no battery)"
        elif ":" in out:
            status, _, pct = out.partition(":")
            try:
                status_i = int(status)
                pct_i = int(pct) if pct.isdigit() else 100
                pct_s = f" ({pct}%)" if pct.isdigit() else ""
                # Win32_Battery.BatteryStatus: 1=Discharging, 2=AC, 3=Fully charged,
                # 4=Low, 5=Critical, 6=Charging, 7=Charging+High, 8=Charging+Low,
                # 9=Charging+Critical, 10=Undefined, 11=Partially charged
                if status_i == 1:
                    result = f"{_bat_glyph(pct_i)} On battery{pct_s}"
                elif status_i in (2, 3, 11):
                    result = f"⚡ On AC{pct_s}"
                elif status_i in (6, 7, 8, 9):
                    result = f"⚡ Charging{pct_s}"
                else:
                    result = f"⚡ AC/battery state {status_i}{pct_s}"
            except ValueError:
                result = ""

    elif sys_name == "Darwin":
        # `pmset -g batt` first line is the AC adapter state; second line
        # has the per-cell battery state in a human-parseable shape like
        # "  -InternalBattery-0 (id=0)  82%; discharging; 4:12 remaining"
        try:
            r = subprocess.run(["pmset", "-g", "batt"], capture_output=True,
                               text=True, timeout=5)
            lines = (r.stdout or "").splitlines()
        except Exception:
            lines = []
        if not lines:
            result = ""
        else:
            ac_line = (lines[0] or "").lower()
            batt_line = lines[1] if len(lines) > 1 else ""
            import re as _re
            pct_m = _re.search(r"(\d+)%", batt_line)
            pct_i = int(pct_m.group(1)) if pct_m else 100
            pct_s = f" ({pct_i}%)" if pct_m else ""
            if "no batteries" in ac_line or "no battery" in ac_line:
                result = "▰ Plugged in (no battery)"
            elif "discharging" in batt_line.lower():
                result = f"{_bat_glyph(pct_i)} On battery{pct_s}"
            elif "charging" in batt_line.lower():
                result = f"⚡ Charging{pct_s}"
            elif "charged" in batt_line.lower() or "ac power" in ac_line:
                result = f"⚡ On AC{pct_s}"
            else:
                result = ""

    elif sys_name == "Linux":
        # sysfs is universal on Linux desktops + Crostini. Find the first
        # BAT* entry; if there's none assume desktop (no battery row).
        try:
            from pathlib import Path as _Path
            ps_root = _Path("/sys/class/power_supply")
            bats = sorted(ps_root.glob("BAT*")) if ps_root.exists() else []
        except Exception:
            bats = []
        if not bats:
            result = ""
        else:
            bat = bats[0]
            try:
                cap = (bat / "capacity").read_text().strip()
                stat = (bat / "status").read_text().strip().lower()
                pct_i = int(cap) if cap.isdigit() else 100
                pct_s = f" ({pct_i}%)" if cap.isdigit() else ""
            except Exception:
                pct_i, pct_s, stat = 100, "", ""
            if stat == "discharging":
                result = f"{_bat_glyph(pct_i)} On battery{pct_s}"
            elif stat == "charging":
                result = f"⚡ Charging{pct_s}"
            elif stat in ("full", "not charging"):
                result = f"⚡ On AC{pct_s}"

    g[cache_key] = (_time.time(), result)
    return result


def _local_api_health(port: int = 8000, timeout_s: float = 3.0) -> "tuple[bool, str]":
    """Probe http://localhost:<port>/api/health. Returns (ok, detail).
    detail is a short status string for printing (e.g. "200 OK" / "no
    connection" / "timeout"). Used by --resurrect Step 4 to confirm the
    backend is actually responding before declaring success.

    Cross-platform via urllib (stdlib) — pre-2026-05-20 this used
    PowerShell's Invoke-WebRequest which made the POSIX --resurrect Step 4
    health probe a silent no-op. Now works the same everywhere.
    """
    import urllib.request as _urlreq
    import urllib.error as _urlerr
    try:
        req = _urlreq.Request(
            f"http://localhost:{port}/api/health",
            headers={"User-Agent": "research.py/_local_api_health"},
        )
        with _urlreq.urlopen(req, timeout=timeout_s) as r:
            if r.status == 200:
                return True, "200 OK"
            return False, f"HTTP {r.status}"
    except _urlerr.HTTPError as e:
        return False, f"HTTP {e.code}"
    except _urlerr.URLError as e:
        # ConnectionRefusedError, DNS failure, timeout — all wrapped here.
        reason = getattr(e, "reason", e)
        msg = str(reason)
        return False, msg[:120] if msg else "connection failed"
    except Exception as e:
        return False, f"probe error: {e}"[:120]


def _print_with_flourish(line: str, fade_to_color: str | None = None,
                         hold_s: float = 0.5) -> None:
    """Print a final-line flourish at the tail of a subcommand. If
    fade_to_color is None, prints once and returns. If set, prints `line`
    raw, sleeps hold_s, then \\r-overwrites the same line wrapped in
    fade_to_color so the eye sees a soft settle from bright → dim.
    Skipped (plain print) when stdout isn't a TTY or color is off, so
    CI/log-capture stays clean."""
    import time as _time
    print(line)
    if fade_to_color is None or not _USE_COLOR or not sys.stdout.isatty():
        return
    import re as _re
    plain = _re.sub(r"\x1b\[[0-9;]*m", "", line)
    _time.sleep(hold_s)
    sys.stdout.write("\033[F\r\033[2K")  # cursor up, col 0, erase line
    sys.stdout.write(_c(fade_to_color, plain) + "\n")
    sys.stdout.flush()


def _aegis_rune(supervised: bool, transition_to: str | None = None) -> str:
    """Render the supervised-state cell for context strips with manuscript
    runes instead of plain "on"/"off". Filled diamond = aegis vigilans
    (watching); hollow diamond = quiescens (resting). Optional transition
    arrow shows an about-to-arm state."""
    if supervised:
        return _c(_OK, "◆ vigilans")
    if transition_to == "on":
        return _c(_DIM, "◇ quiescens → ") + _c(_OK, "vigilans")
    if transition_to == "nothing-to-undo":
        return _c(_DIM, "◇ quiescens — nothing to undo")
    return _c(_DIM, "◇ quiescens")


def _render_context_strip(items: list[tuple[str, str]]):
    """Print a 'metadata strip' of (label, preformatted_value) pairs right
    after _branded_header, before any [n/total] step counters fire. Gives
    every subcommand the same 'here's where you are' header that --serve's
    Paired to / Token / Local API / Heartbeat block already nails.

    Caller pre-formats values (so green `(active)` chips, dim fallbacks,
    etc. are its call). Labels auto-pad to the longest one so the right
    column aligns without manual column math in every caller."""
    if not items:
        return
    label_width = max(len(lab) for lab, _ in items)
    print()
    for lab, val in items:
        print(f"  {_c(_DIM, (lab + ':').ljust(label_width + 2))}  {val}")


def _fetch_paired_email(paired_uid: str | None) -> str:
    """Best-effort lookup of the user's email for display. Returns empty
    string if Firestore is unreachable or the uid is unknown — callers
    fall back to showing '(not paired)' or the truncated uid.

    Post-Track-D: reads from the device doc's `ownerEmail` field (set
    by the claim Cloud Function from claimerRecord.email), NOT the
    legacy `users/{uid}.email` path which the synth user can't read
    per the user-tree rule."""
    if not _firebase_db:
        return ""
    device_id = load_device_id()
    if not device_id:
        return ""
    try:
        snap = _firebase_db.collection("devices").document(device_id).get()
        if snap.exists:
            return (snap.to_dict() or {}).get("ownerEmail", "") or ""
    except Exception:
        pass
    return ""


def _fetch_device_meta() -> dict:
    """Read the BE's own `devices/{deviceId}` doc for banner display.
    Returns {} on any failure; the synth user can read its own device
    doc per the rule. Surfaces owner identity (name + email) +
    device-side metadata (user-editable name + OS string) so the
    --serve banner can show the same identity surface as the FE
    Account-page tile."""
    if not _firebase_db:
        return {}
    device_id = load_device_id()
    if not device_id:
        return {}
    try:
        snap = _firebase_db.collection("devices").document(device_id).get()
        if snap.exists:
            return snap.to_dict() or {}
    except Exception:
        pass
    return {}


def _fetch_device_meta_rest() -> dict:
    """REST-based variant of `_fetch_device_meta` for subcommands that
    deliberately skip `init_firebase()` to stay fast (--retire,
    --resurrect, --unpair). Uses the keystore-cached id token + Firestore
    REST GET — no gRPC client init.

    The synth user's read rule allows `auth.uid == syntheticDeviceUid`
    on its own device doc, so this works without owner credentials.
    Returns {} on any failure (missing token, network, decode).
    """
    device_id = load_device_id()
    if not device_id:
        return {}
    id_token = _fresh_user_mode_id_token()
    if not id_token:
        return {}
    try:
        from auth.v2_flow import PROJECT_ID as _PID
        import requests as _requests
    except ImportError:
        return {}
    url = (
        f"https://firestore.googleapis.com/v1/projects/{_PID}"
        f"/databases/(default)/documents/devices/{device_id}"
    )
    try:
        resp = _requests.get(
            url,
            headers={"Authorization": f"Bearer {id_token}"},
            timeout=5,
        )
        if resp.status_code != 200:
            return {}
        body = resp.json() or {}
        fields = body.get("fields") or {}
    except Exception:
        return {}
    # Unwrap Firestore REST primitive shape → plain Python dict.
    out: dict = {}
    for k, v in fields.items():
        if not isinstance(v, dict):
            continue
        if "stringValue" in v:
            out[k] = v["stringValue"]
        elif "booleanValue" in v:
            out[k] = bool(v["booleanValue"])
        elif "integerValue" in v:
            try:
                out[k] = int(v["integerValue"])
            except Exception:
                pass
        elif "arrayValue" in v:
            arr = (v["arrayValue"] or {}).get("values") or []
            out[k] = [
                _x.get("stringValue") for _x in arr if isinstance(_x, dict)
            ]
    return out


def _render_next_actions(items: list[tuple[str, str]]):
    """Print a compact 'Next' block at the tail of every subcommand: 2-3
    likely follow-up commands with one-liner purposes. items = [(command,
    description), ...]. Gives the user a consistent discovery surface for
    adjacent tooling so they're not hunting through --help or memory."""
    # pip-style upgrade nudge: when a NEWER version is published on PyPI, prepend
    # an "update available" action so it surfaces in the Next block of whatever
    # command the user just ran. Memoized + 24h-cached + fail-silent (see
    # _check_newer_version) so it adds no real cost and never blocks.
    try:
        _newer = _newer_version_notice()
    except Exception:
        _newer = None
    if _newer:
        items = [(
            "python research.py --update",
            f"update available — v{_newer} is on PyPI (you have v{_sr_version()})",
        )] + list(items)
    if not items:
        return
    # Commands are authored as `python research.py …`; swap in the prefix that
    # matches how this process was launched (drop-in `superresearch` when
    # installed). Done before width calc so column alignment uses the real text.
    items = [(cmd.replace("python research.py", _PROG), desc) for cmd, desc in items]
    bar = _rule("┈")
    cmd_width = min(max(len(c) for c, _ in items), 40)
    print()
    print(f"  {bar}")
    print(f"  {_c(_DIM, 'Next')}")
    for cmd, desc in items:
        print(f"    {_c(_ACCENT, '→')}  {_c(_BOLD, cmd.ljust(cmd_width))}   {_c(_DIM, desc)}")
    print()


class _SyncSpinnerCtx:
    """Context manager rendering a Braille-dot spinner on a single line
    until the block exits. Used around short sync poll loops (--retire kill
    wait, --resurrect daemon-loop appearance, --unpair process cleanup)
    so 5-8s of otherwise silent wall-clock time reads as 'alive' to the
    user. Single \\r-overwritten line — no scroll noise."""
    def __init__(self, label: str):
        self.label = label
        import threading as _threading
        self._threading = _threading
        self._stop = _threading.Event()
        self._thread: _threading.Thread | None = None

    def _spin(self):
        i = 0
        start = time.time()
        while not self._stop.is_set():
            frame = _SPINNER_FRAMES[i % len(_SPINNER_FRAMES)]
            elapsed = int(time.time() - start)
            sys.stdout.write(
                f"\r  {_c(_ACCENT, frame)}  {_c(_DIM, self.label + '…')}   "
                f"{_c(_DIM, f'{elapsed}s')}    "
            )
            sys.stdout.flush()
            i += 1
            time.sleep(0.1)

    def __enter__(self):
        self._thread = self._threading.Thread(target=self._spin, daemon=True)
        self._thread.start()
        return self

    def __exit__(self, *_exc):
        self._stop.set()
        if self._thread is not None:
            self._thread.join(timeout=0.5)
        _clear_status_line()
        return False


def _sync_spinner_ctx(label: str) -> _SyncSpinnerCtx:
    return _SyncSpinnerCtx(label)


class _AsyncSpinnerCtx:
    """Async-context spinner. The animation runs in a BACKGROUND THREAD (not an
    asyncio task) so it keeps spinning even when the wrapped operation blocks the
    event loop — a Chrome cold-launch, a sync call that wasn't offloaded, a
    Playwright op, etc. An asyncio-task spinner freezes in exactly those cases,
    which is what read as 'stuck' during --pair (browser launch, etc.). Thread
    animation is independent of the loop, so it animates no matter what the
    wrapped op does."""
    def __init__(self, label: str):
        self.label = label
        import threading as _threading
        self._threading = _threading
        self._stop = _threading.Event()
        self._thread = None

    def _spin(self):
        i = 0
        start = time.time()
        while not self._stop.is_set():
            frame = _SPINNER_FRAMES[i % len(_SPINNER_FRAMES)]
            elapsed = int(time.time() - start)
            sys.stdout.write(
                f"\r  {_c(_ACCENT, frame)}  {_c(_DIM, self.label + '…')}   "
                f"{_c(_DIM, f'{elapsed}s')}    "
            )
            sys.stdout.flush()
            i += 1
            time.sleep(0.1)

    async def __aenter__(self):
        self._thread = self._threading.Thread(target=self._spin, daemon=True)
        self._thread.start()
        return self

    async def __aexit__(self, *_exc):
        self._stop.set()
        if self._thread is not None:
            self._thread.join(timeout=0.5)
        _clear_status_line()
        return False


def _async_spinner_ctx(label: str) -> _AsyncSpinnerCtx:
    return _AsyncSpinnerCtx(label)


def log_action(action, details=""):
    ts = datetime.now().strftime("%H:%M:%S")
    extra = f" — {details}" if details else ""
    print(f"[{ts}] [ACTION] {action}{extra}")


def safe_name(topic, max_len=50):
    # Collapse any run of non-(word|dash) characters into a single underscore.
    # Old impl replaced literal spaces only — newlines and other whitespace
    # leaked into queue dir names (e.g. multi-line Flow C topics like
    # "Research\n\nLinks to..."), which Windows rejects with WinError 123.
    return re.sub(r'[^\w-]+', '_', topic).strip('_')[:max_len]


# ── Run-name reference ───────────────────────────────────────────────────────
# `_tracks_dir` is a legacy name kept for the many call sites that read
# `_tracks_dir.name` (the run identifier). The tracks/ folder tree was
# fully removed in 2026-04-29 (events.jsonl writes + per-platform JSON
# scrape snapshots both gone), so the Path is no longer constructed
# under a tracks/ root — it just holds the run name so existing
# `_tracks_dir.name` reads continue to resolve. Firestore + queues/ are
# the only on-disk + transport surfaces now.

_tracks_dir = None  # Set per-run in run_pipeline


def init_tracks(run_name):
    """Set the per-run name reference for `_tracks_dir.name` lookups.
    Does NOT create any directories. Previously rooted under tracks/;
    that folder tree is gone, so the Path here is just a name holder."""
    global _tracks_dir
    _tracks_dir = Path(run_name)
    return _tracks_dir


# Once-per-process gate so a Linux box without wl-clipboard/xclip installed
# logs the missing-tool diagnosis exactly once (not on every clipboard read).
_clipboard_tool_missing_warned: set = set()


def _warn_clipboard_tool_missing_once(platform_label: str, tried: list):
    if platform_label in _clipboard_tool_missing_warned:
        return
    _clipboard_tool_missing_warned.add(platform_label)
    try:
        log(f"[clipboard] No usable clipboard tool found on {platform_label} "
            f"(tried: {', '.join(tried)}). Install wl-clipboard (Wayland) or "
            f"xclip (X11) for clipboard-based extraction to work.", "WARN")
    except Exception:
        pass


def get_clipboard():
    """Read clipboard text via the platform-native tool.

    Windows : powershell.exe Get-Clipboard
    macOS   : pbpaste
    Linux   : wl-paste --no-newline (Wayland) → xclip -selection clipboard -o (X11)

    Returns "" on any failure (tool missing, timeout, non-zero exit). On Linux
    a missing tool is reported once-per-process so the run log surfaces it
    without spamming."""
    if sys.platform == "win32":
        try:
            result = subprocess.run(
                ["powershell.exe", "-NoProfile", "-Command", "Get-Clipboard"],
                capture_output=True, text=True, timeout=5,
                creationflags=_PS_NO_WINDOW,
            )
            return result.stdout.strip() if result.returncode == 0 else ""
        except Exception:
            return ""
    if sys.platform == "darwin":
        try:
            result = subprocess.run(
                ["pbpaste"], capture_output=True, text=True, timeout=5
            )
            return result.stdout.strip() if result.returncode == 0 else ""
        except FileNotFoundError:
            _warn_clipboard_tool_missing_once("macOS", ["pbpaste"])
            return ""
        except Exception:
            return ""
    # Linux / other POSIX: try Wayland first, then X11.
    tried = []
    for cmd in (["wl-paste", "--no-newline"],
                ["xclip", "-selection", "clipboard", "-o"]):
        tried.append(cmd[0])
        try:
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=5)
            if result.returncode == 0:
                return result.stdout.strip()
            # wl-paste exits 1 on an empty clipboard ("Nothing is copied" on
            # stderr) — that's the intended "" result, not a tool failure.
            # Without this branch we'd cascade to xclip and, on a Wayland-only
            # box without xclip, fire a spurious tool-missing WARN on every
            # extraction (because clear_clipboard() runs immediately before
            # get_clipboard() at every call site).
            if cmd[0] == "wl-paste" and result.returncode == 1:
                return ""
        except FileNotFoundError:
            continue
        except Exception:
            continue
    _warn_clipboard_tool_missing_once("Linux", tried)
    return ""


def clear_clipboard():
    """Clear the OS clipboard. Silent no-op on failure.

    Used to prevent stale text from a prior run / prior phase being returned
    by extractors that race a fresh copy against an old clipboard. Same
    platform branching as get_clipboard()."""
    if sys.platform == "win32":
        try:
            subprocess.run(
                ["powershell.exe", "-NoProfile", "-Command", "Set-Clipboard -Value ''"],
                capture_output=True, timeout=5,
                creationflags=_PS_NO_WINDOW,
            )
        except Exception:
            pass
        return
    if sys.platform == "darwin":
        try:
            subprocess.run(["pbcopy"], input="", text=True,
                           capture_output=True, timeout=5)
        except Exception:
            pass
        return
    # Linux / other POSIX: try Wayland first, then X11.
    for cmd in (["wl-copy", "--clear"],
                ["xclip", "-selection", "clipboard", "-i"]):
        try:
            # wl-copy --clear takes no stdin; xclip -i needs empty stdin.
            kwargs = {"capture_output": True, "timeout": 5}
            if cmd[0] == "xclip":
                kwargs["input"] = ""
                kwargs["text"] = True
            subprocess.run(cmd, **kwargs)
            return
        except FileNotFoundError:
            continue
        except Exception:
            return


# Canonical agent/platform key the frontend uses in details[<key>]. Matches the
# keys set when agent_progress events are emitted (lowercase, whitespace-stripped).
_AGENT_KEY_ALIASES = {
    # Phase 1 is ChatGPT Pro + Extended Thinking — surface it as "chatgpt"
    # (the platform) rather than "brief" (the output artifact) so the UI
    # shows a single ChatGPT card, not two cards labelled "Brief" and "ChatGPT".
    "phase1": "chatgpt",
    "brief": "chatgpt",
    "chatgpt": "chatgpt",
    "gemini": "gemini",
    "claude": "claude",
    "notebooklm": "notebooklm",
    "system": "system",
}

def normalize_agent_key(name):
    """Normalize any agent/platform name (capitalized, spaced, aliased) to the
    canonical key the frontend expects in pipelineData.details. Safe for event emits."""
    if not name:
        return "system"
    k = str(name).lower().replace(" ", "")
    return _AGENT_KEY_ALIASES.get(k, k)


# save_track removed 2026-04-29 — was write-only telemetry under tracks/{rid}/
# with zero readers. Firestore + pipeline_events events are the single source
# of truth for run progress.


# ── Firebase Bridge (Firestore real-time transport) ──────────────────────────

_firebase_db = None     # Firestore client (module-level, init once)
# #717 — why the client is down, so recovery routes correctly. Overloading
# `_firebase_db is None` for BOTH a transient network/DNS blip AND a genuine
# token revoke was the 2026-05-31 incident: a `getaddrinfo` blip nulled the
# client, the relink loop assumed revoke and spun on a stale customToken
# (INVALID_CUSTOM_TOKEN), and the device sat OFFLINE until the 1-hour cap.
#   None        → healthy
#   "transient" → DNS/network/5xx; refresh token still valid (keystore intact).
#                 _firebase_reconnect_loop retries init_firebase on a tight backoff.
#   "revoked"   → refresh token rejected (Reset Pair Code / keystore wiped).
#                 _revoked_recovery_loop owns recovery (customToken relink).
_firebase_down_reason = None
_fb_uid = None          # Per-run: user ID for Firestore path
_fb_research_id = None  # Per-run: research ID for Firestore path
_fb_seq = 0             # Per-run: last-emitted seq (monotonic guard; ms-based)
_fb_listener = None     # Per-run: command listener unsubscribe handle

# Shared queue state: mutated by the job worker in run_server, read by the
# Firestore start listener (module-level function) so queued research docs
# know the current backend busy state + what they're waiting behind.
_QUEUE_STATE = {
    "running": False, "current_job": None, "queue_ref": None, "recompute_fn": None,
    # 2026-05-15: persist_fn exposes the run_server closure
    # `_persist_pending_queue` to the module-scope device-cmd listener
    # (research.py:1766) so hard_reset can flush a clean snapshot to disk
    # before os._exit. _hard_reset_lock makes the gate-state clear+persist
    # atomic w.r.t. the worker's `finally` writes — without it, a worker
    # finishing between the device-cmd's clear (memory) and persist (disk)
    # would resurrect the wedged values to disk. Both initialised inside
    # run_server (research.py:24049-24051) before the device-cmd listener
    # starts at research.py:24898.
    "persist_fn": None, "_hard_reset_lock": None,
    # 2026-05-11: prior-run tracking for the FE-completion queue gate
    # (BE_PHASES_TIMEOUT_SEC). The worker's finally{} block records the
    # just-completed run's uid+rid+timestamp here so the NEXT dequeue can
    # poll its Firestore status until FE-P5 flips it to "completed" (or
    # the 4200s fallback fires). last_be_done_at=0 on error/timeout paths
    # short-circuits the gate so a watchdog-stopped run doesn't wedge the
    # queue for 70 min.
    "last_completed_uid": None, "last_completed_rid": None, "last_be_done_at": 0,
    # 2026-05-22: listener-replay dual-claim gate.
    # Firestore on_snapshot delivers ADDED changes synchronously in a
    # callback thread; the actual asyncio.Queue.put happens via
    # `loop.call_soon_threadsafe(...)`, which is asynchronous. Between
    # the listener's claim+schedule of doc A and its next iteration
    # processing doc B, the gate at research.py:4106 reads
    # `job_queue.qsize()` — but A's put hasn't landed on the event loop
    # yet, so qsize() is still 0. Gate passes, B is also claimed,
    # dual-spawn for back-to-back submissions (the 2026-05-22 St Bernard
    # repro). The counter increments AFTER `_try_claim_queue_doc`
    # success + BEFORE call_soon_threadsafe, decrements either at the
    # worker's running-flag flip OR on `_safe_enqueue == False` (rare
    # race-loss in the call_soon callback). `threading.Lock` because
    # increment runs on the Firestore listener thread and decrement
    # runs on the asyncio main thread — true cross-thread access.
    "_pending_listener_enqueues": 0, "_pending_enq_lock": None,
}


def _pending_enq_inc():
    """Listener-thread increment. Idempotent on first-call when the
    `_pending_enq_lock` hasn't been initialised yet (run_server
    initialises it during startup at research.py:~26686). The pre-init
    case only matters in tests; in prod the lock is always set before
    the listener attaches."""
    lock = _QUEUE_STATE.get("_pending_enq_lock")
    if lock is None:
        _QUEUE_STATE["_pending_listener_enqueues"] = \
            _QUEUE_STATE.get("_pending_listener_enqueues", 0) + 1
        return
    with lock:
        _QUEUE_STATE["_pending_listener_enqueues"] = \
            _QUEUE_STATE.get("_pending_listener_enqueues", 0) + 1


def _pending_enq_dec():
    """Asyncio-main-thread decrement. Fires from one of three sites:
    (a) the worker's running-flag flip (normal path, after dequeue +
    gate wait); (b) the stop-during-gate-wait short-circuit; (c) the
    `_enqueue_with_position_refresh` `_safe_enqueue == False` branch
    inside the `call_soon_threadsafe` callback (cancel landed between
    claim and put). All three run on the asyncio main thread; the
    increment in `_pending_enq_inc` runs on the Firestore listener
    thread, so the lock guards cross-thread access. `max(0, ...)`
    defensively in case a stray decrement (e.g., a worker crash +
    daemon-loop respawn between increment and decrement) would
    otherwise drive the counter negative — false-busy gate would
    block all submissions until next process bounce."""
    lock = _QUEUE_STATE.get("_pending_enq_lock")
    if lock is None:
        _QUEUE_STATE["_pending_listener_enqueues"] = \
            max(0, _QUEUE_STATE.get("_pending_listener_enqueues", 0) - 1)
        return
    with lock:
        _QUEUE_STATE["_pending_listener_enqueues"] = \
            max(0, _QUEUE_STATE.get("_pending_listener_enqueues", 0) - 1)


def _sweep_stuck_research_docs_for_device(
    db, paired_uid: str, device_id: str, *,
    stopped_by: str, summary: str,
) -> "tuple[int, int]":
    """Multi-user wrapper around `_sweep_stuck_research_docs`. Sweeps
    the paired owner's tree AND every uid in `device.sharedWith[]`.

    Without this wrapper, an owner-only sweep leaves sharer-submitted
    runs stuck on Reset BE / unpair — the sharer's chat tiles persist
    as "ongoing" with no live BE behind them. The 2026-05-22 St
    Bernard repro highlighted this gap (St Bernard was owner-tree so
    the user-facing fix landed, but the same flow on a sharer's run
    would be invisible to a Reset).

    Firestore rules path: synth-device-user reads/writes user-tree
    research docs via `deviceMemberOf(userId)` (firestore.rules:45-49),
    which checks `deviceOwnership(deviceId, userId)` — true when this
    device's `ownerUid == userId` OR `userId in sharedWith`. So the
    sweep can iterate any uid the device's sharedWith[] lists, same
    as it already does for the paired owner.

    Resolves `sharedWith` from `devices/{deviceId}.sharedWith[]`. Best-
    effort — if the device-doc read fails (revoked token, etc.), falls
    back to owner-only sweep. Per-uid sweep failures (PERMISSION_DENIED
    on an unexpected sharer permissions edge case, etc.) are logged
    DEBUG + counted; sweeping continues with remaining uids.
    """
    if not (db and paired_uid and device_id):
        return (0, 0)
    sharers: "list[str]" = []
    try:
        ds = db.collection("devices").document(device_id).get()
        if ds.exists:
            shared = (ds.to_dict() or {}).get("sharedWith") or []
            # Deduplicate against paired_uid + filter empties so a
            # mis-configured device doc with the owner listed twice
            # doesn't cause a double-sweep.
            sharers = [u for u in shared if u and u != paired_uid]
    except Exception as _de:
        log(
            f"[sweep:{stopped_by}] sharedWith read failed ({_de}); sweeping owner only",
            "DEBUG",
        )
    total_n = 0
    total_fail = 0
    for uid in [paired_uid, *sharers]:
        try:
            n, f = _sweep_stuck_research_docs(
                db, uid, device_id,
                stopped_by=stopped_by, summary=summary,
            )
            total_n += n
            total_fail += f
            if n or f:
                _label = "owner" if uid == paired_uid else f"sharer {uid[:8]}"
                log(
                    f"[sweep:{stopped_by}] {_label}: swept={n} failed={f}",
                    "DEBUG",
                )
        except Exception as _ue:
            # PERMISSION_DENIED, transient network, etc. Sharer-tree
            # reads should succeed under the deviceMemberOf rule, but
            # the rule cache or a rules-engine `get()` call limit can
            # cause sporadic 403s in edge cases. Defensive: continue
            # with the remaining trees.
            log(
                f"[sweep:{stopped_by}] sweep raised for uid={uid[:8]} ({_ue}); continuing",
                "DEBUG",
            )
    return (total_n, total_fail)


def _sweep_stuck_research_docs(db, paired_uid: str, device_id: str, *,
                                stopped_by: str, summary: str) -> "tuple[int, int]":
    """Bulk-sweep stale BE-self-set states for one device's runs in the
    owner's research collection. Returns `(swept_count, fail_count)`.

    Used by:
      - HARD_RESET (FE Reset Backend / Online button)
      - run_unpair (CLI `--unpair`)

    Both contexts mean "the BE is leaving / restarting on this device,
    leave Firestore in a clean state". User-driven terminal states
    (`stopped`, `completed`, `terminated_by_user_discard`,
    `stopped_by_watchdog`) are left alone — those are audit-trail.

    Stuck set (extended 2026-05-22 from {ongoing, running, paused}):
      - `queued`: pre-claim docs the BE will never get to process
      - `paused_backend_restart`: BE-self-set on reboot when a run
        was status=ongoing pre-exit (the 2026-05-22 St Bernard
        symptom — HARD_RESET's prior sweep missed this status, so a
        "Reset BE" couldn't actually unstick the chat)
      - `paused_backend_restart_failed`: BE-self-set when the resume
        attempt also crashed

    Per-doc patch: status=stopped, cancelled=true, stoppedBy=<arg>,
    summary=<arg>, plus DELETE_FIELD on queuePosition /
    queuedBehindRunId / queuedBehindTitle so a freshly-paired BE
    doesn't see leftover position markers.

    Best-effort: any per-doc update failure is counted as `fail`;
    sweeping continues. A query-level failure raises (caller logs)."""
    if not (db and paired_uid and device_id):
        return (0, 0)
    swept_n = 0
    swept_fail = 0
    stuck_set = {
        "ongoing", "running", "paused", "queued",
        "paused_backend_restart", "paused_backend_restart_failed",
    }
    now_ms = int(time.time() * 1000)
    try:
        from google.cloud.firestore import DELETE_FIELD as _DF
    except Exception:
        _DF = None  # type: ignore
    res_col = db.collection("users").document(paired_uid).collection("researches")
    # No compound where: deviceId may be absent on legacy docs.
    # Cheap to filter client-side — research collection is small
    # (<200 docs per user typically).
    for snap in res_col.where("deviceId", "==", device_id).stream():
        sd = snap.to_dict() or {}
        status = (sd.get("status") or "").lower()
        if status not in stuck_set:
            continue
        patch: dict = {
            "status": "stopped",
            "updatedAt": now_ms,
            "stoppedAt": now_ms,
            "stoppedBy": stopped_by,
            "summary": summary,
        }
        # 2026-05-26: only mark `cancelled: True` for runs that were
        # QUEUED (pre-claim, never started executing). Ongoing /
        # paused / paused_backend_restart runs have partial work
        # (browser state, intermediate artifacts, possibly emitted
        # phase events) that the user should see in their listing as
        # "Stopped" — not silently disappear. The FE's chat-close
        # cascade-delete fires only on cancelled=true (see
        # ChatContainer.tsx cancelledRef cleanup ~line 596), so
        # leaving cancelled unset preserves these runs in the
        # listing as historical Stopped entries.
        if status == "queued":
            patch["cancelled"] = True
        if _DF is not None:
            patch["queuePosition"] = _DF
            patch["queuedBehindRunId"] = _DF
            patch["queuedBehindTitle"] = _DF
        try:
            # #720: _be_payload injects the deviceId deviceUpdatingFor REQUIRES
            # (this was a raw dict → denied even with a fresh token), and the
            # heal recovers a stale-token 403 (this runs on the long-lived
            # device-command listener thread, where the token can be stale).
            _grpc_write_with_heal(
                lambda snap=snap, patch=patch: snap.reference.update(_be_payload(patch)),
                what=f"sweep:{stopped_by} {snap.id[:8]}")
            swept_n += 1
        except Exception as _sw_err:
            swept_fail += 1
            log(
                f"[sweep:{stopped_by}] update failed for {snap.id[:24]}…: {_sw_err}",
                "DEBUG",
            )
    return (swept_n, swept_fail)


def _queue_doc_fifo_ms(data: dict) -> "int | None":
    """Resolve a queue-doc payload's ordering timestamp in epoch ms.

    Prefers `submittedAt` (Firestore `serverTimestamp()` set in
    `buildQueuePayload` at FE-side — immune to client clock skew between
    owner / sharer browsers). Falls back to the legacy `timestamp`
    (client `Date.now()` ms) when the server field is missing — covers
    pre-server-timestamp docs that may still sit in the queue across a
    deploy. Returns None when neither field carries a usable value, so
    the caller can demote the snap to last-place.

    Clock-skew was the 2026-05-22 follow-up to Bug A: sharer's browser
    clock was behind owner's by a few seconds, so a sharer-submitted
    Bull Dog doc could land with `timestamp < Husky.timestamp` and sort
    ahead of an owner-submitted Husky that actually reached Firestore
    first. The server timestamp removes that variability."""
    sat = data.get("submittedAt")
    if sat is not None:
        try:
            return int(sat.timestamp() * 1000)
        except (AttributeError, TypeError, ValueError):
            pass
    ts = data.get("timestamp")
    if isinstance(ts, (int, float)) and ts > 0:
        return int(ts)
    return None


def _compute_global_queue_position(col_ref, my_doc_id: str) -> "tuple[int, str, str]":
    """Compute this queue-doc's authoritative position in the device-
    wide FIFO ordering across all submitters (owner + sharers). The
    FE-side `existingQueuedCount` only sees the current user's
    cachedResearches (Firestore rules block cross-user research reads),
    so the FE's optimistic position is wrong on multi-user devices —
    sharer's submission renders as #1 when an owner's deferred run is
    actually ahead of it (the 2026-05-22 Bull Dog / St Bernard repro).

    Returns `(position, behind_rid, behind_title)`:
      - position: 1-indexed slot in the global queue. 1 means "head"
        (next to run when any worker becomes free).
      - behind_rid / behind_title: research-id + topic of the doc
        immediately ahead of mine in FIFO order. Empty strings when
        I'm head (caller can fall back to `device.currentRunTitle`
        for the user-facing "queued behind X" message).

    Filter rules mirror the existing FIFO pre-query at research.py:4226:
      - skip `processed: true` (already-claimed-and-finished)
      - skip `assignedWorker: <not me>` (sibling has it)
      - include `assignedWorker == self` (post-claim-pre-delete window
        where my doc carries my own worker id)
      - skip non-start actions (cancel/resume have their own paths)

    Sort key: `submittedAt` (Firestore server timestamp) ASC with
    doc-id tiebreaker, falls back to client `timestamp` (ms) for
    legacy docs. Identical to the FIFO pre-query — must match exactly
    so callers and pre-query agree on who's head.

    Best-effort: on Firestore error, returns (1, "", "") so callers
    fall back to "head" semantics (safer than reporting a misleading
    larger number)."""
    try:
        candidates = list(col_ref.limit(50).stream())
    except Exception as _qe:
        log(f"[queue-position] global-scan failed (best-effort): {_qe}", "DEBUG")
        return (1, "", "")

    def _fifo_key(snap):
        d = snap.to_dict() or {}
        ms = _queue_doc_fifo_ms(d)
        if ms is not None:
            return (0, ms, snap.id)
        return (1, 0, snap.id)

    sorted_cands = sorted(candidates, key=_fifo_key)
    queue = []
    for snap in sorted_cands:
        d = snap.to_dict() or {}
        is_me = snap.id == my_doc_id
        if d.get("processed"):
            continue
        aw = d.get("assignedWorker")
        if aw and not is_me:
            continue
        if (d.get("action") or "start") != "start":
            continue
        queue.append((snap.id, d, is_me))

    my_idx = -1
    for i, (_id, _d, is_me) in enumerate(queue):
        if is_me:
            my_idx = i
            break
    if my_idx < 0:
        # Doc disappeared between caller's read and our scan
        # (cancel/delete race). Safe fallback.
        return (1, "", "")
    position = my_idx + 1
    behind_rid = ""
    behind_title = ""
    if my_idx > 0:
        _, prev_data, _ = queue[my_idx - 1]
        behind_rid = (prev_data.get("researchId") or "")
        behind_title = (prev_data.get("topic") or "")[:60]
    return (position, behind_rid, behind_title)


# Phase-duration heuristics for ETA estimation. Values are ROUGH typical
# durations from prod traces; ETA copy on the FE is intentionally fuzzy
# (rounded to 5-min granularity above 15min, "~1 hr 14 min" above 60min)
# to honor the imprecision. Prefer per-device analytics (loaded by
# `load_analytics()` into `_phase_averages` from run_analytics.json) via
# `_phase_estimate_ms` — these constants are the FRESH-INSTALL fallback
# when analytics is empty.
QUEUE_ETA_PHASE_MS = {
    0: 30 * 1000,       # P0 init — ~30s
    1: 7 * 60 * 1000,   # P1 brief — ~7 min
    2: 22 * 60 * 1000,  # P2 deep research — ~22 min (slowest)
    3: 18 * 60 * 1000,  # P3 audio gen — ~18 min
    4: 3 * 60 * 1000,   # P4 FE YouTube — ~3 min
    5: 30 * 1000,       # P5 FE delivery — ~30s
}


def _phase_estimate_ms(phase: int) -> int:
    """Per-phase duration estimate, in milliseconds. Prefers the learned
    per-device analytics (in-memory `_phase_averages`, populated from
    `run_analytics.json` at startup + after each phase completes) over
    the device-agnostic hardcoded `QUEUE_ETA_PHASE_MS`. Falls back to
    the hardcoded value when analytics is empty (fresh install) or
    missing for this specific phase. `_phase_averages` stores SECONDS
    keyed by phase int; convert to ms here.

    Forward-reference safe — `_phase_averages` is defined at module
    line ~4001 (post-helper-definition) but Python resolves globals
    at call time so this works as long as `load_analytics()` has run
    before any `_estimate_queue_eta_ms` call (it runs in server
    startup, well before listeners fire)."""
    try:
        avg_sec = _phase_averages.get(phase, 0)
        if avg_sec and avg_sec > 0:
            return int(avg_sec * 1000)
    except Exception:
        pass
    return QUEUE_ETA_PHASE_MS.get(phase, 0)


def _typical_run_ms() -> int:
    """Sum of per-phase estimates for one full run, using analytics where
    available. Replaces the module-level QUEUE_ETA_TYPICAL_RUN_MS
    constant — computing per-call is cheap (6 dict lookups) and keeps
    the value live with analytics updates from `record_phase_duration`."""
    return sum(_phase_estimate_ms(p) for p in range(6))


# Legacy alias retained for any external callers; deprecated in favor of
# `_typical_run_ms()` which respects learned analytics.
QUEUE_ETA_TYPICAL_RUN_MS = sum(QUEUE_ETA_PHASE_MS.values())  # ~51 min


def _estimate_queue_eta_ms(
    head_phase: int,
    head_phase_started_at_ms: int,
    position: int,
    worker_count: int,
) -> int:
    """Best-effort ETA for a queued doc.

    Inputs:
      head_phase: which phase the head-of-queue is currently in (0-5).
                  Falls back to 0 if unknown — caller passes 0 then.
      head_phase_started_at_ms: when the head entered its current phase,
                                in epoch ms. 0 means unknown — falls
                                back to "0 elapsed in phase" (worst-case
                                conservative).
      position: this doc's 1-indexed position in the global FIFO.
      worker_count: device's workerCount (parallelism).

    Returns: estimated ms-until-this-doc-starts. Always >= 0.

    Math:
      remaining_for_head = (remaining time in head_phase) + sum of
                          expected durations for phases AFTER head_phase
      eta = remaining_for_head + TYPICAL_RUN_MS * floor((position - 1) / W)

      Multi-worker rationale: W workers process W runs in parallel. The
      first run to complete frees a worker for position 1. With W=2 and
      both workers running, position 1 ≈ remaining_for_head (assumes
      both workers finish around the same time — true approximation),
      position 2 also ≈ remaining_for_head (other worker frees up
      similarly), position 3 ≈ remaining_for_head + TYPICAL_RUN_MS
      (next rotation), etc.

      Single-worker (W=1): position N ≈ remaining_for_head +
                          (N-1) * TYPICAL_RUN_MS — purely serial.
    """
    if position < 1:
        return 0
    _head_phase = max(0, min(5, int(head_phase or 0)))
    # 2026-05-26: switched from hardcoded QUEUE_ETA_PHASE_MS lookups to
    # _phase_estimate_ms which prefers per-device analytics. The
    # heuristic constants under-estimate by ~half on this device's
    # actual traces (P1: 7min hardcoded vs 12min analytics; P2: 22min
    # vs 56min). Switching halves the "Estimated start" undershoot
    # and produces ETAs that match observed completion times.
    _expected_head_phase_ms = _phase_estimate_ms(_head_phase)
    _started_at = int(head_phase_started_at_ms or 0)
    _now_ms = int(time.time() * 1000)
    if _started_at > 0:
        _elapsed_in_phase = max(0, _now_ms - _started_at)
        _remaining_in_head_phase = max(0, _expected_head_phase_ms - _elapsed_in_phase)
    else:
        # Unknown elapsed — conservative: assume head just entered its
        # current phase (full duration ahead). Better to overshoot ETA
        # than undershoot — undershoots produce "stuck at 0 min" UX.
        _remaining_in_head_phase = _expected_head_phase_ms
    _remaining_phases_for_head = sum(
        _phase_estimate_ms(p) for p in range(_head_phase + 1, 6)
    )
    _remaining_for_head = _remaining_in_head_phase + _remaining_phases_for_head
    _w = max(1, int(worker_count or 1))
    _rotations = max(0, (position - 1) // _w)
    return int(_remaining_for_head + _typical_run_ms() * _rotations)


def _compute_queue_enrichment(col_ref, my_doc_id: str, my_uid: str) -> dict:
    """Extended queue-position scan returning the full enrichment payload
    needed by the FE banner. Wraps the same global-FIFO scan as
    `_compute_global_queue_position` but also breaks down "ahead of me"
    by submitter UID so the FE can render copy like:

        "Your run starts after 2 other runs. 1 from your account,
         including 1 from another account."

    Returns dict keys (all present; defaults shown):
      position:           1-indexed slot (>= 1)
      total_ahead:        position - 1
      ahead_from_self:    count of ahead docs whose submittedBy == my_uid
      ahead_from_others:  total_ahead - ahead_from_self
      other_uids:         sorted list of distinct submittedBy UIDs ahead
                          (excluding self). Lets the FE compute
                          per-other-account counts if it ever wants
                          a richer breakdown.
      behind_rid:         rid of doc immediately ahead (empty if head)
      behind_title:       topic of doc immediately ahead (empty if head)
      behind_uid:         submittedBy of doc immediately ahead

    Best-effort. Falls back to defaults on Firestore error.
    """
    defaults = {
        "position": 1,
        "total_ahead": 0,
        "ahead_from_self": 0,
        "ahead_from_others": 0,
        "other_uids": [],
        "behind_rid": "",
        "behind_title": "",
        "behind_uid": "",
    }
    try:
        candidates = list(col_ref.limit(50).stream())
    except Exception as _qe:
        log(f"[queue-enrich] global-scan failed (best-effort): {_qe}", "DEBUG")
        return defaults

    def _fifo_key(snap):
        d = snap.to_dict() or {}
        ms = _queue_doc_fifo_ms(d)
        if ms is not None:
            return (0, ms, snap.id)
        return (1, 0, snap.id)

    sorted_cands = sorted(candidates, key=_fifo_key)
    queue = []
    for snap in sorted_cands:
        d = snap.to_dict() or {}
        is_me = snap.id == my_doc_id
        if d.get("processed"):
            continue
        aw = d.get("assignedWorker")
        if aw and not is_me:
            continue
        if (d.get("action") or "start") != "start":
            continue
        queue.append((snap.id, d, is_me))

    my_idx = -1
    for i, (_id, _d, is_me) in enumerate(queue):
        if is_me:
            my_idx = i
            break
    if my_idx < 0:
        return defaults

    position = my_idx + 1
    ahead = queue[:my_idx]
    other_uids = []
    ahead_from_self = 0
    ahead_from_others = 0
    for _id, _d, _ in ahead:
        _u = (_d.get("submittedBy") or "")
        if _u == my_uid and my_uid:
            ahead_from_self += 1
        else:
            ahead_from_others += 1
            if _u and _u not in other_uids:
                other_uids.append(_u)
    behind_rid = ""
    behind_title = ""
    behind_uid = ""
    if my_idx > 0:
        _, prev_data, _ = queue[my_idx - 1]
        behind_rid = (prev_data.get("researchId") or "")
        behind_title = (prev_data.get("topic") or "")[:60]
        behind_uid = (prev_data.get("submittedBy") or "")
    return {
        "position": position,
        "total_ahead": position - 1,
        "ahead_from_self": ahead_from_self,
        "ahead_from_others": ahead_from_others,
        "other_uids": sorted(other_uids),
        "behind_rid": behind_rid,
        "behind_title": behind_title,
        "behind_uid": behind_uid,
    }


def _read_eta_inputs_and_compute(position: int) -> "tuple[int, int]":
    """Helper that wraps `_estimate_queue_eta_ms` with a Firestore read
    of the device doc's `currentRunPhase` + `currentRunPhaseStartedAt`
    + `workerCount` (head-of-queue context). Returns (eta_ms, computed_at_ms).

    Sentinel: returns `(-1, now)` when Firestore is unavailable, device
    id is missing, the device doc doesn't exist, or any read raises.
    FE banner reads `queueEtaMs < 0` as "unknown" and suppresses the
    ETA line. When the device doc DOES exist but has no phase data
    yet (pre-first-run), falls through to the conservative
    `_estimate_queue_eta_ms(0, 0, …)` ~51min estimate — matches what
    `_recompute_deferred_queue_positions` does on the same condition,
    so the two paths can't diverge.
    """
    _now_ms = int(time.time() * 1000)
    if not _firebase_db:
        return (-1, _now_ms)
    try:
        _did = load_device_id()
        if not _did:
            return (-1, _now_ms)
        _dev_snap = _firebase_db.collection("devices").document(_did).get()
        if not _dev_snap.exists:
            return (-1, _now_ms)
        _dd = _dev_snap.to_dict() or {}
        _head_phase = int(_dd.get("currentRunPhase") or 0)
        _head_phase_started = int(_dd.get("currentRunPhaseStartedAt") or 0)
        _wc = int(_dd.get("workerCount") or load_worker_count() or 1)
        _eta = _estimate_queue_eta_ms(_head_phase, _head_phase_started, position, _wc)
        return (_eta, _now_ms)
    except Exception as _eta_err:
        log(f"[queue-eta] device-doc read failed (best-effort): {_eta_err}", "DEBUG")
        return (-1, _now_ms)


# 2026-05-25 (banner enrichment): single-flight lock for the deferred-
# queue ETA recompute. The phase_start hook fires recompute on every
# phase transition; if a prior recompute is still running (slow
# Firestore round-trip on a busy device), the new one short-circuits.
# Prevents thread piling and concurrent batch-write races over the same
# research docs. try_acquire-skip semantics: if lock is busy, skip
# this recompute — the next phase_start will refresh ETAs anyway, and
# the in-flight recompute will pick up whatever device-doc state was
# fresh when it started.
#
# 2026-05-25 P0 fix: local `import threading` here — the module-level
# `import threading as _threading` at line ~4050 is AFTER this code,
# so the original `_threading.Lock()` raised NameError at module load
# (worker crashed on startup, daemon-loop respawned tightly = 67+
# restarts in <5min on the affected E2E). stdlib `threading` is
# always importable; the local import + alias is the smallest fix.
import threading as _threading_for_eta_lock  # noqa: E402
_ETA_RECOMPUTE_LOCK = _threading_for_eta_lock.Lock()


def _local_pending_owner_entries() -> "list[dict]":
    """Owner-pill (`queueOwners`) entries for LOCALLY-claimed queued jobs —
    this worker's in-memory deque, exposed via ``_QUEUE_STATE["queue_ref"]``.

    Why (#890): a busy SINGLE-worker install claims every submit immediately
    (research doc stamped status="queued", queue doc deleted at claim), so
    locally-queued runs are invisible to the `devices/{id}/queue` scan below —
    the owner's "Shared with" popup never showed the amber #N badge for them.
    Agent-fired runs surfaced it (their queue always lands this way), but a
    web-fired sharer run on a busy single-worker device had the same gap.

    Positions are 1..N: a locally-claimed job always runs before any
    Firestore-deferred doc (deferral only happens while every worker is busy,
    and the local deque drains first). SINGLE-WORKER ONLY: sibling workers'
    local deques live in other PROCESSES and are invisible here, and every
    worker publishes queueOwners as a full-array overwrite — so in a
    multi-worker install a sibling's publish (e.g. after a restart restored
    a pending queue into one worker's deque) would ERASE another worker's
    local entries. Multi-worker keeps the deferred-only behavior (its busy
    submits are DEFERRED — visible to the scan — not locally queued, so
    nothing is lost). Resume-dir jobs (no uid/researchId) are skipped."""
    try:
        if int(load_worker_count() or 1) > 1:
            return []
    except Exception:
        return []
    q = _QUEUE_STATE.get("queue_ref")
    if q is None:
        return []
    try:
        pending = list(q._queue)
    except Exception:
        return []
    out: "list[dict]" = []
    for job in pending:
        uid_v = (job.get("uid") or "").strip()
        rid_v = (job.get("research_id") or "").strip()
        if not (uid_v and rid_v):
            continue
        out.append({
            "uid": uid_v,
            "runId": rid_v,
            "title": (job.get("topic") or "")[:60],
            "position": len(out) + 1,
        })
    return out


def _recompute_deferred_queue_positions() -> None:
    """Re-write `queuePosition` / `queuedBehindRunId` / `queuedBehindTitle`
    on every research doc whose queue entry is still deferred in
    Firestore (sitting in `devices/{id}/queue/` without `assignedWorker`).

    Single-flight guarded by `_ETA_RECOMPUTE_LOCK` — concurrent callers
    skip rather than queue. See lock's defining comment for rationale.

    Why this exists separately from `_recompute_queue_positions`:
      - `_recompute_queue_positions` (run_server closure, ~line 27030)
        reads only `_job_queue._queue` — the LOCAL asyncio deque of
        jobs that have already been claimed (queue doc deleted, status
        flipped to ongoing/queued). It cannot see Firestore-deferred
        docs.
      - When a worker claims a deferred doc, the docs behind it should
        shift up by one immediately. Pre-fix, those positions stayed
        stale on the research doc until the next event happened to re-
        fire their defer path (next BE restart, etc.). The FE banner
        kept showing the wrong number for minutes-to-hours.

    Mechanism: single Firestore scan of `devices/{id}/queue/`, apply
    the same FIFO sort + filter as `_compute_global_queue_position`
    (so callers and pre-claim agree on ordering), then commit one
    WriteBatch updating every remaining deferred doc. Chunks at 450
    ops to stay under Firestore's 500-op batch ceiling.

    Eventual-consistency window: between the scan and the batch commit,
    a sibling worker may claim a doc and delete its queue entry. The
    batch update on that now-orphan research doc still lands but is
    benign (FE filters on status, which transitions to ongoing first).
    Worst case: ~50ms of a momentarily wrong queuePosition before the
    next event corrects it. Mitigation via TX was rejected as too
    expensive given the 500-op batch cap.

    SYNC implementation — wrap in `asyncio.to_thread` from asyncio call
    sites so the Firestore scan + write doesn't block the event loop
    (heartbeat, watchdog, listener callbacks all live there)."""
    # Single-flight: if a prior recompute is still running, skip.
    # The next phase_start (or claim/finally) will refresh ETAs.
    if not _ETA_RECOMPUTE_LOCK.acquire(blocking=False):
        return
    try:
        _recompute_deferred_queue_positions_locked()
    finally:
        _ETA_RECOMPUTE_LOCK.release()


def _recompute_deferred_queue_positions_locked() -> None:
    """Lock-protected body of `_recompute_deferred_queue_positions`.
    Do not call directly — use the public wrapper above which enforces
    single-flight via `_ETA_RECOMPUTE_LOCK`."""
    if not _firebase_db:
        return
    device_id = load_device_id()
    if not device_id:
        return
    # #890: locally-claimed queued jobs (single-worker busy claims) lead the
    # published queueOwners union — the subcollection scan below can't see
    # them (their queue docs were deleted at claim). Snapshot here, as close
    # to the publish as possible, so a just-picked-up job drops out promptly.
    _local_owners = _local_pending_owner_entries()
    col = _firebase_db.collection("devices").document(device_id).collection("queue")
    try:
        candidates = list(col.limit(50).stream())
    except Exception as e:
        log(f"[deferred-recompute] scan failed (best-effort): {e}", "DEBUG")
        return
    if not candidates:
        # Queue subcollection empty — publish the local-only union (clears
        # stale amber badges when the local deque drained too). Best-effort.
        try:
            _firebase_db.collection("devices").document(device_id).update(
                {"queueOwners": _local_owners})
        except Exception:
            pass
        return

    def _fifo_key(snap):
        d = snap.to_dict() or {}
        ms = _queue_doc_fifo_ms(d)
        if ms is not None:
            return (0, ms, snap.id)
        return (1, 0, snap.id)

    sorted_cands = sorted(candidates, key=_fifo_key)
    queue: "list[tuple[str, dict]]" = []
    for snap in sorted_cands:
        d = snap.to_dict() or {}
        if d.get("processed"):
            continue
        if d.get("assignedWorker"):
            # Skip any-worker-assigned (including self). Self-claimed
            # docs are in the local deque path's recompute scope; this
            # helper handles only unclaimed deferred docs.
            continue
        if (d.get("action") or "start") != "start":
            continue
        queue.append((snap.id, d))

    if not queue:
        # All candidates filtered out (claimed/processed) — the deferred set
        # just drained; publish the local-only union (clears amber badges when
        # the local deque is empty too). Best-effort.
        try:
            _firebase_db.collection("devices").document(device_id).update(
                {"queueOwners": _local_owners})
        except Exception:
            pass
        return

    try:
        from google.cloud.firestore import DELETE_FIELD
    except Exception:
        DELETE_FIELD = None  # pyright: ignore[reportConstantRedefinition]

    # 2026-05-25 (banner enrichment): also recompute ETA + ahead-by-
    # account split. Read device-doc ETA inputs ONCE outside the loop
    # (head phase doesn't change per-doc; only position/worker_count
    # matter), then derive each doc's ETA from its position.
    _eta_head_phase = 0
    _eta_head_started = 0
    _eta_worker_count = 1
    try:
        _dev_snap_r = _firebase_db.collection("devices").document(device_id).get()
        if _dev_snap_r.exists:
            _dd_r = _dev_snap_r.to_dict() or {}
            _eta_head_phase = int(_dd_r.get("currentRunPhase") or 0)
            _eta_head_started = int(_dd_r.get("currentRunPhaseStartedAt") or 0)
            _eta_worker_count = int(_dd_r.get("workerCount") or load_worker_count() or 1)
    except Exception as _eta_r_err:
        log(f"[deferred-recompute] device-doc read failed (best-effort): {_eta_r_err}", "DEBUG")

    _now_ms_recompute = int(time.time() * 1000)

    # #890: deferred docs sit BEHIND any locally-claimed queued jobs — offset
    # their published positions so the amber badges + banner numbers reflect
    # the true device-wide order (offset is 0 in the common multi-worker case,
    # where busy submits defer instead of queueing locally).
    _local_offset = len(_local_owners)
    patches: "list[tuple[str, str, dict]]" = []
    _queue_owners: "list[dict]" = []
    for idx, (_sid, d) in enumerate(queue):
        uid_v = (d.get("uid") or "").strip()
        rid_v = (d.get("researchId") or "").strip()
        if not (uid_v and rid_v):
            continue
        new_pos = _local_offset + idx + 1
        # 2026-05-28: per-sharer amber-badge source for the "Shared with"
        # popup. submittedBy is the sharer who queued the run (uid fallback);
        # position is the 1-indexed global FIFO slot the FE joins on by uid.
        _queue_owners.append({
            "uid": (d.get("submittedBy") or d.get("uid") or "").strip(),
            "runId": rid_v,
            "title": (d.get("topic") or "")[:60],
            "position": new_pos,
        })
        # Per-doc ahead-by-account breakdown (uses each doc's own uid) —
        # locally-claimed queued jobs count as "ahead" too (#890).
        _ahead_self = 0
        _ahead_others = 0
        for _lo in _local_owners:
            if _lo.get("uid") == uid_v and uid_v:
                _ahead_self += 1
            else:
                _ahead_others += 1
        for _ji, (_jsid, _jd) in enumerate(queue[:idx]):
            _ju = (_jd.get("submittedBy") or _jd.get("uid") or "")
            if _ju == uid_v and uid_v:
                _ahead_self += 1
            else:
                _ahead_others += 1
        _eta_ms_r = _estimate_queue_eta_ms(
            _eta_head_phase, _eta_head_started, new_pos, _eta_worker_count)
        if idx > 0:
            _, prev_d = queue[idx - 1]
            patch = {
                "queuePosition": new_pos,
                "queuedBehindRunId": (prev_d.get("researchId") or ""),
                "queuedBehindTitle": (prev_d.get("topic") or "")[:60],
                "queueTotalAhead": new_pos - 1,
                "queueAheadFromSelf": _ahead_self,
                "queueAheadFromOthers": _ahead_others,
                "queueEtaMs": _eta_ms_r,
                "queueEtaComputedAt": _now_ms_recompute,
            }
        elif _local_owners:
            # Head of the DEFERRED set but locally-claimed jobs are ahead —
            # point "behind" at the local tail so the banner names the run
            # it actually waits on (#890), not the currently-running one.
            patch = {
                "queuePosition": new_pos,
                "queuedBehindRunId": _local_owners[-1]["runId"],
                "queuedBehindTitle": _local_owners[-1]["title"],
                "queueTotalAhead": new_pos - 1,
                "queueAheadFromSelf": _ahead_self,
                "queueAheadFromOthers": _ahead_others,
                "queueEtaMs": _eta_ms_r,
                "queueEtaComputedAt": _now_ms_recompute,
            }
        else:
            # Head of deferred queue — no doc ahead in queue. FE falls
            # back to `device.currentRunTitle` for the "queued behind
            # running X" message (see ChatMessage.QueuedBanner). Clear
            # behind fields explicitly so a stale prior value can't
            # render as "behind a cancelled/already-completed run."
            patch = {
                "queuePosition": new_pos,
                "queueTotalAhead": 0,
                "queueAheadFromSelf": 0,
                "queueAheadFromOthers": 0,
                "queueEtaMs": _eta_ms_r,
                "queueEtaComputedAt": _now_ms_recompute,
            }
            if DELETE_FIELD is not None:
                patch["queuedBehindRunId"] = DELETE_FIELD
                patch["queuedBehindTitle"] = DELETE_FIELD
        patches.append((uid_v, rid_v, patch))

    # 2026-05-28: publish the ordered queue summary onto the device doc so the
    # owner's "Shared with" popup shows amber "#N" badges per sharer (joined
    # by uid). Full-array overwrite — this single-flight recompute is the
    # authoritative snapshot; positions shift as the queue drains, so a
    # partial merge would leak stale entries. #890: locally-claimed queued
    # jobs lead the union (they run first). Best-effort / non-fatal.
    try:
        _firebase_db.collection("devices").document(device_id).update({
            "queueOwners": _local_owners + _queue_owners,
        })
    except Exception as _qo_err:
        log(f"[deferred-recompute] queueOwners publish failed (best-effort): {_qo_err}", "DEBUG")

    if not patches:
        return

    CHUNK = 450
    for i in range(0, len(patches), CHUNK):
        chunk = patches[i:i + CHUNK]
        def _commit_chunk(chunk=chunk):
            batch = _firebase_db.batch()
            for uid_v, rid_v, patch in chunk:
                ref = _firebase_db.collection("users").document(uid_v) \
                    .collection("researches").document(rid_v)
                batch.update(ref, _be_payload(patch))
            batch.commit()
        try:
            # #720: heal a stale-token 403 on the renumber; rebuild the batch
            # inside the op so a retry commits a fresh batch, not a consumed one.
            _grpc_write_with_heal(_commit_chunk, what=f"deferred queue-pos batch [{i}:{i+CHUNK}]")
        except Exception as e:
            log(f"[deferred-recompute] batch commit failed [{i}:{i+CHUNK}]: {e}", "WARN")


def _pending_enq_read() -> int:
    """Gate-time read. Returns int. Always lock-protected when the lock
    is initialised so a torn read (mid-increment-by-listener) can't
    leak through as a false-low value."""
    lock = _QUEUE_STATE.get("_pending_enq_lock")
    if lock is None:
        return int(_QUEUE_STATE.get("_pending_listener_enqueues", 0) or 0)
    with lock:
        return int(_QUEUE_STATE.get("_pending_listener_enqueues", 0) or 0)


def _pending_enq_reset():
    """Force the busy-counter to 0. Self-heal ONLY (called by the idle-rescan
    loop after a worker has been verifiably idle with a stuck counter for >30s).
    A leaked `_pending_listener_enqueues` (an inc on the listener thread with no
    matching dec) permanently arms the busy-defer gate at the listener, blocking
    that worker's listener claim path forever. In a genuinely-idle worker the
    counter MUST be 0, so a sustained >0 can only be a leak. Lock-guarded like
    inc/dec since the listener thread also touches the value."""
    lock = _QUEUE_STATE.get("_pending_enq_lock")
    if lock is None:
        _QUEUE_STATE["_pending_listener_enqueues"] = 0
        return
    with lock:
        _QUEUE_STATE["_pending_listener_enqueues"] = 0

# 2026-05-11: queue gate fallback — wait at most this many seconds for the
# prior run's FE-P5 to flip status="completed" before force-dequeueing the
# next job. Hoisted to module scope (2026-05-12) so the Firestore start
# listener (module-level) can reference the same constant when predicting
# whether the gate will block at queue-banner time; the worker's existing
# in-server reference resolves via normal global lookup.
BE_PHASES_TIMEOUT_SEC = 4200


def _try_claim_queue_doc(doc_ref, worker_id: int, log_prefix: str = "[claim]",
                          max_attempts: int = 3):
    """Atomic conditional-claim of a `devices/{id}/queue/{docId}` entry.

    Replaces the prior `@firestore.transactional` approach which masked
    `BeginTransaction` failures (synth-user JWT refresh blip, gRPC
    channel hiccup, transient `Unauthenticated`) behind a misleading
    `ValueError("The transaction has no transaction ID, so it cannot
    be rolled back.")` — see 2026-05-22 root-cause investigation.

    Mechanism:
      1. `snap = doc_ref.get()` to read current state + update_time.
      2. Early-out if doc gone / already-assigned / already-processed.
      3. `doc_ref.update({assignedWorker, claimedAt}, option=
         write_option(last_update_time=snap.update_time))` — Firestore
         single-doc writes are linearized server-side, so a precondition
         on update_time gives the same atomicity guarantee as a TX.
      4. `FailedPrecondition` on update = sibling beat us (race-loss).
         Return False without re-raising — that's the expected path.

    Retry semantics: transient failures (`ServiceUnavailable`,
    `DeadlineExceeded`, `Unauthenticated`, `InternalServerError`) retry
    up to `max_attempts` with `250ms * attempt` backoff. Per-failure
    surfacing of `__context__` so unmasked exceptions show up in logs
    (the TX decorator buried them; the conditional-update path leaves
    them on the wire).

    Returns:
      True   — this worker claimed the doc.
      False  — race lost (sibling claimed, doc deleted, already-processed).
      None   — unexpected error after retries; caller logs + skips,
               the idle-rescan loop picks it up later.
    """
    import google.api_core.exceptions as _gax_exc

    for attempt in range(1, max_attempts + 1):
        # ── Read current state ────────────────────────────────────────
        try:
            snap = doc_ref.get()
        except (_gax_exc.ServiceUnavailable, _gax_exc.DeadlineExceeded,
                _gax_exc.Unauthenticated, _gax_exc.InternalServerError) as _re:
            if attempt < max_attempts:
                time.sleep(0.25 * attempt)
                continue
            log(f"{log_prefix} worker {worker_id}: read failed after "
                f"{attempt} attempts: {type(_re).__name__}: {_re}", "WARN")
            return None
        except _gax_exc.NotFound:
            return False  # doc gone — race lost cleanly
        except Exception as _ge:
            _root = _ge.__context__ or _ge
            log(f"{log_prefix} worker {worker_id}: read unexpected: "
                f"{type(_ge).__name__}: {_ge} | "
                f"root: {type(_root).__name__}: {_root}", "WARN")
            return None

        if not snap.exists:
            return False
        d = snap.to_dict() or {}
        if d.get("assignedWorker") or d.get("processed"):
            return False  # already claimed / processed by sibling

        # ── Conditional update ────────────────────────────────────────
        try:
            doc_ref.update(
                {"assignedWorker": worker_id,
                 "claimedAt": int(time.time() * 1000)},
                option=_firebase_db.write_option(
                    last_update_time=snap.update_time),
            )
            return True
        except _gax_exc.FailedPrecondition:
            # Sibling updated the doc between our read and write.
            # Expected race-loss path — not an error.
            return False
        except _gax_exc.NotFound:
            # Owner deleted the doc between our read and write.
            return False
        except (_gax_exc.ServiceUnavailable, _gax_exc.DeadlineExceeded,
                _gax_exc.Unauthenticated, _gax_exc.InternalServerError) as _re:
            if attempt < max_attempts:
                time.sleep(0.25 * attempt)
                continue
            log(f"{log_prefix} worker {worker_id}: update failed after "
                f"{attempt} attempts: {type(_re).__name__}: {_re}", "WARN")
            return None
        except Exception as _ue:
            _root = _ue.__context__ or _ue
            log(f"{log_prefix} worker {worker_id}: update unexpected: "
                f"{type(_ue).__name__}: {_ue} | "
                f"root: {type(_root).__name__}: {_root}", "WARN")
            return None
    return None  # Defensive — loop should always return inside


def init_firebase():
    """Initialize the Firestore client for this BE process. Backed by the
    OS-keystore refresh token (deposited by `cmd_pair_v2`'s Stage 1
    handshake) via a per-user `google.cloud.firestore.Client`. No Admin
    SDK; no firebase-service-account.json on disk.

    Returns True on success, False if the keystore is empty (user hasn't
    paired) or the refresh token has been revoked (owner triggered
    Reset). Caller's typical recovery is to log the user-facing message
    and prompt re-pair.

    #717 — also sets `_firebase_down_reason` so recovery routes correctly. This
    is the AUTHORITATIVE classification point: init_firestore_user_scoped does a
    live creds.refresh(), catching RevokedError internally (returns None,
    keystore wiped) but letting a transient RequestException/RuntimeError
    PROPAGATE. So a propagated exception == transient (token intact, retry);
    a None return == genuine revoke (relink). Unknown defaults to transient so a
    novel failure self-heals via retry rather than spinning the relink path."""
    global _firebase_db, _firebase_down_reason
    if _firebase_db:
        _firebase_down_reason = None
        return True
    try:
        from auth import v2_flow, keystore as _ks
    except ImportError as e:
        log(f"Firestore init: auth/ package import failed: {e}", "ERROR")
        _firebase_down_reason = "transient"  # import hiccup — let reconnect retry
        return False
    install_uuid = _ks.install_uuid()
    if _ks.try_recover(install_uuid) is None:
        log(
            f"Firestore init: keystore empty — run `{_PROG} --pair` "
            "to establish a refresh token.",
            "ERROR",
        )
        # Nothing to reconnect with — post-Reset / never-paired. The relink
        # loop (not the reconnect loop) owns this. (#717)
        _firebase_down_reason = "revoked"
        return False
    try:
        client = v2_flow.init_firestore_user_scoped(install_uuid)
    except Exception as _net_err:
        # init_firestore_user_scoped swallows RevokedError (returns None); what
        # PROPAGATES here is the live creds.refresh() hitting the network —
        # getaddrinfo/DNS, ConnectionError, timeout, or a non-revoke 5xx
        # (RuntimeError). Token is still valid ("leaving keystore intact"), so
        # classify transient and let _firebase_reconnect_loop retry. (#717)
        log(f"Firestore init: transient network error ({type(_net_err).__name__}: {_net_err}) — will retry", "WARN")
        _firebase_down_reason = "transient"
        return False
    if client is None:
        log(
            "Firestore init: refresh token rejected (revoked or expired). "
            "If you triggered Reset Pair Code, check your email for the new "
            "code and enter it in Account → Add Device — the recovery "
            "watcher will pick it up and respawn the backend automatically.",
            "ERROR",
        )
        # init_firestore_user_scoped already wiped the keystore on RevokedError
        # — genuine revoke → relink loop owns recovery. (#717)
        _firebase_down_reason = "revoked"
        return False
    _firebase_db = client
    _firebase_down_reason = None
    log(f"Firestore client initialized ✓ (install={install_uuid[:8]}…)")
    # #720: verify the gRPC client's freshly-minted idToken actually carries the
    # deviceId custom claim the user-tree rules require. A claim-propagation race
    # at bootstrap can mint a claim-less token; force one more refresh so the
    # first real research write doesn't 403. Also surfaces a config-vs-claim
    # deviceId mismatch (which force-refresh CAN'T fix — it needs a re-pair) at
    # startup instead of buried under run-time 403s. Best-effort; never blocks.
    try:
        # The heal + _grpc_token_claims read the gRPC client's credential at the
        # private `._credentials` attr. If a google-cloud-firestore upgrade
        # renames it, the heal silently can't force-refresh — assert loudly.
        try:
            from auth.credentials import RefreshTokenCredentials as _RTC
            _c = getattr(_firebase_db, "_credentials", None)
            if not isinstance(_c, _RTC):
                log(f"[init] ⚠ _firebase_db._credentials is {type(_c).__name__}, not "
                    f"RefreshTokenCredentials — the #720 gRPC 403 self-heal is "
                    f"NEUTERED (can't force-refresh); a google-cloud-firestore "
                    f"upgrade likely moved the attr.", "WARN")
        except Exception:
            pass
        claims = _grpc_token_claims()
        cfg_did = _config_device_id_uncached()
        tok_did = claims.get("deviceId")
        if not tok_did:
            creds = getattr(_firebase_db, "_credentials", None)
            if creds is not None:
                creds.refresh(None)
                tok_did = _grpc_token_claims().get("deviceId")
            log(f"[init] gRPC token lacked deviceId claim at bootstrap; "
                f"re-refreshed → deviceId={tok_did!r}", "WARN")
        if tok_did and cfg_did and tok_did != cfg_did:
            log(f"[init] ⚠ gRPC token deviceId claim ({tok_did!r}) != config "
                f"deviceId ({cfg_did!r}) — user-tree writes will 403 until "
                f"re-pair reconciles them", "WARN")
        elif tok_did:
            log(f"[init] gRPC token deviceId claim ✓ ({tok_did!r})", "INFO")
        else:
            log("[init] ⚠ gRPC token carries NO deviceId claim even after "
                "re-refresh — user-tree writes will 403; re-pair required", "WARN")
    except Exception as _ve:
        log(f"[init] token-claim verification skipped (non-fatal): {_ve}", "DEBUG")
    return True


def _be_payload(data: dict) -> dict:
    """Inject `deviceId` into a Firestore write payload.

    The `deviceWritingTo` / `deviceUpdatingFor` rules on user-tree
    sub-collections require the BE write to declare which device is
    making it; the deviceId in the payload MUST equal the BE's
    `auth.token.deviceId` claim (set at custom-token mint time by the
    claim Cloud Function). Every centralized write helper that targets
    a `users/{ownerUid}/...` path calls this immediately before the
    Firestore put."""
    did = load_device_id()
    if not did:
        # No deviceId persisted — pair never completed. Caller's write
        # will permission-deny; surface the misconfig here so the
        # failure mode is obvious.
        log("_be_payload: deviceId missing from research_config.json — re-pair required", "WARN")
        return data
    return {**data, "deviceId": did}


# ── Track D synth-user 403 self-heal + instrumentation (#720) ──────────────
# Every user-tree research write below authenticates as the synthetic device
# user via the gRPC `_firebase_db` client, gated by the deviceMemberOf (read) /
# deviceWritingTo (create) / deviceUpdatingFor (update) rules. Those require the
# request's idToken to carry a `deviceId` custom claim AND (for writes) the
# payload's deviceId to equal that claim AND the device doc to list this user.
# The deployed rules, the synth user's persisted claims, and the device doc
# were all verified CORRECT — yet writes 403 ("Missing or insufficient
# permissions"; the flip masks it as "transaction has no transaction ID").
#
# The denying clause is NOT assumed. It could be (a) a cached token missing the
# claim — read-side deviceMemberOf, which a force-refresh CLEARS; (b) a config-
# vs-claim deviceId mismatch — write-side payload clause, which a refresh CANNOT
# fix (needs re-pair); or (c) a device-ownership / doc-deviceId mismatch. So the
# heal is empirical: on a synth-user 403 it force-refreshes the credential
# (re-minting from the live claims) and retries ONCE, and LOGS the decoded
# token.deviceId/ownerUid vs the UNCACHED config deviceId + the likely cause, so
# the next run reveals which mechanism is actually at play rather than asserting
# one. Throttled (≤1 force-refresh per cooldown) so a 403 storm can't hammer
# securetoken; latches "structural" after N unhealed denials so a deterministic
# mismatch escalates ONCE (re-pair required) instead of churning the keystore
# for the whole run. All refreshes serialize via auth.credentials._REFRESH_LOCK
# so the heal can't corrupt the keystore rotation.
_GRPC_HEAL_COOLDOWN_S = 30.0
# After this many consecutive heals that DON'T clear the denial, stop force-
# refreshing (cause is structural — a refresh can't fix it) and escalate once.
_GRPC_HEAL_STRUCTURAL_AFTER = 3
_grpc_heal_last_ts = 0.0
_grpc_heal_consec_fail = 0
_grpc_heal_structural = False
# The module-level `import threading as _threading` lives further down (~line
# 4633); import here too so this lock resolves at import time (re-import is a
# harmless rebind of the same module object).
import threading as _threading  # noqa: E402
_grpc_heal_lock = _threading.Lock()


def _decode_jwt_claims(tok: "str | None") -> dict:
    """Best-effort no-verify decode of a Firebase ID token's payload → dict.
    Returns {} on any malformation; never raises. We only read claims for
    diagnostics + the rules-visible deviceId, so signature verification is
    irrelevant (Firestore verifies server-side)."""
    if not tok or not isinstance(tok, str):
        return {}
    try:
        import base64 as _b64
        parts = tok.split(".")
        if len(parts) != 3:
            return {}
        seg = parts[1]
        seg += "=" * (-len(seg) % 4)
        return json.loads(_b64.urlsafe_b64decode(seg.encode("ascii")).decode("utf-8"))
    except Exception:
        return {}


def _grpc_token_claims() -> dict:
    """Decode the gRPC `_firebase_db` client's CURRENT cached idToken claims —
    i.e. exactly what the Firestore rules evaluate for the next write. {} if
    the client / credential / token is unavailable."""
    creds = getattr(_firebase_db, "_credentials", None)
    return _decode_jwt_claims(getattr(creds, "token", None)) if creds is not None else {}


def _is_synth_permission_denied(exc: "BaseException | None") -> bool:
    """True if `exc` (walking __cause__/__context__) is a Firestore rules
    denial. Covers google.api_core.exceptions.PermissionDenied AND the
    transactional wrapper's "transaction has no transaction ID" ValueError
    that masks a denied read inside `_flip_queued_to_ongoing`."""
    seen: "set[int]" = set()
    stack = [exc]
    while stack:
        e = stack.pop()
        if e is None or id(e) in seen:
            continue
        seen.add(id(e))
        if type(e).__name__ == "PermissionDenied":
            return True
        s = str(e)
        if "Missing or insufficient permissions" in s or "PERMISSION_DENIED" in s:
            return True
        stack.append(getattr(e, "__cause__", None))
        stack.append(getattr(e, "__context__", None))
    return False


def _config_device_id_uncached() -> "str | None":
    """Read deviceId straight from research_config.json, bypassing the module
    `load_device_id()` cache. The cache can hold a STALE deviceId after a
    mid-process re-pair, which would poison the heal's config-vs-claim
    diagnostic — so the diagnostic must compare against the file's live value."""
    try:
        with open(RESEARCH_CONFIG_PATH, "r", encoding="utf-8") as f:
            return (json.load(f) or {}).get("deviceId")
    except Exception:
        return None


def _grpc_write_with_heal(op, *, what: str):
    """Run a gRPC user-tree write `op` (a zero-arg callable). On a synth-user
    rules denial, force the credential to re-mint a claim-bearing idToken and
    retry `op` ONCE; re-raise so the caller's existing try/except still logs +
    degrades. Throttled to ≤1 force-refresh per `_GRPC_HEAL_COOLDOWN_S`; latches
    structural after `_GRPC_HEAL_STRUCTURAL_AFTER` unhealed denials. Logs the
    token vs (uncached) config deviceId + the likely denying clause so the true
    mechanism is diagnosable (#720)."""
    global _grpc_heal_last_ts, _grpc_heal_consec_fail, _grpc_heal_structural
    try:
        result = op()
        # A write just succeeded → any prior denial is resolved; drop the latch.
        if _grpc_heal_consec_fail or _grpc_heal_structural:
            with _grpc_heal_lock:
                _grpc_heal_consec_fail = 0
                _grpc_heal_structural = False
        return result
    except Exception as exc:
        if not _is_synth_permission_denied(exc):
            raise
        # Throttle + structural latch under the lock so concurrent worker
        # threads can't all slip past the cooldown and fire simultaneous heals.
        with _grpc_heal_lock:
            now = time.time()
            if _grpc_heal_structural or (now - _grpc_heal_last_ts < _GRPC_HEAL_COOLDOWN_S):
                # Structural (a refresh won't fix it), or just force-refreshed —
                # let the caller degrade this write rather than churn securetoken.
                raise
            _grpc_heal_last_ts = now
        before = _grpc_token_claims()
        cfg_did = _config_device_id_uncached()
        healed_did = None
        creds = getattr(_firebase_db, "_credentials", None)
        try:
            if creds is not None:
                creds.refresh(None)  # serialized + coalesced re-mint (live claims)
                healed_did = _grpc_token_claims().get("deviceId")
        except Exception as ref_e:
            log(f"[grpc-heal] {what}: force-refresh failed: {ref_e}", "WARN")
        tok_did = before.get("deviceId")
        if not tok_did:
            cause = "token MISSING deviceId claim — read-side deviceMemberOf (a refresh CLEARS this)"
        elif cfg_did and tok_did != cfg_did:
            cause = (f"token/config deviceId MISMATCH ({tok_did!r} != {cfg_did!r}) — "
                     "write-side payload clause; force-refresh CANNOT fix, re-pair")
        else:
            cause = "token+config deviceId AGREE — deviceOwnership / doc-deviceId mismatch"
        # #728: this is a SELF-HEALING retry — on basically every run's first
        # user-tree write the freshly-minted/cached synth token lags the
        # deviceId-claim propagation (most often the `queued→ongoing` flip's
        # transactional READ racing deviceMemberOf on a fresh doc; see
        # firestore.rules:175-203 #723), the force-refresh re-mints, and the
        # retry below succeeds. Logging it at WARN every time was misleading
        # noise (it reads as a problem when it self-heals). Log the heal ATTEMPT
        # at INFO; a genuinely UNHEALED denial still surfaces — the retry-failed
        # branch increments the structural counter (ERROR at the latch) and the
        # caller's own try/except logs the degrade.
        log(
            f"[grpc-heal] {what}: synth-user 403 — re-minting token + retrying once "
            f"(self-heal). token.deviceId={tok_did!r} ownerUid={before.get('ownerUid')!r} "
            f"| config deviceId={cfg_did!r} | likely cause: {cause} | after "
            f"force-refresh deviceId={healed_did!r}.",
            "INFO",
        )
        try:
            result = op()  # retry with the freshly-minted token
            with _grpc_heal_lock:
                _grpc_heal_consec_fail = 0
            return result
        except Exception:
            with _grpc_heal_lock:
                _grpc_heal_consec_fail += 1
                if (_grpc_heal_consec_fail >= _GRPC_HEAL_STRUCTURAL_AFTER
                        and not _grpc_heal_structural):
                    _grpc_heal_structural = True
                    log(
                        f"[grpc-heal] STRUCTURAL: {_grpc_heal_consec_fail} consecutive "
                        f"heals failed to clear the synth-user 403 ({cause}). A force-"
                        f"refresh cannot fix this — re-pair required. Suppressing further "
                        f"force-refreshes until a write succeeds.",
                        "ERROR",
                    )
            raise


_start_listener = None  # Global start-command listener
# Q8 observability: track when our heartbeat last successfully landed, +
# how many consecutive writes have failed. /api/health surfaces the
# timestamp so the FE can sanity-check "device offline despite localhost
# responsive" cases (FE reads Firestore lastHeartbeat; BE may be writing
# to a stale Firestore client). Reinit threshold below.
_last_heartbeat_at_ms = 0
_heartbeat_failures = 0
# 2026-07-05 — BE-update signal for the app. worker-1 heartbeat publishes the
# running version + PyPI update state to the device doc, throttled + written only
# on change (see _heartbeat_loop / _device_version_fields).
_last_published_version_fields: "dict | None" = None
_version_publish_next_ms = 0
# #717 — per-worker liveness pulse, bumped every iteration of
# _firebase_reconnect_loop (which runs on ALL workers). /api/health surfaces it
# as `lastTickAt` so the supervisor watchdog can spot a wedged event loop on ANY
# worker — `_last_heartbeat_at_ms` is worker-1-only and can't see a hung worker 2.
_last_loop_tick_ms = 0
HEARTBEAT_REINIT_THRESHOLD = 3  # consecutive fails before reinit_firebase()
# Heartbeat cadence. Paired with the frontend's 15s offline threshold at
# `DEVICE_OFFLINE_THRESHOLD_MS` in web/src/lib/firestore.ts so missing
# two consecutive ticks + a ~5s slack flips the UI to offline. Cadence
# tightened over two passes (30→15→5) because user kept observing the
# "device killed, tile still green" gap and asked for near-realtime.
# Cost: 12 writes/min/device on token + device docs — negligible at
# personal-usage scale.
HEARTBEAT_INTERVAL_SEC = 5

# Pairing/runtime state lives in the stable per-user state dir (~/.super-research/),
# NOT next to the code. In a pipx-installed build the code dir is the venv's
# site-packages, which a `pipx upgrade`/reinstall recreates — storing the pairing
# identity there would orphan the device on every upgrade. _migrate_state_to_home()
# (called from main) moves any pre-relocation file out of the old code dir once.
_STATE_DIR = Path.home() / ".super-research"
RESEARCH_CONFIG_PATH = _STATE_DIR / "research_config.json"
# Legacy path — auto-migrated on first load so existing users don't lose their token.
_LEGACY_PIPE_CONFIG_PATH = _STATE_DIR / "pipe_config.json"


def _atomic_write_json(path: Path, data: dict) -> None:
    """Atomic JSON dump: write to a sibling temp file, then os.replace
    onto the target. Guarantees readers in another process/thread never
    see a partial or truncated file — os.replace is atomic on Windows
    and POSIX when source + destination are on the same volume (which
    they are; we use the same directory). Prevents the concurrent
    --pair + serve heartbeat + daemon-loop respawn race where a reader
    catches mid-write garbage, json.loads throws, and the reader's
    save_device_config writes back a default-{} config that wipes
    deviceId — which would mint a fresh deviceId on the next pair
    and orphan the Firestore device doc."""
    import tempfile
    path.parent.mkdir(parents=True, exist_ok=True)  # ensure ~/.super-research/ exists
    parent = str(path.parent)
    fd, tmp_path = tempfile.mkstemp(dir=parent, prefix=path.name + ".", suffix=".tmp")
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2)
            f.flush()
            try:
                os.fsync(f.fileno())
            except Exception:
                pass
        os.replace(tmp_path, str(path))
    except Exception:
        try:
            if os.path.exists(tmp_path):
                os.remove(tmp_path)
        except Exception:
            pass
        raise


def _migrate_state_to_home() -> None:
    """Move pre-relocation pairing/runtime state out of the code dir into the
    stable ~/.super-research/ state dir. Older builds stored research_config.json
    / pipe_config.json / run_analytics.json next to the code (site-packages in a
    pipx build); a `pipx upgrade`/reinstall recreates that dir and would orphan
    the paired device. Best-effort + idempotent: each file is moved only if the
    new home doesn't already have it. No-op on a fresh install or once migrated."""
    try:
        _STATE_DIR.mkdir(parents=True, exist_ok=True)
    except Exception:
        return
    try:
        _old_dir = Path(_launcher_path()).parent
    except Exception:
        return
    try:
        if _old_dir.resolve() == _STATE_DIR.resolve():
            return  # already co-located (shouldn't happen, but never self-move)
    except Exception:
        pass
    import shutil as _shutil
    for _name in ("research_config.json", "pipe_config.json", "run_analytics.json"):
        try:
            _old = _old_dir / _name
            _new = _STATE_DIR / _name
            if _old.exists() and not _new.exists():
                _shutil.move(str(_old), str(_new))
                log(f"[migrate] moved {_name} -> {_STATE_DIR}", "INFO")
        except Exception:
            pass


# ── Device registry (multi-device support) ─────────────────────────────────
# A "device" is a paired backend PC. One doc per device lives at
# users/{uid}/devices/{deviceId}. Multiple devices let a user run concurrent
# research on different machines. The deviceId is stable across --pair runs
# on the same machine (stored in research_config.json) so re-pairing preserves
# the user's rename + supervised toggle.

_device_id: str | None = None
_device_paired_uid: str | None = None


def load_device_id():
    """Return the deviceId persisted in research_config.json, or None."""
    global _device_id
    if _device_id:
        return _device_id
    if RESEARCH_CONFIG_PATH.exists():
        try:
            cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
            _device_id = (cfg.get("deviceId") or "").strip() or None
            return _device_id
        except Exception:
            pass
    return None


def _sharer_rehydration_enabled() -> bool:
    """#724 item 3 / #725: worker-reboot rehydration of SHARER-submitted runs.

    DEFAULT ON (validated live 2026-06-01: a clean 3-sharer-tree scan with no
    permission denials, and both owner + sharer runs recovered across an
    in-flight restart). Opt OUT via the `ENABLE_SHARER_REHYDRATION` env var set
    to `0`/`false`/`off`/`no`, OR `research_config.json {"enableSharerRehydration": false}`.

    Precedence: explicit env override → explicit config entry → default(=on).
    The config path exists because a Windows User-scope env var did NOT
    propagate to the relaunched daemon (the supervisor inherited the OLD
    process environment); the JSON file is re-read from disk every boot. Reads
    via the same `Path` + `json` path used for `deviceId` — fully cross-platform
    (Windows / Linux / macOS), no shell-specific env quoting involved."""
    env = os.environ.get("ENABLE_SHARER_REHYDRATION")
    if env is not None and env.strip() != "":
        return env.strip().lower() not in ("0", "false", "off", "no")
    try:
        if RESEARCH_CONFIG_PATH.exists():
            cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
            v = cfg.get("enableSharerRehydration")
            if v is not None:
                return bool(v)
    except Exception:
        pass
    return True  # default ON


def load_poll_secret() -> str | None:
    """Track D — the 256-bit pollSecret for the BE-only path-key under which
    the FE claim Cloud Function writes the customToken. Lives in
    research_config.json (NOT the keystore — it must survive Reset Pair
    Code, which wipes the keystore but reuses the same secret hash on
    re-pair). Returns None if not yet minted (legacy install, fresh pre-
    pair state)."""
    if RESEARCH_CONFIG_PATH.exists():
        try:
            cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
            val = (cfg.get("pollSecret") or "").strip()
            if val:
                return val
        except Exception:
            pass
    return None


def save_user_mode_state(*, device_id: str, paired_uid: str, poll_secret: str) -> None:
    """Persist Track D user-mode state after a successful cmd_pair_v2.
    Flips authMode to "user" so subsequent commands route to the new
    Firestore client + heartbeat target. Reuses the atomic-write path that
    save_device_config uses."""
    global _device_id, _device_paired_uid
    local_cfg = {}
    if RESEARCH_CONFIG_PATH.exists():
        try:
            local_cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
        except Exception:
            pass
    local_cfg["authMode"] = "user"
    local_cfg["deviceId"] = device_id
    local_cfg["pairedUid"] = paired_uid
    local_cfg["pollSecret"] = poll_secret
    _atomic_write_json(RESEARCH_CONFIG_PATH, local_cfg)
    _device_id = device_id
    _device_paired_uid = paired_uid


def load_paired_uid():
    """Return the Firebase uid this device is paired to (from config file),
    or None if --pair hasn't completed yet."""
    global _device_paired_uid
    if _device_paired_uid:
        return _device_paired_uid
    if RESEARCH_CONFIG_PATH.exists():
        try:
            cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
            _device_paired_uid = (cfg.get("pairedUid") or "").strip() or None
            return _device_paired_uid
        except Exception:
            pass
    return None


def save_device_config(device_id: str | None = None, paired_uid: str | None = None):
    """Merge-write device_id / paired_uid into research_config.json."""
    global _device_id, _device_paired_uid
    local_cfg = {}
    if RESEARCH_CONFIG_PATH.exists():
        try:
            local_cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
        except Exception:
            pass
    if device_id:
        local_cfg["deviceId"] = device_id
        _device_id = device_id
    if paired_uid:
        local_cfg["pairedUid"] = paired_uid
        _device_paired_uid = paired_uid
    _atomic_write_json(RESEARCH_CONFIG_PATH, local_cfg)


def load_worker_count() -> int:
    """Number of concurrent-run slots this device has logins for.

    1 = single-worker (legacy default). 2+ = multi-profile, set up during
    pair Stage 4's "Add another browser profile?" loop. PR 2 wires this
    into daemon-loop so N worker subprocesses spawn, each pinned to its
    own browser profile.

    Defaults to 1 if the field is missing, the file is malformed, or any
    read raises — never returns <1.
    """
    if RESEARCH_CONFIG_PATH.exists():
        try:
            cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
            raw = cfg.get("workerCount", 1)
            n = int(raw) if raw is not None else 1
            return max(1, n)
        except Exception:
            pass
    return 1


# ── #903 worker rest (2026-07-06) ────────────────────────────────────────────
# The owner can park a worker from the app (Shared-With popup → tap an idle
# pill): the device doc's `restingWorkerIds` (owner-writable, firestore.rules)
# lists parked worker ids. A resting worker takes NO new runs — in-flight runs
# finish (resumes bypass the start listener entirely), and if every worker
# rests, submitted runs queue with a position until one is woken. Read fresh
# with a short TTL cache (the start listener can fire for a batch of docs);
# FAILS OPEN (awake) so a Firestore blip can never pause the device.
_RESTING_CACHE: dict = {"at": 0.0, "ids": ()}
# Latched True the first time THIS process defers a doc for rest — lets the
# single-worker idle-rescan pick the deferred doc back up after a wake (the
# queue doc won't re-fire ADDED). Not persisted: a restart re-delivers every
# surviving queue doc as ADDED on listener start, so recovery self-heals.
_REST_DEFER_SEEN = {"v": False}


def _worker_is_resting(*, ttl_sec: float = 3.0) -> bool:
    """True when the owner parked THIS worker (WORKER_ID ∈ device doc's
    restingWorkerIds). Mirrors the fresh device-doc `.get()` pattern of
    `_handle_update_command`; ~3s TTL so a batched listener callback costs
    one read, not one per doc."""
    global _RESTING_CACHE
    now = time.time()
    if now - _RESTING_CACHE["at"] > ttl_sec:
        ids: tuple = ()
        try:
            did = load_device_id()
            if _firebase_db is not None and did:
                _dev = (_firebase_db.collection("devices").document(did)
                        .get().to_dict() or {})
                _raw = _dev.get("restingWorkerIds") or []
                # Type-guard (review): a garbage owner write ("12", a map,
                # [true]) must count NOBODY as resting — never char-iterate a
                # scalar, never let bool coerce to worker 1.
                if not isinstance(_raw, (list, tuple)):
                    _raw = []
                ids = tuple(int(x) for x in _raw
                            if (isinstance(x, (int, float)) and not isinstance(x, bool))
                            or (isinstance(x, str) and x.isdigit()))
        except Exception as e:
            log(f"[rest-gate] restingWorkerIds read failed (treating as awake): {e}", "DEBUG")
            ids = ()
        _RESTING_CACHE = {"at": now, "ids": ids}
    return WORKER_ID in _RESTING_CACHE["ids"]


# #904 (2026-07-06): throttle for the resting keep-alive pass — the idle
# rescan ticks every ~15-25s per worker; the keep-alive only needs to act
# on the order of minutes, so cap the Firestore reads it costs.
_REST_KEEPALIVE_STATE = {"last_ms": 0}


def _rest_keepalive_pass():
    """#904: while THIS worker is resting, keep the parked queue durable.

    Called from the idle rescan's resting branch (via asyncio.to_thread).
    Two jobs, both scoped to UNCLAIMED action="start" docs (a resting
    worker still never claims — Gate 2 stays intact):

    (a) Keep-alive: refresh `restDeferredAt` when the stamp is >30min
        old. Gate 1 stamps it once per listener ADDED, but no defer
        passes happen during a steady-state rest — so a doc parked over
        a weekend woke up with a days-old stamp and the 12h ABANDONED
        stale-skip purged it on the wake replay (the sweep's rest
        exemption measures age from this stamp once the worker is no
        longer resting). Re-stamping here makes "park for days" safe.

    (b) Status self-heal: if the linked research doc drifted to
        status="ongoing" with no claim (FE mispredicted "run" at submit,
        or Gate 1's corrective status="queued" write lost the #720
        user-tree race), re-assert the queued state + enrichment. Live
        repro 2026-07-06 ("Yo", all workers rested): the FE rendered
        "Got it. Submitting..." + a Phase-0 Init tile that never
        advanced because nothing re-corrected the doc. With this pass
        the doc reads queued within ~a minute and the app's listener
        paints the banner no matter what the submit-time prediction did.
        Never touches terminal/claimed states: docs with assignedWorker
        are skipped, research docs with a backendRunId (claimed at some
        point) are skipped, and only status=="ongoing" is healed.

    Sync (blocking Firestore I/O). All failures are non-fatal DEBUG: the
    next tick retries.
    """
    now_ms = int(time.time() * 1000)
    if now_ms - _REST_KEEPALIVE_STATE["last_ms"] < 60_000:
        return
    _REST_KEEPALIVE_STATE["last_ms"] = now_ms
    _STAMP_REFRESH_MS = 30 * 60 * 1000
    try:
        did = load_device_id()
        if not did or _firebase_db is None:
            return
        col = _firebase_db.collection("devices").document(did).collection("queue")
        snaps = list(col.limit(20).stream())
    except Exception as e:
        log(f"[rest-keepalive] worker {WORKER_ID}: scan failed (non-fatal): {e}", "DEBUG")
        return
    for s in snaps:
        d = s.to_dict() or {}
        if d.get("processed") or d.get("assignedWorker"):
            continue
        if (d.get("action") or "start") != "start":
            continue
        rid = d.get("researchId") or ""
        uid = d.get("submittedBy") or d.get("uid") or ""
        if not rid or not uid:
            continue
        # Research-doc read FIRST — both the stamp and the heal gate on it.
        try:
            _rsnap = (_firebase_db.collection("users").document(uid)
                      .collection("researches").document(rid).get())
        except Exception as _e:
            log(f"[rest-keepalive] status read failed for {rid[:8]}… (non-fatal): {_e}", "DEBUG")
            continue
        _rd = (_rsnap.to_dict() or {}) if _rsnap.exists else {}
        _rstatus = _rd.get("status") or ""
        # (a) keep-alive stamp — same field Gate 1 writes on defer. Review
        # fold: gate on a HEALTHY research doc (queued, or the drifted
        # "ongoing" healed below). A cancel-orphaned queue doc (research
        # stopped/deleted but the queue-doc delete failed) must NOT be kept
        # alive — the 12h ABANDONED sweep is what bounds the pre-existing
        # wake-claims-a-cancelled-run hole, and an indefinite stamp would
        # extend that hole forever.
        if _rsnap.exists and _rstatus in ("queued", "ongoing"):
            _stamp = d.get("restDeferredAt")
            if (not isinstance(_stamp, (int, float))
                    or now_ms - int(_stamp) > _STAMP_REFRESH_MS):
                try:
                    s.reference.update({"restDeferredAt": now_ms})
                except Exception as _e:
                    log(f"[rest-keepalive] stamp failed for {rid[:8]}… (non-fatal): {_e}", "DEBUG")
        # (b) status self-heal — drifted "ongoing" with no claim anywhere.
        if not _rsnap.exists or _rstatus != "ongoing" or _rd.get("backendRunId"):
            continue
        try:
            _enrich = _compute_queue_enrichment(col, s.id, uid)
            _eta_ms, _eta_at = _read_eta_inputs_and_compute(_enrich["position"])
            # Review fold (TOCTOU): the enrichment compute above costs reads
            # (~0.5-2s) — a user cancelling the paused run (the likeliest
            # action on a paused queue) or an awake sibling claiming in that
            # window must not be overwritten: a stopped→queued clobber would
            # RESURRECT the cancelled run as a zombie banner with no queue
            # doc behind it. Track D denies synth-user transactional reads
            # on the user tree (#720), so a transaction isn't available —
            # re-read both docs just before the write to shrink the race to
            # one write RTT. The heal re-runs every ~60s, so a doc that
            # slips through as still-"ongoing" is caught next tick.
            _qs2 = s.reference.get()
            if not _qs2.exists or (_qs2.to_dict() or {}).get("assignedWorker"):
                continue
            _rs2 = (_firebase_db.collection("users").document(uid)
                    .collection("researches").document(rid).get())
            if not _rs2.exists:
                continue
            _rd2 = _rs2.to_dict() or {}
            if (_rd2.get("status") or "") != "ongoing" or _rd2.get("backendRunId"):
                continue
            if _update_research_doc(uid, rid, {
                "status": "queued",
                "queuePosition": _enrich["position"],
                "queuedBehindRunId": _enrich["behind_rid"],
                "queuedBehindTitle": _enrich["behind_title"],
                "queueTotalAhead": _enrich["total_ahead"],
                "queueAheadFromSelf": _enrich["ahead_from_self"],
                "queueAheadFromOthers": _enrich["ahead_from_others"],
                "queueEtaMs": _eta_ms,
                "queueEtaComputedAt": _eta_at,
            }):
                log(
                    f"[rest-keepalive] worker {WORKER_ID}: re-asserted status=queued "
                    f"for {rid[:8]}… (doc had drifted to 'ongoing' with no claim)",
                    "INFO",
                )
        except Exception as _e:
            log(f"[rest-keepalive] re-assert failed for {rid[:8]}… (non-fatal): {_e}", "DEBUG")


def save_worker_count(n: int) -> None:
    """Merge-write workerCount into research_config.json. Clamped to >=1
    so a bad caller can't disable the only worker. Atomic write via
    _atomic_write_json — partial-write safe."""
    n = max(1, int(n))
    local_cfg = {}
    if RESEARCH_CONFIG_PATH.exists():
        try:
            local_cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
        except Exception:
            local_cfg = {}
    local_cfg["workerCount"] = n
    _atomic_write_json(RESEARCH_CONFIG_PATH, local_cfg)


def clear_paired_uid():
    """Wipe pairedUid from memory + research_config.json without touching
    deviceId or researchToken. Used when the relink watcher sees linkedUid
    cleared — local state must forget the old owner so the heartbeat stops
    recreating the device doc under their account. deviceId + researchToken
    stay put so a subsequent relink (via paste-token) resumes without a
    re-setup."""
    global _device_paired_uid
    _device_paired_uid = None
    if not RESEARCH_CONFIG_PATH.exists():
        return
    try:
        local_cfg = json.loads(RESEARCH_CONFIG_PATH.read_text(encoding="utf-8"))
    except Exception:
        return
    if "pairedUid" not in local_cfg:
        return
    local_cfg.pop("pairedUid", None)
    try:
        _atomic_write_json(RESEARCH_CONFIG_PATH, local_cfg)
    except Exception as e:
        log(f"Could not clear pairedUid from config: {e}", "WARN")


def generate_device_id():
    """Mint a new stable deviceId shaped '<sanitized-hostname>-<6-char-hex>'.
    Called once per machine — subsequent --pair runs reuse the persisted id."""
    import uuid
    import socket
    import re as _re
    hostname = socket.gethostname()
    sanitized = _re.sub(r'[^a-z0-9-]', '-', hostname.lower()).strip('-')
    if not sanitized:
        sanitized = "device"
    new_id = f"{sanitized[:30]}-{uuid.uuid4().hex[:6]}"
    save_device_config(device_id=new_id)
    return new_id


def _detect_supervised() -> bool:
    """Dispatcher — routes to platform-specific probes. The scheduled task
    / launchd job / systemd unit is the actual source of truth for
    supervised mode; the Firestore device doc is just a mirror that can
    drift (e.g., after unlink deletes the doc but the task lives on).
    Returns False on Unsupported."""
    plat = _supervisor_platform()
    if plat == "Windows":
        return _detect_supervised_windows()
    if plat == "Darwin":
        return _detect_supervised_macos()
    if plat == "Linux":
        return _detect_supervised_linux()
    return False


def _detect_supervised_windows() -> bool:
    """Probe Windows Task Scheduler for the SuperResearchBackend task.
    Returns False on schtasks failure or task not found."""
    import subprocess as _sp
    try:
        result = _sp.run(
            ["schtasks", "/Query", "/TN", _SUPERVISOR_TASK_NAME],
            capture_output=True,
            timeout=5,
            creationflags=0x08000000,  # CREATE_NO_WINDOW — avoid flashing console
        )
        return result.returncode == 0
    except Exception:
        return False


async def _heartbeat_loop():
    """Write lastHeartbeat to the top-level `devices/{deviceId}` doc every
    HEARTBEAT_INTERVAL_SEC so the frontend can show Online/Offline status
    per device. Pairs with the FE 15s offline threshold
    (DEVICE_OFFLINE_THRESHOLD_MS) — missing two consecutive ticks plus
    a small slack flips the UI to offline.

    Device doc uses millis-as-int — the frontend compares
    `Date.now() - lastHeartbeat` directly, so a Timestamp object would
    become NaN and the tile would look perpetually offline.

    First-tick confirms the atomic-pair contract: writes
    pairConfirmedAt:true + FieldValue.delete() on expireAt. The claim
    Cloud Function sets expireAt:now+5min when granting ownership, and
    if the BE never reaches this heartbeat (custom-token exchange fails,
    keystore write fails, anything else downstream), Firestore TTL
    auto-deletes the doc and the FE tile never appears. Once
    pairConfirmedAt is set, every subsequent heartbeat keeps it true
    (idempotent — `update` overwrites cleanly).
    """
    from google.cloud.firestore import DELETE_FIELD
    # All globals must be declared at the top of the function — Python
    # rejects `global X` if X has already been read in this scope.
    global _last_heartbeat_at_ms, _heartbeat_failures, _firebase_db, _firebase_down_reason
    global _last_published_version_fields, _version_publish_next_ms
    while True:
        try:
            # Update top-level `devices/{deviceId}` — BE is signed in as
            # the synth device user; the device doc's update rule lets us
            # set the allow-listed fields (path identifies the writer; no
            # deviceId field in the payload, which would push it into
            # affectedKeys() and break the rule's hasOnly check).
            device_id = load_device_id()
            if _firebase_db and device_id:
                # Multi-worker (2026-05-21): publish workerCount so the FE
                # can gate its "queue vs ongoing" decision on actual slot
                # capacity. Without this, FE treats ANY active run on the
                # device as "device busy" — a second submit shows as
                # queued even when worker 2 is idle and ready to take it.
                # Heartbeat is the natural carrier (already running on
                # worker 1 only, already updating allow-listed fields).
                _wc_payload = load_worker_count()
                await asyncio.wait_for(
                    asyncio.to_thread(
                        lambda: _firebase_db.collection("devices")
                            .document(device_id).update({
                                "lastHeartbeat": int(time.time() * 1000),
                                "status": "active",
                                # Atomic-pair contract: confirm this BE
                                # is alive + cancel the post-claim TTL.
                                "pairConfirmedAt": True,
                                "expireAt": DELETE_FIELD,
                                "workerCount": _wc_payload,
                            })),
                    timeout=10.0,
                )
                _last_heartbeat_at_ms = int(time.time() * 1000)
                if _heartbeat_failures > 0:
                    log(f"[heartbeat] recovered after {_heartbeat_failures} consecutive failures", "INFO")
                    _heartbeat_failures = 0

                # 2026-07-05: self-report version + PyPI update signal so the FE
                # can prompt "run superresearch --update on the Research computer"
                # (the agent no longer handles BE updates). DECOUPLED from the
                # liveness write above and best-effort by design: these two fields
                # are a SEPARATE allow-list entry, so if the firestore.rules update
                # hasn't been deployed yet a 403 here must NOT flip the device
                # offline. Throttled to ~5 min + written only when the value
                # changes (version/updateAvailable move ~once per release), so it
                # adds no meaningful write volume to the 5s heartbeat.
                _now_ms = int(time.time() * 1000)
                if _now_ms >= _version_publish_next_ms:
                    try:
                        _vf = await asyncio.to_thread(_device_version_fields)
                        if _vf != _last_published_version_fields:
                            await asyncio.wait_for(
                                asyncio.to_thread(
                                    lambda: _firebase_db.collection("devices")
                                        .document(device_id).update(_vf)),
                                timeout=10.0,
                            )
                            _last_published_version_fields = _vf
                        _version_publish_next_ms = _now_ms + 300_000
                    except Exception as _vf_err:
                        # Back off on failure too (e.g. rules not yet deployed) so a
                        # persistent 403 retries every ~5 min, not every tick.
                        _version_publish_next_ms = _now_ms + 300_000
                        log(f"[heartbeat] version-signal publish skipped ({_vf_err})", "DEBUG")
        except Exception as e:
            _heartbeat_failures += 1
            # #738: the dominant failure is asyncio.TimeoutError, whose str()
            # is "" — render a real detail so the WARN isn't blank (these are
            # slow-write timeouts, not auth errors; now distinguishable in
            # log sweeps).
            _hb_detail = ("write timed out after 10s"
                          if isinstance(e, asyncio.TimeoutError)
                          else (str(e) or repr(e) or type(e).__name__))
            log(f"[heartbeat] write failed (consecutive={_heartbeat_failures}): {_hb_detail}", "WARN")
            # Hand recovery to _firebase_reconnect_loop instead of reiniting
            # inline. #717: the old inline reinit was UNREACHABLE after the
            # first failed rebuild — it lived in THIS except block, but once
            # `_firebase_db` is None the write `if` above is skipped, so no
            # exception fires, so this block never runs again. The loop went
            # silent and a transient DNS blip never self-healed (it waited out
            # the relink loop's 1-hour cap). Now we just drop the client +
            # tentatively flag transient; the always-armed reconnect loop (every
            # worker) retries init_firebase on a tight backoff, and that call is
            # where the authoritative revoked-vs-transient classification
            # happens (init_firebase probes the live token refresh). If it's
            # actually a revoke, init_firebase flips the reason to "revoked" and
            # the relink loop takes over.
            if _heartbeat_failures >= HEARTBEAT_REINIT_THRESHOLD and _firebase_db is not None:
                log(f"[heartbeat] {_heartbeat_failures} consecutive failures — dropping client; reconnect loop will rebuild", "WARN")
                _firebase_db = None
                _firebase_down_reason = "transient"
        await asyncio.sleep(HEARTBEAT_INTERVAL_SEC)


async def _firebase_reconnect_loop():
    """Self-heal a DROPPED Firestore client after a transient network/DNS blip
    — the autopilot fix for the 2026-05-31 incident where a `getaddrinfo`
    failure nulled `_firebase_db`, the heartbeat's inline reinit was
    unreachable, and the device sat OFFLINE until the relink loop's 1-hour
    wall-clock cap force-exited (#717).

    Runs on EVERY worker (decoupled from the worker-1-only heartbeat and from
    boot-init success) so workers 2+ and a boot-time blip recover too. Owns ALL
    transient reconnection; the relink loop owns genuine revokes. They are
    mutually exclusive on `_firebase_down_reason`:
        "transient" (or unknown) + down → THIS loop retries init_firebase.
        "revoked"               + down → idle here; _revoked_recovery_loop
        drives the customToken relink.

    Backoff is deliberately TIGHT (5→10→30s, never minutes — the FE flips a
    device Offline at ~15s, so a short blip clears before the tile changes).
    Don't borrow a slow minutes-scale backoff — far too slow for a
    device-liveness signal. init_firebase
    runs in a thread because its live creds.refresh() has a 10s timeout that
    would otherwise stall the loop past its own cadence.

    Re-bind (#718): a reconnect rebuilds `_firebase_db` in-process, which restores
    the heartbeat + writes immediately — but the existing on_snapshot Watch
    streams (job listener, device-command listener) are bound to the OLD client
    object. For a short blip they auto-resume on their own gRPC channel; for a
    SUSTAINED outage they can give up (_on_rpc_done → close) and never
    re-subscribe, leaving the worker "online but deaf" — heartbeat back, but new
    jobs / device-commands silently dropped. A boot-time blip never bound them at
    all. So after ANY successful reconnect we schedule a CLEAN respawn, which
    re-runs boot and re-wires every listener deterministically. Never respawn
    mid-run (it would os._exit a live browser) — defer until the worker is idle.

    Bumps `_last_loop_tick_ms` every iteration so the supervisor watchdog has a
    per-worker liveness pulse (lastHeartbeatAt is worker-1-only)."""
    global _last_loop_tick_ms, _firebase_down_reason
    BACKOFF = (5, 5, 10, 30)
    idx = 0
    # After a reconnect, re-bind listeners via a clean respawn — deferred while a
    # run is active so we never os._exit a live browser (a local /api/runs submit
    # can start one even with Firestore down). (#718)
    pending_respawn = False
    log("[reconnect] watcher armed (idle while Firestore healthy)", "DEBUG")
    while True:
        try:
            _last_loop_tick_ms = int(time.time() * 1000)
            if _firebase_db is not None:
                idx = 0
                if pending_respawn and not _QUEUE_STATE.get("running"):
                    log("[reconnect] run finished — clean respawn to re-bind Firestore listeners", "INFO")
                    # Stagger the respawn by worker id so a shared blip doesn't
                    # exit the whole fleet in lockstep (which would briefly drop
                    # every worker → stale heartbeat → device flickers offline).
                    # Worker 1 goes first, siblings follow 8s apart. (RC-29)
                    _schedule_server_exit("firestore-reconnect", delay_sec=3.0 + (max(1, WORKER_ID) - 1) * 8.0)
                    pending_respawn = False
                await asyncio.sleep(5)
                continue
            if _firebase_down_reason == "revoked":
                # Genuine revoke — _revoked_recovery_loop owns this. Stay idle
                # (but keep ticking liveness) so recovery isn't double-driven.
                idx = 0
                await asyncio.sleep(5)
                continue
            # Down + transient → rebuild the client. Live refresh in a thread so
            # a slow/hung DNS resolve can't stall this loop.
            ok = await asyncio.to_thread(init_firebase)
            if ok:
                idx = 0
                # Client rebuilt in-process — heartbeat + writes resume now. Then
                # re-bind listeners via a clean respawn (immediately if idle;
                # deferred to the idle branch if a run is active so we don't
                # os._exit a live browser). Covers boot-time blips (listeners
                # never bound) AND sustained mid-serve outages (Watch streams
                # gave up and won't re-subscribe to the new client). (#718)
                if _QUEUE_STATE.get("running"):
                    pending_respawn = True
                    log("[reconnect] Firestore back, run active — rebuilt in-process; clean respawn deferred to idle to re-bind listeners", "INFO")
                else:
                    log("[reconnect] Firestore reachable again — clean respawn to re-bind listeners", "INFO")
                    # Stagger by worker id so the fleet doesn't exit in lockstep. (RC-29)
                    _schedule_server_exit("firestore-reconnect", delay_sec=3.0 + (max(1, WORKER_ID) - 1) * 8.0)
                await asyncio.sleep(5)
            else:
                if _firebase_down_reason == "revoked":
                    # init_firebase reclassified this as a real revoke — hand to
                    # the relink loop on the next tick.
                    continue
                wait = BACKOFF[min(idx, len(BACKOFF) - 1)]
                idx += 1
                log(f"[reconnect] Firestore still unreachable — retrying init in {wait}s", "WARN")
                await asyncio.sleep(wait)
        except asyncio.CancelledError:
            return
        except Exception as _e:
            log(f"[reconnect] loop error: {_e}", "WARN")
            await asyncio.sleep(10)


async def _revoked_recovery_loop():
    """Auto-relink after the owner triggers Reset Pair Code from the FE.

    Reset revokes the synth device user's refresh tokens; the next
    securetoken refresh on this BE raises RevokedError → the keystore
    is wiped → `_firebase_db` goes None. The owner gets emailed the
    fresh 8-char code and enters it in Account → Add Device within 15
    minutes. The claim Cloud Function writes a new customToken to the
    same `devices/{deviceId}/pending/{hash(pollSecret)}` subdoc that
    initial pair used (pollSecret survives Reset in research_config.json),
    so we can pick it up here without any new handshake.

    On success we exit cleanly. Under the daemon-loop supervisor (Win
    Scheduled Task / mac launchd / linux systemd-user) the BE respawns
    within ~5s with the new keystore + fresh Firestore client + fresh
    listener subscriptions. Unsupervised installs need a manual
    `python research.py --serve`; we log the instruction.

    Loop is quiet during normal operation — sleeps until `_firebase_db`
    goes None. Backs off 5 min after a PollTimeout (code window
    expired) so a stuck recovery doesn't spin.

    2026-05-22: wall-clock cap at MAX_RECOVERY_WALLCLOCK_SEC (1hr). After
    the device doc TTL-deletes at 15 min (reset-pair-code/route.ts:269),
    the pending subdoc path becomes unreachable — polling forever wastes
    CPU + log volume. At the cap we log + os._exit(0) so the supervisor
    sees a clean exit code (and stops respawning a worker that will just
    re-enter the same dead loop)."""
    MAX_RECOVERY_WALLCLOCK_SEC = 3600  # 1 hour
    log("[relink] watcher armed (idle until Firestore drops)", "DEBUG")
    first_recovery_attempt_ts: "float | None" = None
    while True:
        try:
            if _firebase_db is not None or _firebase_down_reason != "revoked":
                # Idle unless the client is down AND classified a genuine
                # revoke. #717: a transient DNS/network blip ALSO nulls
                # _firebase_db (keystore intact), but it's owned by
                # _firebase_reconnect_loop. Entering the customToken poll for a
                # transient blip is exactly what caused the stale-token
                # INVALID_CUSTOM_TOKEN spin. Reset the wall-clock anchor so a
                # later genuine revoke doesn't inherit a stale timer.
                first_recovery_attempt_ts = None
                await asyncio.sleep(15)
                continue
            # Stamp the wall-clock anchor on first entry to recovery mode.
            if first_recovery_attempt_ts is None:
                first_recovery_attempt_ts = time.time()
            elif (time.time() - first_recovery_attempt_ts) > MAX_RECOVERY_WALLCLOCK_SEC:
                log(
                    f"[relink] giving up after {MAX_RECOVERY_WALLCLOCK_SEC}s "
                    "(device doc TTL likely expired) — exiting so supervisor "
                    "stops respawning into the same dead loop. Owner must "
                    f"run `{_PROG} --pair` to recover.",
                    "ERROR",
                )
                await asyncio.sleep(0.5)
                import os as _os
                _os._exit(0)
            poll_secret = load_poll_secret()
            device_id = load_device_id()
            if not (poll_secret and device_id):
                # No way to auto-relink (legacy install never paired,
                # or fresh install pre --pair). Caller must run --pair.
                await asyncio.sleep(30)
                continue
            try:
                from auth import v2_flow as _v2
            except ImportError as e:
                log(f"[relink] auth.v2_flow import failed: {e}", "ERROR")
                await asyncio.sleep(60)
                continue
            log(
                "[relink] Firestore client down — polling pending subdoc for "
                "fresh pair code (15 min window). "
                "Owner enters the emailed code in Account → Add Device.",
                "INFO",
            )
            poll_hash = _v2.compute_poll_secret_hash(poll_secret)
            try:
                await _v2.do_redeem_reset(
                    device_id=device_id,
                    poll_secret_hash=poll_hash,
                    poll_timeout_seconds=15 * 60,
                )
                log("[relink] new refresh token bootstrapped to keystore", "INFO")
                # CRITICAL: cancel the 5-min `expireAt` TTL on the device
                # doc BEFORE exiting. The claim Cloud Function (Branch 1
                # re-pair / Branch 2 initial-pair) wrote `expireAt: now+5min`
                # as the "BE-must-confirm" deadline. Without this patch:
                #   t=0   user re-pairs → device doc has expireAt: now+5min
                #   t=0.5s BE picks up customToken, bootstraps fresh keystore
                #   t=1s  BE _os._exit(0) → daemon-loop respawns
                #   t=6-30s new --serve completes init (DPAPI + gRPC + port)
                #   t=30s+ heartbeat fires → tries to clear expireAt
                #   IF respawn takes >5min (rare but not impossible on cold
                #   start with antivirus / heavy load) OR if heartbeat's
                #   first tick lands after the TTL fired → Firestore TTL
                #   DELETES the entire devices/{deviceId} doc. Once gone:
                #   deviceAuthorizedFor returns false (no ownerUid lookup
                #   target) → every Storage/Firestore cross-tree call 403s
                #   → audio upload broken, source download broken, queue
                #   writes rejected by the FE-side `isDeviceMember` rule.
                # cmd_pair_v2 Stage 1 (research.py:~26931) does this eager
                # patch already; the recovery path was missed when Track D
                # shipped. _pair_patch_device uses REST PATCH so it works
                # with just the freshly-minted ID token (no gRPC client
                # required).
                try:
                    if _pair_patch_device(
                        device_id,
                        {"pairConfirmedAt": True},
                        delete_fields=["expireAt"],
                    ):
                        log(
                            "[relink] device-doc TTL canceled — pairConfirmedAt set + expireAt cleared; doc survives supervisor respawn",
                            "INFO",
                        )
                    else:
                        log(
                            "[relink] device-confirm patch failed (heartbeat will retry post-respawn — race window with the 5-min TTL)",
                            "WARN",
                        )
                except Exception as _confirm_err:
                    log(f"[relink] device-confirm patch raised: {_confirm_err}", "WARN")
                # Exit so the supervisor respawns with a fresh Firestore
                # client + fresh listener subscriptions. In-process swap
                # would leave the old listeners pointing at the revoked
                # gRPC channel, which silently stops delivering snapshots.
                log(
                    "[relink] exiting --serve so subscriptions reload "
                    "(supervisor will respawn within ~5s; "
                    f"unsupervised installs need `{_PROG} --serve`).",
                    "INFO",
                )
                # Give the log line a beat to flush before we go.
                await asyncio.sleep(0.5)
                import os as _os
                _os._exit(0)
            except _v2.PollTimeout:
                log(
                    "[relink] 15-min code window expired — owner can re-Reset "
                    "from Settings → Manage devices, or run --pair on this PC.",
                    "WARN",
                )
                await asyncio.sleep(5 * 60)
            except Exception as e:
                log(f"[relink] recovery attempt failed: {e}", "WARN")
                await asyncio.sleep(60)
        except asyncio.CancelledError:
            return
        except Exception as e:
            log(f"[relink] watcher loop error: {e}", "WARN")
            await asyncio.sleep(30)


_device_cmd_watch = None  # Firestore Watch handle; kept for lifetime cleanup


def _write_update_status(device_id: str, status: dict) -> None:
    """Best-effort write of a remote-update outcome to the device doc so the app
    can render it (the same channel as the version signal). `at` is stamped here.
    Never raises — a rules gap / offline write must not break the listener."""
    try:
        _firebase_db.collection("devices").document(device_id).update({
            "updateStatus": {**status, "at": int(time.time() * 1000)},
        })
    except Exception as e:
        log(f"[device-cmds] update-status write skipped: {e}", "DEBUG")


def _handle_check_update_command(device_id: str) -> None:
    """App-driven 'check for a backend update' (About-page 'Check' button). Forces
    a FRESH PyPI check and republishes version + updateAvailable to the device doc,
    plus a `versionCheckedAt` timestamp so the app knows the check completed (vs
    still pending). No restart — this only refreshes the update signal. Best-effort;
    runs off the listener thread's happy path (a failed PyPI fetch just leaves the
    prior signal + still stamps versionCheckedAt so the spinner clears)."""
    try:
        fields = _device_version_fields(force=True)
    except Exception:
        fields = {}
    try:
        _firebase_db.collection("devices").document(device_id).update({
            **fields,
            "versionCheckedAt": int(time.time() * 1000),
        })
    except Exception as e:
        log(f"[device-cmds] check-update publish skipped: {e}", "DEBUG")


def _handle_update_command(data: dict, device_id: str, loop) -> None:
    """App-driven remote backend update (owner-only `update` device command).
    Runs on WORKER_ID==1 only. Reuses `_perform_self_update`; forces THIS worker
    to exit so the detached `pipx upgrade` waiter can rebuild the venv (the OS
    scheduled task / daemon-loop respawns the BE on the new version).

    Guards (in order):
      1. OWNER-ONLY defense-in-depth — refuse if submittedBy != device.ownerUid
         (the Firestore rule also enforces this, but rules can lag deploy and this
         is a code-execution primitive).
      2. SUPERVISED-only — the upgrade kills the daemon-loop + workers; something
         must relaunch the BE. A live daemon-loop (from --resurrect / the OS task)
         is that supervisor; a foreground --serve has nothing to bring it back, so
         refuse remotely and point to `superresearch --update` on the machine.
      3. MID-RUN — defer while a research run is active (local queue OR any
         busyWorkerId) unless the command sets force=True; on force, stop the
         active run first (keeps partial results), mirroring hard_reset.
    Outcomes are written to `updateStatus` for the app; success is also observable
    via the heartbeat `version` bumping once the BE respawns on the new build."""
    cur = _sr_version()
    # 1. Owner-only + read busy-state in one device-doc fetch.
    try:
        _dev = _firebase_db.collection("devices").document(device_id).get().to_dict() or {}
    except Exception as _oe:
        log(f"[device-cmds] UPDATE: device read failed ({_oe}) — refusing", "WARN")
        return
    _owner = _dev.get("ownerUid")
    if _owner and data.get("submittedBy") and data["submittedBy"] != _owner:
        log("[device-cmds] UPDATE: refusing — submittedBy is not the device owner", "WARN")
        _write_update_status(device_id, {"state": "failed", "current": cur,
                                         "latest": None, "reason": "not the device owner"})
        return

    # 2. Supervised-only: the upgrade kills THIS worker + the daemon-loop, so an OS
    #    supervisor (Scheduled Task / launchd / systemd) must exist to relaunch the
    #    BE on the rebuilt venv. Check that artifact directly — it's the source of
    #    truth (a live daemon-loop alone could be a manual run with no auto-restart,
    #    which would leave the machine stranded offline after the update).
    if not _detect_supervised():
        log("[device-cmds] UPDATE: not supervised (no OS auto-start) — refusing remote update", "WARN")
        _write_update_status(device_id, {
            "state": "failed", "current": cur, "latest": None,
            "reason": "not supervised — run `superresearch --update` on the machine"})
        return

    # 3. Mid-run guard: defer unless forced. `busy` is device-wide (any worker) and
    #    gates the defer decision; `local_busy` is THIS worker's own run — the only
    #    one we can stop gracefully (sibling workers are separate processes,
    #    terminated by the venv rebuild like any update).
    force = bool(data.get("force"))
    local_busy = bool(_QUEUE_STATE.get("running"))
    try:
        _qr = _QUEUE_STATE.get("queue_ref")
        if _qr is not None and _qr.qsize() > 0:
            local_busy = True
    except Exception:
        pass
    busy = local_busy or bool(_dev.get("busyWorkerIds"))
    if busy and not force:
        log("[device-cmds] UPDATE: deferred — a run is in progress (resend with force to override)")
        _write_update_status(device_id, {"state": "deferred", "current": cur,
                                         "latest": None, "reason": "a research run is in progress"})
        return

    # Decide + spawn the detached upgrade (does NOT print / exit — we own the exit).
    res = _perform_self_update(force_check=True)
    _write_update_status(device_id, {"state": res["state"], "current": res.get("current"),
                                     "latest": res.get("latest"), "reason": res.get("reason", "")})
    if res["state"] == "started":
        # Only NOW that an upgrade is actually launched do we stop this worker's own
        # run (gracefully, keeping partial results). Never stop a run for a no-op
        # update (already/failed/unsupported) — that would abort an in-flight run
        # for nothing. Sibling workers were just terminated by
        # _spawn_detached_lifecycle so pipx can rebuild the shared venv.
        if local_busy and loop is not None:
            try:
                loop.call_soon_threadsafe(_controls.request_stop)
                log("[device-cmds] UPDATE: signalled this worker's run to stop before the upgrade")
            except Exception as _rs:
                log(f"[device-cmds] UPDATE: request_stop dispatch failed: {_rs}", "WARN")
        log(f"[device-cmds] UPDATE: upgrade launched ({res.get('current')} → "
            f"{res.get('latest') or 'latest'}); exiting so pipx can rebuild the venv")
        _schedule_server_exit("device-update", delay_sec=1.5)
    else:
        log(f"[device-cmds] UPDATE: no upgrade ({res['state']}: {res.get('reason')})")


def _start_device_command_listener(uid: str, device_id: str, loop=None):
    """Subscribe to devices/{deviceId}/commands so the FE can issue
    device-level commands that aren't scoped to a particular research
    run (e.g. `hard_reset` from the Account-page Online pill, or
    `clear_local_storage` broadcast from Settings → Manage Data).

    Owner + sharers write to the subcollection (rule `isDeviceMember`
    + `submittedBy == auth.uid`); the BE-as-synth-device reads + deletes
    after processing (rule `isDeviceItself`). The synth user can listen
    here because the parent device doc's read rule permits self-reads.

    Startup sweep + 30s stale-age gate match the research-scoped
    listener's pattern — handled docs are tail-deleted in the same
    callback so a crash-before-delete doesn't double-fire on the next
    --serve. Lifetime is `--serve`-long (no per-run teardown).

    The `uid` param is now informational only (kept for logging /
    backward-compat); routing uses the top-level device path."""
    global _device_cmd_watch
    if not _firebase_db or not device_id:
        log("[device-cmds] not starting — missing device_id/firebase", "DEBUG")
        return
    del uid  # routed via deviceId only post-D8
    col_ref = _firebase_db.collection("devices").document(device_id) \
        .collection("commands")

    # Startup sweep — same rationale as _start_command_listener (line ~2127).
    try:
        for d in col_ref.where("processed", "==", True).stream():
            try:
                d.reference.delete()
            except Exception:
                pass
    except Exception as _sweep_err:
        log(f"[device-cmds] startup sweep failed: {_sweep_err}", "DEBUG")

    def _on_snap(_col_snapshot, changes, _read_time):
        for change in changes:
            if change.type.name != "ADDED":
                continue
            doc = change.document
            data = doc.to_dict() or {}
            if data.get("processed"):
                continue

            # 30s stale-command gate — commands older than this are from a
            # previous serve session and should NOT replay (e.g. a stop
            # written 5 minutes ago when serve was already down). Same
            # threshold as the research-scoped listener at line ~2154.
            STALE_COMMAND_AGE_MS = 30_000
            _ts = data.get("timestamp")
            if isinstance(_ts, (int, float)) and _ts > 0:
                _age_ms = int(time.time() * 1000) - int(_ts)
                if _age_ms > STALE_COMMAND_AGE_MS:
                    try:
                        doc.reference.update({"processed": True, "staleSkipped": True})
                    except Exception:
                        pass
                    continue

            action = (data.get("action") or "").strip()
            log(f"[device-cmds] received action={action!r} doc={doc.id}")

            # 2026-05-26: HARD_RESET defers the cmd-doc DELETE until AFTER
            # the sweep completes. The route at reset-pair-code/route.ts:140
            # polls for cmd-doc deletion as the ack signal, then proceeds
            # to clear sharedWith[] on the device doc (step 5). Pre-fix the
            # early-delete acked the route IMMEDIATELY, and route step 5
            # then ran in parallel with the BE sweep → sharedWith was
            # cleared mid-sweep → Firestore rule (deviceOwnership re-reads
            # sharedWith on every write) denied the sharer-tree updates
            # with 403. Observable in BE log line 37642 at 09:08:58:
            #   [sweep:hard_reset_sweep] update failed for chat_…: 403
            #   [sweep:hard_reset_sweep] sharer LQwUbFUp: swept=0 failed=1
            # → sharer's queued runs stayed at status=queued indefinitely
            # while owner's runs were correctly flipped.
            #
            # Mark processed=true upfront so SDK-reconnect mid-handler
            # re-fires skip via the processed check at the top of on_snap.
            # The actual delete happens at the END of the hard_reset
            # branch (just before the `continue` at line ~4017), so the
            # route's ack lands only after sharedWith-dependent writes are
            # done. Other actions keep the original tail-delete-first
            # semantics.
            if action == "hard_reset":
                try:
                    doc.reference.update({"processed": True})
                except Exception as _de:
                    log(f"[device-cmds] processed-marker write failed for {doc.id}: {_de}", "DEBUG")
            elif action in ("update", "check-update") and WORKER_ID != 1:
                # Only worker 1 ACTS on `update` / `check-update`. A sibling worker
                # must NOT delete the doc here — deleting it before worker 1's
                # Firestore stream delivers the ADDED could drop the command with no
                # replay (a create+delete inside a stream-resync window is coalesced
                # away). Leaving it means the doc persists until worker 1 processes
                # it (or the 30s stale gate reaps it). Worker 1 deletes it (`else`).
                continue
            else:
                try:
                    doc.reference.delete()
                except Exception as _de:
                    # Fall back to mark-processed if delete fails (e.g.
                    # transient permission glitch) — at least the doc won't
                    # replay. The startup sweep cleans it up later.
                    try:
                        doc.reference.update({"processed": True})
                    except Exception:
                        pass
                    log(f"[device-cmds] doc cleanup failed for {doc.id}: {_de}", "WARN")

            # ── Action dispatch ──
            if action == "hard_reset":
                # FE asked to fully reset the backend. Sequence:
                #   1. Touch the active run's .stop sentinel so the new
                #      --serve doesn't auto-resume it after respawn
                #      (matches how the research-scoped stop action
                #      writes the sentinel at line ~2278). Best-effort:
                #      if no run is active, skip silently.
                #   2. Wait up to 5s for any in-flight Storage upload
                #      to drain — see _wait_for_uploads_to_settle.
                #      Without this, an os._exit during a P3 audio
                #      blob.upload_from_filename leaves a half-written
                #      blob whose Firestore audios/{id} doc already
                #      points at it.
                #   3. Clear the queue-gate state (last_completed_*) so
                #      daemon-loop's respawn rehydrates a clean slate.
                #      Without this, the next --serve picks up the same
                #      stale prior-run pointer and re-engages the wedge
                #      that prompted the reset in the first place.
                #      Race-guarded by _QUEUE_STATE["_hard_reset_lock"]:
                #      the worker `finally` acquires the same lock
                #      around its gate-state writes + persist call so
                #      a worker finishing within our exit window can't
                #      interleave between our clear and our persist.
                #   4. Schedule os._exit via _schedule_server_exit with
                #      a 1.5s grace (shorter than the 3s default for
                #      research stop because we have less to ack —
                #      no pipeline_stopped emit owed). The daemon-
                #      loop's blocking subprocess.run sees the exit,
                #      sleeps 5s + the new C0a port-free probe, then
                #      respawns --serve. Total cycle ~7-12s.
                #
                # We deliberately do NOT use loop.call_soon_threadsafe
                # to set _controls.request_stop here — the process exit
                # is the authoritative stop, and the device-cmd
                # listener doesn't have an asyncio loop reference.
                # File-sentinel + os._exit is the contract.
                #
                # 2026-05-15: set the race-guard FIRST so any concurrent
                # worker-finally execution (between here and os._exit)
                # respects it.
                _QUEUE_STATE["_hard_reset_in_progress"] = True
                try:
                    if _tracks_dir is not None:
                        _stop_path = Path(__file__).parent / "queues" / _tracks_dir.name / ".stop"
                        try:
                            _stop_path.touch()
                            log(f"[device-cmds] HARD_RESET: marked .stop on active run {_tracks_dir.name}")
                        except Exception as _se:
                            log(f"[device-cmds] HARD_RESET: .stop touch failed: {_se}", "WARN")
                        # Flip the active run's research doc to cancelled so
                        # the FE chat shows the red Cancelled dialog and
                        # the auto-delete-on-close cascade kicks in —
                        # parity with the queued-jobs drain below + with
                        # how a user-triggered Cancel from the chat input
                        # behaves today. Reads the run's uid/rid from
                        # _QUEUE_STATE["current_job"]; falls back to a
                        # meta.json lookup on the active queue dir if
                        # current_job hasn't been written yet (rare race
                        # between worker assignment and Stop).
                        try:
                            _cur = _QUEUE_STATE.get("current_job") or {}
                            _au = _cur.get("uid") or ""
                            _ar = _cur.get("research_id") or ""
                            if (not _au or not _ar) and _tracks_dir is not None:
                                _meta_p = _tracks_dir / "meta.json"
                                if _meta_p.exists():
                                    try:
                                        _meta = json.loads(_meta_p.read_text(encoding="utf-8"))
                                        _au = _au or (_meta.get("uid") or "")
                                        _ar = _ar or (_meta.get("researchId") or "")
                                    except Exception:
                                        pass
                            if _au and _ar and _firebase_db:
                                try:
                                    from google.cloud.firestore import DELETE_FIELD as _ACT_DF
                                except Exception:
                                    _ACT_DF = None  # type: ignore
                                # 2026-05-26: do NOT set `cancelled: True`
                                # on the active run. It was status=ongoing
                                # with real partial work (browser state,
                                # intermediate phase artifacts, possibly
                                # emitted phase events). User wants it
                                # preserved in the listing as "Stopped"
                                # rather than silently purged by FE's
                                # chat-close cascade. Summary copy also
                                # reflects the actual event (Stopped, not
                                # Cancelled).
                                _act_patch: dict = {
                                    "status": "stopped",
                                    "summary": "Stopped by Reset Backend",
                                    "stoppedBy": "hard_reset_active",
                                    "stoppedAt": int(time.time() * 1000),
                                }
                                if _ACT_DF is not None:
                                    _act_patch["queuePosition"] = _ACT_DF
                                    _act_patch["queuedBehindRunId"] = _ACT_DF
                                    _act_patch["queuedBehindTitle"] = _ACT_DF
                                _update_research_doc(_au, _ar, _act_patch)
                                log(f"[device-cmds] HARD_RESET: flipped active run {_ar[:24]}… to stopped (preserved in listing)")
                        except Exception as _act_err:
                            log(f"[device-cmds] HARD_RESET: active-run cancel-flip failed: {_act_err}", "WARN")
                except NameError:
                    # _tracks_dir might not be defined yet on this serve
                    # (boot-time hard_reset before any run has started).
                    pass
                try:
                    residual = _wait_for_uploads_to_settle(max_wait_s=5.0)
                    if residual > 0:
                        log(f"[device-cmds] HARD_RESET: {residual} upload(s) still in flight after 5s — exiting anyway", "WARN")
                    else:
                        log("[device-cmds] HARD_RESET: uploads drained")
                except Exception as _ue:
                    log(f"[device-cmds] HARD_RESET: upload-settle check failed: {_ue}", "WARN")
                # 2026-05-15: clear queue-gate state + persist clean
                # snapshot under the hard-reset lock so the worker
                # `finally` block (research.py:~24400) can't race
                # between our clear and our persist. _persist_pending_queue
                # is a closure inside run_server, so we look it up via
                # _QUEUE_STATE["persist_fn"] (set at the function-def
                # tail, research.py:~24153). The atomic .tmp + os.replace
                # write inside that helper means a mid-write os._exit
                # can't corrupt _pending_queue.json — either the OLD file
                # (replace not committed) or NEW (clean) survives.
                try:
                    _hr_lock = _QUEUE_STATE.get("_hard_reset_lock")
                    _persist_fn = _QUEUE_STATE.get("persist_fn")
                    if _hr_lock is None or _persist_fn is None:
                        # Pre-run_server-init hard_reset (boot-time race).
                        # No worker yet → no race risk → no lock needed
                        # AND no in-memory gate state to clear yet, so the
                        # disk snapshot (if any) lives on. Best-effort log.
                        log("[device-cmds] HARD_RESET: pre-init — gate clear skipped (no run_server yet)", "WARN")
                    else:
                        with _hr_lock:
                            _QUEUE_STATE["last_completed_uid"] = None
                            _QUEUE_STATE["last_completed_rid"] = None
                            _QUEUE_STATE["last_be_done_at"] = 0
                            # Also clear gate_pending_job so any worker
                            # currently sitting in _wait_for_prior_fe_
                            # completion immediately falls through on
                            # its next is_stop() check (we set request
                            # _stop below in the foreground branch).
                            _QUEUE_STATE.pop("gate_pending_job", None)
                            _persist_fn(current_job=None)
                        log("[device-cmds] HARD_RESET: cleared queue-gate state and persisted clean snapshot")
                except Exception as _ge:
                    log(f"[device-cmds] HARD_RESET: gate clear/persist failed: {_ge}", "WARN")

                # Drain queued jobs — Reset Backend means "stop everything
                # on this device, not just the active run". Without this,
                # pending jobs in _job_queue survive the reset and start
                # executing the moment the worker is back, surprising the
                # user who thought they cleared the slate. Each queued
                # research gets:
                #   1. status="stopped" + cancelled=true on its research
                #      doc → the FE chat shows the Cancelled red dialog
                #      and the auto-delete-on-close cascade kicks in
                #      (mirroring how a user-triggered Cancel behaves
                #      from the chat input).
                #   2. The devices/{id}/queue/{auto} doc deleted so the
                #      Firestore start listener doesn't re-enqueue it on
                #      next BE startup.
                # The in-memory _job_queue is drained to "" via a tight
                # loop using get_nowait — works on asyncio.Queue from the
                # listener thread because _queue is the underlying deque.
                try:
                    # Drain via the underlying deque directly rather than
                    # asyncio.Queue.get_nowait() — get_nowait pops AND
                    # touches the unfinished_tasks counter (Queue.join
                    # internals), and calling task_done out-of-band from
                    # the listener thread can ValueError "called too many
                    # times". The deque popleft is thread-safe in CPython
                    # (single C-level operation), matches how the queue-
                    # position recompute at research.py:24700 already
                    # snapshots `_job_queue._queue`, and bypasses the
                    # counter entirely. The drained jobs are about to be
                    # cancelled anyway, so the counter mismatch doesn't
                    # matter — the process will exit + respawn fresh.
                    _drained_jobs: list[dict] = []
                    # 2026-05-26 FIX: reach the in-memory queue via
                    # _QUEUE_STATE["queue_ref"] (set in --serve at
                    # research.py:~28894). The bare name `_job_queue` is a
                    # LOCAL of the serve function — NOT in scope in this
                    # Firestore-listener callback thread — so referencing it
                    # raised NameError on every reset ("name '_job_queue' is
                    # not defined"), silently skipping the in-memory drain
                    # (harmless only because the deque was empty; a job queued
                    # in memory at reset time would have survived the reset).
                    _qref = _QUEUE_STATE.get("queue_ref")
                    if _qref is not None:
                        try:
                            while True:
                                _drained_jobs.append(_qref._queue.popleft())
                        except IndexError:
                            # deque empty — done draining
                            pass
                        except Exception as _drain_pop_err:
                            log(f"[device-cmds] HARD_RESET: deque pop failed mid-drain: {_drain_pop_err}", "WARN")
                    else:
                        log("[device-cmds] HARD_RESET: no in-memory queue_ref yet (boot race) — skipping deque drain", "DEBUG")
                    log(f"[device-cmds] HARD_RESET: drain found {len(_drained_jobs)} queued job(s)")
                    if _drained_jobs and _firebase_db:
                        try:
                            from google.cloud.firestore import DELETE_FIELD as _DRAIN_DF
                        except Exception:
                            _DRAIN_DF = None  # type: ignore
                        log(
                            f"[device-cmds] HARD_RESET: draining {len(_drained_jobs)} queued job(s) — flipping research status to stopped + cancelled"
                        )
                        for _qjob in _drained_jobs:
                            _qu = _qjob.get("uid") or ""
                            _qr = _qjob.get("research_id") or ""
                            if not _qu or not _qr:
                                continue
                            # 2026-05-26: drained deque jobs were CLAIMED
                            # by this worker (status=ongoing in Firestore
                            # via the claim path) but the actual phase
                            # work hadn't started yet. They have SOME
                            # state (queue_dir on disk, claim metadata)
                            # so preserve them in the listing as
                            # "Stopped" — same semantic as the active
                            # run above. User can manually delete from
                            # the listing if undesired.
                            _patch: dict = {
                                "status": "stopped",
                                "summary": "Stopped by Reset Backend",
                                "stoppedBy": "hard_reset_drained",
                                "stoppedAt": int(time.time() * 1000),
                            }
                            if _DRAIN_DF is not None:
                                _patch["queuePosition"] = _DRAIN_DF
                                _patch["queuedBehindRunId"] = _DRAIN_DF
                                _patch["queuedBehindTitle"] = _DRAIN_DF
                            try:
                                _update_research_doc(_qu, _qr, _patch)
                            except Exception as _drain_doc_err:
                                log(f"[device-cmds] HARD_RESET: queued-research update failed for {_qr[:24]}…: {_drain_doc_err}", "WARN")
                            # Also delete the device-queue entry so the
                            # start-listener doesn't replay it. The
                            # queue-collection iteration is best-effort.
                            try:
                                _did = load_device_id()
                                if _did:
                                    _q_col = _firebase_db.collection("devices") \
                                        .document(_did).collection("queue") \
                                        .where("researchId", "==", _qr).stream()
                                    for _qsnap in _q_col:
                                        try:
                                            _qsnap.reference.delete()
                                        except Exception:
                                            pass
                            except Exception as _drain_q_err:
                                log(f"[device-cmds] HARD_RESET: queue-doc delete failed for {_qr[:24]}…: {_drain_q_err}", "DEBUG")
                    elif _drained_jobs:
                        log(f"[device-cmds] HARD_RESET: drained {len(_drained_jobs)} job(s) from memory (no Firestore client — research docs left as-is)", "WARN")
                    # CRITICAL: re-persist after drain so the disk snapshot
                    # reflects the now-empty queue. Without this second
                    # persist, the pending list written by the gate-clear's
                    # _persist_fn call above still contained the jobs we
                    # just drained — on BE respawn, the rehydrate block
                    # would re-enqueue them and the user's "cleared queue"
                    # silently came back. Same _hr_lock semantics — write
                    # the post-drain snapshot atomically w.r.t. any
                    # racing worker `finally` block. Skip if persist_fn
                    # isn't available (boot-time race; gate-clear branch
                    # already logged about it).
                    try:
                        _hr_lock2 = _QUEUE_STATE.get("_hard_reset_lock")
                        _persist_fn2 = _QUEUE_STATE.get("persist_fn")
                        if _hr_lock2 is not None and _persist_fn2 is not None:
                            with _hr_lock2:
                                _persist_fn2(current_job=None)
                            log("[device-cmds] HARD_RESET: re-persisted clean snapshot post-drain")
                    except Exception as _rp_err:
                        log(f"[device-cmds] HARD_RESET: post-drain re-persist failed: {_rp_err}", "WARN")
                except Exception as _dr_err:
                    log(f"[device-cmds] HARD_RESET: queue drain failed: {_dr_err}", "WARN")

                # 2026-05-25: Firestore queue-collection sweep. The drain
                # above only deletes queue docs corresponding to entries
                # in the in-memory `_job_queue` deque. Docs sitting in
                # `devices/{deviceId}/queue/` that BE never had a chance
                # to claim — submitted while BE was off, deferred from a
                # prior crash, FE-replay residue, etc. — stayed put.
                # On next BE startup the start-listener replayed them
                # silently, re-running work the user thought they cleared
                # (Venom OS 10-day-old doc re-fired 2026-05-25 even after
                # user did Reset Backend). Enumerate + delete the entire
                # collection so HARD_RESET means HARD_RESET.
                #
                # Multi-worker: only WORKER_ID==1 sweeps. The collection
                # is device-scoped so all workers see the same docs;
                # running the loop N times is just wasted RPC. A doc
                # might be mid-claim by a sibling worker — deleting it
                # under that worker is acceptable for HARD_RESET (the
                # user explicitly asked to nuke everything; sibling's
                # claim TX fails and it skips). Best-effort, gated on
                # _firebase_db presence; failures logged not raised.
                try:
                    if _firebase_db and WORKER_ID == 1:
                        try:
                            _hr_did = load_device_id() or ""
                        except Exception:
                            _hr_did = ""
                        if _hr_did:
                            try:
                                _q_col_root = _firebase_db.collection("devices") \
                                    .document(_hr_did).collection("queue")
                                _q_deleted = 0
                                _q_failed = 0
                                for _qsnap in _q_col_root.stream():
                                    try:
                                        _qsnap.reference.delete()
                                        _q_deleted += 1
                                    except Exception:
                                        _q_failed += 1
                                if _q_deleted or _q_failed:
                                    log(
                                        f"[device-cmds] HARD_RESET: Firestore "
                                        f"queue-collection sweep — deleted "
                                        f"{_q_deleted} doc(s), "
                                        f"{_q_failed} failed"
                                    )
                                else:
                                    log("[device-cmds] HARD_RESET: Firestore queue-collection sweep — already empty")
                            except Exception as _qc_err:
                                log(f"[device-cmds] HARD_RESET: Firestore queue-collection sweep failed: {_qc_err}", "WARN")
                        else:
                            log("[device-cmds] HARD_RESET: skipping queue-collection sweep — device id missing", "WARN")
                except Exception as _qcw_err:
                    log(f"[device-cmds] HARD_RESET: queue-collection sweep wrapper failed: {_qcw_err}", "WARN")

                # 2026-05-21: bulk-sweep ANY stale ongoing/paused/running
                # research docs for the paired owner. The drain above only
                # closes jobs that are CURRENTLY queued or running in BE
                # memory — it misses runs that were wedged in a prior
                # session and never finished writing a terminal status
                # (process crash, kill -9, BE-restart-without-finally, etc).
                # Pre-fix, those zombie docs kept the FE chat tile showing
                # "Ongoing" forever and the queue gate (which keys on the
                # most recent beDone marker) would refuse to advance into
                # the NEXT user's queued run until the user manually went
                # tile-by-tile in Account → Manage devices to delete them.
                #
                # Filter: by deviceId so other devices' in-flight work
                # isn't accidentally killed. The research doc's deviceId
                # field is stamped by `_be_payload` on every BE write, so
                # this filter matches anything THIS device ever started.
                # Owner-other-device runs are left alone.
                #
                # Best-effort: a Firestore client failure here doesn't
                # block the exit — gate state is already cleared above.
                #
                # Multi-worker (2026-05-21): only WORKER_ID==1 runs the
                # sweep. The collection is device-scoped (shared across
                # all workers on this device), and the sweep's writes
                # are idempotent — running it N times only wastes
                # Firestore RPC and opens a tiny race where two updates
                # could contend on the same doc.
                try:
                    if _firebase_db and WORKER_ID == 1:
                        # Resolve paired uid + device id from local config.
                        try:
                            _sweep_uid = load_paired_uid() or ""
                        except Exception:
                            _sweep_uid = ""
                        try:
                            _sweep_did = load_device_id() or ""
                        except Exception:
                            _sweep_did = ""
                        if _sweep_uid and _sweep_did:
                            try:
                                _swept_n, _swept_fail = _sweep_stuck_research_docs_for_device(
                                    _firebase_db, _sweep_uid, _sweep_did,
                                    stopped_by="hard_reset_sweep",
                                    summary="Cancelled by Reset Backend",
                                )
                                if _swept_n or _swept_fail:
                                    log(f"[device-cmds] HARD_RESET: Firestore sweep marked {_swept_n} stale run(s) as stopped ({_swept_fail} failed) — covers owner + sharer trees")
                                else:
                                    log("[device-cmds] HARD_RESET: Firestore sweep — no stale ongoing/queued/paused/paused_backend_restart runs found (owner + sharers)")
                            except Exception as _q_err:
                                log(f"[device-cmds] HARD_RESET: Firestore sweep query failed: {_q_err}", "WARN")
                        else:
                            log("[device-cmds] HARD_RESET: skipping Firestore sweep — paired uid or device id missing", "WARN")
                    else:
                        log("[device-cmds] HARD_RESET: skipping Firestore sweep — no _firebase_db", "WARN")
                except Exception as _bs_err:
                    log(f"[device-cmds] HARD_RESET: Firestore sweep wrapper failed: {_bs_err}", "WARN")

                # Local-disk meta.json sweep — stamp every queues/<dir>/meta.json
                # whose status is still "ongoing"/"paused"/"running" as
                # "stopped". Without this, the local `/api/runs` listing
                # (read by the BE's HTTP layer; surfaces in the Account-page
                # device debug view) keeps showing zombie entries from
                # crashed prior runs even after the Firestore docs are
                # cleaned. Each crashed run typically leaves a meta.json
                # frozen at the phase where it died.
                #
                # Multi-worker (2026-05-21): only WORKER_ID==1 sweeps.
                # The queues/ tree is shared across workers; two workers
                # rmtree-ing the same dirs would race. The "active dir"
                # exclusion below uses the CALLING worker's _tracks_dir
                # (process-local), so w1's sweep already skips w1's
                # active run; w2+'s active dirs would NOT be excluded
                # if w2's hard_reset also fired the sweep — which is
                # exactly the bug worker-1-only avoids.
                try:
                    queues_root_local = Path(__file__).parent / "queues"
                    if WORKER_ID == 1 and queues_root_local.exists():
                        _m_swept = 0
                        _m_active = None
                        try:
                            if _tracks_dir is not None:
                                _m_active = _tracks_dir.name
                        except NameError:
                            _m_active = None
                        for _qd in queues_root_local.iterdir():
                            if not _qd.is_dir():
                                continue
                            if _m_active and _qd.name == _m_active:
                                continue  # leave the active run's meta alone — its finally will write
                            _mp = _qd / "meta.json"
                            if not _mp.exists():
                                continue
                            try:
                                _md = json.loads(_mp.read_text(encoding="utf-8"))
                                _ms = (_md.get("status") or "").lower()
                                if _ms in ("ongoing", "running", "paused"):
                                    _md["status"] = "stopped"
                                    _md["stoppedAt"] = int(time.time() * 1000)
                                    _md["stoppedBy"] = "hard_reset_sweep"
                                    _mp.write_text(json.dumps(_md, indent=2), encoding="utf-8")
                                    _m_swept += 1
                            except Exception:
                                # Best-effort; corrupted meta files are
                                # left for the user's local-storage clear.
                                continue
                        if _m_swept:
                            log(f"[device-cmds] HARD_RESET: local meta.json sweep marked {_m_swept} stale dir(s) as stopped")
                except Exception as _ms_err:
                    log(f"[device-cmds] HARD_RESET: local meta.json sweep failed: {_ms_err}", "WARN")

                # Supervisor detection. If a daemon-loop process is alive,
                # os._exit lets it respawn us cleanly. If not (foreground
                # --serve run), os._exit kills the BE permanently — the
                # user wouldn't see Online come back. Detect via process
                # enumeration: any python(.exe) with --daemon-loop in its
                # command line is the supervisor.
                _supervisor_alive = False
                try:
                    self_pid = os.getpid()
                    for pid, _cmd, role in _enumerate_research_py_procs():
                        if pid != self_pid and role == "daemon-loop":
                            _supervisor_alive = True
                            break
                except Exception as _enum_err:
                    log(f"[device-cmds] HARD_RESET: supervisor detect failed (assuming foreground): {_enum_err}", "DEBUG")

                # 2026-05-26: delete the cmd doc NOW — sweep is done, so
                # acking the route here means sharedWith stays populated
                # through every cross-account write. See the comment block
                # at the top of the dispatch (action == "hard_reset"
                # branch) for the full race + fix narrative.
                try:
                    doc.reference.delete()
                except Exception as _de_end:
                    log(f"[device-cmds] HARD_RESET: cmd-doc delete (post-sweep) failed for {doc.id}: {_de_end}", "DEBUG")

                if _supervisor_alive:
                    log("[device-cmds] HARD_RESET: scheduling exit in 1.5s — daemon-loop will respawn")
                    _schedule_server_exit("device-hard-reset", delay_sec=1.5)
                else:
                    # Foreground --serve. Don't os._exit — the user is
                    # watching their terminal and a silent process death
                    # leaves the FE tile offline with no auto-recovery.
                    # Instead: request_stop on any active run (so the
                    # worker's finally drains cleanly), keep the
                    # heartbeat + listeners alive, and let the FE's next
                    # tile poll see us still online with a freshly-
                    # cleared gate state.
                    log("[device-cmds] HARD_RESET: foreground mode — clearing in-place (no daemon-loop detected)")
                    if loop is not None:
                        try:
                            loop.call_soon_threadsafe(_controls.request_stop)
                            log("[device-cmds] HARD_RESET: complete — active run signalled to stop, gate cleared, BE staying up")
                        except Exception as _rs_err:
                            log(f"[device-cmds] HARD_RESET: request_stop dispatch failed: {_rs_err}", "WARN")
                    else:
                        # Pre-run_server-init hard_reset (boot-time race)
                        # or call site that didn't pass the loop. Gate is
                        # already cleared; just log and continue. Any
                        # active run on this BE will keep running, which
                        # is fine — gate state is the thing that matters
                        # for unstucking the next pipeline.
                        log("[device-cmds] HARD_RESET: no event loop ref — gate cleared, no active-run stop signal sent", "WARN")
                continue

            if action == "clear_local_storage":
                # User-triggered manual cleanup of the device-side queues/
                # dir. Documents/audios/chat already live in Firestore +
                # Storage, so the only thing we lose is intermediate
                # per-run scratch (sources_*.md, brief.md, source PDFs,
                # half-rendered podcasts). Safe to wipe.
                #
                # Active-run guard: if a pipeline is currently producing
                # for `_tracks_dir`, that single dir is preserved. Without
                # this, an in-flight run would crash mid-phase when its
                # checkpoint.json / source files vanish.
                queues_root = Path(__file__).parent / "queues"
                active_name = None
                try:
                    if _tracks_dir is not None:
                        active_name = _tracks_dir.name
                except NameError:
                    active_name = None

                wiped = 0
                preserved = 0
                try:
                    if queues_root.exists():
                        for entry in queues_root.iterdir():
                            # Keep top-level files (README.md, _pending_queue.json).
                            if not entry.is_dir():
                                continue
                            if active_name and entry.name == active_name:
                                preserved += 1
                                continue
                            try:
                                shutil.rmtree(entry, ignore_errors=True)
                                wiped += 1
                            except Exception as _wipe_err:
                                log(f"[device-cmds] CLEAR_LOCAL_STORAGE: failed to wipe {entry.name}: {_wipe_err}", "WARN")
                except Exception as _walk_err:
                    log(f"[device-cmds] CLEAR_LOCAL_STORAGE: walk failed: {_walk_err}", "WARN")

                if active_name and preserved:
                    log(f"[device-cmds] CLEAR_LOCAL_STORAGE: wiped {wiped} dir(s); preserved active run {active_name}")
                else:
                    log(f"[device-cmds] CLEAR_LOCAL_STORAGE: wiped {wiped} dir(s)")
                continue

            if action == "update":
                # App-driven remote backend update (owner-only command). Single
                # actor: only worker 1 executes it (it owns the heartbeat/version
                # publish); other workers no-op (the doc is already deleted above).
                # All the authz / supervised / mid-run guards live in the handler.
                if WORKER_ID == 1:
                    _handle_update_command(data, device_id, loop)
                continue

            if action == "check-update":
                # App-driven "check for a backend update" (About-page Check button).
                # Worker 1 forces a fresh PyPI check + republishes the version signal
                # + versionCheckedAt. Benign (no restart); single-actor like update.
                if WORKER_ID == 1:
                    _handle_check_update_command(device_id)
                continue

            # Unknown action — already logged above and the doc is
            # already deleted. No-op past this point so future actions
            # can be slotted in as elif branches.

    try:
        _device_cmd_watch = col_ref.on_snapshot(_on_snap)
        log(f"Device command listener started for device {device_id[:24]}…")
    except Exception as e:
        log(f"Could not start device command listener: {e}", "WARN")


# ── Run Analytics (phase duration tracking for realistic ETAs) ────────────

ANALYTICS_PATH = _STATE_DIR / "run_analytics.json"
_phase_averages: dict[int, float] = {}  # phase → avg duration in seconds

# Reasonable defaults when no analytics exist yet. Based on observed runs
# (2026-04-15 data + pipeline design targets). Updated as real data arrives.
_DEFAULT_PHASE_MINUTES = {0: 0.2, 1: 27, 2: 55, 3: 15, 4: 8, 5: 4}

# 2026-05-14: Phase 3 audio generation varies with podcast_length mode.
# (low, high) ranges in minutes. Narration uses both ends in the user-
# visible string ("5–10m typical"); the structured `expectedMinutes`
# emit field uses the high end (FE displays a single number for the
# progress-bar label, and overestimating beats underestimating —
# avoids panicking the user when actual exceeds estimate). Matches the
# Settings UI copy at FE settings/page.tsx ("Short ≈ 5–10 · Default ≈
# 10–20 · Long ≈ 30–45").
_AUDIO_TYPICAL_RANGE_MIN = {
    "short":   (5, 10),
    "default": (10, 20),
    "long":    (30, 45),
}


def load_analytics():
    """Load run_analytics.json and compute per-phase average durations."""
    global _phase_averages
    if not ANALYTICS_PATH.exists():
        _phase_averages = {}
        return
    try:
        data = json.loads(ANALYTICS_PATH.read_text(encoding="utf-8"))
        runs = data.get("runs", [])
        # Group by phase, compute average
        from collections import defaultdict
        buckets: dict[int, list[float]] = defaultdict(list)
        for r in runs:
            p = r.get("phase")
            d = r.get("durationSec", 0)
            if isinstance(p, int) and d > 0:
                buckets[p].append(d)
        _phase_averages = {p: sum(ds) / len(ds) for p, ds in buckets.items() if ds}
        if _phase_averages:
            log(f"Analytics loaded: {', '.join(f'P{p}={v/60:.0f}m' for p, v in sorted(_phase_averages.items()))}")
    except Exception as e:
        log(f"Failed to load analytics: {e}", "WARN")
        _phase_averages = {}


def record_phase_duration(phase: int, duration_sec: float, agent: str = ""):
    """Append a phase completion record to run_analytics.json. Recomputes
    in-memory averages from the same in-process data — avoids the redundant
    file read that load_analytics() would do."""
    global _phase_averages
    try:
        data = {"runs": []}
        if ANALYTICS_PATH.exists():
            data = json.loads(ANALYTICS_PATH.read_text(encoding="utf-8"))
        data.setdefault("runs", []).append({
            "phase": phase,
            "agent": agent,
            "durationSec": round(duration_sec),
            "timestamp": int(time.time()),
        })
        ANALYTICS_PATH.write_text(json.dumps(data, indent=2), encoding="utf-8")
        from collections import defaultdict
        buckets: dict[int, list[float]] = defaultdict(list)
        for r in data["runs"]:
            p = r.get("phase")
            d = r.get("durationSec", 0)
            if isinstance(p, int) and d > 0:
                buckets[p].append(d)
        _phase_averages = {p: sum(ds) / len(ds) for p, ds in buckets.items() if ds}
    except Exception as e:
        log(f"Failed to record analytics: {e}", "WARN")


def get_expected_minutes(phase: int) -> int:
    """Return realistic ETA in minutes for a phase, using analytics if available."""
    if phase in _phase_averages:
        return max(1, round(_phase_averages[phase] / 60))
    return _DEFAULT_PHASE_MINUTES.get(phase, 10)


# Counter of in-flight Storage uploads, protected by a lock for thread-
# safe inc/dec. The hard-reset handler waits briefly for this to drop to
# zero before triggering os._exit so that an in-progress audio/.m4a
# upload doesn't end up half-written in the bucket while its Firestore
# audios/{id} doc points at the partial blob. Anything that uploads to
# Storage on the user's behalf should bracket the call with this
# counter — only audio uploads do today (album-art is FE-side).
import threading as _threading
_inflight_uploads_lock = _threading.Lock()
_inflight_uploads = 0


def _begin_storage_upload() -> None:
    global _inflight_uploads
    with _inflight_uploads_lock:
        _inflight_uploads += 1


def _end_storage_upload() -> None:
    global _inflight_uploads
    with _inflight_uploads_lock:
        if _inflight_uploads > 0:
            _inflight_uploads -= 1


def _wait_for_uploads_to_settle(max_wait_s: float = 5.0, poll_s: float = 0.1) -> int:
    """Block until _inflight_uploads == 0 or the deadline fires. Returns
    the count remaining at the end (0 if drained, >0 if we timed out).
    Used by the hard-reset path so a kill that lands mid-upload waits a
    few seconds for the upload to finish rather than truncating it.
    Caller decides what to do if the count is still nonzero — typically
    log + proceed (the BE shutdown is the user's primary intent)."""
    import time as _t
    deadline = _t.time() + max_wait_s
    while _t.time() < deadline:
        with _inflight_uploads_lock:
            if _inflight_uploads <= 0:
                return 0
        _t.sleep(poll_s)
    with _inflight_uploads_lock:
        return _inflight_uploads


def _resolve_storage_bucket() -> str:
    """Resolve the Firebase Storage bucket name. Honors the
    `FIREBASE_STORAGE_BUCKET` env override; falls back to the
    `<project>.firebasestorage.app` convention used by Firebase
    projects created Oct 2024+."""
    explicit = os.environ.get("FIREBASE_STORAGE_BUCKET", "").strip()
    if explicit:
        return explicit
    try:
        from auth.v2_flow import PROJECT_ID
        return f"{PROJECT_ID}.firebasestorage.app"
    except Exception:
        return ""


# Bounded backoff for transient Firebase Storage REST failures on the Track D
# synth-user upload/download paths. A 403 here is almost always a claim-
# propagation race — a sharer was just added (share-claim) or the device
# re-paired, and the synth user's custom claims (ownerUid / sharedWith) hadn't
# caught up when the token was minted. Each retry re-mints a FRESH id token
# (_fresh_user_mode_id_token force-refreshes, so it re-reads the latest
# claims), which lets the request self-heal with no user action. 429 / 5xx /
# network blips get the same treatment. Total added wait is bounded (~6.5s)
# so a genuinely doomed request still returns well inside the Track-D silence-
# watchdog window — and a structural failure (refresh token revoked →
# fresh-mint returns None) breaks out immediately instead of burning the
# whole schedule.
_STORAGE_REST_RETRY_DELAYS = (1.0, 2.0, 3.5)


def _storage_rest_should_retry(status_code: "int | None") -> bool:
    """True when a Storage REST outcome warrants a silent retry: an auth race
    (403), throttling (429), or a transient server error (5xx). status_code is
    None for a network-level exception, which is also retryable."""
    if status_code is None:
        return True
    return status_code == 403 or status_code == 429 or status_code >= 500


def _upload_audio_via_storage_rest(local_path: "Path", owner_uid: str, research_id: str) -> "str | None":
    """Track D user-mode audio upload — Firebase Storage REST API using
    the synth-device-user's ID token. The Storage rule for
    `audio/{userId}/{...}` permits create+update when the token's
    `deviceId` claim resolves to a device authorized for `userId`.

    Returns a download-token URL on success — publicly fetchable by URL,
    so the FE Podcasts page can stream it via `<audio src>` without an
    Authorization header. Returns None on token-mint failure, upload
    failure, or missing bucket.

    Object path mirrors legacy: audio/{ownerUid}/{researchId}/{filename}.
    """
    import requests as _requests
    import time as _t
    from urllib.parse import quote as _quote

    bucket = _resolve_storage_bucket()
    if not bucket:
        log("[storage REST] FIREBASE_STORAGE_BUCKET unresolved — skip audio upload", "WARN")
        return None
    id_token = _fresh_user_mode_id_token()
    if not id_token:
        log("[storage REST] no usable ID token — re-pair required", "WARN")
        return None

    filename = local_path.name
    object_path = f"audio/{owner_uid}/{research_id}/{filename}"
    ct = "audio/mpeg" if filename.lower().endswith(".mp3") else (
        "audio/mp4" if filename.lower().endswith((".m4a", ".mp4")) else "audio/*"
    )
    upload_url = (
        f"https://firebasestorage.googleapis.com/v0/b/{bucket}/o"
        f"?uploadType=media&name={_quote(object_path, safe='')}"
    )
    def _do_upload(_id_token: str):
        """Single POST attempt. Returns the requests.Response or None on
        network error (already logged). Pulled out so the bounded retry
        loop below can re-issue it with freshly minted tokens."""
        try:
            with open(local_path, "rb") as f:
                return _requests.post(
                    upload_url,
                    headers={
                        "Authorization": f"Firebase {_id_token}",
                        "Content-Type": ct,
                    },
                    data=f,
                    timeout=120,
                )
        except _requests.RequestException as e:
            log(f"[storage REST] audio upload network error: {e}", "WARN")
            return None

    resp = _do_upload(id_token)

    # Silent bounded retry on transient failures (claim-propagation 403 / 429 /
    # 5xx / network). Each pass re-mints a fresh token so a just-propagated
    # claim (sharer added via share-claim, device re-paired) is picked up; the
    # upload heals itself with no user-facing Retry. A revoked-token None
    # breaks out immediately — that's structural (re-pair required), not
    # something a retry can fix — and falls through to the diagnostic below.
    _retried = False
    for _delay in _STORAGE_REST_RETRY_DELAYS:
        _status = resp.status_code if resp is not None else None
        if not _storage_rest_should_retry(_status):
            break
        _t.sleep(_delay)
        _retry_id_token = _fresh_user_mode_id_token()
        if not _retry_id_token:
            break
        log(f"[storage REST] transient audio-upload outcome ({_status}) — re-minted token, "
            f"retrying after {_delay:.1f}s (silent self-heal)", "INFO")
        _retried = True
        id_token = _retry_id_token
        resp = _do_upload(id_token)

    if resp is None:
        return None
    if _retried and resp.status_code == 200:
        log("[storage REST] audio upload succeeded after retry — transient outcome resolved")

    if resp.status_code != 200:
        # Surface enough diagnostic to debug the common Track D regression:
        # synth-user upload getting 403 because the device doc's `ownerUid`
        # was cleared (FE owner-Unlink without token revoke pre-fix) or
        # `sharedWith[]` doesn't include this user. Decoding the JWT claims
        # lets us see the actual deviceId/ownerUid the BE is sending vs
        # what the rule expected.
        _claim_dump = ""
        try:
            import base64 as _b64
            import json as _json
            _payload_b64 = id_token.split(".")[1]
            _payload_b64 += "=" * (-len(_payload_b64) % 4)
            _claims = _json.loads(_b64.urlsafe_b64decode(_payload_b64))
            _claim_dump = (
                f" claims={{deviceId={_claims.get('deviceId')!r}, "
                f"ownerUid={_claims.get('ownerUid')!r}, "
                f"sharedWith={_claims.get('sharedWith')!r}, "
                f"sub={_claims.get('sub')!r}}}"
            )
        except Exception:
            pass
        log(
            f"[storage REST] audio upload HTTP {resp.status_code} "
            f"path=audio/{owner_uid}/{research_id}/{filename}{_claim_dump} "
            f"body={resp.text[:300]}",
            "WARN",
        )
        if resp.status_code == 403:
            log(
                "[storage REST] 403 hint (after retries): rule expected "
                "token.ownerUid == path-uid OR path-uid in token.sharedWith. "
                "If sharer firing on shared device: confirm sharer is in the "
                "device's sharedWith via FE Account → Manage Sharers. If owner: "
                "device may have lost ownerUid — re-pair via FE Account → Add Device. "
                "If ALL identifiers already match yet it still 403s, suspect a "
                "DEPLOYED-ruleset lag (the rules engine 403s blanket when the "
                "live storage.rules differs from the repo) — redeploy via "
                "`firebase deploy --only storage` and confirm.",
                "WARN",
            )
        return None
    try:
        meta = resp.json()
    except Exception:
        log("[storage REST] audio upload returned non-JSON response", "WARN")
        return None
    # Firebase returns a comma-separated downloadTokens list; first entry
    # is the active one. The URL with `?alt=media&token=...` is public-
    # by-URL — anyone with the URL can fetch the bytes.
    tokens = (meta.get("downloadTokens") or "").split(",")
    token = tokens[0].strip() if tokens else ""
    if not token:
        log("[storage REST] audio upload returned no downloadTokens", "WARN")
        return None
    public_url = (
        f"https://firebasestorage.googleapis.com/v0/b/{bucket}/o/"
        f"{_quote(object_path, safe='')}?alt=media&token={token}"
    )
    log(f"Audio uploaded via Storage REST: gs://{bucket}/{object_path}")
    return public_url


def _download_user_source_via_storage_rest(storage_path: str, dest_path: "Path") -> bool:
    """Track D user-mode source download — Firebase Storage REST GET using
    the synth-device-user's ID token. The Storage rule for
    `users/{userId}/researches/{rid}/sources/{filename}` permits read
    when the token's `deviceId` claim resolves to a device authorized
    for `userId`. Streams to disk; returns True on success."""
    import requests as _requests
    import time as _t
    from urllib.parse import quote as _quote

    bucket = _resolve_storage_bucket()
    if not bucket:
        log("[storage REST] FIREBASE_STORAGE_BUCKET unresolved — skip source download", "WARN")
        return False
    id_token = _fresh_user_mode_id_token()
    if not id_token:
        log("[storage REST] no usable ID token — re-pair required", "WARN")
        return False

    url = (
        f"https://firebasestorage.googleapis.com/v0/b/{bucket}/o/"
        f"{_quote(storage_path, safe='')}?alt=media"
    )

    def _do_get(_tok: str):
        """Single GET attempt. Returns the requests.Response, or None on a
        network-level error (already logged) so the retry loop treats it as
        retryable."""
        try:
            return _requests.get(
                url,
                headers={"Authorization": f"Firebase {_tok}"},
                stream=True,
                timeout=60,
            )
        except _requests.RequestException as e:
            log(f"[storage REST] source download network error ({storage_path}): {e}", "WARN")
            return None

    resp = _do_get(id_token)

    # Silent bounded retry — parity with the audio-upload path. A source-
    # download 403 is the same claim-propagation race, and this path had NO
    # retry before, so a transient stale-claim window aborted the whole run.
    # Re-minting a fresh token each pass lets it self-heal; 429/5xx/network
    # blips retry too; a revoked-token None breaks out (structural re-pair).
    _retried = False
    for _delay in _STORAGE_REST_RETRY_DELAYS:
        _status = resp.status_code if resp is not None else None
        if not _storage_rest_should_retry(_status):
            break
        _t.sleep(_delay)
        _retry_tok = _fresh_user_mode_id_token()
        if not _retry_tok:
            break
        log(f"[storage REST] transient source-download outcome ({_status}) for {storage_path} "
            f"— re-minted token, retrying after {_delay:.1f}s (silent self-heal)", "INFO")
        _retried = True
        id_token = _retry_tok
        resp = _do_get(id_token)

    if resp is None:
        return False
    if _retried and resp.status_code == 200:
        log(f"[storage REST] source download succeeded after retry ({storage_path}) — transient outcome resolved")
    if resp.status_code != 200:
        log(f"[storage REST] source download HTTP {resp.status_code} ({storage_path}): {resp.text[:200]}", "WARN")
        # 2026-05-21: 403 diagnostic. The Track D synth-user storage read
        # depends on a deviceId claim resolving to a device authorized for
        # the path's `userId`. When it fails, dump the actionable state:
        # (a) synth uid + deviceId claim from the live token, (b) device
        # doc's ownerUid + sharedWith so the user can see the mismatch.
        # Without this, the 403 above is opaque — same string regardless
        # of whether the synth-user claims are stale, the device doc
        # owner is wrong, or the path's owner just isn't in scope.
        if resp.status_code == 403:
            try:
                import base64 as _b64
                import json as _j
                # Decode the ID-token middle segment (no signature verify
                # — we're just reading claims for diagnostic purposes).
                _claims = {}
                try:
                    _seg = id_token.split(".")[1] + "=="
                    _claims = _j.loads(_b64.urlsafe_b64decode(_seg).decode("utf-8"))
                except Exception:
                    pass
                _synth_uid = _claims.get("user_id") or _claims.get("sub") or "?"
                _claim_did = _claims.get("deviceId") or "?"
                _claim_owner = _claims.get("ownerUid") or "?"
                # Path's userId is the first segment after "users/".
                _path_owner = "?"
                if storage_path.startswith("users/"):
                    _path_owner = storage_path.split("/", 2)[1]
                # Look up the device doc — sharedWith / ownerUid current
                # state. Best-effort: skip if Firestore client not ready.
                _dev_owner = "?"
                _dev_shared: list[str] = []
                try:
                    if _firebase_db and _claim_did and _claim_did != "?":
                        _snap = _firebase_db.collection("devices").document(_claim_did).get()
                        if _snap.exists:
                            _dd = _snap.to_dict() or {}
                            _dev_owner = _dd.get("ownerUid") or "?"
                            _dev_shared = list(_dd.get("sharedWith") or [])
                except Exception as _de:
                    _dev_owner = f"(lookup failed: {_de})"
                log(
                    f"[storage REST] 403 diagnostic: "
                    f"synth_uid={_synth_uid[:24]}… "
                    f"claim_deviceId={_claim_did[:16] if _claim_did else '?'}… "
                    f"claim_ownerUid={_claim_owner[:16] if _claim_owner else '?'}… "
                    f"path_owner={_path_owner[:16] if _path_owner else '?'}… "
                    f"device_doc_owner={_dev_owner[:16] if _dev_owner else '?'}… "
                    f"device_doc_sharedWith={[s[:16] for s in _dev_shared]}",
                    "ERROR",
                )
                # Specifically call out the mismatch class so the user
                # knows whether it's a stale-claim issue (re-pair fixes)
                # vs a sharing issue (owner needs to share with sharer).
                if _path_owner != "?" and _dev_owner != "?":
                    if _path_owner == _dev_owner:
                        log("[storage REST] 403 root: path is for THIS device's owner yet still denied AFTER retries — either claim/token freshness (try Reset Pair Code → re-pair) OR a DEPLOYED-ruleset lag (live storage.rules differs from repo → blanket 403 regardless of claims; redeploy via `firebase deploy --only storage`).", "ERROR")
                    elif _path_owner in _dev_shared:
                        log("[storage REST] 403 root: path is for a sharer who IS in sharedWith — device-doc state OK, suspect synth-token claim staleness (re-pair to refresh)", "ERROR")
                    else:
                        log(f"[storage REST] 403 root: path owner {_path_owner[:24]}… is NOT in device's owner/sharedWith. Owner must share with this user via Manage devices → Add sharer.", "ERROR")
            except Exception as _diag_err:
                log(f"[storage REST] 403 diagnostic raised: {_diag_err}", "WARN")
        return False
    try:
        with open(dest_path, "wb") as out:
            for chunk in resp.iter_content(chunk_size=64 * 1024):
                if chunk:
                    out.write(chunk)
    except Exception as e:
        log(f"[storage REST] source write failed ({storage_path} → {dest_path}): {e}", "WARN")
        return False
    return True


def upload_audio_to_storage(local_path: "Path") -> str | None:
    """Upload the NotebookLM audio file to Firebase Storage via the REST
    API as the synth device user, and return a download-token URL that
    the FE Podcasts page can play via plain `<audio src>`. Path is
    scoped under the submitter's uid + researchId so users can only see
    their own files (see storage.rules)."""
    if not (_fb_uid and _fb_research_id):
        return None
    if not local_path or not local_path.exists():
        return None
    _begin_storage_upload()
    try:
        return _upload_audio_via_storage_rest(local_path, _fb_uid, _fb_research_id)
    finally:
        _end_storage_upload()


def save_audio_to_firestore(audio_id: str, name: str, duration_sec: int, audio_url: str | None):
    """Upsert an audio entry into users/{uid}/researches/{id}/audios/{audio_id}
    so the Podcasts page on Vercel can list + stream it without needing the
    local backend. audio_url is the public Storage URL from upload_audio_to_storage.
    """
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return
    try:
        mins, secs = divmod(max(0, int(duration_sec)), 60)
        _grpc_write_with_heal(
            lambda: _firebase_db.collection("users").document(_fb_uid)
                .collection("researches").document(_fb_research_id)
                .collection("audios").document(audio_id)
                .set(_be_payload({
                    "id": audio_id,
                    "name": name,
                    "duration": f"{mins}:{secs:02d}" if duration_sec else "",
                    "durationSec": int(duration_sec or 0),
                    "createdAt": int(time.time() * 1000),
                    **({"audioUrl": audio_url} if audio_url else {}),
                })),
            what=f"audio {audio_id}")
    except Exception as e:
        log(f"Failed to sync audio to Firestore: {e}", "WARN")


def save_document_to_firestore(doc_type: str, content: str, name: str | None = None) -> bool:
    """Upsert a research document (brief/chatgpt/gemini/claude/consolidated)
    into the user's Firestore documents subcollection so the Documents page
    on Vercel can render it without direct access to this local backend.
    Phase 3 (NotebookLM) still reads MDs from queue_dir/documents/ on local
    disk — this sync is strictly for the frontend Documents UI.

    Upsert semantics: doc_type is used as the Firestore doc ID, so re-runs
    or re-extractions for the same research overwrite in place instead of
    creating duplicates.

    Returns True iff the Firestore write committed; False otherwise (no
    Firestore client, blank content, or API error). Callers gate the
    `link_extracted` emit on this so an unsynced doc never gets a "Read
    report" button that would open an empty modal.
    """
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return False
    if not content or not content.strip():
        return False
    try:
        _grpc_write_with_heal(
            lambda: _firebase_db.collection("users").document(_fb_uid)
                .collection("researches").document(_fb_research_id)
                .collection("documents").document(doc_type)
                .set(_be_payload({
                    "id": doc_type,
                    "name": name or f"{doc_type}.md",
                    "type": doc_type,
                    "content": content,
                    "size": f"{len(content) / 1024:.0f} KB",
                    "createdAt": int(time.time() * 1000),
                })),
            what=f"document {doc_type}")
        return True
    except Exception as e:
        # F5 (2026-05-13): include exception class + gRPC/HTTP status code
        # so the next sync failure is diagnosable. google.api_core exceptions
        # (DeadlineExceeded, ResourceExhausted, Unavailable, PermissionDenied,
        # InvalidArgument…) carry .code (gRPC StatusCode). The bare {e} repr
        # at the WARN log was hiding the category the operator needs to
        # categorize transient-vs-persistent failure modes.
        _code = getattr(e, "code", None)
        _code_str = ""
        if _code is not None:
            _code_str = f" [code={getattr(_code, 'name', _code)}]"
        log(f"Failed to sync {doc_type}.md to Firestore: "
            f"{type(e).__name__}: {e}{_code_str}", "WARN")
        return False


async def save_document_to_firestore_with_retry(
    doc_type: str,
    content: str,
    name: str | None = None,
    *,
    label: str | None = None,
    backoffs: tuple = (1.0, 4.0, 16.0),
) -> bool:
    """F5 (2026-05-13): retry-wrapped variant for the inline P2 agent sync
    path. Absorbs transient Firestore blips (429 / Unavailable / network)
    with exponential backoff. Returns True on first successful sync, False
    after exhausting attempts.

    `label` is the agent display name used in log lines (defaults to doc_type).
    Caller is responsible for the agent_progress=failed emit on False return.
    """
    tag = label or doc_type
    total = len(backoffs) + 1
    for _attempt in range(total):
        if save_document_to_firestore(doc_type, content, name):
            return True
        if _attempt < len(backoffs):
            _sleep = backoffs[_attempt]
            log(f"[{tag}] Firestore document sync attempt {_attempt + 1} failed — "
                f"retrying in {_sleep:g}s", "WARN")
            await asyncio.sleep(_sleep)
        else:
            log(f"[{tag}] Firestore document sync FAILED after {total} attempts — "
                f"FE doc-reachable gate will not flip until next save attempt.", "ERROR")
    return False


def start_firestore_start_listener(job_queue, loop):
    """Listen for pipeline start requests via this backend's queue.

    Routing is mode-aware:
    - User-mode → subscribe to top-level `devices/{deviceId}/queue/`.
      That's the D4 canonical FIFO; rule `isDeviceItself()` lets the
      synth device user read + delete entries. cmd_pair_v2 doesn't
      mint a researchToken, so `_research_token` is None here anyway.
    - Legacy mode → subscribe to `research_tokens/{token}/queue/` as
      before. Falls back to global `pipeline_requests/` when no
      researchToken (pre-pair installs).
    Backend picks up the request, queues the job, writes run_id back."""
    global _start_listener
    if not _firebase_db:
        return

    did = load_device_id()
    if not did:
        log("deviceId missing — start listener not initialized; run --pair", "WARN")
        return
    col_ref = _firebase_db.collection("devices").document(did).collection("queue")
    listener_label = f"devices/{did[:8]}…/queue/"

    def on_snapshot(_col_snapshot, changes, _read_time):
        for change in changes:
            if change.type.name != 'ADDED':
                continue
            doc = change.document
            data = doc.to_dict() or {}
            if data.get("processed"):
                continue
            # Stale-queue defense (2026-05-22 rewrite): Firestore's
            # onSnapshot replays every unprocessed doc as ADDED on first
            # attach. Pre-rewrite we deleted EVERY doc > 30s old, which
            # conflated two distinct cases and caused multi-account FIFO
            # loss after STOP+respawn:
            #   (a) Post-crash zombie — prior session claimed the doc
            #       (assignedWorker + claimedAt set) but the process
            #       died before processing. Safe to delete (no live
            #       worker on it; submitter's FE will surface "couldn't
            #       start — retry" via the watchdog landing in commit 5).
            #   (b) Legit FIFO wait — doc was deferred by the listener
            #       because both workers were busy. assignedWorker
            #       UNSET. The original 30s gate killed these on every
            #       respawn, deleting deferred-FIFO entries that
            #       should have been claimed cleanly post-restart.
            # 3-way decision:
            #   ZOMBIE        (assignedWorker + claimedAt set,
            #                  age_since_claim > grace)        → delete
            #   ZOMBIE-IN-GRACE (claimed within grace)         → skip,
            #                  don't delete (sibling may still
            #                  be alive). On next process bounce,
            #                  age_since_claim will exceed grace and
            #                  the ZOMBIE branch cleans up.
            #   ABANDONED     (no assignedWorker, age ≥ 12h)   → delete
            #   UNCLAIMED-RECENT (no assignedWorker, age < 12h) →
            #                  fall through to normal claim path
            # Missing-timestamp legacy docs (no _ts and no _ca) fall
            # through, preserving the original code's bug-compatible
            # behavior. The FIFO pre-query at line 3901 already filters
            # docs with assignedWorker set, so a claimed-doc passing
            # through the elif chain is harmless either way.
            ZOMBIE_GRACE_MS = 30_000
            ABANDONED_MAX_MS = 12 * 60 * 60 * 1000  # 12h — user moved on
            _ts = data.get("timestamp")
            _age_ms = 0
            if isinstance(_ts, (int, float)) and _ts > 0:
                _age_ms = int(time.time() * 1000) - int(_ts)
            _aw = data.get("assignedWorker")
            _ca = data.get("claimedAt")
            if _aw is not None and isinstance(_ca, (int, float)) and _ca > 0:
                _age_since_claim = int(time.time() * 1000) - int(_ca)
                if _age_since_claim > ZOMBIE_GRACE_MS:
                    log(
                        f"Queue: stale-skip ZOMBIE {(data.get('researchId') or '')[:8]}… "
                        f"topic={(data.get('topic') or '')[:40]!r} "
                        f"submittedBy={(data.get('submittedBy') or '?')[:8]} "
                        f"assignedWorker={_aw} claimedAt={_ca} "
                        f"age_since_claim={_age_since_claim // 1000}s — deleting",
                        "INFO",
                    )
                    try:
                        doc.reference.delete()
                    except Exception:
                        pass
                    continue
                # Within grace — sibling may still be alive. Skip this
                # listener fire but don't delete. Doc gets re-evaluated
                # on next process bounce (replay → ZOMBIE → delete).
                continue
            elif (_age_ms > ABANDONED_MAX_MS and data.get("action", "start") != "cancel"
                    and not _worker_is_resting()
                    and not (isinstance(data.get("restDeferredAt"), (int, float))
                             and int(time.time() * 1000) - int(data["restDeferredAt"])
                             <= ABANDONED_MAX_MS)):
                # #903 rest exemptions (review MAJOR): a rest-deferred doc is
                # EXPECTED to sit unclaimed past 12h (park over a weekend is
                # the feature's headline use). While resting, never sweep;
                # after a wake+restart, measure age from the last rest-defer
                # stamp (restDeferredAt, re-stamped by the defer path) so a
                # doc parked >12h isn't silently dropped before pickup.
                # 2026-05-28: exempt action="cancel" docs from the 12h
                # ABANDONED sweep. A cancel doc is a terminal SIGNAL, not
                # queued work — silently deleting one before the
                # action=="cancel" handler runs would drop a stop/cancel
                # (incl. an owner-initiated Stop/Cancel) with no feedback.
                # Processing a stale cancel is a cheap idempotent no-op
                # (the target run is long terminal), so let it through.
                # (resume docs keep their prior behavior — out of scope.)
                #
                # #904 review catch (wake-before-boot hole): the keepalive
                # re-stamps restDeferredAt only while the BE is ALIVE. Park
                # Friday → shut the PC down → wake the workers from the phone
                # Sunday (device-doc write needs no BE) → boot Monday: on the
                # replay this branch saw age>12h, worker no longer resting,
                # stamp days-stale → deleted the run the user was waiting on.
                # Before purging an UNCLAIMED start doc, read its research
                # doc: a healthy status="queued" means the run is still
                # WANTED and this queue doc is its only claim ticket — skip
                # the purge (the rescan claims it within a tick). Read error
                # → skip too (never destroy work on a transient); missing doc
                # or terminal status → purge as before.
                if (data.get("action", "start") == "start"
                        and data.get("researchId") and data.get("submittedBy")):
                    try:
                        _ab_snap = (_firebase_db.collection("users")
                                    .document(data["submittedBy"])
                                    .collection("researches")
                                    .document(data["researchId"]).get())
                        _ab_status = ((_ab_snap.to_dict() or {}).get("status") or "") \
                            if _ab_snap.exists else ""
                    except Exception as _ab_err:
                        log(
                            f"Queue: stale-skip ABANDONED health read failed for "
                            f"{(data.get('researchId') or '')[:8]}… — keeping doc "
                            f"(transient): {_ab_err}",
                            "DEBUG",
                        )
                        continue
                    if _ab_status == "queued":
                        log(
                            f"Queue: stale-skip ABANDONED exempt {(data.get('researchId') or '')[:8]}… "
                            f"— research doc still status=queued (parked run awaiting "
                            f"pickup; age={_age_ms // 1000}s)",
                            "INFO",
                        )
                        continue
                log(
                    f"Queue: stale-skip ABANDONED {(data.get('researchId') or '')[:8]}… "
                    f"topic={(data.get('topic') or '')[:40]!r} "
                    f"submittedBy={(data.get('submittedBy') or '?')[:8]} "
                    f"age={_age_ms // 1000}s — deleting",
                    "INFO",
                )
                try:
                    doc.reference.delete()
                except Exception:
                    pass
                continue
            # 2026-05-25: Missing-timestamp legacy queue docs (typically
            # pre-2026-05-15 schema) used to fall straight through to the
            # claim path. That re-ran the entire pipeline today for a
            # queue doc from 10 days ago (Venom OS E2E 2026-05-25 —
            # predates the P4/P5 FE cutover so feP5State was never
            # written, status stayed "ongoing", queue doc never deleted).
            # Fall back to the linked research doc's updatedAt/createdAt
            # as a secondary staleness signal. Scoped to action="start"
            # so cancel/skip-action docs (rare but valid path for
            # orchestrator cleanups) are unaffected. Adds one Firestore
            # read per legacy doc, zero overhead for modern (timestamped)
            # docs. Sync .get() mirrors the existing existence check at
            # research.py:4647 — same listener thread, same pattern.
            elif _age_ms == 0 and _aw is None and data.get("action", "start") == "start":
                try:
                    _rid_legacy = data.get("researchId") or ""
                    _uid_legacy = data.get("uid") or ""
                    if _rid_legacy and _uid_legacy:
                        _rd_snap = _firebase_db.collection("users") \
                            .document(_uid_legacy) \
                            .collection("researches") \
                            .document(_rid_legacy).get()
                        if _rd_snap.exists:
                            _rd_data = _rd_snap.to_dict() or {}

                            def _to_ms(v):
                                if v is None:
                                    return 0
                                if hasattr(v, "timestamp"):
                                    return int(v.timestamp() * 1000)
                                if isinstance(v, (int, float)):
                                    return int(v)
                                return 0
                            _rd_ms = max(_to_ms(_rd_data.get("updatedAt")),
                                         _to_ms(_rd_data.get("createdAt")))
                            _rd_age_ms = int(time.time() * 1000) - _rd_ms
                            if _rd_ms > 0 and _rd_age_ms > ABANDONED_MAX_MS:
                                log(
                                    f"Queue: stale-skip ABANDONED-BY-RESEARCH "
                                    f"{_rid_legacy[:24]}… "
                                    f"topic={(data.get('topic') or '')[:40]!r} "
                                    f"research_age={_rd_age_ms // 1000}s — deleting",
                                    "INFO",
                                )
                                try:
                                    doc.reference.delete()
                                except Exception:
                                    pass
                                continue
                except Exception as _stale_check_err:
                    log(
                        f"Queue: research-doc staleness fallback failed "
                        f"(allowing through): {_stale_check_err}",
                        "DEBUG",
                    )
            # UNCLAIMED-RECENT or missing-timestamp (research-doc fresh
            # or unreadable) — fall through to action handling + normal
            # claim path.
            action = data.get("action", "start")
            # Handle cancel-queued: remove the target research from the job
            # queue before it reaches the worker and mark it stopped. The
            # actively-running job is handled by its own per-run command
            # listener, not here.
            if action == "cancel":
                target_rid = data.get("researchId", "")
                target_uid = data.get("uid", "")
                # 2026-05-28: owner-initiated stop/cancel of a SHARER's run
                # (the "Shared with" popup badge long-press). "stop" =
                # running run → preserve; "cancel" = queued run → purge.
                # Absent for a normal self-cancel. See _owner_control_patch.
                _oc = data.get("ownerControl") or ""
                if not target_rid or not target_uid:
                    log("Cancel: missing researchId/uid", "WARN")
                    try:
                        doc.reference.delete()
                    except Exception:
                        pass
                    continue
                # If the target is the actively-running job, route to the
                # same stop path the per-run command listener uses:
                # request_stop + schedule_server_exit. _controls.is_stop()
                # checks aren't inside long Playwright awaits, so a stop
                # signal alone can take minutes to land — the 3s exit
                # timer bounds tear-down. daemon-loop respawns --serve
                # fresh and any orphan Patchright/Chromium dies with the
                # parent process. Mark the research status="stopped" too
                # so the FE chat + tile reflect cancelled immediately;
                # `_flip_queued_to_ongoing` is now transactional and
                # honors this even if the worker dequeues concurrently.
                # (Replaces the old cancelTooLate band-aid: the cancel
                # actually cancels now, so no "couldn't cancel" message
                # path is needed.)
                current = _QUEUE_STATE.get("current_job") or {}
                # 2026-05-12: also check the gate-pending job. Worker pops
                # from job_queue then awaits _wait_for_prior_fe_completion
                # BEFORE setting current_job — so a cancel that arrives
                # while the worker is in the gate wait sees neither
                # current_job nor a queue entry and silently no-ops. The
                # gate_pending_job marker closes this gap.
                gate_pending = _QUEUE_STATE.get("gate_pending_job") or {}
                if gate_pending.get("research_id") == target_rid:
                    log(f"Cancel: target {target_rid[:8]}… is in gate wait — requesting stop + flipping status{' (owner '+_oc+')' if _oc else ''}", "INFO")
                    loop.call_soon_threadsafe(_controls.request_stop)
                    if _firebase_db:
                        from google.cloud.firestore import DELETE_FIELD as _DF
                        _update_research_doc(target_uid, target_rid, _owner_control_patch(_oc, running=False) or {
                            "status": "stopped",
                            "summary": "Cancelled while queued",
                            "cancelled": True,
                            "queuePosition": _DF,
                            "queuedBehindRunId": _DF,
                            "queuedBehindTitle": _DF,
                        })
                    try:
                        doc.reference.delete()
                    except Exception:
                        pass
                    continue
                if current.get("research_id") == target_rid:
                    log(f"Cancel: target {target_rid[:8]}… is the running job — requesting stop + scheduling exit{' (owner '+_oc+')' if _oc else ''}", "INFO")
                    loop.call_soon_threadsafe(_controls.request_stop)
                    run_id = current.get("run_id") or ""
                    if run_id:
                        try:
                            (Path(__file__).parent / "queues" / run_id / ".stop").touch()
                        except Exception:
                            pass
                    if _firebase_db:
                        from google.cloud.firestore import DELETE_FIELD as _DF
                        # Q6: distinguishes user-cancel from worker-stop. FE
                        # consumes for the red dialog and the auto-delete-on-
                        # close. queuePosition/queuedBehind* dropped — banner
                        # reads them as still-queued otherwise.
                        # Owner-stop (running) preserves the run (no cancelled,
                        # no cascade-delete); _owner_control_patch returns {}
                        # for a self-cancel so the original write is kept.
                        # Only THIS worker (the one holding current_job) writes
                        # the terminal status for an owner-stop — idle siblings
                        # that also see the cancel doc skip the flip in
                        # _do_cancel (see the owner-stop guard there), avoiding a
                        # cancelled=True clobber that would wrongly purge the run.
                        _update_research_doc(target_uid, target_rid, _owner_control_patch(_oc, running=True) or {
                            "status": "stopped",
                            "summary": "Cancelled",
                            "cancelled": True,
                            "queuePosition": _DF,
                            "queuedBehindRunId": _DF,
                            "queuedBehindTitle": _DF,
                        })
                    try:
                        doc.reference.delete()
                    except Exception:
                        pass
                    _schedule_server_exit("token-cancel-current")
                    continue
                def _do_cancel(rid=target_rid, u=target_uid, dref=doc.reference, oc=_oc):
                    try:
                        # 2026-05-12: also re-check gate_pending_job. The
                        # listener-thread initial check above could miss a
                        # job that JUST entered the gate wait. Same fix as
                        # the sync path.
                        gate_pending_now = _QUEUE_STATE.get("gate_pending_job") or {}
                        if gate_pending_now.get("research_id") == rid:
                            log(f"Cancel: target {rid[:8]}… moved to gate wait between listener checks — requesting stop{' (owner '+oc+')' if oc else ''}", "INFO")
                            _controls.request_stop()
                            if _firebase_db:
                                from google.cloud.firestore import DELETE_FIELD as _DF
                                _update_research_doc(u, rid, _owner_control_patch(oc, running=False) or {
                                    "status": "stopped",
                                    "summary": "Cancelled while queued",
                                    "cancelled": True,
                                    "queuePosition": _DF,
                                    "queuedBehindRunId": _DF,
                                    "queuedBehindTitle": _DF,
                                })
                            try:
                                dref.delete()
                            except Exception:
                                pass
                            return
                        # Race-safe re-check: between the listener's initial
                        # current_job read (above) and this callback running on
                        # the asyncio loop, the worker may have completed its
                        # `await _job_queue.get()` AND set _QUEUE_STATE
                        # ["current_job"]. If we just scanned the deque, the
                        # job would be missing (already popped) → no-op → the
                        # pipeline would start despite the cancel. Re-checking
                        # current_job here closes that window.
                        current_now = _QUEUE_STATE.get("current_job") or {}
                        if current_now.get("research_id") == rid:
                            log(f"Cancel: target {rid[:8]}… popped to current_job between listener checks — routing to stop+exit{' (owner '+oc+')' if oc else ''}", "INFO")
                            _controls.request_stop()
                            run_id_now = current_now.get("run_id") or ""
                            if run_id_now:
                                try:
                                    (Path(__file__).parent / "queues" / run_id_now / ".stop").touch()
                                except Exception:
                                    pass
                            if _firebase_db:
                                from google.cloud.firestore import DELETE_FIELD as _DF
                                _update_research_doc(u, rid, _owner_control_patch(oc, running=True) or {
                                    "status": "stopped",
                                    "summary": "Cancelled",
                                    "cancelled": True,
                                    "queuePosition": _DF,
                                    "queuedBehindRunId": _DF,
                                    "queuedBehindTitle": _DF,
                                })
                            try:
                                dref.delete()
                            except Exception:
                                pass
                            _schedule_server_exit("token-cancel-current-late")
                            return
                        dq = job_queue._queue  # deque
                        kept = [j for j in dq if j.get("research_id") != rid]
                        removed = any(j.get("research_id") == rid for j in dq)
                        dq.clear()
                        for j in kept:
                            dq.append(j)
                        # Bug Cancel-Stale (2026-05-22): for deferred jobs
                        # (still in Firestore queue, no worker has claimed
                        # them) the local dq scan misses, removed=False,
                        # and the pre-fix code skipped both the
                        # Firestore-queue-doc deletion AND the research-
                        # doc status flip. Result: chat tile stayed
                        # "queued" forever, only Reset BE could clear it,
                        # and a BE restart would replay the start doc and
                        # actually run the "cancelled" job.
                        #
                        # Fix: scan + delete the start queue doc + flip
                        # the research status regardless of dq state.
                        # Idempotent for cross-worker case (sibling already
                        # handled it via its own listener — duplicate
                        # writes of the same payload are no-ops).
                        # Hoisted out of the `if not removed` block so the
                        # deferred-flip owner-stop guard below can test whether
                        # THIS worker actually located the start doc.
                        _start_doc_id = None
                        if not removed and _firebase_db:
                            try:
                                for _qsnap in col_ref.limit(50).stream():
                                    _qd = _qsnap.to_dict() or {}
                                    if (_qd.get("researchId") == rid
                                            and (_qd.get("action") or "start") == "start"):
                                        _start_doc_id = _qsnap.id
                                        break
                                if _start_doc_id is not None:
                                    try:
                                        col_ref.document(_start_doc_id).delete()
                                        log(
                                            f"Cancel: deferred start doc {_start_doc_id[:8]}… "
                                            f"deleted for rid={rid[:8]}…",
                                            "INFO",
                                        )
                                    except Exception as _de:
                                        log(
                                            f"Cancel: deferred start doc delete failed "
                                            f"(non-fatal — sibling may have got it): {_de}",
                                            "DEBUG",
                                        )
                            except Exception as _se:
                                log(
                                    f"Cancel: deferred start doc scan failed (non-fatal): {_se}",
                                    "DEBUG",
                                )
                        # Owner-STOP of a running run: only the worker holding
                        # current_job (handled in the sync + late re-check
                        # branches above) writes the terminal status. An idle
                        # sibling worker also sees the cancel doc, reaches here,
                        # finds nothing (removed=False, no start doc), and must
                        # NOT flip — for an owner-stop that would clobber the
                        # holding worker's preserve-write and there is no
                        # deferred run to cancel. Skip the flip in that case.
                        # Owner-CANCEL of a queued run is genuinely deferred, so
                        # it always flips (matching the self-cancel path).
                        _op_def = _owner_control_patch(oc, running=False)
                        _owner_stop_not_held = (
                            oc == "stop" and not (removed or _start_doc_id is not None)
                        )
                        if _firebase_db and _owner_stop_not_held:
                            log(
                                f"Cancel: owner-stop rid={rid[:8]}… not held by "
                                f"this worker — skipping deferred flip",
                                "DEBUG",
                            )
                        elif _firebase_db:
                            # Always flip status — the removed=True case
                            # had this; the removed=False case used to
                            # skip it. Both paths now converge on the
                            # same write so the FE banner clears either
                            # way.
                            from google.cloud.firestore import DELETE_FIELD as _DF
                            _update_research_doc(u, rid, _op_def or {
                                "status": "stopped",
                                "phase": 0,
                                "summary": (
                                    "Cancelled before starting"
                                    if removed
                                    else "Cancelled while queued"
                                ),
                                "cancelled": True,
                                "queuePosition": _DF,
                                "queuedBehindRunId": _DF,
                                "queuedBehindTitle": _DF,
                            })
                            if removed:
                                # recompute_fn re-numbers everyone behind
                                # me in my own worker's local queue. Skip
                                # for the deferred case — nothing was
                                # popped, nothing to renumber.
                                fn = _QUEUE_STATE.get("recompute_fn")
                                if fn:
                                    fn()
                            else:
                                # Deferred cancel: cancelled doc was
                                # somewhere in the global FIFO; everyone
                                # behind it shifts up. Real-time renumber
                                # (2026-05-22) so the remaining queued
                                # tiles reflect the new order
                                # immediately. Fire-and-forget via
                                # to_thread — we're on the asyncio loop
                                # via call_soon_threadsafe, and the scan
                                # is bounded.
                                fn_d = _QUEUE_STATE.get("recompute_deferred_fn")
                                if fn_d is not None:
                                    try:
                                        asyncio.create_task(asyncio.to_thread(fn_d))
                                    except Exception as _re:
                                        log(
                                            f"Cancel: deferred-recompute launch failed: {_re}",
                                            "DEBUG",
                                        )
                        # Log the outcome. The `cancelled: True` field on
                        # the research doc (Q6) is the FE signal that
                        # drives the red Cancelled dialog AND the
                        # auto-delete-on-chat-close cascade. The
                        # token-queue cancel doc itself is deleted
                        # immediately above (dref.delete()) — the FE
                        # tracks completion via the research doc, not the
                        # cancel doc's existence.
                        log(f"Cancel: rid={rid[:8]}... removed_from_queue={removed}", "INFO")
                        try:
                            dref.delete()
                        except Exception:
                            pass
                    except Exception as ex:
                        log(f"Cancel queued failed: {ex}", "WARN")
                loop.call_soon_threadsafe(_do_cancel)
                continue
            # Resume-from-checkpoint: the FE banner Resume / chat-tool resume
            # for a paused_backend_restart / stopped_by_watchdog run lands here.
            # The per-research command listener is dead in those states (this
            # is a fresh daemon process), so the token-queue is the only path
            # that re-enqueues the job from disk artifacts.
            if action == "resume":
                target_uid = data.get("uid", "")
                target_rid = data.get("researchId", "")
                if not target_uid or not target_rid:
                    log("Resume: missing uid/researchId", "WARN")
                    try: doc.reference.delete()
                    except Exception: pass
                    continue
                # Track D: synth user can't read users/{ownerUid}/researches.
                # FE now carries backendRunId in the queue payload, so the
                # research-doc read is a fallback only (legacy Admin-SDK BEs
                # or installs where the FE somehow forgot to include it).
                # Initialize `rd` so the topic fallback at line ~2829 is
                # safe even when we skip the doc-read branch entirely.
                rd: dict = {}
                backend_run_id = (data.get("backendRunId") or "").strip()
                if not backend_run_id:
                    try:
                        rs = _firebase_db.collection("users").document(target_uid) \
                            .collection("researches").document(target_rid).get()
                    except Exception as ex:
                        err_str = str(ex)
                        if (
                            "403" in err_str
                            or "PERMISSION_DENIED" in err_str
                            or "Missing or insufficient permissions" in err_str
                        ):
                            log(
                                "Resume: read denied on research doc + no backendRunId in payload — drop queue entry",
                                "WARN",
                            )
                        else:
                            log(f"Resume: failed to read research doc: {ex}", "WARN")
                        try: doc.reference.delete()
                        except Exception: pass
                        continue
                    if not rs.exists:
                        log(f"Resume: research {target_rid[:8]}... not found", "WARN")
                        try: doc.reference.delete()
                        except Exception: pass
                        continue
                    rd = rs.to_dict() or {}
                    backend_run_id = rd.get("backendRunId") or ""
                if not backend_run_id:
                    log(f"Resume: research {target_rid[:8]}... has no backendRunId", "WARN")
                    try: doc.reference.delete()
                    except Exception: pass
                    continue
                queue_dir = Path(__file__).parent / "queues" / backend_run_id
                if not queue_dir.exists():
                    log(f"Resume: queue_dir missing for {backend_run_id} — disk artifacts gone", "WARN")
                    try: doc.reference.delete()
                    except Exception: pass
                    continue
                # Block resume of terminal-stopped runs (mirrors HTTP endpoint).
                if (queue_dir / ".stop").exists():
                    log(f"Resume: run {backend_run_id} marked .stop (terminal) — skipping", "WARN")
                    try: doc.reference.delete()
                    except Exception: pass
                    continue
                # Clear .pause signal so the dispatcher / phase loops drain.
                p = queue_dir / ".pause"
                if p.exists():
                    try: p.unlink()
                    except Exception: pass
                # Atomic single-worker claim — every worker process runs its OWN
                # on_snapshot listener on the shared devices/{id}/queue collection,
                # so all workers receive this one resume doc. Without a claim each
                # would flip status + enqueue → the SAME run fires on every worker
                # (the reported 3-workers → 3 duplicate runs on Retry). Mirror the
                # `start` path's compare-and-swap; only the CAS winner proceeds to
                # flip status / delete the doc / enqueue. Placed AFTER validation
                # (so a doomed resume isn't claimed-then-orphaned) and BEFORE the
                # status flip + delete below.
                _resume_claim = _try_claim_queue_doc(
                    doc.reference, WORKER_ID, log_prefix="[resume]")
                if _resume_claim is None:
                    # CAS errored after retries — skip rather than risk a duplicate
                    # enqueue; the doc lingers and replays on the next BE restart.
                    log(f"[resume] worker {WORKER_ID}: claim error — skipping {backend_run_id} "
                        f"(replays on restart)", "WARN")
                    continue
                if _resume_claim is False:
                    log(f"[resume] worker {WORKER_ID}: resume doc claimed by a sibling worker — "
                        f"skipping {backend_run_id}", "INFO")
                    continue
                # Merge config into config.json if provided.
                payload_config = data.get("config") or {}
                if payload_config:
                    config_path = queue_dir / "config.json"
                    try:
                        existing = json.loads(config_path.read_text(encoding="utf-8")) if config_path.exists() else {}
                        existing.update(payload_config)
                        config_path.write_text(json.dumps(existing, indent=2), encoding="utf-8")
                    except Exception as ex:
                        log(f"Resume: config merge failed: {ex}", "WARN")
                # Reset delivery + meta status from "paused" back to "ongoing"
                # so disk artifacts agree with the new run state.
                for fname in ("delivery.json", "meta.json"):
                    fpath = queue_dir / fname
                    if fpath.exists():
                        try:
                            d = json.loads(fpath.read_text(encoding="utf-8"))
                            if d.get("status") == "paused":
                                d["status"] = "ongoing"
                                fpath.write_text(json.dumps(d, indent=2), encoding="utf-8")
                        except Exception:
                            pass
                # Read topic from checkpoint (most authoritative); fall back to
                # the research doc's topic.
                cp = load_checkpoint(queue_dir)
                topic = (cp or {}).get("topic", "") or rd.get("topic", "")
                email = data.get("email") or ""
                # Flip Firestore status to "ongoing" so the FE drops the alert
                # banner immediately (the listener race below is harmless —
                # _safe_enqueue's whitelist accepts ongoing). #728: re-stamp
                # assignedWorker = the worker resuming it (this process), so a
                # later restart's rehydration keeps the affinity correct.
                _update_research_doc(target_uid, target_rid,
                                     {"status": "ongoing", "assignedWorker": WORKER_ID})
                # Delete the queue doc — Firestore's onSnapshot replays it
                # otherwise, double-enqueueing on every BE restart.
                try: doc.reference.delete()
                except Exception: pass
                # Enqueue with resume_dir. We've already validated existence,
                # so put_nowait directly bypasses _safe_enqueue's status check
                # (which can race with our just-written "ongoing" flip).
                def _do_resume_enqueue(t=topic, e=email, c=payload_config,
                                       r=backend_run_id, u=target_uid, ri=target_rid,
                                       rd_path=str(queue_dir)):
                    try:
                        job_queue.put_nowait({
                            "topic": t, "email": e, "config": c, "run_id": r,
                            "uid": u, "research_id": ri, "resume_dir": rd_path,
                        })
                    except Exception as ex:
                        log(f"Resume: put_nowait failed: {ex}", "WARN")
                loop.call_soon_threadsafe(_do_resume_enqueue)
                log(f"Resume: re-enqueued {backend_run_id} for rid={target_rid[:8]}...")
                continue
            if action != "start":
                continue
            uid = data.get("uid", "")
            research_id = data.get("researchId", "")
            topic = data.get("topic", "").strip()
            email = data.get("email", "")
            config = data.get("config", {})
            brief_text = (data.get("briefText") or "").strip()
            # Flow B (P1+P2 skipped, user attached source files) — list of
            # {name, storagePath, mime, size}. BE downloads each from Storage
            # into queue_dir/documents/ before P3 runs.
            user_sources = data.get("userSources") or []
            # Flow C (P1+P2+P3 skipped, user pasted URLs) — list of
            # {kind, label, url}. BE hydrates notebook_url / youtube_url /
            # links from these in the P3-skip block of run_pipeline.
            user_links = data.get("userLinks") or []
            if not topic or not uid or not research_id:
                log(f"Firestore start request missing fields: uid={uid}, rid={research_id}, topic={topic[:30]}", "WARN")
                try:
                    doc.reference.delete()
                except Exception:
                    pass
                continue
            # uid validation is enforced server-side by the Firestore queue
            # rule (`submittedBy == request.auth.uid`) and the device-doc
            # `sharedWith[]` check via `deviceWritingTo`. No additional
            # BE-side gate needed here.
            # Research-doc existence check — user may have deleted the chat
            # from the app between firing the research and us picking up the
            # queue doc. Without this, we'd run a full pipeline and try to
            # write back status to a doc that doesn't exist (the "404 No
            # document to update" WARN the user saw), which wastes an hour
            # of API calls on work the user already abandoned. Mark the
            # queue doc staleSkipped so it doesn't replay on future
            # listener attaches.
            try:
                research_doc = _firebase_db.collection("users").document(uid) \
                    .collection("researches").document(research_id).get()
                if not research_doc.exists:
                    log(f"Queue: skipped — research doc {research_id} no longer exists (user deleted chat?)", "INFO")
                    try:
                        doc.reference.delete()
                    except Exception:
                        pass
                    continue
                # 2026-05-22 (cancel-stale fix): cross-worker cancel race
                # mitigation. The cancel handler at research.py:4090 flips
                # research status="stopped" + cancelled=True, but there's
                # a window where worker A claimed the queue doc + scheduled
                # call_soon_threadsafe enqueue BEFORE the cancel arrives —
                # the cancel handler's dq scan finds nothing on either
                # worker, and worker A's pending enqueue lands afterward.
                # Pre-claim status re-check catches this: if the research
                # doc is already in a terminal state, skip + delete the
                # queue doc so it doesn't replay on listener attach.
                _rd_data = research_doc.to_dict() or {}
                _rd_status = _rd_data.get("status")
                if _rd_status in (
                    "stopped", "completed", "archived",
                    "terminated_by_user_discard", "stopped_by_watchdog",
                ):
                    log(
                        f"Queue: skipped — research {research_id[:24]}… "
                        f"already status={_rd_status} (cancel landed mid-claim?)",
                        "INFO",
                    )
                    try:
                        doc.reference.delete()
                    except Exception:
                        pass
                    continue
                # 2026-05-28 (duplicate-retry defense): if research is
                # already "ongoing" AND a sibling worker holds the lock
                # for it, this queue doc is a duplicate — drop it. Repro:
                # user at queue position #1, BE stalls (listener missed
                # event / network blip), user clicks Retry → FE writes a
                # new queue doc with the same researchId. The atomic FE
                # batch (firestore.ts startPipelineViaFirestore with
                # dedupForRetry) deletes the old doc + adds the new one
                # in one commit, but a cross-user race (sibling fires
                # between the FE's delete and add) can leave both docs
                # live momentarily. This guard catches that race + any
                # other path that landed two queue docs on the same rid.
                #
                # Discriminator vs. legitimate FE pre-flip ("ongoing"
                # written client-side before BE claims): the sibling
                # lock check. _scan_sibling_locks_for_research returns
                # non-empty ONLY when another worker on THIS device has
                # already claimed the same research_id (live PID, fresh
                # started_at). FE pre-flip alone leaves no sibling lock
                # → check passes → normal flow continues. Without this
                # branch, a duplicate doc proceeds into _flip_queued_to_
                # ongoing (which no-ops on already-ongoing, NOT in the
                # BAIL_STATUSES set) and worker enters run_pipeline for
                # an already-running research → dual-spawn.
                if _rd_status == "ongoing":
                    _siblings = _scan_sibling_locks_for_research(
                        research_id, WORKER_ID
                    )
                    if _siblings:
                        _h = _siblings[0]
                        log(
                            f"Queue: skipped — research {research_id[:24]}… "
                            f"already running on sibling worker {_h['worker_id']} "
                            f"(PID {_h['pid']}); duplicate queue doc, deleting",
                            "INFO",
                        )
                        try:
                            doc.reference.delete()
                        except Exception:
                            pass
                        continue
            except Exception as e:
                log(f"Queue: research-doc existence check failed (allowing through): {e}", "WARN")

            # ── Multi-worker claim (2026-05-21) ─────────────────────────────
            # With workerCount>1, every worker's listener fires for this same
            # queue doc. Workers cooperate via a Firestore transactional
            # claim on the queue doc itself — first to set `assignedWorker`
            # wins, losers exit this loop iteration cleanly. Without the
            # claim, every worker would process the doc end-to-end:
            # duplicate research-doc writes, duplicate queue-doc deletes,
            # and N copies of the SAME pipeline running on N profiles.
            #
            # Gate-on-busy is layered with the claim, BUT only in
            # multi-worker mode. Single-worker (workerCount=1) keeps the
            # pre-PR behavior — listener always processes and enqueues,
            # local job_queue handles serial ordering. Pre-PR, busy meant
            # status="queued" with position; the user saw "queued behind X"
            # in the chat. We preserve that by NOT gating in single-worker.
            #
            # Multi-worker gate logic:
            #   - If MY worker is busy → don't claim. An idle sibling
            #     picks it up. If ALL workers are busy, the doc sits with
            #     no assignedWorker until the idle-rescan loop (PR 2,
            #     follow-up commit) catches it on the next worker idle.
            #   - Else → try claim. On win, fall through to existing
            #     status-decision + side-effect path. On loss, skip.
            _multi_worker_mode = load_worker_count() > 1
            # #903 worker rest (2026-07-06): the owner parked THIS worker from
            # the app → it must not take NEW runs. Applies in BOTH worker-count
            # modes (a resting single worker defers exactly like a busy multi-
            # worker one, so the run still queues with a position and the app
            # can show "Workers paused"). Resumes never pass through this
            # listener, so in-flight runs are untouched. The defer body below
            # is shared with busy-defer on purpose: the sibling-claimed
            # re-check still applies (an AWAKE sibling should claim, and then
            # we must not write status=queued over its ongoing).
            _resting = _worker_is_resting()
            if _resting:
                _REST_DEFER_SEEN["v"] = True
            # Review MAJOR (2026-07-06): while _REST_DEFER_SEEN is set, the
            # single-worker idle-rescan is armed as the wake-side pickup — so
            # the listener MUST claim too (mutual exclusion via the claim's
            # conditional update), else the rescan can race this listener
            # mid-processing and double-run the same research. The flag is
            # level-triggered: the rescan clears it once the worker is awake
            # and the queue has no unclaimed start docs, restoring pristine
            # single-worker behavior (no claim RTT per start event).
            if _resting or _multi_worker_mode or _REST_DEFER_SEEN["v"]:
                # Multi-worker: gate-on-busy + Firestore claim. Single-worker
                # installs skip both (no contender to race; no free Firestore
                # RTT per start event) — UNLESS resting, which defers.
                if (_resting
                        or _QUEUE_STATE.get("running")
                        or job_queue.qsize() > 0
                        or _pending_enq_read() > 0):
                    # Silent defer was the load-bearing observability gap
                    # for the multi-account FIFO investigation — a
                    # sharer-submitted doc that arrives while both
                    # workers are busy has no trace until idle-rescan
                    # picks it up (or stale-skip wipes it). Log so future
                    # repros are traceable from BE log alone. Gated on
                    # multi-worker (this whole block is) so single-worker
                    # installs stay quiet.
                    #
                    # The `_pending_enq_read() > 0` clause closes the
                    # listener-replay race: when this listener fired
                    # ADDED for the previous doc in the same callback
                    # batch, the call_soon_threadsafe enqueue hasn't
                    # landed on the event loop yet (qsize() still 0)
                    # but the counter was bumped synchronously after
                    # claim. Without this clause, both docs claim and
                    # the second job goes stale (the 2026-05-22 St
                    # Bernard symptom).
                    if _resting:
                        _defer_reason = "worker-resting"
                    elif _QUEUE_STATE.get("running"):
                        _defer_reason = "busy-running"
                    elif job_queue.qsize() > 0:
                        _defer_reason = "queue-nonempty"
                    else:
                        _defer_reason = "claim-in-flight"
                    log(
                        f"[start-listener] worker {WORKER_ID}: defer {research_id[:8]}… "
                        f"topic={topic[:40]!r} submittedBy={(data.get('submittedBy') or '?')[:8]} "
                        f"reason={_defer_reason}",
                        "INFO",
                    )
                    # 2026-05-26 (2nd-fire-on-2-worker flicker fix): settle
                    # window + re-check before writing status=queued. If a
                    # sibling worker is idle and claims this doc within the
                    # window, the doc transitions queue → ongoing in <1s.
                    # Without the settle, our busy-defer wrote status=queued
                    # FIRST, the FE's listener rendered the amber queue
                    # banner, THEN the sibling's claim wrote status=ongoing
                    # and the banner transitioned to green/hidden — the
                    # user-visible "shows queue banner (#1) → pipeline
                    # started banner → goes into the run" flicker on the
                    # 2nd fire. Skipping the queued write when a sibling
                    # has already claimed (assignedWorker set, OR queue doc
                    # deleted post-claim) eliminates the flicker. For the
                    # genuine-queue case (all workers busy), the sibling
                    # check fails after the window and we proceed to write
                    # — the 600ms latency is invisible against minutes of
                    # queue wait. Per user spec: "If there are N workers,
                    # only post Nth fire gets queue treatment."
                    try:
                        time.sleep(0.6)
                        _q_snap = doc.reference.get()
                        if not _q_snap.exists:
                            log(
                                f"[start-listener] worker {WORKER_ID}: post-defer re-check "
                                f"{research_id[:8]}… — sibling claimed + deleted, skipping queued write",
                                "DEBUG",
                            )
                            continue
                        _q_data = _q_snap.to_dict() or {}
                        if _q_data.get("assignedWorker"):
                            log(
                                f"[start-listener] worker {WORKER_ID}: post-defer re-check "
                                f"{research_id[:8]}… — sibling claimed (worker={_q_data.get('assignedWorker')}), "
                                f"skipping queued write",
                                "DEBUG",
                            )
                            continue
                    except Exception as _rce:
                        # Re-check failed (transient Firestore error). Fall
                        # through to the queued write — the FE banner is
                        # better than a silent stale state if the doc
                        # genuinely IS queued.
                        log(
                            f"[start-listener] worker {WORKER_ID}: post-defer re-check raised "
                            f"(allowing queued write): {_rce}",
                            "DEBUG",
                        )
                    # Bug A fix (2026-05-22): write authoritative
                    # queuePosition to the research doc so the FE
                    # displays the correct cross-account number. The
                    # FE's optimistic `existingQueuedCount + 1` only
                    # sees the current user's runs (per-user Firestore
                    # rules); deferred submits from other accounts are
                    # invisible to it. Without this write the wrong
                    # number persists indefinitely (BE never updates it
                    # for deferred docs in the original code).
                    #
                    # 2026-05-25 (banner enrichment): also write the
                    # enriched fields the FE banner consumes — total
                    # ahead count split by self vs other accounts,
                    # ETA, and head-of-queue refs. _compute_queue_
                    # enrichment subsumes _compute_global_queue_position
                    # and adds the breakdown. Device-doc current run
                    # phase fields drive the ETA approximation.
                    try:
                        _enrich = _compute_queue_enrichment(col_ref, doc.id, uid)
                        _eta_ms, _eta_at = _read_eta_inputs_and_compute(_enrich["position"])
                        _update_research_doc(uid, research_id, {
                            "status": "queued",
                            "queuePosition": _enrich["position"],
                            "queuedBehindRunId": _enrich["behind_rid"],
                            "queuedBehindTitle": _enrich["behind_title"],
                            "queueTotalAhead": _enrich["total_ahead"],
                            "queueAheadFromSelf": _enrich["ahead_from_self"],
                            "queueAheadFromOthers": _enrich["ahead_from_others"],
                            "queueEtaMs": _eta_ms,
                            "queueEtaComputedAt": _eta_at,
                        })
                    except Exception as _pwerr:
                        log(
                            f"[start-listener] worker {WORKER_ID}: position write failed for "
                            f"{research_id[:8]}… (non-fatal): {_pwerr}",
                            "DEBUG",
                        )
                    if _resting:
                        # #903: keep-alive stamp — the 12h ABANDONED sweep
                        # measures a rest-deferred doc's age from this field
                        # (re-stamped on every defer pass), so parking a
                        # worker for >12h + a BE restart can't silently drop
                        # the queued run. Best-effort (rules allow-listed).
                        try:
                            doc.reference.update({"restDeferredAt": int(time.time() * 1000)})
                        except Exception as _rda_err:
                            log(f"[start-listener] restDeferredAt stamp failed (non-fatal): {_rda_err}", "DEBUG")
                    # 2026-05-28: refresh the device-doc queueOwners array so
                    # the owner's "Shared with" popup shows this run's amber
                    # queue badge immediately. Without this, queueOwners only
                    # refreshed on worker-1 phase_start / claim / cancel, so a
                    # freshly-deferred run had no amber badge until the next
                    # (sparse) phase boundary. Threaded so it never blocks the
                    # start-listener; single-flight via its own lock.
                    try:
                        _threading.Thread(
                            target=_recompute_deferred_queue_positions,
                            daemon=True, name="queueowners-defer",
                        ).start()
                    except Exception as _qo_t_err:
                        log(f"[start-listener] queueOwners recompute launch failed (non-fatal): {_qo_t_err}", "DEBUG")
                    continue
                if _firebase_db is not None:
                    _claim_ref = doc.reference

                    # FIFO pre-query (PR 3, 2026-05-21): before attempting
                    # claim, verify this doc is the OLDEST unclaimed start
                    # action on the device queue. Without this gate the
                    # claim was "first-free-worker-wins" — Firestore
                    # delivers ADDED changes in doc-id order (random for
                    # auto-IDs), NOT createdAt order. With 3 docs A,B,C
                    # arriving fast and 2 workers, W1 could iterate B
                    # first and claim B while older A sat unclaimed until
                    # idle-rescan. Pre-query sorts candidates by
                    # `submittedAt` (Firestore server timestamp) ASC —
                    # immune to FE-clock skew between owner and sharer
                    # browsers (2026-05-22 follow-up). Falls back to
                    # legacy client-ms `timestamp` for older docs;
                    # missing-both legacy docs sort LAST so they don't
                    # FIFO-block well-formed new docs. Doc-id tiebreaker.
                    try:
                        _head_candidates = list(col_ref.limit(20).stream())

                        def _fifo_key(_snap):
                            _hd = _snap.to_dict() or {}
                            _ms = _queue_doc_fifo_ms(_hd)
                            if _ms is not None:
                                return (0, _ms, _snap.id)
                            return (1, 0, _snap.id)

                        _head_candidates.sort(key=_fifo_key)
                        _head_id = None
                        for _hs in _head_candidates:
                            _hd = _hs.to_dict() or {}
                            if _hd.get("processed") or _hd.get("assignedWorker"):
                                continue
                            # FIFO only over start actions. Cancel/resume
                            # have their own dispatch paths upstream.
                            if (_hd.get("action") or "start") != "start":
                                continue
                            _head_id = _hs.id
                            break
                        if _head_id is not None and _head_id != doc.id:
                            # Promoted from DEBUG to INFO (2026-05-22) so
                            # multi-account FIFO ordering is visible in
                            # prod logs without needing to lower the
                            # logger level. Includes topic + submittedBy
                            # for cross-account triage.
                            log(
                                f"[start-listener] worker {WORKER_ID}: FIFO defer {research_id[:8]}… "
                                f"topic={topic[:40]!r} submittedBy={(data.get('submittedBy') or '?')[:8]} "
                                f"(older unclaimed {_head_id[:8]}… is head)",
                                "INFO",
                            )
                            # 2026-05-25 (3rd-run queue regression fix):
                            # mirror the busy-running defer's authoritative
                            # queuePosition write so FIFO-deferred docs
                            # also surface a queue banner on the FE. Prior
                            # to this, the FIFO branch did `continue` with
                            # no research-doc write — the doc retained its
                            # FE-optimistic `status="ongoing"` and the FE
                            # rendered pipeline tiles for a queued run.
                            # The user's 2-worker repro: 2 runs running +
                            # 3rd submitted → 3rd FIFO-deferred → 3rd
                            # showed Pipeline Started instead of "Place in
                            # queue #1". This write closes the gap.
                            #
                            # 2026-05-25 (banner enrichment): also write
                            # enriched fields — see busy-running branch
                            # comment for field-set rationale.
                            try:
                                _enrich = _compute_queue_enrichment(col_ref, doc.id, uid)
                                _eta_ms, _eta_at = _read_eta_inputs_and_compute(_enrich["position"])
                                _update_research_doc(uid, research_id, {
                                    "status": "queued",
                                    "queuePosition": _enrich["position"],
                                    "queuedBehindRunId": _enrich["behind_rid"],
                                    "queuedBehindTitle": _enrich["behind_title"],
                                    "queueTotalAhead": _enrich["total_ahead"],
                                    "queueAheadFromSelf": _enrich["ahead_from_self"],
                                    "queueAheadFromOthers": _enrich["ahead_from_others"],
                                    "queueEtaMs": _eta_ms,
                                    "queueEtaComputedAt": _eta_at,
                                })
                            except Exception as _fifo_pwerr:
                                log(
                                    f"[start-listener] worker {WORKER_ID}: FIFO-defer position write failed for "
                                    f"{research_id[:8]}… (non-fatal): {_fifo_pwerr}",
                                    "DEBUG",
                                )
                            # 2026-05-28: refresh queueOwners so the owner's
                            # popup amber badge appears for this FIFO-deferred
                            # run too (see busy-running branch above). Unlike
                            # that branch, the FIFO path has no 0.6s sibling-
                            # claim settle — intentional: if an idle sibling
                            # claims this doc right after, the next recompute
                            # (claim / phase_start) re-scans and drops it from
                            # queueOwners via full-array overwrite, so the
                            # worst case is a self-correcting sub-second badge.
                            try:
                                _threading.Thread(
                                    target=_recompute_deferred_queue_positions,
                                    daemon=True, name="queueowners-defer",
                                ).start()
                            except Exception as _fifo_qo_err:
                                log(f"[start-listener] queueOwners recompute launch failed (non-fatal): {_fifo_qo_err}", "DEBUG")
                            continue
                    except Exception as _fe:
                        log(
                            f"[start-listener] worker {WORKER_ID}: FIFO pre-query failed (proceeding): {_fe}",
                            "WARN",
                        )

                    # Conditional-update claim (replaces prior TX-based
                    # claim that masked BeginTransaction failures behind
                    # the "no transaction ID" rollback ValueError —
                    # 2026-05-22 root-cause fix). Same atomicity (single-
                    # doc writes are linearized server-side), no TX
                    # lifecycle, no masking, half the RPCs.
                    _claim_outcome = _try_claim_queue_doc(
                        _claim_ref, WORKER_ID,
                        log_prefix="[start-listener]")
                    if _claim_outcome is None:
                        # Unexpected failure after retries — the helper
                        # logged the root cause; skip + let idle-rescan
                        # retry later. Add a topic-bearing marker so the
                        # silent skip is traceable from log alone.
                        log(
                            f"[start-listener] worker {WORKER_ID}: claim error — skipping {research_id[:8]}… "
                            f"topic={topic[:40]!r} submittedBy={(data.get('submittedBy') or '?')[:8]} "
                            f"(idle-rescan will retry)",
                            "WARN",
                        )
                        continue
                    if _claim_outcome is False:
                        log(
                            f"[start-listener] worker {WORKER_ID}: queue doc lost to sibling — skipping {research_id[:8]}… "
                            f"topic={topic[:40]!r} submittedBy={(data.get('submittedBy') or '?')[:8]}",
                            "INFO",
                        )
                        continue
                    log(f"[start-listener] worker {WORKER_ID}: claimed {research_id[:8]}… topic={topic[:40]!r} submittedBy={(data.get('submittedBy') or '?')[:8]}", "INFO")
                    # Synchronously reserve a "pending enqueue" slot
                    # BEFORE call_soon_threadsafe schedules the actual
                    # put. This closes the back-to-back-claim race
                    # exploited by Firestore listener replay (see the
                    # gate clause at research.py:~4106). Decrement
                    # lands either at the worker's running-flag flip
                    # OR via _enqueue_with_position_refresh on
                    # _safe_enqueue failure (rare cancel-mid-flight).
                    _pending_enq_inc()

            # Generate run_id
            run_id = f"{safe_name(topic)}_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
            log(f"Firestore start: uid={uid[:8]}... topic={topic[:40]} run_id={run_id}")
            # Decide initial status: "ongoing" if worker is idle AND the gate
            # won't block, else "queued" with position + behind-target so the
            # chat banner + tile badge can tell the user which run must
            # finish first.
            is_busy = bool(_QUEUE_STATE.get("running")) or job_queue.qsize() > 0
            # 2026-05-12: also predict the queue gate. Even when the worker is
            # idle and queue empty, `_wait_for_prior_fe_completion` can block
            # the dequeue for up to BE_PHASES_TIMEOUT_SEC waiting on a prior
            # run's FE-P5. Without surfacing this, the new run lands as
            # status="ongoing" but with no phase_start:0 events for the entire
            # gate window — the FE renders an "ongoing" chat with no Phase 0
            # tile (the inconsistency the user flagged 2026-05-12). Compute
            # the same predicate the gate uses so the user sees a queued
            # banner during the wait instead of empty silence.
            _gate_will_block = False
            _gate_prid = _QUEUE_STATE.get("last_completed_rid") or ""
            _gate_puid = _QUEUE_STATE.get("last_completed_uid") or ""
            _gate_pdone = int(_QUEUE_STATE.get("last_be_done_at") or 0)
            if (
                not is_busy
                and _gate_prid and _gate_puid and _gate_pdone > 0
                # Skip when this rid IS the gate's prior rid (resume path —
                # the helper at research.py:22457 skips the wait for this
                # case, so we must NOT show a banner either).
                and research_id != _gate_prid
            ):
                _gate_deadline = _gate_pdone + (BE_PHASES_TIMEOUT_SEC * 1000)
                if int(time.time() * 1000) < _gate_deadline:
                    _gate_will_block = True
            if is_busy or _gate_will_block:
                # Bug A fix (2026-05-22): position calc via device-wide
                # FIFO scan instead of per-worker `job_queue.qsize()+1`.
                # In multi-worker installs the local qsize misses
                # sibling-worker busy jobs (and FE's optimistic number
                # misses cross-user submits), so the original code
                # under-reported position for sharer's runs and over-
                # reported for owner's runs when the queue spanned
                # accounts. Helper at research.py:_compute_global_queue_position
                # uses the same FIFO predicate as the pre-claim sort
                # (timestamp ASC, doc-id tiebreaker, action==start,
                # !processed, !assignedWorker-by-other) so positions
                # and head-decisions agree.
                try:
                    position, behind_rid, behind_title = \
                        _compute_global_queue_position(col_ref, doc.id)
                except Exception as _pcerr:
                    log(
                        f"[start-listener] worker {WORKER_ID}: global position calc failed "
                        f"({_pcerr}); falling back to local qsize+1",
                        "DEBUG",
                    )
                    position = job_queue.qsize() + 1
                    behind_rid = ""
                    behind_title = ""
                # Gate-blocked path special-case: when no behind-doc
                # found in the global queue (we're head), fill behind
                # from the prior run whose FE-P5 the gate is waiting
                # on. Best-effort title read.
                if not behind_rid and _gate_will_block:
                    behind_rid = _gate_prid
                    try:
                        _prior_doc = _firebase_db.collection("users").document(_gate_puid) \
                            .collection("researches").document(_gate_prid).get()
                        if _prior_doc.exists:
                            _prior_data = _prior_doc.to_dict() or {}
                            behind_title = (_prior_data.get("title") or _prior_data.get("topic") or "")[:60]
                    except Exception:
                        pass
                # Falling back to local current_job ONLY if global helper
                # returned no behind AND we're not in gate-block — happens
                # when I'm position 1 and worker has a job mid-completion
                # not yet visible as currentRunId on device doc.
                if not behind_rid:
                    current = _QUEUE_STATE.get("current_job")
                    if current:
                        behind_rid = current.get("research_id") or ""
                        behind_title = (current.get("topic") or "")[:60]
                status_payload = {
                    "backendRunId": run_id,
                    "status": "queued",
                    "queuePosition": position,
                    "queuedBehindRunId": behind_rid,
                    "queuedBehindTitle": behind_title,
                }
            else:
                # Clear any stale pendingDecision from a PRIOR run of this same
                # research doc (#710). A run that paused at a gate then died (or
                # resumed straight into a later phase, bypassing the gate's own
                # _clear_pending_decision) could leave a stale "Log in / Retry"
                # mirror on the doc; wiping it at every fresh start guarantees a
                # cold chat-open never paints a decision the run has moved past.
                from google.cloud.firestore import DELETE_FIELD as _DF_START
                # #728: stamp the worker that is about to RUN this pipeline. Each
                # worker runs on its OWN browser profile (_profile_dir(WORKER_ID))
                # = its own logged-in ChatGPT/Gemini/Claude/NotebookLM accounts.
                # On a BE restart, worker-1's rehydration uses this to avoid
                # auto-resuming a run onto the WRONG worker's profile (the
                # "worker-1 funnel"). The researches update rule has no field
                # whitelist (firestore.rules:206 deviceUpdatingFor), so it rides
                # the same write that already sets backendRunId/status.
                status_payload = {"backendRunId": run_id, "status": "ongoing",
                                  "assignedWorker": WORKER_ID,
                                  "pendingDecision": _DF_START}
            # Write run_id + initial status back to the research doc.
            # `_update_research_doc` returns False on failure (logs WARN);
            # we then attempt a set(merge=True) as a fallback for the
            # "doc doesn't exist yet" race (FE hasn't created it).
            if not _update_research_doc(uid, research_id, status_payload):
                _set_research_doc(uid, research_id, status_payload, merge=True)
            # Delete the queue doc (was: mark processed). Queue subcollection
            # accumulated forever before this — every start request a permanent
            # entry. The success path doesn't need to surface run_id back via
            # the queue doc; it's already written to the research doc above.
            try:
                doc.reference.delete()
            except Exception:
                pass
            # Queue the job via _safe_enqueue (Q7) — does a final
            # existence + status check on the asyncio loop right before
            # put_nowait, catching any delete/cancel that landed between
            # this listener's pre-checks above and the actual enqueue.
            # On successful enqueue, also fire _recompute_queue_positions
            # so the freshly-enqueued job's `queuedBehindTitle` is
            # corrected from the FE's submit-time guess (which always
            # uses the currently-running pipeline — correct for
            # position #1 but wrong for position #2+ where "behind"
            # should be the previously-queued run, not the running one).
            # Recompute is reached via _QUEUE_STATE because the function
            # lives inside run_server's closure scope.
            # Default-arg capture avoids the lambda-in-loop closure bug.
            def _enqueue_with_position_refresh(
                t, e, c, r, u, ri, bt, us, ul,
            ):
                if _safe_enqueue(job_queue,
                        {"topic": t, "email": e, "config": c, "run_id": r,
                         "uid": u, "research_id": ri, "brief_text": bt,
                         "user_sources": us, "user_links": ul},
                        source="start-listener"):
                    _recompute = _QUEUE_STATE.get("recompute_fn")
                    if _recompute is not None:
                        try:
                            _recompute()
                        except Exception as _re:
                            log(f"[start-listener] post-enqueue recompute failed: {_re}", "WARN")
                    # Real-time deferred-doc renumber (2026-05-22): a
                    # successful claim implicitly shifted everyone behind
                    # me in the global FIFO up by one. The local recompute
                    # above only sees local-deque jobs; the Firestore-
                    # deferred set is renumbered here. Fire-and-forget
                    # via to_thread so the listener-thread callback
                    # doesn't block on the Firestore scan.
                    _recompute_deferred = _QUEUE_STATE.get("recompute_deferred_fn")
                    if _recompute_deferred is not None:
                        try:
                            asyncio.create_task(asyncio.to_thread(_recompute_deferred))
                        except Exception as _re:
                            log(
                                f"[start-listener] deferred-recompute launch failed: {_re}",
                                "WARN",
                            )
                else:
                    # _safe_enqueue dropped this job (cancel landed
                    # between claim and call_soon_threadsafe). The
                    # listener-side _pending_enq_inc() must be undone
                    # here — the worker's running-flip decrement won't
                    # fire because no put landed on the queue.
                    _pending_enq_dec()
            loop.call_soon_threadsafe(
                lambda t=topic, e=email, c=config, r=run_id, u=uid, ri=research_id, bt=brief_text, us=user_sources, ul=user_links:
                    _enqueue_with_position_refresh(t, e, c, r, u, ri, bt, us, ul)
            )

    _start_listener = col_ref.on_snapshot(on_snapshot)
    log(f"Firestore start listener active on {listener_label}")


def setup_firestore_run(uid, research_id, loop=None, run_id=None):
    """Set per-run Firestore context. Call at pipeline start."""
    global _fb_uid, _fb_research_id, _fb_seq, _fb_listener
    _fb_uid = uid
    _fb_research_id = research_id
    _fb_seq = 0
    # Persist owner so the DELETE endpoint can cascade-delete Firestore
    # subcollections when the user purges a run from disk. Without this, the
    # DELETE endpoint only knows the backend run_id and would leave partial
    # docs/audios orphaned in Firestore.
    if run_id and uid and research_id:
        try:
            queue_dir = Path(__file__).parent / "queues" / run_id
            queue_dir.mkdir(parents=True, exist_ok=True)
            (queue_dir / "owner.json").write_text(
                json.dumps({"uid": uid, "researchId": research_id}),
                encoding="utf-8",
            )
        except Exception as _e:
            log(f"owner.json write failed: {_e}", "WARN")
    # Start command listener if Firestore is available
    if _firebase_db and uid and research_id and _controls:
        _start_command_listener(uid, research_id, loop or asyncio.get_event_loop())
        log(f"Firestore bridge active: users/{uid}/researches/{research_id}")


def teardown_firestore_run():
    """Clean up per-run Firestore state."""
    global _fb_uid, _fb_research_id, _fb_seq, _fb_listener
    if _fb_listener:
        _fb_listener.unsubscribe()
        _fb_listener = None
    _fb_uid = None
    _fb_research_id = None
    _fb_seq = 0


_exit_scheduled = False

# 2026-05-21: handle on the live pipeline Browser instance. The stop /
# discard / hard-reset paths reach this from the Firestore command
# listener thread (sync context) and schedule a graceful `browser.close()`
# via `loop.create_task` so the patchright session tears down
# IMMEDIATELY instead of waiting for the pipeline coroutine to notice
# `_controls.is_stop()` at the next phase boundary (mid-Phase-2 stops
# would otherwise leave Chromium open for the full 30-60min remainder
# of the run, since the deep-research polling loop has no inline
# is_stop check). Set in run_pipeline after each successful
# `browser.start()`, cleared in the pipeline's finally. Pause+resume
# re-creates a Browser instance so the ref is re-assigned each time.
_active_browser_ref = None  # type: Optional["Browser"]


def _safe_enqueue(job_queue, job, source: str,
                  allowed_statuses: "tuple[str, ...]" = ("queued", "ongoing", "paused_backend_restart")) -> bool:
    """Existence-validate + status-whitelist check before put_nowait.

    Returns True if the job entered the queue, False if it was skipped.
    Q7: single funnel for all 3 enqueue paths (Firestore start listener,
    Phoenix rehydrate, disk-restore) so a research deleted between any
    of those decision points and the actual put_nowait can't slip
    through. The disk-restore Q1 inline check was the first patch; this
    helper consolidates the same logic for all paths and adds a
    status-whitelist (queued / ongoing / paused_backend_restart) so a
    cancelled or completed research can't get re-enqueued either.

    #728: `allowed_statuses` lets a caller TIGHTEN the whitelist. The default
    keeps the original 3-set (the resume / start-listener paths legitimately
    re-enqueue a paused_backend_restart run). The BOOT disk-restore passes
    ("queued", "ongoing") — it must NOT silently relaunch a run that worker-1's
    rehydration just marked paused_backend_restart (intentionally awaiting a
    user Resume). Firestore is the shared cross-worker source of truth here, so
    this also closes the multi-worker double-enqueue: worker-2's per-process
    disk-restore can't re-fire a run worker-1 already parked, even though
    worker-2's local `_rehydrated_rids` set never saw it.
    """
    rid = (job or {}).get("research_id") or ""
    uid_v = (job or {}).get("uid") or ""
    if not (rid and uid_v):
        log(f"[safe_enqueue:{source}] skipped — missing research_id/uid", "WARN")
        return False
    # ── .stop sentinel: a terminally-stopped run must NEVER be re-enqueued ──
    # The STOP command handler + HARD_RESET touch queues/<run>/.stop. That
    # signal is LOCAL and permission-independent, so it must be the FIRST gate
    # here — BEFORE the Firestore status read below, which 403s for the
    # synth-device-user (user-tree read rule) and then FAILS OPEN ("trust the
    # FE"). Pre-fix, a reconnect-respawn's disk-restore/rehydrate hit that 403
    # fall-through and re-fired a run the user had already stopped (the
    # German-Shepherd resurrection). The resume HTTP/listener paths already
    # gate on .stop (research.py:~5415); this closes the same hole in the
    # enqueue funnel. Derive the run dir from resume_dir (full path) or run_id.
    _rd = (job or {}).get("resume_dir")
    _stop_path = None
    if _rd:
        _stop_path = Path(_rd) / ".stop"
    else:
        _rid_dir = (job or {}).get("run_id")
        if _rid_dir:
            _stop_path = Path(__file__).parent / "queues" / _rid_dir / ".stop"
    if _stop_path is not None:
        try:
            if _stop_path.exists():
                log(f"[safe_enqueue:{source}] skipped — run {rid[:24]}… has .stop sentinel (terminally stopped)", "INFO")
                return False
        except Exception:
            pass
    if _firebase_db is None:
        log(f"[safe_enqueue:{source}] skipped — Firestore unavailable", "WARN")
        return False
    try:
        snap = _firebase_db.collection("users").document(uid_v) \
            .collection("researches").document(rid).get()
        if not snap.exists:
            log(f"[safe_enqueue:{source}] skipped — research {rid[:24]}… no longer exists in Firestore", "INFO")
            return False
        status = (snap.to_dict() or {}).get("status")
        if status not in allowed_statuses:
            log(f"[safe_enqueue:{source}] skipped — research {rid[:24]}… status={status} (not in {allowed_statuses})", "INFO")
            return False
    except Exception as e:
        # Track D synth-device-user can't read `users/{ownerUid}/
        # researches/{rid}` — the rule's `allow read` requires
        # auth.uid==userId and the synth uid never matches the owner.
        # Treat 403 as "trust the FE", since the queue-listener entry
        # we're acting on was authenticated FE-side (the FE rule for
        # devices/{id}/queue gates create on submittedBy==auth.uid).
        # Any OTHER exception still bails defensively.
        err_str = str(e)
        if (
            "403" in err_str
            or "PERMISSION_DENIED" in err_str
            or "Missing or insufficient permissions" in err_str
        ):
            log(
                f"[safe_enqueue:{source}] existence check denied (user-mode read "
                f"rule blocks synth user) — trusting FE-side queue write",
                "DEBUG",
            )
        else:
            log(f"[safe_enqueue:{source}] skipped — Firestore check failed for {rid[:24]}…: {e}", "WARN")
            return False
    try:
        job_queue.put_nowait(job)
        return True
    except Exception as e:
        log(f"[safe_enqueue:{source}] put_nowait failed: {e}", "WARN")
        return False


def _clear_current_run_id_best_effort(reason: str) -> None:
    """Release this worker's footprint on the device doc. Best-effort,
    swallows errors.

    Two responsibilities:
      1. (ALL workers) array_remove THIS WORKER_ID from
         `devices/{deviceId}.busyWorkerIds`. The FE QueuedBanner stall
         detector reads `busyWorkerIds.length < workerCount` to know
         whether ANY worker is idle (powering the 5-min retry gate at
         position #1). Each worker manages its own membership so
         crash-leftovers self-heal on next boot-clear.
      2. (Worker-1 only) clear the device-doc `currentRunId` /
         `currentRunOwnerUid` / `currentRunTitle` / `currentRunStartedAt`
         /`currentRunPhase` / `currentRunPhaseStartedAt` fields. These
         track worker-1's run only (single-field schema; per-worker
         tracking is intentional scope-limit per #552), so worker N>1
         has no signal here to clear.

    Why a shared helper: ANY exit that skips the in-worker `finally`
    — STOP, hard_reset, watchdog T3, `_schedule_server_exit` from
    agent-decision-stop / firestore-command / http-endpoint /
    token-cancel-current / device-hard-reset — leaves stale state on
    the device doc. Patching the helper once covers all paths.

    Stale `currentRunId` is the data-layer root cause of the
    QueuedBanner-shows-on-fresh-run regression (2026-05-22 repro);
    a leaked busyWorkerIds entry is the analogous 2026-05-28 repro
    where the retry button false-fires immediately after a worker
    "appears" to free up (it didn't — entry just leaked from prior
    process death).
    """
    if not _firebase_db:
        return
    _did = None
    try:
        _did = load_device_id()
    except Exception:
        pass
    if not _did:
        return
    # ── (1) Release this worker's busyWorkerIds slot (all workers) ──
    try:
        from google.cloud.firestore import ArrayRemove as _AR, DELETE_FIELD as _WK_DF
        # 2026-05-28: also drop this worker's per-sharer `workers.<id>` usage
        # entry (the "Shared with" green badge) in lockstep with
        # busyWorkerIds. Runs for ALL workers so a crash / STOP / hard_reset
        # can't leak a phantom badge — every exit funnels through here, and
        # the next boot-clear self-heals the slot, same as busyWorkerIds.
        _firebase_db.collection("devices").document(_did).update({
            "busyWorkerIds": _AR([WORKER_ID]),
            f"workers.{WORKER_ID}": _WK_DF,
        })
    except Exception as _bw_err:
        log(
            f"[device] busyWorkerIds release ({reason}, w{WORKER_ID}) failed (non-fatal): {_bw_err}",
            "DEBUG",
        )
    # ── (2) Worker-1 clears the currentRun* mirror fields ──
    if WORKER_ID != 1:
        return
    try:
        from google.cloud.firestore import DELETE_FIELD as _CR_DF
        # 2026-05-26: also clear the phase fields. Without these, a STOP /
        # hard_reset / Phoenix exit left `currentRunPhase` pointing at the
        # terminal phase of the just-stopped run. The next run's first
        # phase_start emit would overwrite, but in the gap between worker-1
        # picking up the new job and that emit landing, the FE QueuedBanner
        # head-phase line would show the prior run's stale phase. Pair this
        # with the publish-on-pickup patch in `_job_worker` (~line 29773)
        # which writes phase=0 the moment a new job is claimed.
        _firebase_db.collection("devices").document(_did).update({
            "currentRunId": _CR_DF,
            "currentRunOwnerUid": _CR_DF,
            "currentRunTitle": _CR_DF,
            "currentRunStartedAt": _CR_DF,
            "currentRunPhase": _CR_DF,
            "currentRunPhaseStartedAt": _CR_DF,
        })
    except Exception as _crun_clear_err:
        log(
            f"[device] currentRunId clear ({reason}) failed (non-fatal): {_crun_clear_err}",
            "DEBUG",
        )


def _schedule_server_exit(source: str, delay_sec: float = 3.0):
    """Schedule a one-shot daemon thread that calls os._exit(0) after a short
    delay, giving the pipeline time to emit pipeline_stopped + close the
    browser cleanly. Idempotent: if the same run is stopped via BOTH the
    Firestore command listener AND the HTTP endpoint, we only spawn one
    exit thread. Called from whichever stop transport fires first.

    2026-05-21: reap child PIDs (patchright node driver + chromium)
    BEFORE os._exit. Pre-fix, `os._exit(0)` left the patchright node
    driver as an orphan with chromium hanging off it — the user saw
    Stop fail to close the browser after pressing it mid-Phase-2.
    The psutil sweep walks our own pid's children recursively and
    kills them before the parent exits, so the daemon-loop respawn
    starts with a clean process tree.

    2026-05-22: clear device-doc currentRunId fields before exit.
    All exit paths (STOP, hard_reset, watchdog, agent-decision-stop,
    etc.) route through this helper, so patching it once covers them
    all. Without this, the field persists past os._exit pointing at
    the now-stopped run, and the next submission's FE renders a
    spurious QueuedBanner (Bug X).
    """
    global _exit_scheduled
    if _exit_scheduled:
        log(f"[{source}] Exit already scheduled — ignoring duplicate", "INFO")
        return
    _exit_scheduled = True
    # Clear currentRunId before the os._exit lands. Synchronous + best-
    # effort; if Firestore is unreachable the worker-1-boot startup
    # clear (commit 2b) is the fallback.
    _clear_current_run_id_best_effort(f"exit-{source}")
    import threading as _threading
    def _runner():
        import time as _t
        import os as _os
        # Brief grace for the async cleanup path (pipeline finally:
        # browser.close + dispatcher_task.cancel + teardown_firestore_run)
        # to complete on its own. The `_active_browser_ref` close that the
        # stop handler scheduled in parallel typically lands in <1s on a
        # healthy patchright session.
        _t.sleep(min(delay_sec, 2.0))
        # Hard-reap any remaining child processes before os._exit. Without
        # this, the patchright node-driver + chromium subprocesses persist
        # past os._exit and orphan into the user's process list (memory
        # entry `project_queue_bug_investigation.md` documents this exact
        # failure mode from 2026-04-29).
        try:
            import psutil as _ps
            me = _ps.Process(_os.getpid())
            killed_n = 0
            for child in me.children(recursive=True):
                try:
                    child.kill()
                    killed_n += 1
                except (_ps.NoSuchProcess, _ps.AccessDenied):
                    pass
            if killed_n:
                log(f"[{source}] Reaped {killed_n} child process(es) before exit", "INFO")
        except Exception as _ps_err:
            try:
                log(f"[{source}] Child-process sweep failed (non-fatal): {_ps_err}", "WARN")
            except Exception:
                pass
        # Any remaining delay budget after the grace + sweep (typically 0
        # since 2s grace + sub-second sweep already consumed delay_sec=3).
        _t.sleep(max(0, delay_sec - 2.0))
        log(f"Exiting server after Stop ({source})", "WARN")
        _os._exit(0)
    _threading.Thread(target=_runner, daemon=True).start()


def _emit_to_firestore(event):
    """Write event to Firestore pipeline_events subcollection.

    expireAt: a 30-day-future Timestamp paired with the Firestore TTL policy
    on `pipeline_events.expireAt` (configured manually in the console). At
    a typical cadence of 2-3k events per 90-min run, the unbounded subcoll
    would otherwise hit ~1.5 MB / run × N users → linear-storage growth.
    Completed-run replay reads from the parent message doc + agents map,
    not the event log, so 30-day pruning is invisible to UX.

    `seq` uses millisecond timestamps (Date.now()-equivalent) so the FE's
    `where("seq", ">", lastSeq)` filter correctly orders BE-emitted events
    relative to FE-side emits (FE-P5 uses Date.now() + offset). The prior
    per-run 0-based counter caused FE to silently drop post-resume BE
    events because lastSeq in localStorage had advanced past them via
    FE-P5's Date.now()-based emits in an earlier session. `_fb_seq` is
    kept as the monotonic guard so multiple emits in the same millisecond
    still get strictly-increasing seq values.
    """
    global _fb_seq
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return
    new_seq = int(time.time() * 1000)
    if new_seq <= _fb_seq:
        new_seq = _fb_seq + 1
    _fb_seq = new_seq
    from datetime import timedelta, timezone
    doc_data = {
        **event,
        "seq": _fb_seq,
        "expireAt": datetime.now(timezone.utc) + timedelta(days=30),
    }
    try:
        _grpc_write_with_heal(
            lambda: _firebase_db.collection("users").document(_fb_uid)
                .collection("researches").document(_fb_research_id)
                .collection("pipeline_events").add(_be_payload(doc_data)),
            what="emit_event",
        )
    except Exception as e:
        log(f"Firestore emit failed: {e}", "WARN")


def update_link_in_firestore(kind: str, url: str, **fields):
    """Write a single canonical-slot link into `users/{uid}/researches/{rid}.links.{kind}`.

    This is HALF of the Firestore link-storage contract; the other half is
    the `userSources` array (see `append_user_source_in_firestore`).

    `links.{kind}` — first-of-kind canonical CACHE. One URL per kind. Used
    where the FE needs a single canonical URL: phase dropdown buttons
    ("Open NotebookLM", "Watch on YouTube"), the brief Doc URL embedded
    in completion emails, etc. Pipeline-generated runs naturally produce
    one link per kind, so the keyed map is a clean fit. Flow C / B paste
    flows write only the FIRST pasted link of each kind here so those
    canonical-slot consumers keep working.

    `userSources` — append-log of every pasted link, full labels preserved.
    The single source of truth for "all links" when assembling the Doc;
    the FE-P5 composer reads it alongside the keyed `links` map and
    dedupes by URL before rendering uniform sections.

    `kind` is the platform key (matches `emit_validated_link`'s `agent` arg):
      - "brief" / "chatgpt" / "gemini" / "claude"  — research links
      - "notebooklm" / "audio"                      — Phase 3
      - "youtube"                                   — Phase 4

    Idempotent: same key + URL is a no-op merge.
    """
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return
    if not kind or not url:
        return
    payload = {"url": url, **fields}
    try:
        _grpc_write_with_heal(
            lambda: _firebase_db.collection("users").document(_fb_uid)
                .collection("researches").document(_fb_research_id)
                .set(_be_payload({"links": {kind: payload}}), merge=True),
            what=f"link {kind}",
        )
    except Exception as e:
        log(f"Firestore link update failed ({kind}): {e}", "WARN")


def append_user_source_in_firestore(kind: str, url: str, label: str = "", phase: int = 3) -> None:
    """Append a user-pasted source link to `users/{uid}/researches/{rid}.userSources`
    (a Firestore array). Used for Flow C / Flow B inputs where the user
    explicitly hands the BE a list of reference links — bypasses the strict
    `validate_link` allow-list, preserves the user's label verbatim, and
    avoids the key-collision overwrite that the per-kind `links` map has
    when multiple pasted links share the same kind (two Google Docs, three
    pasted ChatGPT chats, etc.).

    Each element: `{kind, url, label, phase, ts}`. The FE-P5 Doc composer
    reads this array and renders one row per element, preserving order +
    user-supplied labels — every pasted link is guaranteed to land in the
    Doc, with consistent formatting.
    """
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return
    if not url:
        return
    try:
        from google.cloud import firestore as _gcfs
        entry = {
            "kind": (kind or "other").lower(),
            "url": url,
            "label": (label or "").strip() or "Source",
            "phase": phase,
            "ts": int(time.time() * 1000),
        }
        _grpc_write_with_heal(
            lambda: _firebase_db.collection("users").document(_fb_uid)
                .collection("researches").document(_fb_research_id)
                .set(_be_payload({"userSources": _gcfs.ArrayUnion([entry])}), merge=True),
            what=f"userSource {entry['kind']}",
        )
    except Exception as e:
        log(f"Firestore userSources append failed ({kind}): {e}", "WARN")


def _update_firestore_research(updates):
    """Update the research document in Firestore (status, phase, links, agents, etc.).

    Convenience wrapper around `_update_research_doc` that pulls uid +
    research_id from the active-pipeline globals (`_fb_uid`, `_fb_research_id`).
    Use this from inside `run_pipeline` / phase handlers where the current
    research is unambiguous. Use `_update_research_doc(uid, rid, ...)`
    directly from cancel-watcher / queue-handler paths where the target
    is some OTHER research than the one currently running."""
    if not _fb_uid or not _fb_research_id:
        return
    _update_research_doc(_fb_uid, _fb_research_id, updates)


# Observability flag (worker-local): True while a pendingDecision mirror is
# believed live, so `_clear_pending_decision` only emits its INFO line when it
# actually retracts something — the central clear fires on every
# resume/skip/stop, so an unconditional "cleared" log would be pure noise.
# NOT load-bearing for correctness (the Firestore field is the source of truth;
# the DELETE_FIELD always runs regardless of this flag).
_pending_decision_active = False
# Which agent (lowercased) the live mirror targets, or None for a non-agent
# decision (login_required / env-check). Lets `_clear_pending_decision(agent=…)`
# retract ONLY the acting agent's card at a skip/retry command chokepoint — a
# launch-failed agent's mirror is NON-blocking, so a later agent's blocking
# decision can overwrite the single pendingDecision field, and a blanket clear
# would delete the newer agent's still-live card (reviewer-confirmed clobber).
_pending_decision_agent = None
# #955 Phase 3: the decision_id that owns the single live durable-mirror slot,
# or None. The async AI copy upgrade re-persists the mirror in place ONLY when
# it still owns it — if a SIBLING agent's card has since taken the slot, the
# late upgrade must NOT clobber it (it suppresses the generic mirror instead).
_pending_decision_did = None


def _persist_pending_decision(payload: dict):
    """Mirror a structured 'pending decision' (login_required, pro_required,
    human_verification_required, agent_link_failed, pipeline_error, …) onto the
    ROOT research doc so a frontend that opens the chat AFTER the pause was
    raised — i.e. while the user was viewing a different chat — can re-surface
    the actionable card from durable state.

    Why this exists: decision alerts are otherwise emitted ONLY as transient
    `pipeline_events`. The FE renders the card by consuming that live stream
    behind a per-browser `seq` cursor; a background notifications listener can
    advance (burn) that cursor past the event before the user ever opens the
    chat, so on cold open there is nothing left to replay and the chat looks
    "stuck at init" with no Retry. Persisting the decision on the run doc makes
    re-surfacing cursor-independent. Paired with `_clear_pending_decision`,
    which retracts it the instant the gate resolves (resume / skip / stop) so a
    stale card can never re-appear on a later open. Best-effort; never blocks
    the run."""
    global _pending_decision_active, _pending_decision_agent, _pending_decision_did
    try:
        _update_firestore_research({"pendingDecision": payload})
        _pending_decision_active = True
        _pending_decision_agent = (payload.get("agent") or "").lower() or None
        # #955 Phase 3: record which decision owns the slot so the async copy
        # upgrade can tell "still mine" from "a sibling took it" before re-persist.
        _pending_decision_did = payload.get("decision_id")
        # E2E-observable lifecycle: confirms the durable mirror was written.
        log(f"[pending-decision] persisted kind={payload.get('kind')} "
            f"phase={payload.get('phase')} agent={payload.get('agent')} "
            f"alert_id={payload.get('alert_id')}", "INFO")
    except Exception as e:
        log(f"[pending-decision] persist failed (non-fatal): {e}", "DEBUG")


def _clear_pending_decision(agent: "str | None" = None):
    """Retract a previously-persisted `pendingDecision` once the gate resolves.
    Idempotent — harmless when none was set. Must be paired with every
    `_persist_pending_decision` call so a resolved decision cannot linger on the
    doc and re-surface on a later cold chat-open.

    `agent` scopes a COMMAND-time retraction (skip_agent / retry_agent) to the
    agent the user acted on. A launch-failed agent's fail_agent mirror is
    NON-blocking (the run proceeds to the next agent), so a LATER agent's
    blocking decision can OVERWRITE the single pendingDecision field; a blanket
    clear on any skip/retry would then delete the NEWER agent's still-live card
    (reviewer-confirmed cross-agent clobber — the loss surfaces on a chat
    close/reopen). When `agent` is given, clear ONLY if the live mirror targets
    that agent (or isn't agent-scoped / is unknown). The universal resolve path
    (central emit_event seam, login gates) passes no agent and clears
    unconditionally, exactly as before."""
    global _pending_decision_active, _pending_decision_agent, _pending_decision_did
    a = (agent or "").lower() or None
    # #955 Phase 2: drop this agent's armed auto-skip deadline BEFORE the mirror
    # keep-guard below. The guard protects the single durable-mirror slot when a
    # DIFFERENT agent owns it — but the registry is per-agent and multi-entry, so
    # disarming the acting agent's deadline is always correct even when the live
    # mirror belongs to a sibling (gating it behind the guard would orphan the
    # entry and auto-skip a recovered agent). Agent-LESS clears (None) leave the
    # registry untouched here — the central resolve seam owns clear-all on the
    # genuine phase-level / whole-run signals, so an incidental agent-less mirror
    # clear (an HV finalize, a login gate) can't nuke a sibling's live deadline.
    if a is not None:
        _disarm_registry(a)
    if (a is not None and _pending_decision_active
            and _pending_decision_agent is not None
            and _pending_decision_agent != a):
        # A different agent's decision is the live mirror — leave it intact so
        # its card can still re-surface on a cold reopen.
        log(f"[pending-decision] keep — {a} skip/retry but live mirror targets "
            f"{_pending_decision_agent}", "DEBUG")
        return
    try:
        from google.cloud.firestore import DELETE_FIELD
        _update_firestore_research({"pendingDecision": DELETE_FIELD})
        if _pending_decision_active:
            log("[pending-decision] cleared (decision resolved)", "INFO")
            _pending_decision_active = False
        _pending_decision_agent = None
        _pending_decision_did = None
    except Exception as e:
        log(f"[pending-decision] clear failed (non-fatal): {e}", "DEBUG")


def _update_research_doc(uid: str, research_id: str, updates: dict) -> bool:
    """Centralized update of `users/{uid}/researches/{rid}`. The single
    seam through which every BE-side research-doc write flows — so the
    Track D PR-D5a-core user-mode adapter can inject the `deviceId` field
    (required by the `deviceUpdatingFor` Firestore rule) in ONE place
    instead of patching 17 scattered call sites.

    In user-mode `_be_payload` injects `deviceId` so the
    `deviceUpdatingFor` rule passes; in legacy mode it's a no-op.

    Returns True on success, False on failure (logged WARN; never raises).
    Sync — async callers wrap with `asyncio.to_thread`."""
    if not _firebase_db or not uid or not research_id:
        return False
    try:
        _grpc_write_with_heal(
            lambda: _firebase_db.collection("users").document(uid)
                .collection("researches").document(research_id)
                .update(_be_payload(updates)),
            what=f"update research {research_id[:8]}…",
        )
        return True
    except Exception as e:
        log(
            f"research doc update failed "
            f"(uid={uid[:8]}.., rid={research_id[:8]}..): {e}",
            "WARN",
        )
        return False


def _set_research_doc(uid: str, research_id: str, data: dict, *, merge: bool = True) -> bool:
    """Centralized `set(..., merge=True)` of `users/{uid}/researches/{rid}`
    — the "doc may not exist yet" sibling of `_update_research_doc`. Used
    when writing `backendRunId` on first arrival (before the FE has
    created the doc) and on error-rescue paths where the doc state is
    uncertain. Same Track D PR-D5a seam as `_update_research_doc`."""
    if not _firebase_db or not uid or not research_id:
        return False
    try:
        _grpc_write_with_heal(
            lambda: _firebase_db.collection("users").document(uid)
                .collection("researches").document(research_id)
                .set(_be_payload(data), merge=merge),
            what=f"set research {research_id[:8]}…",
        )
        return True
    except Exception as e:
        log(
            f"research doc set failed "
            f"(uid={uid[:8]}.., rid={research_id[:8]}..): {e}",
            "WARN",
        )
        return False


def _owner_control_patch(oc: str, *, running: bool) -> dict:
    """Research-doc patch for an OWNER-initiated device-queue stop/cancel.

    The owner long-presses a sharer's worker/queue badge in the "Shared
    with" popup; the FE enqueues a device-queue `action="cancel"` doc
    carrying `ownerControl` = "stop" (a RUNNING run → preserve partial
    work, NO cascade-delete) or "cancel" (a QUEUED run → cascade-delete on
    chat close, mirror the self-cancel queued field set). `running` is
    consulted ONLY on the "cancel" branch — it skips the queued `phase: 0`
    reset for a run that already started; the "stop" branch ignores it
    (so gate-pending callers may pass either value).

    The sharer's FE matches `summary`/`stoppedBy` to render the
    owner-attributed chat notice + freeze the live pipeline tile (the
    ChatContainer `isResetStop` sibling branch). Queue-position markers
    are always cleared so a stale "queued #N" banner doesn't linger.

    Returns {} for an unrecognized `oc` so callers fall back to their
    existing self-cancel write verbatim (zero behavior change for the
    user-cancels-own-run path)."""
    if oc not in ("stop", "cancel"):
        return {}
    from google.cloud.firestore import DELETE_FIELD as _DF
    patch: dict = {
        "status": "stopped",
        "stoppedAt": int(time.time() * 1000),
        "queuePosition": _DF,
        "queuedBehindRunId": _DF,
        "queuedBehindTitle": _DF,
    }
    if oc == "stop":
        # Owner stopped a RUNNING run. Mirror the HARD_RESET active-run
        # flip (research.py:_sweep / hard_reset_active): leave `cancelled`
        # UNSET so the run survives in the listing as a historical
        # "Stopped" entry with partial results.
        patch["summary"] = "Stopped by the device owner"
        patch["stoppedBy"] = "owner_stop"
    else:  # cancel
        # Owner cancelled a QUEUED run — never started, safe to purge.
        # `cancelled=True` drives the FE red dialog + auto-delete-on-close
        # cascade, same as a self-cancel of a queued run.
        patch["summary"] = "Cancelled by the device owner"
        patch["stoppedBy"] = "owner_cancel"
        patch["cancelled"] = True
        if not running:
            patch["phase"] = 0
    return patch


# ════════════════════════════════════════════════════════════════════
# Autonomous P4/P5 trigger
#
# After BE finishes P3 + writes beDone, write a `needsFeTrigger: true`
# marker on the research doc. The FE catch-up hook reads that marker
# on next chat-open and re-fires the YouTube upload + Doc + Email +
# status="completed" chain via FE-side credentials.
# ════════════════════════════════════════════════════════════════════


def _mint_fe_id_token(uid):
    """Always returns None — the BE has no path to mint a Firebase ID
    token for an arbitrary uid (the synth-device-user's refresh-token
    credentials only authorize itself, and Admin custom-token mint
    requires the service account that's no longer on disk). Returning
    None triggers `_fire_fe_p4_trigger`'s `needsFeTrigger` fallback;
    the FE catch-up hook re-fires P4/P5 on next chat-open."""
    del uid  # unused — kept for caller signature compatibility
    log("FE trigger: ID token mint unavailable — fallback to needsFeTrigger marker", "INFO")
    return None


def _fire_fe_p4_trigger(uid, research_id):
    """Write a `needsFeTrigger` marker on the research doc so the FE
    catch-up hook re-fires the autonomous P4 + P5 chain on next
    chat-open. Without an Admin SDK service account, the BE can no
    longer mint user ID tokens or enqueue Cloud Tasks directly — the
    FE-side catch-up is the canonical trigger.

    Returns False (no successful enqueue ever happens from this BE).
    The caller doesn't actually distinguish True/False besides log
    formatting; the FE catch-up always handles it."""
    if not uid or not research_id:
        log(f"FE trigger: skip (uid={bool(uid)} rid={bool(research_id)})", "WARN")
        return False
    try:
        _update_firestore_research({
            "needsFeTrigger": True,
            "needsFeTriggerAt": int(time.time() * 1000),
        })
        log(f"FE trigger: needsFeTrigger marker written rid={research_id[:8]}…")
    except Exception as e:
        log(f"FE trigger: marker write failed: {e}", "WARN")
    return False


def _post_fe_p4p5_trigger(uid, research_id):
    """Option C (#742): drive P4 (YouTube) + P5 (Doc/email) autonomously so a
    run completes even when the chat app is never opened.

    Two cooperating parts:
      1) Write the `needsFeTrigger` marker synchronously (via
         _fire_fe_p4_trigger) — the long-standing FE catch-up backstop AND the
         safe fallback if the autonomous POST below can't run. This uses the
         worker's module-global Firestore context, so it MUST run here in the
         worker thread, never the background thread.
      2) Additionally POST {FE_BASE_URL}/api/uploadYouTube authenticated with
         the synth-device user's OWN fresh ID token; the route authorizes the
         device->research binding (authorizeSynthForResearch) and runs P4 then
         chains P5 server-side on Cloud Run. We hit ONLY uploadYouTube (it owns
         the P5 chain) to avoid a double P5. casRouteP4 dedups this against the
         FE catch-up, so the two triggers coexist safely.

    The POST runs in a detached daemon thread with a long timeout: the encode +
    resumable upload can take minutes and the route processes inline while the
    connection is open, so we must neither block the worker (it has a queue to
    drain) nor disconnect early (a client-disconnect can abort the route
    mid-encode). On any POST failure the marker — already written — ensures the
    FE catch-up still runs on next chat-open. Best-effort; never raises."""
    # (1) marker backstop — synchronous, worker context (module globals valid).
    _fire_fe_p4_trigger(uid, research_id)
    if not uid or not research_id:
        return False
    # (2) autonomous server-to-server trigger.
    id_token = _fresh_user_mode_id_token()
    if not id_token:
        log("FE trigger: no synth id-token (creds revoked?) — needsFeTrigger marker only", "INFO")
        return False

    def _drive():
        try:
            import requests as _requests
            from auth.v2_flow import FE_BASE_URL as _FE_BASE_URL
            _resp = _requests.post(
                f"{_FE_BASE_URL}/api/uploadYouTube",
                headers={"Authorization": f"Bearer {id_token}"},
                json={"research_id": research_id, "ownerUid": uid},
                timeout=3600,  # match the route's Cloud Run maxDuration (long podcast encode + upload)
            )
            if _resp.status_code in (200, 202):
                log(f"FE trigger: BE-driven P4/P5 dispatched ✓ (HTTP {_resp.status_code}) rid={research_id[:8]}…")
            else:
                log(
                    f"FE trigger: BE-driven P4/P5 HTTP {_resp.status_code} "
                    f"({_resp.text[:160]}) — FE catch-up covers via marker",
                    "WARN",
                )
        except Exception as _e:
            log(f"FE trigger: BE-driven P4/P5 dispatch failed ({_e}) — FE catch-up covers via marker", "WARN")

    try:
        import threading as _threading
        _threading.Thread(
            target=_drive,
            name=f"fe-p4p5-{research_id[:8]}",
            daemon=True,
        ).start()
    except Exception as _e:
        log(f"FE trigger: could not spawn BE-driven dispatch thread ({_e}) — marker only", "WARN")
    return True


# #722 Bug A: save_meta() rebuilds the whole agents map + phases array and
# propagates them with `.update({"agents": …, "phases": …})` — a whole-FIELD
# REPLACE, not a recursive merge — which WIPES the per-agent/per-phase
# `status` that _write_agent/phase_terminal_status wrote via merge moments
# earlier. Result: chatgpt/claude/gemini icons never green-ticked on reload
# (only FE-written gdocs/gmail status survived, because save_meta only rebuilds
# the 3 P2 agents). Fix: record each terminal status SYNCHRONOUSLY here (keyed
# by research id so a long-lived worker handling multiple runs never leaks
# status across them) and re-stamp it onto the rebuilt entries inside
# save_meta, so the clobbering whole-field write carries the status itself and
# ordering vs the daemon-thread merge no longer matters.
_agent_status_by_rid: dict = {}
_phase_status_by_rid: dict = {}
# Bound the per-rid status maps so a long-lived worker that processes many
# runs can't grow them without limit. Each entry is tiny (a few platform/phase
# → status strings); 64 recent runs is far more than any worker holds live.
_STATUS_BY_RID_CAP = 64


def _record_terminal_status(store: dict, rid: str, key, status: str) -> None:
    """Synchronously record a terminal status under store[rid][key], evicting
    the oldest rid (FIFO) once the cap is exceeded. Callers guarantee rid is
    truthy (the public _write_* helpers early-return on a missing rid)."""
    bucket = store.get(rid)
    if bucket is None:
        bucket = store[rid] = {}
        while len(store) > _STATUS_BY_RID_CAP:
            store.pop(next(iter(store)), None)
    bucket[key] = status


def _do_agent_terminal_status_write(agent_key: str, status: str):
    """Inner sync write — kept separate so the public _write_*
    helpers can fire-and-forget on a daemon thread, avoiding the
    event-loop blocking that B2 (research.py:1046) called out for
    sync Firestore I/O on the main asyncio loop."""
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return
    # #720: route through _set_research_doc so the write carries _be_payload's
    # deviceId (deviceUpdatingFor's payload clause REQUIRES it — a raw dict
    # 403s even with a fresh token) AND gets the gRPC 403 self-heal.
    ak = (agent_key or "").lower()
    _set_research_doc(_fb_uid, _fb_research_id, {"agents": {ak: {"status": status}}}, merge=True)


def _write_agent_terminal_status(agent_key: str, status: str):
    """Persist a per-agent terminal status to the root research doc so the
    listing-page tile + chat phase icons + in-chat config icons all stay
    consistent across browser reloads. Volatile signals (FE alerts,
    chat-message details) survive only the same-tab session; this is
    the single source of truth post-reload.

    Tile/Icon Consistency (2026-05-01): without this write, an agent that
    was skipped or errored mid-run has no persisted record on the root
    doc — `Research.agents[k]` only had timing + sources. Tile reverted
    to all-green checks for completed runs after reload.

    Fire-and-forget on a daemon thread so the sync Firestore round-trip
    doesn't block the asyncio event loop (heartbeat, command listener,
    narration ticker). Same lesson as B2 (research.py:1046) — any
    multi-second sync I/O on the main loop starves heartbeat and trips
    the FE 15s offline threshold.

    Caller writes one of:
      - "complete"  → on phase_complete phase=2 for agents whose details
                      show status complete/done/done_partial.
      - "skipped"   → on agent_skipped (runtime, NOT config-skip — config
                      skip stays derived from pipelineConfig). Note: a
                      runtime skip persists for the run; the BE has no
                      "un-skip" path, so an agent disabled-during-pause
                      then re-enabled would still read as skipped on the
                      tile. In the current pipeline shape this is bounded
                      because re-enable applies to future phases (P3+),
                      and only P2 has per-agent records — no real surface.
      - "errored"   → on fail_agent terminal (no successful retry by run end).
      - "running"   → transient (NOT terminal) status written on user
                      Retry intake to clear the persisted "errored" badge
                      immediately. Helper name still says "terminal" for
                      historic reasons — kept since renaming would touch
                      every callsite. fail_agent overwrites with "errored"
                      if the retry also fails; phase_complete overwrites
                      with "complete" on success.

    Uses set+merge with dotted path so we don't clobber the rest of the
    agents map (other agents' sources/sourceUrls/etc.).
    """
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return
    if not agent_key or status not in ("complete", "skipped", "errored", "running"):
        return
    # #953 (root fix for the retry-vs-completion race): a TRANSIENT "running"
    # write (fired by the retry_agent command intake purely to clear an
    # 'errored' badge) must NEVER overwrite a terminal "complete". The
    # 2026-07-13 incident: the user's Retry click on a stale card stamped a
    # COMPLETED Gemini 'running', which poisoned _agent_status_by_rid — the
    # shared map two #953 completed-agent guards read — so the eventual Skip
    # clobbered the recorded 101k-char report. A completed agent has no
    # 'errored' badge to clear, so refusing this is exactly correct and heals
    # the poisoning at its source (both the sync record AND the Firestore
    # write below). Terminal↔terminal transitions (errored→complete, etc.)
    # are unaffected.
    if status == "running":
        _cur = (_agent_status_by_rid.get(_fb_research_id, {}) or {}).get((agent_key or "").lower())
        if _cur == "complete":
            log(f"[{agent_key}] Ignoring transient 'running' status write — agent "
                "already recorded 'complete' (stale retry on a resolved card)", "INFO")
            return
    # #722 Bug A: record synchronously (BEFORE the async write) so a
    # concurrent save_meta() rebuild re-stamps this status onto its agents
    # map instead of clobbering it. Carries the actual status (complete/
    # skipped/errored/running), never a blanket "complete".
    _record_terminal_status(_agent_status_by_rid, _fb_research_id, (agent_key or "").lower(), status)
    try:
        _threading.Thread(
            target=_do_agent_terminal_status_write,
            args=(agent_key, status),
            name=f"agent-status-{(agent_key or '').lower()}-{status}",
            daemon=True,
        ).start()
    except Exception as e:
        log(f"Failed to dispatch agent-status thread ({agent_key}={status}): {e}", "WARN")


def _do_phase_terminal_status_write(phase_num: int, status: str):
    """Inner sync write — see _do_agent_terminal_status_write rationale."""
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return
    ref = _firebase_db.collection("users").document(_fb_uid) \
        .collection("researches").document(_fb_research_id)

    def _op():
        # #720: the .get() is itself deviceMemberOf-gated, so a stale token 403s
        # the READ too — wrap the whole read+upsert+update so the heal's force-
        # refresh re-runs both. _be_payload the update (deviceUpdatingFor's
        # payload clause REQUIRES deviceId; a raw dict 403s even fresh).
        snap = ref.get()
        data = (snap.to_dict() or {}) if snap.exists else {}
        phases = list(data.get("phases") or [])
        # Upsert by phase number
        found = False
        for entry in phases:
            if isinstance(entry, dict) and entry.get("phase") == phase_num:
                entry["status"] = status
                found = True
                break
        if not found:
            phases.append({"phase": phase_num, "label": f"Phase {phase_num}",
                           "startedAt": int(time.time() * 1000), "status": status})
        ref.update(_be_payload({"phases": phases}))

    try:
        _grpc_write_with_heal(_op, what=f"phase-status phase={phase_num}")
    except Exception as e:
        log(f"Firestore phase-status write failed (phase={phase_num}, status={status}): {e}", "WARN")


def _write_phase_terminal_status(phase_num: int, status: str):
    """Persist a per-phase status to the root research doc. Mirror of
    _write_agent_terminal_status for phases. Used by tile + chat phase
    icons to color the phase node correctly after reload.

    Config skips (user toggled the phase off in pipelineConfig) are NOT
    written — they stay derived from pipelineConfig.skippedPhases so a
    re-enable mid-run isn't masked by stale "skipped" status.

    Allowlist:
      - "complete" / "skipped" / "errored" — terminal states, written
                                             from phase_complete /
                                             phase_skipped / fail_phase.
      - "running" — transient pre-retry intake (helper name still says
                    "terminal" for historic reasons). Written from the
                    retry_phase command handler to clear the persisted
                    "errored" badge before the retry runs. fail_phase
                    rewrites "errored" if the retry also fails.

    Tile/Icon Consistency (2026-05-01). Fire-and-forget on a daemon
    thread (same B2 rationale as _write_agent_terminal_status). The
    read-modify-write on the `phases` array isn't a Firestore
    transaction — concurrent writes on the same phase could race, but
    same-phase concurrency is rare in practice (events serialize
    through emit_event).
    """
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return
    if status not in ("complete", "skipped", "errored", "running"):
        return
    # #722 Bug A: record synchronously so save_meta()'s whole-array rebuild
    # re-stamps this phase status (an array can't be dotted-merged, so the
    # status MUST be carried in the rebuilt entries).
    _record_terminal_status(_phase_status_by_rid, _fb_research_id, phase_num, status)
    try:
        _threading.Thread(
            target=_do_phase_terminal_status_write,
            args=(phase_num, status),
            name=f"phase-status-{phase_num}-{status}",
            daemon=True,
        ).start()
    except Exception as e:
        log(f"Failed to dispatch phase-status thread (phase={phase_num}, status={status}): {e}", "WARN")


def _read_firestore_research_title(fallback=""):
    """Read the current `title` field from the research doc in Firestore.
    Frontend's /api/title fills this with a smart 4–8 word title right after
    pipeline start. Returns the fallback (typically topic[:60]) if empty."""
    if not _firebase_db or not _fb_uid or not _fb_research_id:
        return fallback
    try:
        snap = _firebase_db.collection("users").document(_fb_uid) \
            .collection("researches").document(_fb_research_id).get()
        if snap.exists:
            data = snap.to_dict() or {}
            title = (data.get("title") or "").strip()
            if title:
                return title
    except Exception as e:
        log(f"Firestore title read failed: {e}", "WARN")
    return fallback


def smart_title(topic: str) -> str:
    """Return the best short title for this run. Prefers the frontend-generated
    smart title in Firestore; falls back to topic[:60] cleaned up."""
    clean_fallback = (topic or "").strip().split("\n", 1)[0][:60].strip()
    return _read_firestore_research_title(fallback=clean_fallback) or clean_fallback


def _write_config_to_disk(cfg_updates):
    """Write config updates to config.json on disk (so reload_config() picks them up).
    Merges with existing config — does not overwrite."""
    if not _tracks_dir:
        return
    config_path = Path(__file__).parent / "queues" / _tracks_dir.name / "config.json"
    try:
        existing = json.loads(config_path.read_text(encoding="utf-8")) if config_path.exists() else {}
        existing.update(cfg_updates)
        config_path.write_text(json.dumps(existing, indent=2), encoding="utf-8")
    except Exception as e:
        log(f"Failed to write config to disk: {e}", "WARN")


def _start_command_listener(uid, research_id, loop):
    """Listen for frontend commands (stop/pause/resume/config/add_context) via Firestore."""
    global _fb_listener
    col_ref = _firebase_db.collection("users").document(uid) \
        .collection("researches").document(research_id) \
        .collection("commands")

    # Startup sweep — delete any `processed:true` docs left by a prior session
    # that crashed before its tail-delete flushed. Without this, the
    # subcollection grows unbounded across runs and the next listener attach
    # replays every doc as ADDED. The 30s staleness gate below covers the
    # in-flight window between sweep completion and listener attach.
    try:
        for d in col_ref.where("processed", "==", True).stream():
            try:
                _grpc_write_with_heal(lambda d=d: d.reference.delete(), what="cmd-sweep delete")
            except Exception:
                pass
    except Exception as _sweep_err:
        log(f"[commands] startup sweep failed: {_sweep_err}", "DEBUG")

    # First-snapshot tracker — gates the stale-command defense below (#704).
    _cmd_first_snapshot = {"v": True}

    def on_snapshot(_col_snapshot, changes, _read_time):
        # Firestore delivers all pre-existing docs as ADDED in the FIRST
        # callback after attach; every later callback is a live delta.
        is_first_snapshot = _cmd_first_snapshot["v"]
        _cmd_first_snapshot["v"] = False
        for change in changes:
            if change.type.name != 'ADDED':
                continue
            doc = change.document
            data = doc.to_dict() or {}
            if data.get("processed"):
                continue
            # Stale-command defense — FIRST-ATTACH REPLAY ONLY. Firestore
            # replays every pre-existing doc as ADDED when the listener first
            # attaches; a prior session's unprocessed stop/pause/etc would
            # otherwise re-execute the moment a fresh serve reattaches (this
            # killed multiple sessions within seconds of startup). 30s is well
            # past a normal command round-trip, so a first-snapshot doc older
            # than that is from a previous session.
            #
            # CRITICAL (#704): this gate must NOT touch LIVE commands (those
            # delivered AFTER attach). The command listener attaches at
            # pipeline start (setup_firestore_run), so every Retry / Resume /
            # Skip the user clicks on a paused alert arrives LIVE. Applying
            # the client-`timestamp` check to those silently skipped legit
            # clicks whenever the browser clock that wrote `timestamp` was
            # skewed vs this machine's clock — leaving the run stuck on pause
            # after the user had already acted. Live commands always execute.
            if is_first_snapshot:
                STALE_COMMAND_AGE_MS = 30_000
                _ts = data.get("timestamp")
                if isinstance(_ts, (int, float)) and _ts > 0:
                    _age_ms = int(time.time() * 1000) - int(_ts)
                    if _age_ms > STALE_COMMAND_AGE_MS:
                        # Mark processed so it stops replaying on future
                        # attaches, but do NOT execute.
                        try:
                            _grpc_write_with_heal(
                                lambda: doc.reference.update({"processed": True, "staleSkipped": True}),
                                what="cmd stale-skip mark")
                        except Exception:
                            pass
                        continue
            action = data.get("action", "")
            if action == "ping":
                # Watchdog confirmation ping. Frontend writes this when it
                # suspects silence; our processing of the command proves
                # the backend is alive. Fast path — no _controls side
                # effects, just mark the doc processed with a pongedAt
                # timestamp the watchdog can read back.
                try:
                    _grpc_write_with_heal(
                        lambda: doc.reference.update({
                            "processed": True,
                            "pongedAt": int(time.time() * 1000),
                        }),
                        what="cmd ping pong")
                except Exception:
                    pass
                continue
            if action == "stop":
                # Mark processed BEFORE scheduling the 3s exit timer so the
                # flag lands even if the Firestore Admin SDK buffers the
                # tail-end mark-processed write (at line ~1455) and
                # os._exit(0) kills the buffer before flush. Without this,
                # an ungraceful exit leaves the stop doc unprocessed and
                # the next serve replays it the moment the listener
                # reattaches — killing the fresh session within seconds.
                try:
                    _grpc_write_with_heal(
                        lambda: doc.reference.update({"processed": True}),
                        what="cmd stop mark")
                except Exception:
                    pass
                loop.call_soon_threadsafe(_controls.request_stop)
                # 2026-05-21: schedule a graceful browser teardown NOW so
                # the patchright session closes inline instead of waiting
                # for the pipeline coroutine to notice `_controls.is_stop()`
                # at the next phase boundary. Mid-Phase-2 stops would
                # otherwise leave the browser open for the full deep-
                # research remainder (30-60min) since the polling loop
                # has no inline is_stop check. browser.close() raises
                # CancelledError into the awaits chained on the context,
                # unblocking the pipeline coroutine so its finally fires
                # and the queue can drain to the next item. Idempotent —
                # the pipeline's finally re-calls close() which the
                # Browser.close() handler treats as a no-op via try/except.
                _b = _active_browser_ref
                if _b is not None:
                    def _close_now():
                        try:
                            asyncio.get_event_loop().create_task(_b.close())
                        except Exception as _ce:
                            log(f"[stop] inline browser.close schedule failed: {_ce}", "WARN")
                    loop.call_soon_threadsafe(_close_now)
                # Bridge: also create file sentinel for old phase-boundary checks
                if _tracks_dir:
                    try: (Path(__file__).parent / "queues" / _tracks_dir.name / ".stop").touch()
                    except Exception: pass
                log("Command received: STOP — server will exit after cleanup")
                _schedule_server_exit("firestore-command")
            elif action == "pause":
                loop.call_soon_threadsafe(_controls.request_pause)
                if _tracks_dir:
                    try: (Path(__file__).parent / "queues" / _tracks_dir.name / ".pause").touch()
                    except Exception: pass
                log("Command received: PAUSE")
            elif action == "resume":
                # Process config payload sent with resume (if any)
                resume_cfg = data.get("config", {})
                if resume_cfg:
                    loop.call_soon_threadsafe(_controls.update_config, resume_cfg)
                    _write_config_to_disk(resume_cfg)
                    log("Command received: RESUME (with config update)")
                else:
                    log("Command received: RESUME")
                loop.call_soon_threadsafe(_controls.request_resume)
                # Clean up file sentinels on resume
                if _tracks_dir:
                    q = Path(__file__).parent / "queues" / _tracks_dir.name
                    for f in [q / ".pause", q / ".stop"]:
                        try: f.unlink(missing_ok=True)
                        except Exception: pass
            elif action == "add_context":
                text = data.get("text", "")
                # Only Phase 1 (brief generation) accepts add_context. Phase 2
                # agents are deep-research tools (ChatGPT Pro, Gemini Deep
                # Research, Claude with tools) that can't ingest mid-stream
                # input — and Phase 3+ artifacts (NotebookLM / YouTube / Doc)
                # don't take input either. Frontend locks the chat input from
                # Phase 2 onward; this listener is the belt-and-suspenders.
                if _runtime.phase >= 2:
                    log(f"Command received: ADD_CONTEXT IGNORED (phase={_runtime.phase} — input disabled from Phase 2 onward)", "WARN")
                elif text:
                    loop.call_soon_threadsafe(_controls.add_context, text)
                    log(f"Command received: ADD_CONTEXT ({len(text)} chars)")
            elif action == "dismiss_alert":
                # No-op on the BE side: the FE clears its alert slice locally
                # and records the alert_id in dismissedAlertIds so future
                # re-emits with the same id are suppressed. We just log so
                # the bus has an audit trail of which alerts the user closed.
                _aid = data.get("alert_id", "?")
                log(f"Command received: DISMISS_ALERT id={_aid}")
            elif action == "discard_run":
                # Watchdog T3 "Discard" button: clean terminate keeping any
                # partial results. Emits pipeline_complete with a distinct
                # status so the FE doesn't conflate it with stopped_by_watchdog.
                _aid = data.get("alert_id", "?")
                log(f"Command received: DISCARD_RUN id={_aid} — terminating with partial results preserved")
                try:
                    emit_event("pipeline_complete",
                               phase=getattr(_runtime, "phase", 0),
                               status="terminated_by_user_discard",
                               reason="user_discard_after_watchdog_t3")
                except Exception:
                    pass
                loop.call_soon_threadsafe(_controls.request_stop)
                # 2026-05-21: schedule graceful browser teardown on discard
                # too — same rationale as the stop branch above. Discard
                # is user-facing (Watchdog T3 alert), so the same Chromium-
                # orphan symptom would surface here without this hook.
                _b = _active_browser_ref
                if _b is not None:
                    def _close_now_discard():
                        try:
                            asyncio.get_event_loop().create_task(_b.close())
                        except Exception as _ce:
                            log(f"[discard] inline browser.close schedule failed: {_ce}", "WARN")
                    loop.call_soon_threadsafe(_close_now_discard)
                if _tracks_dir:
                    try: (Path(__file__).parent / "queues" / _tracks_dir.name / ".stop").touch()
                    except Exception: pass
                _schedule_server_exit("firestore-command-discard")
            elif action == "config":
                cfg = data.get("config", {})
                if cfg:
                    loop.call_soon_threadsafe(_controls.update_config, cfg)
                    _write_config_to_disk(cfg)
                    # Emit config_updated so the FE has explicit ack that
                    # the BE applied this writeCommand. Without this, the
                    # FE relies entirely on Firestore doc snapshots, and
                    # a delayed onSnapshot delivery can leave the chat
                    # icon row out of sync with the tile that just sent
                    # this command. Mirrors the HTTP /api/runs/{id}/config
                    # PATCH path (line ~18347) which already emits.
                    try:
                        emit_event("config_updated", config=cfg)
                    except Exception:
                        pass
                    log("Command received: CONFIG update (written to disk + ack emitted)")
            # ── Human-intervention contract (DGOPS-2026-05-18) ──────────
            # Any action that acknowledges a paused alert MUST call
            # request_resume() in addition to setting its action-specific
            # flag. Without resume, the pipeline stays paused even after
            # the user clicked the action button — symptom from user E2E:
            # "I hit Retry on Hit-a-snag but pipeline stayed paused".
            # The flag tells the waiting coroutine WHAT to do; resume
            # tells it that ANY new state is ready to be consumed.
            # request_resume is idempotent (no-op when not paused), so
            # adding it everywhere is safe even for non-paused actions.
            elif action == "skip_init_verify":
                # User bailed on Phase 0 login verification from the dropdown.
                loop.call_soon_threadsafe(_controls.request_skip_init_verify)
                loop.call_soon_threadsafe(_controls.request_resume)
                log("Command received: SKIP_INIT_VERIFY — Phase 0 will proceed without full verify")
            elif action == "retry_init_verify":
                # User tapped Retry on the login_required banner. Same as
                # resume, but the frontend has already torn down the old
                # Phase 0 tile — backend will re-emit phase_start so a fresh
                # tile renders below the retry banner.
                loop.call_soon_threadsafe(_controls.request_retry_init_verify)
                loop.call_soon_threadsafe(_controls.request_resume)
                log("Command received: RETRY_INIT_VERIFY — re-running Phase 0 with a fresh tile")
            elif action == "skip_agent":
                # Skip a stuck Phase 2 agent without stopping the rest of the
                # phase. The polling loop consumes _controls.skipped_agents on
                # its next tick: extracts partial output from that agent's
                # page and drops it from `pending`. notebooklm/youtube were
                # added to the allowed list when the phase-time verify gate
                # (BE-2) started routing per-platform Skip clicks here for
                # P3/P4 alerts. #899: the pause-wait consumers of
                # skipped_agents are now _work_tab_login_pause's poll loop
                # + the P2 round-robin; the slimmed gate only echoes a
                # prior skip back to its caller.
                _ag = (data.get("agent", "") or "").strip().lower()
                if _ag in ("chatgpt", "gemini", "claude", "notebooklm", "youtube"):
                    loop.call_soon_threadsafe(_controls.request_skip_agent, _ag)
                    loop.call_soon_threadsafe(_controls.request_resume)
                    # #777 parity: retract any durable "Hit a snag" pendingDecision
                    # mirror the instant the user clicks Skip. A launch-failed agent
                    # (fail_agent → skipped_agents but NOT in `pending`) never emits
                    # agent_skipped, so the central clear seam (~11606) never fires and
                    # the fail_agent mirror lingered → the FE AgentAlertPanel fallback
                    # (decisionToCard) re-rendered the snag card even after the agent
                    # was skipped. Symmetric to the retry_agent clear at ~7787/7805;
                    # idempotent DELETE_FIELD; one chokepoint covers every skip_agent
                    # site (P2 fail_agent Skip + P3/P4 verify-gate Skip). Agent-scoped
                    # (pass _ag) so skipping ONE agent's card can't retract a DIFFERENT
                    # agent's still-live mirror on the single pendingDecision field.
                    loop.call_soon_threadsafe(_clear_pending_decision, _ag)
                    # #953 (audit #8): the user resolved this agent's card — drop
                    # its fail_agent error-card stamp so a much-later completion
                    # can't fire a spurious retraction (which would clear an
                    # unrelated, still-live agentless pendingDecision). fail_agent
                    # re-stamps if the agent fails again.
                    loop.call_soon_threadsafe(_AGENT_ERROR_CARD_TS.pop, _ag, None)
                    log(f"Command received: SKIP_AGENT agent={_ag}")
                else:
                    log(f"Command received: SKIP_AGENT rejected — unknown agent '{_ag}'", "WARN")
            elif action == "skip_phase":
                # Abandon the current phase with whatever partial results we
                # have and jump to the next. Triggered by the watchdog banner
                # when the backend has been unresponsive for 45+ min and the
                # user picks "Skip phase".
                _ph = data.get("phase")
                try:
                    _ph = int(_ph) if _ph is not None else None
                except (TypeError, ValueError):
                    _ph = None
                if _ph is not None:
                    loop.call_soon_threadsafe(_controls.request_skip_phase, _ph)
                    # Cascade: skip P3 → also skip P4 (no YouTube without
                    # podcast — P4 depends on the audio file P3 generates).
                    # User design rule clarified 2026-04-30.
                    if _ph == 3:
                        loop.call_soon_threadsafe(_controls.request_skip_phase, 4)
                        log(f"Command received: SKIP_PHASE phase={_ph} → cascading skip to P4 (no YouTube without podcast)")
                    else:
                        log(f"Command received: SKIP_PHASE phase={_ph}")
                    # Also release any pause so the phase coroutine can exit cleanly
                    loop.call_soon_threadsafe(_controls.request_resume)
                else:
                    log("Command received: SKIP_PHASE rejected — no phase number", "WARN")
            elif action == "continue_anyway":
                # User dismissed a pipeline_warning (e.g. brief-short) and
                # told us to proceed without retry. Flag is one-shot — the
                # caller that emitted the warning consumes it on next check.
                loop.call_soon_threadsafe(_controls.set_continue_anyway)
                loop.call_soon_threadsafe(_controls.request_resume)
                log("Command received: CONTINUE_ANYWAY — resuming past warning")
            elif action == "retry_phase":
                # User clicked "Retry Phase N" on a pipeline_warning. The
                # phase coroutine that emitted the warning is polling
                # consume_retry_phase(N) and will restart its body when it
                # sees the flag. Also releases any pause so the wait exits.
                _ph = data.get("phase")
                try:
                    _ph = int(_ph) if _ph is not None else None
                except (TypeError, ValueError):
                    _ph = None
                if _ph is not None:
                    # Clear persisted "errored" status before the retry runs so
                    # the FE tile + chat phase icon flip from red to neutral on
                    # user intake. Without this the badge sticks until the next
                    # phase_complete (or until another fail_phase rewrites it),
                    # which means a successful retry leaves the red badge until
                    # phase end. fail_phase rewrites "errored" if the retry
                    # also fails — the volatile phaseAlerts repaint covers the
                    # FE side. Fire-and-forget; safe to race with phase_complete.
                    _write_phase_terminal_status(_ph, "running")
                    loop.call_soon_threadsafe(_controls.request_retry_phase, _ph)
                    loop.call_soon_threadsafe(_controls.request_resume)
                    log(f"Command received: RETRY_PHASE phase={_ph}")
                else:
                    log("Command received: RETRY_PHASE rejected — no phase number", "WARN")
            elif action == "retry_agent":
                # User clicked "Retry" on a Phase 2 agent card. #955: the unified
                # spec has ONE Retry — it RESTARTS the agent (close tab + re-run
                # setup), the only retry that recovers a broken/couldn't-start/
                # stuck agent. The card sends NO `mode`, so a mode-less retry_agent
                # DEFAULTS to the restart. (An explicit `mode: "soft"` — a
                # follow-up paste into the live tab, preserving partial output —
                # is still honored for any legacy caller, but no UI emits it; the
                # per-agent restart cap of 2/agent/phase is enforced by polling.)
                #
                # 2026-04-25: when the agent failed BEFORE entering the
                # round-robin (setup/paste failure → not in `pending`), a soft
                # retry would be a no-op (no in-flight session to paste into); the
                # restart seeds `pending` for missing agents, so pre-failed agents
                # always take the restart path below.
                _ag = (data.get("agent") or "").strip()
                _mode = (data.get("mode") or "hard").strip().lower()
                _ag_norm = _ag.lower()
                _agent_pre_failed = _ag_norm in (_controls.skipped_agents or set())
                if _ag and (_mode == "hard" or _agent_pre_failed):
                    # Clear persisted "errored" badge so the FE flips from red
                    # to neutral on user intake. fail_agent rewrites "errored"
                    # if the retry also fails. Same race-class as the
                    # retry_phase analog above; phase_complete may overwrite.
                    _write_agent_terminal_status(_ag, "running")
                    loop.call_soon_threadsafe(_controls.request_retry_agent_hard, _ag)
                    loop.call_soon_threadsafe(_controls.request_resume)
                    # Auto-resume the FE across ALL surfaces on Retry. A fail_agent
                    # card FE-auto-pauses the run locally (usePipeline:3063) with no
                    # BE pause, and this intake otherwise emits NO resume (see the
                    # 8692 note) — so a second tab / phone / cold reopen stayed stuck
                    # "Paused MM:SS" (the user's "still paused after retry" report).
                    # The acting tab clears optimistically FE-side; this covers the
                    # rest. Scheduled on the loop thread (emit does Firestore I/O);
                    # phase = the live phase so the resume lands on the right badge.
                    loop.call_soon_threadsafe(
                        lambda a=_ag_norm: emit_event(
                            "pipeline_resumed",
                            phase=(_runtime.phase if isinstance(_runtime.phase, int)
                                   and _runtime.phase >= 0 else 2),
                            agent=a, reason="agent_retry"))
                    # #777: retract any durable "Hit a snag" pendingDecision mirror
                    # the instant the user clicks Retry. The agent-retry path resolves
                    # the decision via request_retry_agent_hard + request_resume +
                    # await_agent_decision()=="retry" — it emits NO pipeline_resumed /
                    # phase_restart event, so the central clear seam (~11387) never
                    # fired and the snag card lingered until the run advanced PAST the
                    # phase (FE staleness guard nulled it on docPhase>pd.phase). This
                    # ONE chokepoint covers EVERY Phase-2 fail_agent→retry site
                    # (re-auth, missing-artifact, empty-response, stuck, extraction).
                    # Idempotent DELETE_FIELD; harmless if no decision was pending.
                    # Agent-scoped (_ag_norm) so retrying ONE agent's card can't
                    # retract a DIFFERENT agent's still-live mirror.
                    loop.call_soon_threadsafe(_clear_pending_decision, _ag_norm)
                    # #953 (audit #8): user resolved the card via Retry — drop the
                    # error-card stamp so a later completion can't spuriously
                    # retract an unrelated live decision (fail_agent re-stamps on
                    # a repeat failure).
                    loop.call_soon_threadsafe(_AGENT_ERROR_CARD_TS.pop, _ag_norm, None)
                    if _agent_pre_failed:
                        # Drop the pre-fail skip marker so the hard-retry path
                        # doesn't see Gemini as still-skipped (atomic — taps/
                        # reasons retire with the marker).
                        try:
                            _controls.consume_skip_marker(_ag_norm)
                        except Exception:
                            pass
                        log(f"Command received: RETRY_AGENT agent={_ag} mode=hard (auto-promoted — agent had pre-pending setup failure)")
                    else:
                        log(f"Command received: RETRY_AGENT agent={_ag} mode=hard")
                elif _ag:
                    # Same rationale as the hard path above — clear persisted
                    # "errored" before soft-retry dispatch so the badge flips.
                    _write_agent_terminal_status(_ag, "running")
                    loop.call_soon_threadsafe(_controls.request_retry_agent, _ag)
                    loop.call_soon_threadsafe(_controls.request_resume)
                    # Auto-resume the FE across ALL surfaces on Retry — see the
                    # hard-branch note above (acting tab clears optimistically;
                    # this covers second tab / phone / cold reopen).
                    loop.call_soon_threadsafe(
                        lambda a=_ag_norm: emit_event(
                            "pipeline_resumed",
                            phase=(_runtime.phase if isinstance(_runtime.phase, int)
                                   and _runtime.phase >= 0 else 2),
                            agent=a, reason="agent_retry"))
                    # #777: see hard-branch note — retract the snag mirror on Retry
                    # (agent-scoped so it can't clobber another agent's live card).
                    loop.call_soon_threadsafe(_clear_pending_decision, _ag_norm)
                    # #953 (audit #8): drop the error-card stamp on user Retry.
                    loop.call_soon_threadsafe(_AGENT_ERROR_CARD_TS.pop, _ag_norm, None)
                    log(f"Command received: RETRY_AGENT agent={_ag} mode=soft")
                else:
                    log("Command received: RETRY_AGENT rejected — no agent", "WARN")
            elif action == "continue_partial_agent":
                # User accepted an agent's short/timed-out output. Phase 2
                # polling finalizes the agent with status done_partial.
                _ag = (data.get("agent") or "").strip()
                if _ag:
                    loop.call_soon_threadsafe(_controls.request_continue_partial, _ag)
                    loop.call_soon_threadsafe(_controls.request_resume)
                    log(f"Command received: CONTINUE_PARTIAL_AGENT agent={_ag}")
                else:
                    log("Command received: CONTINUE_PARTIAL_AGENT rejected — no agent", "WARN")
            elif action == "poke_agent":
                # User clicked "Poke" on a stuck-agent warning. Phase 2 polling
                # sends a gentle "please continue" follow-up to the agent.
                _ag = (data.get("agent") or "").strip()
                if _ag:
                    loop.call_soon_threadsafe(_controls.request_poke_agent, _ag)
                    loop.call_soon_threadsafe(_controls.request_resume)
                    log(f"Command received: POKE_AGENT agent={_ag}")
                else:
                    log("Command received: POKE_AGENT rejected — no agent", "WARN")
            elif action == "wait_longer_agent":
                # User chose to wait another 10 min on a stuck agent. Phase 2
                # polling resets the no-growth timer.
                _ag = (data.get("agent") or "").strip()
                if _ag:
                    loop.call_soon_threadsafe(_controls.request_wait_longer_agent, _ag)
                    loop.call_soon_threadsafe(_controls.request_resume)
                    log(f"Command received: WAIT_LONGER_AGENT agent={_ag}")
                else:
                    log("Command received: WAIT_LONGER_AGENT rejected — no agent", "WARN")
            elif action == "agent_decision":
                # Frontend response to agent_link_failed modal.
                decision = (data.get("decision", "") or "").lower()
                agent = data.get("agent", "")
                if decision not in ("retry", "skip", "stop"):
                    log(f"Command received: AGENT_DECISION agent={agent} INVALID decision={decision}", "WARN")
                else:
                    loop.call_soon_threadsafe(_controls.set_agent_decision, decision)
                    if decision == "stop":
                        # Full stop semantics — match the dedicated STOP action:
                        # mark doc processed BEFORE scheduling exit (same
                        # reasoning as the top-level stop handler above),
                        # flip the asyncio event, write the sentinel, and
                        # schedule the server exit. Previously this path set
                        # only the event, leaving the backend alive.
                        try:
                            _grpc_write_with_heal(
                                lambda: doc.reference.update({"processed": True}),
                                what="cmd agent-decision-stop mark")
                        except Exception:
                            pass
                        loop.call_soon_threadsafe(_controls.request_stop)
                        if _tracks_dir:
                            try: (Path(__file__).parent / "queues" / _tracks_dir.name / ".stop").touch()
                            except Exception: pass
                        _schedule_server_exit("agent-decision-stop")
                    # Release the pause so the phase coroutine can consume the decision
                    loop.call_soon_threadsafe(_controls.request_resume)
                    log(f"Command received: AGENT_DECISION agent={agent} decision={decision}")
            # Delete the doc (was: mark processed). Deletion stops the
            # subcollection from growing across runs and prevents the next
            # listener attach from replaying old commands. The early
            # update({"processed": True}) writes inside stop/agent_decision-stop
            # branches stay — they're pre-exit-schedule guards needed because
            # os._exit may kill the buffered delete. Ping action also keeps
            # update() because pingBackendForResearch reads pongedAt back.
            try:
                _grpc_write_with_heal(lambda: doc.reference.delete(), what="cmd tail delete")
            except Exception:
                pass

    _fb_listener = col_ref.on_snapshot(on_snapshot)


def _start_cli_command_reader(loop):
    """CLI-mode stdin parser. Daemon thread reads stdin lines and dispatches
    to the same _controls.* handlers --serve's Firestore listener uses, so
    CLI users have a working escape from login_required (and other) pauses
    without needing --serve. No-op if stdin isn't a TTY (e.g. piped input,
    Task Scheduler) — the pause menu still prints but no input is consumed."""
    if not sys.stdin.isatty():
        return
    def _reader():
        for line in sys.stdin:
            cmd = line.strip().lower()
            if not cmd:
                continue
            if cmd in ("r", "resume"):
                # At a Phase 0 pro_required pause, a bare resume falls through
                # to the post-pause "no explicit choice → Free-acknowledged"
                # branch (line ~18877) — even if the user just upgraded to Pro
                # in the browser. The web frontend's Retry button on the
                # pro_required banner sets retry_phase(0); CLI 'r' must do the
                # same so Phase 0 actually re-verifies ChatGPT/Gemini/Claude
                # tier instead of silently downgrading to Free.
                #
                # Same logic applies for login_required (re-verify the platform
                # with a fresh tab + emit phase_start for any UI consumers).
                #
                # DGOPS-7710 (F6, 2026-05-18): claude_chat_mode pause needs a
                # DIFFERENT consume path — Phase 2B's `await_agent_decision`
                # (line 4274) polls consume_continue_anyway / skipped_agents,
                # NOT phase-level flags. Plain `request_resume` releases
                # wait_if_paused but await_agent_decision then hangs for the
                # 3h timeout. CLI `r` here means [Continue in chat mode] (the
                # FE button equivalent); set continue_anyway BEFORE resume.
                # Narrow race note: pause_reason is read here in the CLI
                # thread; if the coroutine cleared it (e.g., timeout fired
                # between the read and dispatch), continue_anyway leaks to
                # the next consumer (Phase 1 Pro backstop). Acceptable —
                # consume_continue_anyway is one-shot and the leak window
                # is microseconds.
                ph = getattr(_runtime, "phase", 0)
                pr = getattr(_controls, "pause_reason", "") or ""
                if ph == 0 and pr in ("pro_required", "login_required"):
                    log(f"[CMD] resume → retry phase 0 ({pr})")
                    loop.call_soon_threadsafe(_controls.request_retry_phase, 0)
                elif pr == "claude_chat_mode":
                    log("[CMD] resume → continue Claude in chat mode")
                    loop.call_soon_threadsafe(_controls.set_continue_anyway)
                elif pr == "agent_link_failed":
                    # DGOPS-7710-followup: wait_for_agent_decision polls
                    # pop_agent_decision; without this branch the CLI dispatcher
                    # only called request_resume and pop returned None → caller
                    # defaulted to "skip". `r` here means "retry the agent".
                    log("[CMD] resume → retry agent (link_failed alert)")
                    loop.call_soon_threadsafe(_controls.set_agent_decision, "retry")
                # human_verification_required `r` falls through to plain
                # resume — the poll loop at line ~18430 already detects
                # is_pause()==False and re-checks the browser. No special
                # flag needed; behavior preserved.
                else:
                    log("[CMD] resume")
                loop.call_soon_threadsafe(_controls.request_resume)
            elif cmd in ("s", "skip"):
                # DGOPS-7710 (F6, 2026-05-18): claude_chat_mode pause's `s`
                # means [Skip Claude] (per-agent), NOT skip-phase. The
                # await_agent_decision loop checks `skipped_agents`; plain
                # request_skip_phase sets `skipped_phases` (wrong set) and
                # the coroutine hangs.
                #
                # DGOPS-7710-followup: agent_link_failed and
                # human_verification_required pauses also need per-agent
                # signaling — the former checks pop_agent_decision, the
                # latter checks skipped_agents (with pause_target_agent
                # naming the specific platform).
                ph = getattr(_runtime, "phase", 0)
                pr = getattr(_controls, "pause_reason", "") or ""
                if pr == "claude_chat_mode":
                    log("[CMD] skip → skip Claude agent (chat-mode alert)")
                    loop.call_soon_threadsafe(_controls.request_skip_agent, "claude")
                    loop.call_soon_threadsafe(_controls.request_resume)
                elif pr == "agent_link_failed":
                    log("[CMD] skip → skip agent (link_failed alert)")
                    loop.call_soon_threadsafe(_controls.set_agent_decision, "skip")
                    loop.call_soon_threadsafe(_controls.request_resume)
                elif pr == "human_verification_required":
                    tgt = getattr(_controls, "pause_target_agent", "") or ""
                    log(f"[CMD] skip → skip {tgt or '<unknown>'} agent (verification alert)")
                    if tgt:
                        loop.call_soon_threadsafe(_controls.request_skip_agent, tgt)
                    loop.call_soon_threadsafe(_controls.request_resume)
                elif pr == "login_required" and (getattr(_controls, "pause_target_agent", "") or ""):
                    # #899: the work-tab login pause names its platform via
                    # pause_target_agent and its poll loop watches
                    # skipped_agents — plain request_skip_phase would hit the
                    # wrong set (the loop re-cards until timeout) AND leave a
                    # stale skipped_phases entry that await_phase_decision
                    # later consumes as a silent 'skip'. Targetless
                    # login_required pauses (P0 walk, legacy gate) fall
                    # through to the branches below unchanged.
                    tgt = getattr(_controls, "pause_target_agent", "") or ""
                    log(f"[CMD] skip → skip {tgt} agent (login_required pause)")
                    loop.call_soon_threadsafe(_controls.request_skip_agent, tgt)
                    loop.call_soon_threadsafe(_controls.request_resume)
                elif pr == "cua_unavailable":
                    # #705: cua_unavailable is a fail-closed INFRA gate — the P0
                    # probe loop (research.py:28426) re-probes and ignores
                    # skip_init_verify, so `s` would silently re-card forever.
                    # Don't pretend to skip; tell the user the real recovery.
                    log("[CMD] skip unavailable at cua_unavailable — vision/CUA is required infra. "
                        "Fix the Anthropic key, then r) resume; or Ctrl+C to stop.")
                elif ph == 0:
                    log(f"[CMD] skip phase {ph}")
                    # Phase 0's verify loop watches _controls.skip_init_verify,
                    # not the generic skipped_phases set. Without this branch
                    # the user's "s" logs "skip phase 0" but Phase 0 keeps
                    # looping on the same login_required platform forever.
                    # request_skip_init_verify also releases the pause, so we
                    # don't need a separate request_resume call below.
                    loop.call_soon_threadsafe(_controls.request_skip_init_verify)
                else:
                    log(f"[CMD] skip phase {ph}")
                    loop.call_soon_threadsafe(_controls.request_skip_phase, ph)
                    # request_skip_phase doesn't release the pause; mirror the
                    # Firestore handler at line ~2682 and resume.
                    loop.call_soon_threadsafe(_controls.request_resume)
            elif cmd in ("c", "continue"):
                # "Continue with Free" — mirrors the web frontend's
                # pro_required banner button. Only meaningful at a
                # pro_required pause; gated to avoid leaking the
                # continue_anyway flag into later phases that also
                # consume it (Phase 1 Pro selector backstop @ 14220,
                # etc.). To stop the pipeline, use Ctrl+C.
                pr = getattr(_controls, "pause_reason", "") or ""
                if pr == "pro_required":
                    log("[CMD] continue with Free")
                    loop.call_soon_threadsafe(_controls.set_continue_anyway)
                else:
                    log(f"[CMD] 'c' only valid at pro_required pause (current: '{pr or 'none'}')")
            else:
                log("[CMD] unknown — type r/s (resume/skip); c at pro_required pauses; Ctrl+C to stop")
    _threading.Thread(target=_reader, daemon=True, name="cli-cmd-reader").start()


# ── Pipeline Controls (asyncio.Event based stop/pause/resume) ────────────────

class PipelineControls:
    """Replaces file-sentinel (.stop/.pause) checks with in-memory async events.
    Set from Firestore command listener OR HTTP endpoint fallback."""

    def __init__(self):
        self.stop_event = asyncio.Event()
        self.pause_event = asyncio.Event()
        self.resume_event = asyncio.Event()
        # Fix D (2026-05-27): True while a phase is blocked on a user
        # decision (await_phase_decision). The outer worker-watchdog
        # excludes this time from its active-time ceiling so a legitimate
        # wait-for-the-user is never mislabeled "stuck" and killed. Reset
        # in reset() too — a stale True would freeze the next run's
        # watchdog (active-time would never accrue → never fire).
        self._awaiting_user: bool = False
        self.extra_context: list = []
        self._config_updates: dict = {}
        # B1: per-agent link-fail decision ("retry" | "skip" | "stop")
        self.pending_agent_decision: str | None = None
        # Phase 0: user-triggered mid-loop skip of the CUA verification gate.
        self.skip_init_verify: bool = False
        # Phase 0: user hit Retry on the login_required banner — triggers a
        # fresh phase_start emit so the frontend can render a new tile below.
        self.retry_init_verify: bool = False
        # #893: platforms whose trusted session cookie was FALSIFIED mid-run
        # (a login wall appeared on their work page). The phase-time gate's
        # cookie fast path skips these — the tile line downgrades to
        # "unverified" and the work-tab preflight (#899) owns the real
        # confirmation on the phase's own page; its 'ok' is the only
        # mid-run remover (trust restored by direct observation).
        self.cookie_trust_broken: set[str] = set()
        # #899: platforms whose work-tab login pause hit the 10-min TIMEOUT
        # (nobody acted — distinct from an explicit user Skip, though both
        # land in skipped_agents). P1's caller keys on this to offer the
        # Retry-able "No brief" card instead of hardcoding the manual-brief
        # skip nobody asked for. Cleared when a later pause resolves 'ok'.
        self.login_pause_timeout_agents: set[str] = set()
        # #896: agents whose page is confirmed behind a human-verification
        # wall (key → short reason like "Cloudflare"). Set when the HV
        # cascade exhausts or a setup/paste fail-path probe finds a wall;
        # cleared on clearance. Lets outer fail handlers name the real
        # cause even when their page reference is already closed (the HV
        # kill-tab tier replaces the page object locally).
        self.hv_blocked: dict[str, str] = {}
        # Phase 2: per-agent skip requests. Sent by the watchdog's
        # BackendSilentBanner (when a specific agent is picked mid-stall) and
        # by HumanVerifyBanner's "Skip agent" button. Lower-case agent keys
        # (chatgpt, gemini, claude). The Phase 2 polling loop consumes these
        # on its next tick — drops the agent from `pending`, extracts whatever
        # partial output exists, and emits agent_skipped.
        self.skipped_agents: set[str] = set()
        # Agents dropped by the HV auto-skip (unacted hands-off wall). Marks a
        # skipped_agents entry as an INTERNAL auto-skip (not a user tap) so the
        # round-robin skip consumer reports the honest reason + doesn't re-emit /
        # re-close a tab the finalize already greyed + closed.
        self.hv_auto_skipped: set[str] = set()
        # 2026-07-11 Gemini-P2 incident: skipped_agents is OVERLOADED — genuine
        # user Skip taps (request_skip_agent) share it with INTERNAL markers
        # (2A/2B/2C setup-fail, login-gate timeout). The poll's skip consumer
        # used to stamp EVERY member "skipped_by_user"/user_skip*, so an agent
        # whose brief never sent was reported to the FE as a user decision AND
        # the agent_skipped emit auto-retracted the honest Retry/Skip card 4s
        # after fail_agent raised it (emit_event pending-decision clear seam).
        # user_skip_taps records which skipped_agents entries came from an
        # actual user tap; anything else is internal and must NOT be labeled
        # or emitted as a user skip.
        self.user_skip_taps: set[str] = set()
        # Internal marker → honest reason string (logged when consumed).
        self.auto_skip_reasons: dict[str, str] = {}
        # Watchdog banner's "Skip phase" button queues phase numbers here.
        # Each phase's coroutine checks is_phase_skip_requested(N) at its
        # natural yield points and exits early with phase_skipped when set.
        self.skipped_phases: set[int] = set()
        # Continue-anyway: user dismissed a pipeline_warning (e.g. "brief is
        # short") and asked the pipeline to keep going regardless. Callers
        # that emit the warning check+clear this flag to decide whether to
        # halt or proceed. One-shot — consumed on read.
        self.continue_anyway: bool = False
        # Retry-phase: user clicked "Retry Phase N" on a pipeline_warning
        # (e.g. brief-short, stuck agent). Set holds phase numbers that
        # the phase coroutine should restart. Each phase's short-output
        # branch calls await_retry_or_continue(N) to wait for the choice.
        self.retry_phase_requested: set[int] = set()
        # Retry-agent: user clicked "Retry [Agent]" on a Phase 2 agent
        # warning (timeout or empty-final). Phase 2 polling checks
        # consume_retry_agent(key) and submits a follow-up prompt.
        self.retry_agents: set[str] = set()
        # Hard retry-agent: user chose "Retry (hard)" on a Phase 2 agent
        # warning, or a handler escalated to hard semantics. Instead of
        # pasting a follow-up into the same tab, the polling loop closes
        # the page, re-runs start_agent_no_gemini_wait from scratch, and
        # replaces pending[name]. Use for session-expiry / broken-tab
        # cases where soft retry cannot recover. Capped at 2 per-agent
        # per-phase via pending[name]["hard_retry_count"] — above that,
        # falls through to soft retry.
        self.retry_agents_hard: set[str] = set()
        # Continue-partial: user accepted a Phase 2 agent's short/timed-out
        # output. Phase 2 polling finalizes the agent with status
        # "done_partial" / "timeout_partial".
        self.continue_partial_agents: set[str] = set()
        # Poke-agent: user clicked "Poke [Agent]" on a stuck-agent warning.
        # Phase 2 polling sends a mild "please continue" follow-up without
        # resetting the budget (unlike retry, which is a heavier restart).
        self.poke_agents: set[str] = set()
        # Wait-longer: user clicked "Wait longer" on a stuck-agent warning.
        # Resets the no-growth timer so the stuck detector grants another
        # 10-min window before re-prompting.
        self.wait_longer_agents: set[str] = set()
        # Reason string set by request_pause(reason=...). The CLI-mode pause
        # menu reads this to print a context-aware header (e.g. "login_required —
        # log in via the browser, then…"). Cleared on resume.
        self.pause_reason: str = ""
        # DGOPS-7710-followup (2026-05-18): per-pause target agent. Set by
        # pause sites that need the CLI dispatcher to know WHICH agent the
        # user is acting on (e.g. human_verification_required pauses one
        # platform — `s` means "skip THIS agent", but dispatcher doesn't
        # know which one without this field). Cleared on resume. Set BEFORE
        # request_pause so the dispatcher's pause_reason snapshot reads it
        # atomically with reason.
        self.pause_target_agent: str = ""
        # User clicked "Continue with Free" on a Phase 0 pro_required alert.
        # Suppresses subsequent platforms' Pro alerts in the same run, plus the
        # Phase 1 backstop at the ChatGPT Pro selector site. Per-run only — NOT
        # persisted to Firestore. A later Pro→Free downgrade should re-prompt.
        self.pro_warning_acknowledged: bool = False
        # F3 (DGOPS-7449): tracks (phase, agent) tuples for every pro_required
        # alert emitted this run so _clear_pro_required_alerts knows which
        # alert_ids to overwrite-and-auto-clear when the user acknowledges
        # Free. Without this, the Firestore-side alert document persists in
        # the FE store after ack, and subsequent generic pauses (env-check,
        # next platform login_required) display the stale Continue-with-Free
        # button — user clicks it again, BE consumes continue_anyway again.
        self.pro_alert_emitted: set[tuple[int, str]] = set()
        # Per-platform Free-tier consent for phase-time pro_required cards.
        # "Continue with Free" sets free_tier_consent[platform]=True so
        # subsequent checks for the SAME platform skip the pro read (the
        # user already decided). Distinct from pro_warning_acknowledged
        # (global). #899: the gate's pro loop is gone — the remaining
        # per-platform writer is the P2 post-2C ChatGPT tier backstop's
        # Retry path; the 2C Gemini backstop consents via the GLOBAL flag
        # (its guard checks both, so behavior is unchanged).
        self.free_tier_consent: dict[str, bool] = {}

    def request_stop(self):
        self.stop_event.set()

    def request_pause(self, reason: str = ""):
        if reason:
            self.pause_reason = reason
        self.pause_event.set()

    def request_resume(self):
        self.pause_reason = ""
        self.pause_target_agent = ""
        self.pause_event.clear()
        self.resume_event.set()

    def set_agent_decision(self, decision: str):
        """Called from command listener when user chooses retry/skip/stop
        for an agent_link_failed prompt. Whitelist-guards the value; only
        retry/skip/stop are written. NOTE: does NOT release the pause —
        callers must invoke `request_resume()` separately (the dispatcher
        at research.py:3819-3854 does this explicitly for both `r` and `s`
        branches at agent_link_failed pauses)."""
        if decision in ("retry", "skip", "stop"):
            self.pending_agent_decision = decision

    def pop_agent_decision(self) -> str | None:
        d = self.pending_agent_decision
        self.pending_agent_decision = None
        return d

    # Size cap for accumulated context (prevents runaway growth across pause cycles)
    MAX_EXTRA_CONTEXT_CHARS = 50_000

    def add_context(self, text):
        if not text:
            return
        # Cap individual entry + cumulative size
        text = text[:self.MAX_EXTRA_CONTEXT_CHARS]
        self.extra_context.append(text)
        total = sum(len(t) for t in self.extra_context)
        while total > self.MAX_EXTRA_CONTEXT_CHARS and len(self.extra_context) > 1:
            dropped = self.extra_context.pop(0)
            total -= len(dropped)
            log(f"[extra_context] Dropped oldest entry ({len(dropped)} chars) — cap {self.MAX_EXTRA_CONTEXT_CHARS}", "WARN")

    def pop_extra_context(self):
        if self.extra_context:
            ctx = "\n\n".join(self.extra_context)
            self.extra_context.clear()
            return ctx
        return ""

    def peek_extra_context(self):
        """Non-destructive read of buffered context (for dispatcher to check before dispatch)."""
        if self.extra_context:
            return "\n\n".join(self.extra_context)
        return ""

    def is_stop(self):
        return self.stop_event.is_set()

    def is_pause(self):
        return self.pause_event.is_set()

    def is_stop_or_pause(self):
        return self.stop_event.is_set() or self.pause_event.is_set()

    async def wait_if_paused(self):
        """Block pipeline coroutine until resume or stop is received."""
        if not self.pause_event.is_set():
            return
        if _cli_mode:
            # Discoverable, context-aware menu so CLI users have a working
            # recovery path without --serve. login_required gets a tailored
            # header instructing the user to log in via the open Chrome
            # window before resuming. pro_required gets the extra `c`
            # option to mirror the web frontend's "Continue with Free"
            # button. Ctrl+C is the stop path (no `q` keystroke needed).
            reason = self.pause_reason or ""
            target = self.pause_target_agent or ""
            if reason == "login_required":
                header = "[PAUSE] login_required — log in via the open browser, then:"
                actions = "  r) resume (re-check after login)   s) skip phase"
            elif reason == "pro_required":
                header = "[PAUSE] pro_required — upgrade in the browser, then:"
                actions = "  r) resume (re-check after upgrade)   s) skip phase   c) continue with Free"
            elif reason == "claude_chat_mode":
                header = "[PAUSE] claude_chat_mode — Research unavailable; continue in chat mode?"
                actions = "  r) resume (continue in chat mode)   s) skip Claude agent"
            elif reason == "agent_link_failed":
                header = f"[PAUSE] agent_link_failed — {target or 'agent'} link failed."
                actions = f"  r) resume (retry {target or 'agent'})   s) skip {target or 'agent'}"
            elif reason == "human_verification_required":
                header = f"[PAUSE] human_verification_required — solve in browser for {target or 'agent'}, then:"
                actions = f"  r) resume (re-check verification)   s) skip {target or 'agent'}"
            elif reason == "cua_unavailable":
                header = "[PAUSE] cua_unavailable — fix Anthropic key/cap, then:"
                # #705: NO skip option. The P0 probe loop (research.py:28426)
                # is fail-closed and ignores skip_init_verify — vision/CUA is
                # required infra, not a login the user can wave past. Advertising
                # `s` here only re-cards forever (Stop was the sole real exit).
                actions = "  r) resume (retry CUA)   (Ctrl+C to stop — vision/CUA is required infrastructure)"
            elif reason:
                header = f"[PAUSE] {reason} — waiting."
                actions = "  r) resume   s) skip phase"
            else:
                header = "[PAUSE] pipeline paused — waiting."
                actions = "  r) resume   s) skip phase"
            print(
                f"\n{header}\n"
                f"{actions}\n"
                "> ",
                flush=True,
            )
        else:
            log("Pipeline paused — waiting for resume or stop...")
        self.resume_event.clear()
        # Wait for either resume or stop
        done, _ = await asyncio.wait(
            [asyncio.create_task(self.resume_event.wait()),
             asyncio.create_task(self.stop_event.wait())],
            return_when=asyncio.FIRST_COMPLETED
        )
        if self.stop_event.is_set():
            log("Stop received while paused")
        else:
            self.pause_event.clear()
            log("Resumed from pause")

    def update_config(self, updates):
        self._config_updates.update(updates)

    def pop_config_updates(self):
        u = dict(self._config_updates)
        self._config_updates.clear()
        return u

    def reset(self):
        self.stop_event.clear()
        self.pause_event.clear()
        self.resume_event.clear()
        self._awaiting_user = False  # Fix D: clear stale wait-for-user flag
        self.pause_reason = ""
        self.pause_target_agent = ""
        self.extra_context.clear()
        self._config_updates.clear()
        self.pending_agent_decision = None
        self.skip_init_verify = False
        self.retry_init_verify = False
        self.cookie_trust_broken.clear()
        self.login_pause_timeout_agents.clear()
        self.hv_blocked.clear()
        self.skipped_agents.clear()
        self.hv_auto_skipped.clear()
        # Classification companions of skipped_agents — must reset with it,
        # or a run-N tap/reason bleeds into run N+1 on this worker's shared
        # controls and misclassifies an internal marker there.
        self.user_skip_taps.clear()
        self.auto_skip_reasons.clear()
        self.skipped_phases.clear()
        self.continue_anyway = False
        self.pro_warning_acknowledged = False
        self.pro_alert_emitted.clear()
        self.free_tier_consent.clear()
        self.retry_phase_requested.clear()
        self.retry_agents.clear()
        self.retry_agents_hard.clear()
        self.continue_partial_agents.clear()
        self.poke_agents.clear()
        self.wait_longer_agents.clear()

    def request_skip_init_verify(self):
        """User clicked 'Skip verification' in Phase 0 dropdown — bail the
        CUA loop and proceed to Phase 1. Also releases any pause so the
        login_required wait exits immediately."""
        self.skip_init_verify = True
        self.pause_event.clear()
        self.resume_event.set()

    def request_retry_init_verify(self):
        """User tapped Retry on the login_required banner. Distinct from a
        plain resume: sets a flag so Phase 0 re-emits phase_start before
        running the next verification attempt (frontend uses this to render
        a fresh Phase 0 tile below the retry banner, in chronological order)."""
        self.retry_init_verify = True
        self.pause_event.clear()
        self.resume_event.set()

    def request_skip_agent(self, agent: str):
        """User hit the Skip button on a stuck Phase 2 agent. The polling
        loop checks this set on every tick and drops any listed agent from
        `pending`, keeping the rest of the phase running. Also releases any
        active pause so a poll-loop blocked in wait_if_paused exits and the
        skip_agents handler runs on the next tick."""
        key = (agent or "").strip().lower()
        if key:
            self.skipped_agents.add(key)
            # Mark this entry as a REAL user tap — the poll's skip consumer
            # only reports "skipped by user" for entries recorded here
            # (2026-07-11 incident: internal setup-fail markers were being
            # stamped user_skip*).
            self.user_skip_taps.add(key)
            self.pause_event.clear()
            self.resume_event.set()

    def consume_skip_marker(self, agent: str):
        """Atomically retire a skipped_agents entry WITH its classification
        (user-tap record + auto reason). Every site that discards a marker
        must use this — a discard that leaves the tap behind lets a stale tap
        misclassify a LATER internal marker for the same agent as a user skip
        (adversarial-review chains: 2D-skip → P2 retry → setup-fail relabeled
        "skipped by user"; and cross-run via the worker-loop's shared
        controls when reset() didn't clear the new fields)."""
        key = (agent or "").strip().lower()
        if not key:
            return
        self.skipped_agents.discard(key)
        self.user_skip_taps.discard(key)
        self.auto_skip_reasons.pop(key, None)

    def request_skip_phase(self, phase: int):
        """User picked "Skip phase" from the 45-min backend-silent banner.
        Each phase calls consume_phase_skip(N) at its entry branch — if True,
        the phase emits phase_skipped(reason=user_skip) instead of running,
        and the pipeline advances to the next phase with whatever partial
        results already exist."""
        try:
            self.skipped_phases.add(int(phase))
        except (TypeError, ValueError):
            pass

    def set_continue_anyway(self):
        """User clicked 'Continue anyway' on a pipeline_warning. One-shot —
        consumed by the next consume_continue_anyway() call. Also releases
        any pause so the caller coroutine can check the flag."""
        self.continue_anyway = True
        self.pause_event.clear()
        self.resume_event.set()

    def consume_continue_anyway(self) -> bool:
        """Check + clear the continue-anyway flag. Callers that emitted a
        pipeline_warning with a [continue_anyway] action call this to decide
        whether to proceed or retry/halt."""
        v = self.continue_anyway
        self.continue_anyway = False
        return v


    def request_retry_phase(self, phase: int):
        """User clicked 'Retry Phase N' on a pipeline_warning. Phase coroutine
        checks consume_retry_phase(N) after emitting the warning and re-runs
        the phase body if set. Also releases any pause so the waiting phase
        can consume the decision."""
        try:
            self.retry_phase_requested.add(int(phase))
        except (TypeError, ValueError):
            return
        self.pause_event.clear()
        self.resume_event.set()

    def consume_retry_phase(self, phase: int) -> bool:
        """Check + clear the retry flag for this phase."""
        try:
            p = int(phase)
        except (TypeError, ValueError):
            return False
        if p in self.retry_phase_requested:
            self.retry_phase_requested.discard(p)
            return True
        return False

    async def await_retry_or_continue(self, phase: int, timeout: float = 600.0) -> str:
        """Wait for the user to respond to a pipeline_warning offering
        [Retry Phase N] / [Continue anyway]. Returns one of:
            'retry'            — user clicked Retry
            'continue_anyway'  — user clicked Continue anyway
            'stop'             — pipeline stopped while waiting
            'timeout'          — neither flag set within timeout (caller defaults to continue)
        Polls every 0.5s."""
        loop = asyncio.get_event_loop()
        deadline = loop.time() + timeout
        while loop.time() < deadline:
            if self.stop_event.is_set():
                return "stop"
            if self.consume_retry_phase(phase):
                return "retry"
            if self.consume_continue_anyway():
                return "continue_anyway"
            await asyncio.sleep(0.5)
        return "timeout"

    async def await_phase_decision(self, phase: int, timeout: float = 86400.0) -> str:
        """Wait for the user to resolve a phase-level pipeline_error. Returns:
            'retry' — Retry clicked (consume_retry_phase)
            'skip'  — Skip clicked (consume_phase_skip)
            'stop'  — Stop clicked (stop_event)
            'timeout' — wait expired (24h default — effectively never)

        Used by all phase callers after fail_phase(...) to honor the
        never-die contract (ARCHITECTURE CHANGE 2026-04-18). Polls every
        0.5s; pause_event is also checked so an indefinite HV pause
        doesn't starve the decision.

        Default bumped 1h → 24h (2026-04-25) — a 1h timeout falling
        through to "timeout" → fall-through-to-stop violates the
        never-die contract: the user being AFK shouldn't terminate
        their run. The FE watchdog T3 catches genuinely-dead runs via
        silence detection; this timeout is now effectively a no-op
        backstop. BE keeps heartbeating in the await loop so the
        watchdog stays alive while paused for user decision."""
        loop = asyncio.get_event_loop()
        deadline = loop.time() + timeout
        # Fix D (2026-05-27): mark "blocked on a user decision" so the outer
        # worker-watchdog excludes this wait from its active-time ceiling — a
        # legitimate human wait must never be mislabeled "stuck" and killed.
        # finally guarantees the flag clears on every return path below.
        self._awaiting_user = True
        try:
            while loop.time() < deadline:
                if self.stop_event.is_set():
                    return "stop"
                if self.consume_retry_phase(phase):
                    return "retry"
                if self.consume_phase_skip(phase):
                    return "skip"
                await asyncio.sleep(0.5)
            return "timeout"
        finally:
            self._awaiting_user = False

    def request_retry_agent(self, agent: str):
        """User clicked 'Retry [Agent]' on a Phase 2 agent warning."""
        key = (agent or "").strip().lower()
        if key:
            self.retry_agents.add(key)
            self.pause_event.clear()
            self.resume_event.set()

    def consume_retry_agent(self, agent: str) -> bool:
        key = (agent or "").strip().lower()
        if key in self.retry_agents:
            self.retry_agents.discard(key)
            return True
        return False

    def request_retry_agent_hard(self, agent: str):
        """Hard retry: close the agent's tab and re-run start_agent_no_gemini_wait
        from scratch. Preserves other agents; only this one gets a clean slate.
        Use when the soft follow-up can't recover (e.g., session expired, tab
        crashed, hostile Cloudflare gate)."""
        key = (agent or "").strip().lower()
        if key:
            self.retry_agents_hard.add(key)
            self.pause_event.clear()
            self.resume_event.set()

    def consume_retry_agent_hard(self, agent: str) -> bool:
        key = (agent or "").strip().lower()
        if key in self.retry_agents_hard:
            self.retry_agents_hard.discard(key)
            return True
        return False

    def request_continue_partial(self, agent: str):
        """User clicked 'Continue with partial' on a Phase 2 agent warning."""
        key = (agent or "").strip().lower()
        if key:
            self.continue_partial_agents.add(key)
            self.pause_event.clear()
            self.resume_event.set()

    def consume_continue_partial(self, agent: str) -> bool:
        key = (agent or "").strip().lower()
        if key in self.continue_partial_agents:
            self.continue_partial_agents.discard(key)
            return True
        return False

    def request_poke_agent(self, agent: str):
        """User clicked 'Poke [Agent]' on a stuck-agent warning. Phase 2 polling
        consumes this and submits a gentle "please continue" follow-up."""
        key = (agent or "").strip().lower()
        if key:
            self.poke_agents.add(key)
            self.pause_event.clear()
            self.resume_event.set()

    def consume_poke_agent(self, agent: str) -> bool:
        key = (agent or "").strip().lower()
        if key in self.poke_agents:
            self.poke_agents.discard(key)
            return True
        return False

    def request_wait_longer_agent(self, agent: str):
        """User clicked 'Wait longer' on a stuck-agent warning. Phase 2 polling
        resets the no-growth timer, granting another 10 min before re-prompting."""
        key = (agent or "").strip().lower()
        if key:
            self.wait_longer_agents.add(key)
            self.pause_event.clear()
            self.resume_event.set()

    def consume_wait_longer_agent(self, agent: str) -> bool:
        key = (agent or "").strip().lower()
        if key in self.wait_longer_agents:
            self.wait_longer_agents.discard(key)
            return True
        return False

    async def await_agent_decision(self, agent: str, timeout: float = 300.0) -> str:
        """Wait for user decision on a Phase 2 agent pipeline_warning
        offering [Retry] / [Wait] / [Skip] (and other context-specific
        action sets). Returns:
            'retry'            — retry this agent with a follow-up prompt
            'wait_longer'      — extend the polling budget without nudging
            'continue_partial' — accept current output and finalize (legacy
                                  command, still handled for backward compat)
            'continue_anyway'  — degraded-mode acknowledgement (E2 / DGOPS-7364
                                  Claude chat-mode alert; user opted to send
                                  in chat mode rather than skip).
            'skip'             — drop this agent entirely
            'stop'             — pipeline stopped
            'timeout'          — no decision in window (caller defaults to wait_longer)
        Polls every 0.5s. Skip is detected via existing skipped_agents set (NOT consumed here — the main Phase 2 loop handles the removal)."""
        key = (agent or "").strip().lower()
        loop = asyncio.get_event_loop()
        deadline = loop.time() + timeout
        while loop.time() < deadline:
            if self.stop_event.is_set():
                return "stop"
            if self.consume_retry_agent(key):
                return "retry"
            # 2026-05-14: also drain the HARD-retry set. The FE's
            # fail_agent Retry button sends mode=hard, which the command
            # handler routes to request_retry_agent_hard → retry_agents_hard.
            # Without this check, clicks on the human-intervention Retry
            # button were silently dropped (added to a set nobody read),
            # and this loop eventually timed out — see 2026-05-13 trace
            # where a Claude extraction-fail retry waited 5min then logged
            # decision=stop. For extraction-fail callers, soft vs hard
            # retry semantically converge ("re-run the tier ladder"); the
            # mode bit only matters for in-flight Phase 2 stalls handled
            # elsewhere.
            if self.consume_retry_agent_hard(key):
                return "retry"
            if self.consume_wait_longer_agent(key):
                return "wait_longer"
            if self.consume_continue_partial(key):
                return "continue_partial"
            if self.consume_continue_anyway():
                return "continue_anyway"
            if key in self.skipped_agents:
                return "skip"
            await asyncio.sleep(0.5)
        return "timeout"

    def poll_agent_decision(self, agent: str) -> str:
        """Non-blocking single check — one iteration of await_agent_decision's
        body, no sleep/deadline. Returns the same verdicts
        ('retry'/'wait_longer'/'continue_partial'/'continue_anyway'/'skip'/
        'stop') or 'pending' when no decision is queued yet.

        #953 (audit): the Phase-2 round-robin used to `await await_agent_decision`
        INSIDE a per-agent leg for session-expiry / empty-extraction / missing-
        artifact cards — which froze the ENTIRE loop (no other agent polled, no
        completion detected) for up to 30 min. The loop now PARKS the agent
        (records p['awaiting_decision']) and calls this once per tick, so the
        other agents keep polling while one waits. Consumes the retry/wait/
        continue markers identically so a parked agent resolves the same way —
        just without blocking. The park's own deadline supplies the 'timeout'
        default the blocking form returned."""
        key = (agent or "").strip().lower()
        if self.stop_event.is_set():
            return "stop"
        if self.consume_retry_agent(key):
            return "retry"
        if self.consume_retry_agent_hard(key):
            return "retry"
        if self.consume_wait_longer_agent(key):
            return "wait_longer"
        if self.consume_continue_partial(key):
            return "continue_partial"
        # #953 (audit): do NOT consume the GLOBAL one-shot continue_anyway here.
        # No parked-decision card offers a "Continue anyway" action (all offer
        # Retry/Skip, + Stop for the hard-fail), so it's never a legitimate park
        # resolution — and because parking now allows MULTIPLE simultaneous
        # parks, a stray/leaked global continue_anyway (a lingering pro/chat-mode
        # button, a stale flag) would be stolen by whichever parked agent's leg
        # ran first and wrongly finalize it (e.g. accept-empty). The park's own
        # deadline 'timeout' supplies the accept-empty parity the blocking form
        # relied on. (The blocking await_agent_decision callers still consume it.)
        if key in self.skipped_agents:
            return "skip"
        return "pending"

    def consume_phase_skip(self, phase: int) -> bool:
        """Check + clear the skip flag for this phase. True when a skip was
        queued; consuming it here ensures a subsequent phase doesn't inherit
        the flag."""
        try:
            p = int(phase)
        except (TypeError, ValueError):
            return False
        if p in self.skipped_phases:
            self.skipped_phases.discard(p)
            return True
        return False

    async def interruptible_sleep(self, seconds, check_interval=10, skip_phase=None):
        """Sleep in small increments, checking stop/pause every check_interval seconds.
        Returns 'stop' if stopped, 'pause' if paused, None if sleep completed normally.

        #778 (2026-06-03): `skip_phase` — when set to a phase number, also returns
        'skip' as soon as the user issues SKIP_PHASE(N) (the phase lands in
        self.skipped_phases) during the wait. Default None preserves the prior
        behavior for every existing caller (no 'skip' return). Used by the P3
        no-audio auto-retry loop so a Skip click breaks the 5-min wait instead of
        being ignored until the wait elapses."""
        elapsed = 0
        while elapsed < seconds:
            chunk = min(check_interval, seconds - elapsed)
            await asyncio.sleep(chunk)
            elapsed += chunk
            if self.stop_event.is_set():
                return "stop"
            if self.pause_event.is_set():
                return "pause"
            if skip_phase is not None:
                try:
                    if int(skip_phase) in self.skipped_phases:
                        return "skip"
                except (TypeError, ValueError):
                    pass
        return None


_controls = PipelineControls()  # Singleton — reset per run
# True when invoked as `python research.py "topic"` or --resume (no --serve).
# Toggled in main() before the asyncio.run call. Drives the CLI pause menu
# and the stdin command reader; --serve keeps Firestore as its sole input.
_cli_mode = False


# ── Pipeline Runtime State (shared across coroutines, reset per run) ────────

class PipelineRuntime:
    """Shared mutable state for pause/resume/dispatcher to coordinate.
    Pages are registered here by each phase when they go active; dispatcher
    reads this to decide where mid-run user input should be pasted."""
    def __init__(self):
        self.phase = 0
        self.sub_state = ""
        self.active_pages: dict = {}  # platform → page object
        self.agent_statuses: dict = {}  # platform → 'generating'|'done'|'failed'
        self.agent_chat_urls: dict = {}  # platform → URL (conversation/chat)
        # Public share / canonical export URLs for each P2 agent — populated
        # in extract_and_record_agent (Commit 11) by an inline best-effort
        # extractor. Falls back silently to the conversation URL when public
        # share extraction fails. Phase 5 (Google Doc) prefers this over
        # agent_chat_urls so the doc carries proper shareable links.
        # Shape: {platform: {"url": str, "kind": "public"|"conversation",
        #                    "label": str, "verified": bool}}
        self.agent_share_urls: dict = {}
        self.partial_text_lens: dict = {}
        self.original_inputs: dict = {}  # {'topic': str, 'brief': str, 'pdf_paths': []}
        self.queue_dir = None
        self.browser = None
        self.cua_client = None
        self.dispatcher_task = None
        # Mid-phase restart signal: set when a paused phase resumes with buffered
        # extra_context. Caller coroutines check this and bail out early so the
        # orchestrator can re-run the phase with the combined input.
        self.restart_requested = False
        # 2026-04-26: Claude artifact panel kept-open flag (commit d45807f).
        # Polling sets True after first artifact open; extract_claude_response
        # reads via getattr to decide whether to close-first before clicking the
        # final artifact. Initialized here so reset() always lands at False
        # (otherwise an attribute set externally would leak across runs).
        self.claude_artifact_panel_open = False
        # E2 / DGOPS-7364 — per-agent mode tracking for Phase 2 setup. Written
        # by start_agent_no_gemini_wait after Layer 1 + Layer 2 + pre-send
        # re-evaluation. Read by extract_claude_response and the polling loop
        # so chat-mode runs don't false-fire artifact-rejection logic.
        # Shape: { agent_key: {"requested": "research", "actual": "research"|"chat"|"skipped",
        #                       "user_acknowledged_chat": bool} }
        self.agent_modes: dict = {}
        # 2026-05-03: per-agent live progress snapshot keyed by lowercase
        # platform name. Polling loop writes into this on every emit cycle
        # (research.py:~12091) so the P2 completion emit at
        # extract_and_record_agent (research.py:~10705) can pull the latest
        # rich fields (source_urls / sections / steps / searches /
        # observed_sources) into the `complete` agent_progress payload.
        # Without this, the completion emit only shipped partialTextLen +
        # links, so the FE's persisted `agents[key]` map ended up empty
        # post-reload (sources / steps absent) and the dropdown rendered
        # the bare "ChatGPT is now in Super Research Phase 2" stub.
        # Shape: { agent_key: { source_urls, sections, steps, searches,
        #                       observed_sources, partial_text_len, ... } }
        self.agent_progress_snapshots: dict = {}
        # Per-agent time-series ring buffer feeding the FE in-tile graphs +
        # the GraphAnalysis "All Agents" sparklines after persistence. Each
        # entry: {"t": ms_since_phase_start, "sources", "chars",
        # "sections", "searches", "sectionsDone", "sectionsTotal"}.
        # Capped at 240 raw entries per agent; downsampled to 60 at
        # finalize time before writing to Firestore agents map. The cap
        # guards RAM on long P2 runs without an LRU dependency. Shape:
        # { agent_key: list[dict] }.
        self.agent_progress_history: dict = {}
        # Per-agent extracted findings (real cited-source highlights, not
        # just section headings). Populated by _extract_findings() after
        # the markdown report is written for an agent. Shape:
        # { agent_key: list[{"url": str, "snippet": str, "sourceTitle": str}] }
        self.agent_findings: dict = {}
        # P2 → P3 handoff state. Populated at end of P2 (and as resume-safety
        # fallback at start of P3) by _build_phase2_to_phase3_handoff. P3
        # consumes these instead of doing its own per-agent reconciliation —
        # keeping all share-URL/MD work scoped to P2.
        self.p2_links_for_p3: dict = {}
        self.p2_md_files_for_p3: list = []
        # Per-agent state keyed by lowercase platform name. Mirrored into
        # checkpoint.json so a Phoenix restart can rebuild "where each
        # agent was" before silence escalation kicked in. Shape:
        #   {agent: {status, url, share_url, partial_text_len, last_event_ms}}
        # Updated by extract_and_record_agent + register_page paths;
        # snapshotted into checkpoint.json on phase boundaries.
        self.agent_states: dict = {}
        # ID of the last event written to events.jsonl + Firestore. Lets a
        # Phoenix-resumed run skip events the FE already saw, instead of
        # replaying them and producing dup phase transitions in chat.
        self.last_event_id: str = ""
        # True when run_pipeline is invoked with resume_dir set (auto-retry
        # from checkpoint OR user-resume from paused). Currently used only
        # for non-browser-crash recovery decisions; browser crashes are
        # always-auto regardless of this flag (see last_failure_kind).
        self.is_retry_attempt: bool = False
        # Tag for the most recent failure that bubbled out of a phase.
        # Set at fail-detection sites (browser-crash, agent timeout, etc.)
        # and read by run_pipeline.finally to decide whether the auto-retry
        # path should bypass its `not resume_dir` gate. Browser crashes
        # always auto-retry — no human in the loop, no per-attempt cap;
        # the worker 5h outer ceiling is the safety net.
        self.last_failure_kind: str = ""
        # #921: user-controllable auto-skip (Settings → Pipeline → "Auto-skip
        # stuck agents"). True (default) = a stuck agent whose [Retry][Skip]
        # card sits unacted, or one past the hard cap, is auto-skipped so the
        # run finishes unattended. False = the card stays up and WAITS for the
        # user (manual Skip only) — the Layer-1 stuck card + FE watchdog still
        # fire; only the Layer-3 auto-skip is suppressed. Primed per-run from
        # pipeline_config["autoSkipStuck"] in reload_config().
        self.auto_skip_stuck: bool = True

    def reset(self):
        self.__init__()
        # Clear module-level page-keyed stream observers — entries are keyed by
        # id(page) and would alias new pages once Python recycles ids.
        _agent_streams.clear()
        # Drop tier escalation history so a fresh run doesn't inherit the
        # previous run's retry budget burn.
        reset_tier_escalations()

    def register_page(self, platform, page, url=None):
        self.active_pages[platform] = page
        if url:
            self.agent_chat_urls[platform] = url
        elif page is not None:
            try:
                self.agent_chat_urls[platform] = page.url
            except Exception:
                pass
        self.agent_statuses[platform] = "generating"

    def unregister_page(self, platform, final_status="done"):
        self.agent_statuses[platform] = final_status
        # Keep URL in agent_chat_urls for checkpoint/link display
        self.active_pages.pop(platform, None)

    def snapshot(self):
        """Snapshot current state for checkpoint.json."""
        try:
            tier_history = {k: e.to_dict() for k, e in _tier_escalations.items()}
        except Exception:
            tier_history = {}
        return {
            "phase": self.phase,
            "sub_state": self.sub_state,
            "agent_chat_urls": dict(self.agent_chat_urls),
            "agent_statuses": dict(self.agent_statuses),
            "partial_text_lens": dict(self.partial_text_lens),
            "original_inputs": dict(self.original_inputs),
            # Enriched fields (2026-04-28, Commit 1 of error-redesign):
            "agent_states": dict(self.agent_states),
            "last_event_id": self.last_event_id,
            "tier_escalation_history": tier_history,
        }


_runtime = PipelineRuntime()  # Singleton — reset per run


# ── Tier Framework ──────────────────────────────────────────────────────────
# Unified retry/escalation tracking across BE operations. Replaces ad-hoc
# tier_transition emits. Tier ladder:
#   T0  in-place retry up to 3× (≤30s gap, ≤90s total)
#   T1  tab-restart (close → reopen → retry, up to 2×)
#   T2  full-browser restart (browser.stop() → browser.start() → retry once)
#   T3  BE Phoenix exit via daemon-loop (saves to pending_queue.json, exits 0)
#
# Each (op, agent) pair gets a TierEscalation record with a 30-min sliding
# window. Outside the window, attempt counts reset — a fresh failure 35 min
# after the last one starts at T0a1, not at whatever tier the prior incident
# escalated to. The history list persists into checkpoint.json so a Phoenix
# restart picks up where the prior run left off.

_TIER_WINDOW_SEC = 30 * 60  # 30-min per-errorId budget window


class TierEscalation:
    """Per-op-and-agent tier tracking. Records each retry/escalation with
    timestamp + reason; auto-resets attempt counters after `_TIER_WINDOW_SEC`.

    Serializable for checkpoint resume — see to_dict / from_dict.
    """
    __slots__ = ("op", "agent", "attempts", "window_start", "history")

    def __init__(self, op: str, agent: str = ""):
        self.op = op
        self.agent = (agent or "").lower()
        self.attempts = {"T0": 0, "T1": 0, "T2": 0, "T3": 0}
        self.window_start = time.time()
        self.history: list = []  # [{tier, ts_ms, reason, attempt}]

    def _maybe_reset_window(self):
        if time.time() - self.window_start > _TIER_WINDOW_SEC:
            self.attempts = {"T0": 0, "T1": 0, "T2": 0, "T3": 0}
            self.window_start = time.time()

    def record(self, tier: str, reason: str = "") -> int:
        """Increment counter for `tier` and append history. Returns the new
        attempt number (1-based) for use in narration / event payloads."""
        self._maybe_reset_window()
        n = self.attempts.get(tier, 0) + 1
        self.attempts[tier] = n
        self.history.append({
            "tier": tier, "ts_ms": int(time.time() * 1000),
            "reason": (reason or "")[:200], "attempt": n,
        })
        # Bound history per (op, agent) so a runaway loop can't bloat
        # checkpoint.json. 50 entries ≈ 2-3 incidents worth of tier moves.
        if len(self.history) > 50:
            self.history = self.history[-50:]
        return n

    def to_dict(self) -> dict:
        return {"op": self.op, "agent": self.agent,
                "attempts": dict(self.attempts),
                "window_start": self.window_start,
                "history": list(self.history)}

    @classmethod
    def from_dict(cls, d: dict) -> "TierEscalation":
        e = cls(d.get("op", ""), d.get("agent", ""))
        e.attempts = dict(d.get("attempts", e.attempts))
        e.window_start = float(d.get("window_start", time.time()))
        e.history = list(d.get("history", []))
        return e


_tier_escalations: "dict[str, TierEscalation]" = {}


def _tier_key(op: str, agent: str = "") -> str:
    return f"{op}:{(agent or '').lower()}"


def get_tier_escalation(op: str, agent: str = "") -> TierEscalation:
    key = _tier_key(op, agent)
    if key not in _tier_escalations:
        _tier_escalations[key] = TierEscalation(op, agent)
    return _tier_escalations[key]


def reset_tier_escalations():
    """Drop all tracked escalations. Called on `_runtime.reset()` so a fresh
    pipeline run starts with empty counters."""
    _tier_escalations.clear()


def emit_tier_transition(*, phase: int, agent: str, op: str,
                         from_tier: str, to_tier: str, reason: str = ""):
    """Centralized tier_transition emit. Records the move into the per-(op,
    agent) TierEscalation registry AND fires the Firestore event for FE
    narration / Track-A telemetry. Failures here are non-fatal — never
    raises into hot paths.
    """
    try:
        esc = get_tier_escalation(op, agent)
        attempt_n = esc.record(to_tier, reason=reason)
    except Exception:
        attempt_n = 0
    try:
        emit_event("tier_transition", phase=phase,
                   agent=(agent or "").lower() or None,
                   op=op, from_tier=from_tier, to_tier=to_tier,
                   reason=reason, attempt=attempt_n)
    except Exception:
        pass


def save_pause_checkpoint(queue_dir, extra=None):
    """Write a full pause checkpoint combining runtime snapshot + extra fields."""
    if not queue_dir:
        return
    cp = _runtime.snapshot()
    cp["timestamp"] = datetime.now().isoformat()
    cp["paused"] = True
    if extra:
        cp.update(extra)
    try:
        (Path(queue_dir) / "checkpoint_pause.json").write_text(
            json.dumps(cp, indent=2), encoding="utf-8")
        log(f"[pause] Checkpoint written — phase={cp['phase']} sub_state={cp['sub_state']} "
            f"agents={list(cp['agent_statuses'].keys())}")
    except Exception as e:
        log(f"[pause] Checkpoint write failed: {e}", "WARN")


def load_pause_checkpoint(queue_dir):
    """Load pause checkpoint if present. Returns dict or None."""
    if not queue_dir:
        return None
    cp_file = Path(queue_dir) / "checkpoint_pause.json"
    if not cp_file.exists():
        return None
    try:
        return json.loads(cp_file.read_text(encoding="utf-8"))
    except Exception:
        return None


def clear_pause_checkpoint(queue_dir):
    if not queue_dir:
        return
    f = Path(queue_dir) / "checkpoint_pause.json"
    if f.exists():
        try: f.unlink()
        except Exception: pass


# ── Email validation ────────────────────────────────────────────────────────

_EMAIL_RE = re.compile(r"^[\w.+-]+@[\w-]+(\.[\w-]+)+$")

def validate_email(email):
    """Return (ok: bool, reason: str). Empty string not allowed."""
    if not email or not isinstance(email, str):
        return False, "empty or non-string email"
    email = email.strip()
    if len(email) > 320:
        return False, "email too long"
    if not _EMAIL_RE.match(email):
        return False, f"email format invalid: {email[:60]}"
    return True, ""


class _SkipRehydration(Exception):
    """Sentinel raised by worker N≥2 to short-circuit the Firestore queue
    rehydration in run_server (research.py:~26882). Multi-worker: only
    worker 1 rehydrates; others rely on the listener claim + idle-rescan
    paths. Catch is non-warning so the log doesn't read as an error."""


class SessionExpiredError(Exception):
    """Raised when a platform's chat URL redirects to login after resume."""
    pass


# ── Platform login markers + root URLs (used by verify_login + setup) ────
#
# Each entry maps a platform key (matching the ones emitted to the frontend)
# to the minimum set of DOM signals that confirm a logged-in session. The
# first marker is checked via Playwright's fast `locator.count()` — a non-zero
# count means logged in. If all markers miss, we fall back to the URL/form
# check from `check_auth()`.
#
# Keep selectors LOOSE — they should survive minor UI tweaks. We care about
# "is this user authenticated" not "is a specific button present".

LOGIN_PLATFORMS = {
    # Markers must be AUTH-SPECIFIC: profile menus, account chips, chat history
    # lists, compose buttons. Never use generic input elements (textarea,
    # rich-textarea) — those appear on logged-out landing pages too and cause
    # false positives. We list MULTIPLE markers per platform to be resilient
    # to UI drift; verify_login() matches if ANY selector is present.
    "chatgpt":    {"root": "https://chatgpt.com/", "markers": [
        'button[data-testid="profile-button"]',
        'button[aria-label="Open Profile Menu"]',
        'nav[aria-label="Chat history"]',
        'a[href="/gpts"]',
        'button[data-testid="create-new-chat-button"]',
        'aside[class*="sidebar"] a[href*="/c/"]',  # existing chat links in sidebar
    ]},
    "gemini":     {"root": "https://gemini.google.com/app", "markers": [
        'a[aria-label*="Google Account"]',
        '.gb_d[aria-label*="Google Account"]',
        'bard-sidenav',
        'button[aria-label*="New chat"]',
        'side-navigation-v2',
        'button[aria-label*="Sign out"]',
    ]},
    "claude":     {"root": "https://claude.ai/chats", "markers": [
        'button[data-testid="user-menu-button"]',
        'button[aria-label*="account"]',
        'div[data-testid="chat-list"]',
        'a[data-testid="starter-prompt"]',
        'button[aria-label*="New Chat"]',
        'nav a[href*="/recents"]',
    ]},
    "notebooklm": {"root": "https://notebooklm.google.com/", "markers": [
        'a[aria-label*="Google Account"]',
        'project-button',
        'create-new-button',
        'button[aria-label*="Create"]',
        '.mat-mdc-card-title',  # project cards on the home page
    ]},
}


async def verify_login(page, platform: str, *, ensure_nav: bool = False, nav_timeout: int = 15000, strict: bool = False) -> bool:
    """Verify the platform session is authenticated on the given page.

    Checks (in order):
      1. Any of the platform's DOM markers is present (fast, deterministic).
      2. Negative-signal check: visible Sign in / Log in button OR password
         input field → returns False.
      3. Ambiguous (no positive markers + no negative signals):
         - strict=False (pipeline path, default): fail-OPEN → return True and
           let downstream check_auth() catch real session failures. Tolerant
           of DOM selector drift after the user has already completed setup.
         - strict=True (setup path): fail-CLOSED → return False. Used by
           --pair step 3 where the entire point is to wait until the user
           actually logs in; we cannot let a persistent browser profile with
           partial state fool setup into auto-advancing.

    When `ensure_nav=True`, navigates to the platform root before checking so
    callers don't have to set up the URL themselves.
    """
    info = LOGIN_PLATFORMS.get(platform.lower())
    if not info:
        return False  # Unknown platform — fail closed

    try:
        if ensure_nav:
            try:
                await page.goto(info["root"], wait_until="domcontentloaded", timeout=nav_timeout)
            except Exception:
                pass
            # Small settle so SPA hydration paints the nav
            await asyncio.sleep(1.5)

        # If URL is obviously a login URL, short-circuit to False
        try:
            current = (page.url or "").lower()
        except Exception:
            current = ""
        login_hosts = ("auth.openai.com", "accounts.google.com/signin", "login.live.com", "claude.ai/login", "claude.ai/signup")
        for h in login_hosts:
            if h in current:
                return False

        # DOM marker check — any positive match means logged in.
        for sel in info["markers"]:
            try:
                loc = page.locator(sel)
                cnt = await loc.count()
                if cnt > 0:
                    return True
            except Exception:
                continue

        # Negative signals — presence of a password input OR a prominent
        # "Sign in / Log in" button means NOT logged in.
        try:
            has_negative = await page.evaluate("""() => {
                if (document.querySelector('input[type="password"]')) return true;
                const LOGIN_RE = /^\\s*(sign\\s*in|log\\s*in|log\\s*on|continue with google)\\s*$/i;
                const buttons = document.querySelectorAll('button, a[role="button"], a');
                for (const b of buttons) {
                    const t = (b.textContent || '').trim();
                    if (!t || t.length > 40) continue;
                    if (!LOGIN_RE.test(t)) continue;
                    const r = b.getBoundingClientRect();
                    if (r.width > 0 && r.height > 0 && r.top < window.innerHeight) return true;
                }
                return false;
            }""")
            if has_negative:
                return False
        except Exception:
            pass

        # Ambiguous — no positive markers, no negative signals. Split based
        # on caller context:
        #   strict=True (setup step 3): fail-CLOSED — we need to WAIT until
        #     the user actually logs in; auto-advancing would defeat setup.
        #   strict=False (pipeline runs): fail-OPEN — don't trap the user on
        #     drifted selectors when check_auth() will catch real failures.
        if strict:
            log(f"[verify_login:strict] {platform}: no login markers yet — waiting", "INFO")
            return False
        log(f"[verify_login] {platform}: ambiguous (no markers + no negative signals) — assuming logged in", "WARN")
        return True
    except Exception as e:
        log(f"[verify_login] {platform}: {e}", "WARN")
        return False


# Structural CUA failures (billing cap, invalid key, overload) are raised
# as this exception so callers can distinguish them from a legitimate
# login-wall NO verdict. See _cua_login_call for the matched error patterns.
class CuaUnavailableError(RuntimeError):
    pass


# Human-readable platform names used when prompting CUA for login verification.
# Keep these descriptive so the model knows which brand/site to identify.
_PLATFORM_DISPLAY = {
    "chatgpt":    "ChatGPT (chatgpt.com)",
    "gemini":     "Google Gemini (gemini.google.com)",
    "claude":     "Claude (claude.ai)",
    "notebooklm": "Google NotebookLM (notebooklm.google.com)",
}


async def _cua_login_call(page, platform: str, cua_client, heavy: bool = False) -> tuple[bool, str]:
    """Single CUA vision call. Returns (verdict_yes, raw_response)."""
    display = _PLATFORM_DISPLAY.get(platform.lower(), platform)
    try:
        buf = await page.screenshot(type="png", timeout=10000, full_page=False)
        b64 = base64.b64encode(buf).decode("ascii")
    except Exception as e:
        log(f"[verify_login_cua:{platform}] screenshot failed: {e}", "WARN")
        return (False, f"screenshot error: {e}")

    # Tight, positive-leaning prompt. We want YES when the authenticated app
    # UI is visible even if some secondary login-looking affordance exists.
    # False positives on modals/login walls are an order of magnitude worse
    # than false negatives — but false negatives (logged-in user shown as
    # logged-out) break the pipeline flow entirely, so we bias YES.
    prompt = (
        f"Screenshot of {display}.\n\n"
        f"Say YES if the authenticated app is visible and usable — e.g., "
        f"a chat composer, sidebar with user's own history, inbox with "
        f"messages, project/doc list, profile avatar, or any other UI "
        f"that only appears AFTER sign-in.\n\n"
        f"Say NO ONLY if the main content is clearly a login wall: a "
        f"centered sign-in form with a password field, a Google account "
        f"picker at accounts.google.com, or a marketing landing page "
        f"where the dominant action is \"Log in\" / \"Sign up\".\n\n"
        f"A transient loading spinner, a cookie banner, a sidebar nav "
        f"link labelled \"Log in\" on an otherwise-authenticated page, "
        f"or a small upsell popup do NOT count as a login wall — answer "
        f"YES in those cases.\n\n"
        f"Reply with ONLY one word: YES or NO."
    )
    try:
        resp = await asyncio.to_thread(
            cua_client.messages.create,
            model=(VISION_HEAVY_MODEL if heavy else VISION_LIGHT_MODEL),
            max_tokens=8,
            messages=[{
                "role": "user",
                "content": [
                    {"type": "image", "source": {"type": "base64", "media_type": "image/png", "data": b64}},
                    {"type": "text", "text": prompt},
                ],
            }],
        )
        raw = ""
        try:
            for blk in resp.content:
                if getattr(blk, "type", None) == "text":
                    raw = (blk.text or "").strip()
                    break
        except Exception:
            raw = ""
        verdict = raw.strip().lower()
        return (verdict.startswith("yes"), raw or "")
    except Exception as e:
        # Distinguish structural API failures (billing cap, invalid key,
        # overload) from a genuine login-wall NO. The caller treats a
        # False verdict as "not logged in" and prompts the user to log
        # in — but if the REAL blocker is an Anthropic 400/401/529, the
        # user chasing a phantom auth issue wastes their time. We surface
        # those errors as an exception so Phase 0 can emit a dedicated
        # pipeline_error ("CUA unavailable — [Skip] [Stop]") instead of
        # spinning on login_required.
        err = str(e)
        # 2026-05-29: classify explicitly. A 429 here was NOT caught before
        # and fell through to a False ("not logged in") verdict — the run then
        # showed a phantom login/key alert that self-healed when the limit
        # cleared (the appear-then-vanish bug). rate_limit / key / overload all
        # raise so Phase 0 surfaces the paused 'load or switch your key, then
        # Retry' card that persists until the user acts.
        if _anthropic_err_kind(err) in ("rate_limit", "key", "overload"):
            raise CuaUnavailableError(err) from e
        return (False, f"API error: {e}")


def _anthropic_err_kind(err: str) -> str:
    """Classify an Anthropic API/SDK error string for alert routing.

    Returns:
      'rate_limit' — 429 / too-many-requests / quota → user must load or
                     switch their API key (immediate paused key card).
      'key'        — 401 / invalid key / workspace usage cap → same key card.
      'overload'   — 529 / overloaded → transient (server-side).
      'transient'  — 403 / 5xx / timeout / connection blip → transient.
      'other'      — anything else.

    Routing: rate_limit + key surface the paused 'load or switch your key,
    then Retry' card; overload + transient are retried rather than alarming
    the user with a key prompt.
    """
    low = err.lower()
    if "429" in err or "rate_limit" in low or "rate limit" in low or "too many requests" in low:
        return "rate_limit"
    if ("workspace api usage limits" in low
            or ("400" in err and "usage limit" in low)
            or ("401" in err and ("unauthorized" in low or "invalid" in low or "api_key" in low))
            or "authentication_error" in low):
        return "key"
    if "529" in err or "overloaded" in low:
        return "overload"
    if ("403" in err or "500" in err or "502" in err or "503" in err
            or "504" in err or "timeout" in low or "timed out" in low
            or "connection" in low):
        return "transient"
    return "other"


async def _probe_cua_available(cua_client) -> None:
    """#705 — one-shot CUA/Anthropic availability probe for Phase 0.

    This is an INFRASTRUCTURE check, NOT a login check, and the distinction
    is the whole point. The Anthropic key powers BOTH the Vision and CUA
    tiers; a capped / invalid / rate-limited key knocks out tiers 2+3 and
    silently degrades the run to the raw-DOM tier the codebase explicitly
    distrusts ("cookies lie", "DOM selectors match cached fragments").

    Before this, the ONLY place a dead key surfaced was the P0 per-platform
    login walk (verify_login_cua) — which `skipInitVerify` blanks entirely
    (`preflight_platforms = []`). So with "Skip login verification" on, a dead
    key flowed straight into the run and FAILED OPEN at every phase-time gate,
    never alerting. (History: that gate has since been slimmed to a CUA-free
    trust check — #899 — so the fail-open concern now lives in the phases'
    own vision/CUA tiers; this probe is still their availability gate.)
    "Skip login verification" is a statement about platform sign-ins; it
    must NOT also disable the vision infra every phase depends on.

    So this probe decouples availability from login: the P0 caller runs it
    REGARDLESS of skipInitVerify, it makes ONE minimal Anthropic call, and it
    raises CuaUnavailableError (the SAME class the login walk uses, so the
    caller reuses the existing fail-closed `cua_unavailable` card) on a
    structural Anthropic failure. Transient blips (529 / 5xx / net) are NOT
    cardable — they're left to the per-phase retry/fail-open paths, matching
    the #705 taxonomy (transient → silent, structural → paused decision).
    """
    if cua_client is None:
        # No client == no key resolved. run_pipeline returns early on an empty
        # key (:27272) so this is belt-and-suspenders, but treat it as a hard
        # unavailable rather than silently degrading.
        raise CuaUnavailableError("No Anthropic client (API key did not resolve)")
    try:
        await asyncio.to_thread(
            cua_client.messages.create,
            model=VISION_LIGHT_MODEL,
            max_tokens=1,
            messages=[{"role": "user", "content": "ping"}],
        )
    except Exception as e:
        err = str(e)
        kind = _anthropic_err_kind(err)
        # Only the unambiguously-structural classes block the run: a bad/capped
        # key (401 / workspace cap) or a rate-limit (429) the user must clear.
        # These are exactly the classes verify_login_cua raises on (:8503).
        if kind in ("rate_limit", "key"):
            log(f"[probe_cua] Anthropic unavailable ({kind}) — fail-closed at P0: {err[:160]}", "ERROR")
            raise CuaUnavailableError(err) from e
        # overload (529) / transient (5xx, net) / unrecognized SDK quirk: do
        # NOT card before the run even starts. A flaky probe false-alarm is
        # worse than letting the run proceed — the per-phase CUA paths have
        # their own retry + fail-open handling. #705 taxonomy: transient →
        # silent.
        log(f"[probe_cua] probe error treated as non-blocking ({kind}): {err[:160]}", "WARN")
    else:
        log("[probe_cua] CUA/Anthropic reachable ✓", "INFO")


# Set membership only — every caller uses this for "is this platform in
# the pro-tier-detection list" and then resolves the actual prompt via
# `prompt_map` below. Previous shape mapped key→prompt-name-as-string
# but the string was never used, just truthiness-checked, which invited
# confusion.
_PRO_TIER_PLATFORMS = frozenset({"chatgpt", "claude", "gemini"})


async def _gemini_dom_tier(page) -> str:
    """Full-document DOM read of Gemini's subscription tier → 'pro'|'free'|'unsure'.

    #743 (2026-06-01): the vision Pro-check screenshots only the composer
    viewport, where an Advanced account looks IDENTICAL to free — after
    Deep-Research setup the composer reads "Gemini" + Flash with no Advanced
    badge (the badge lives in the collapsed left sidebar / account chip; the
    user had to manually open the sidebar before the bot could see it). That
    composer view matches the prompt's FREE signals, so vision confidently —
    and wrongly — returns "free" on a paid account, forcing a manual Retry
    (it hit BOTH workers). The DOM, unlike a viewport screenshot, can read the
    off-screen sidebar/banner text.

    Cost asymmetry drives the policy: a false 'free' WEDGES the run behind a
    manual decision card; a false 'pro' only means a free run goes unflagged
    (silent, acceptable). So we bias HARD toward Pro — only a VISIBLE upsell
    CTA ("Get/Try/Upgrade … Gemini Advanced") declares 'free'; a current-plan
    Advanced/Ultra marker (NOT an upsell) declares 'pro'; anything else is
    'unsure' and the caller fails open. Never raises. Always logs the candidate
    signals so the next E2E can pin exact selectors (the Step 3A dump pattern)."""
    try:
        res = await page.evaluate("""() => {
            const norm = s => (s || '').replace(/\\s+/g, ' ').trim();
            const vis = el => el.getClientRects().length > 0;
            const clickables = [...document.querySelectorAll('button, a, [role="button"], [role="link"]')].filter(vis);
            // FREE: a prominent upsell CTA. Match the VERB so a plain "Gemini
            // Advanced" plan label on a PAID account isn't read as an upsell.
            const upsellRe = /\\b(get|try|upgrade|subscribe|unlock)\\b.{0,24}(gemini advanced|advanced|google ai|pro plan)/i;
            const upsell = clickables.find(el => upsellRe.test(norm(el.textContent)) || upsellRe.test(norm(el.getAttribute('aria-label'))));
            // PRO: a current-plan marker that is NOT itself an upsell CTA.
            const proRe = /(gemini advanced|google ai pro|google ai ultra|gemini ultra|2\\.5 pro|deep think)/i;
            const verbRe = /\\b(get|try|upgrade|subscribe|unlock)\\b/i;
            const proMark = [...document.querySelectorAll('*')].filter(vis).find(el => {
                const t = norm(el.textContent);
                if (!t || t.length > 28) return false;          // a short label/chip, not a paragraph
                const m = t.match(proRe);
                if (!m) return false;
                // The marker must DOMINATE the element's text — a chip/badge
                // ("Gemini Advanced"), not a sentence that merely mentions it
                // ("Using Gemini Advanced for better analysis"). Caps the
                // non-marker remainder so a prose false-positive can't read as
                // a current-plan label.
                if (t.length - m[0].length > 8) return false;
                if (verbRe.test(t)) return false;               // exclude upsell CTAs
                return true;
            });
            const dump = clickables
                .filter(el => /advanced|upgrade|ultra|google ai|get gemini/i.test(norm(el.textContent) + ' ' + norm(el.getAttribute('aria-label'))))
                .slice(0, 8)
                .map(el => (norm(el.textContent) || norm(el.getAttribute('aria-label'))).slice(0, 44));
            return { upsell: !!upsell, proMark: !!proMark,
                     upsellText: upsell ? (norm(upsell.textContent) || norm(upsell.getAttribute('aria-label'))).slice(0, 50) : '',
                     proText: proMark ? norm(proMark.textContent).slice(0, 50) : '',
                     dump };
        }""")
    except Exception as e:
        log(f"[pro_tier:gemini] DOM tier read failed: {e}", "INFO")
        return "unsure"
    if not isinstance(res, dict):
        return "unsure"
    log(f"[pro_tier:gemini] DOM tier signals: upsell={res.get('upsell')} ({res.get('upsellText')!r}) "
        f"proMark={res.get('proMark')} ({res.get('proText')!r}) candidates={res.get('dump')}", "INFO")
    # Bias to Pro: a current-plan Advanced/Ultra marker wins outright; only a
    # clear upsell CTA (with NO pro marker) declares free.
    if res.get("proMark"):
        return "pro"
    if res.get("upsell"):
        return "free"
    return "unsure"


async def _chatgpt_dom_tier(page) -> str:
    """Full-document DOM read of ChatGPT's subscription tier → 'pro'|'free'|'unsure'.

    #751 (2026-06-02): parity with [_gemini_dom_tier]. The E2E proved ChatGPT
    hits the SAME false-'free' as Gemini did in #743 — the viewport screenshot
    the vision model judges can miss the current-plan marker, which lives in the
    top model-selector button / account chip that isn't reliably in frame the
    instant the shot is taken. So vision reads a paid account's bare composer as
    'free' and fires a pro_required card (it hit BOTH workers; the user had to
    manually open the model menu, where Pro showed instantly selected, before
    CUA could see it). The DOM can read those off-screen/top-of-page markers.

    Same cost-asymmetry policy as Gemini: a false 'free' WEDGES the run behind a
    decision card; a false 'pro' only means a free run goes unflagged (silent,
    acceptable). So bias HARD toward Pro — only a VISIBLE upsell CTA ('Upgrade
    to Plus/Pro/Go', 'Get ChatGPT Plus') declares 'free'; a current-plan
    Pro/Plus marker (NOT an upsell) declares 'pro'; anything else is 'unsure'
    and the caller fails open. Never raises. Logs the candidate signals so the
    next E2E can pin exact selectors."""
    try:
        res = await page.evaluate("""() => {
            const norm = s => (s || '').replace(/\\s+/g, ' ').trim();
            const vis = el => el.getClientRects().length > 0;
            const clickables = [...document.querySelectorAll('button, a, [role="button"], [role="link"], [role="menuitem"]')].filter(vis);
            // FREE: a prominent paid-tier upsell CTA (verb + plan noun) — so a
            // plain "ChatGPT Plus" current-plan chip is NOT read as an upsell.
            const upsellRe = /\\b(upgrade|subscribe|get|try)\\b.{0,24}\\b(chatgpt )?(plus|pro|go|team)\\b/i;
            const upsell = clickables.find(el => upsellRe.test(norm(el.textContent)) || upsellRe.test(norm(el.getAttribute('aria-label'))));
            // PRO: a current-plan marker that is NOT itself an upsell CTA.
            const proRe = /(chatgpt pro|chatgpt plus|pro plan|plus plan|team plan|extended pro)/i;
            const verbRe = /\\b(upgrade|subscribe|get|try)\\b/i;
            const proMark = [...document.querySelectorAll('*')].filter(vis).find(el => {
                const t = norm(el.textContent);
                if (!t || t.length > 28) return false;          // a short chip/label, not a paragraph
                const m = t.match(proRe);
                if (!m) return false;
                if (t.length - m[0].length > 8) return false;   // marker must DOMINATE the text
                if (verbRe.test(t)) return false;               // exclude upsell CTAs
                return true;
            });
            // Extra PRO source: the top model-selector trigger. On a Pro account
            // with the Pro model picked it reads e.g. "Pro" / "Extended Pro" —
            // read its OWN text with word boundaries so "Improve"/"product" miss.
            let modelPro = false;
            const mtrig = clickables.find(b => {
                const a = (b.getAttribute('aria-label') || '').toLowerCase();
                const tid = (b.getAttribute('data-testid') || '').toLowerCase();
                return tid.includes('model') || a.includes('model');
            });
            if (mtrig) {
                const mt = norm(mtrig.textContent).toLowerCase();
                if (/\\b(pro|plus)\\b/.test(mt) && !verbRe.test(mt)) modelPro = true;
            }
            const dump = clickables
                .filter(el => /upgrade|plus|\\bpro\\b|\\bgo\\b|plan|model/i.test(norm(el.textContent) + ' ' + norm(el.getAttribute('aria-label'))))
                .slice(0, 8)
                .map(el => (norm(el.textContent) || norm(el.getAttribute('aria-label'))).slice(0, 44));
            return { upsell: !!upsell, proMark: !!proMark, modelPro,
                     upsellText: upsell ? (norm(upsell.textContent) || norm(upsell.getAttribute('aria-label'))).slice(0, 50) : '',
                     proText: proMark ? norm(proMark.textContent).slice(0, 50) : '',
                     dump };
        }""")
    except Exception as e:
        log(f"[pro_tier:chatgpt] DOM tier read failed: {e}", "INFO")
        return "unsure"
    if not isinstance(res, dict):
        return "unsure"
    log(f"[pro_tier:chatgpt] DOM tier signals: upsell={res.get('upsell')} ({res.get('upsellText')!r}) "
        f"proMark={res.get('proMark')} modelPro={res.get('modelPro')} ({res.get('proText')!r}) candidates={res.get('dump')}", "INFO")
    # Bias to Pro: a current-plan Pro/Plus marker (chip or model trigger) wins
    # outright; only a clear upsell CTA (with NO pro marker) declares free.
    if res.get("proMark") or res.get("modelPro"):
        return "pro"
    if res.get("upsell"):
        return "free"
    return "unsure"


async def _chatgpt_extended_pro_confirm(page) -> str:
    """Read-only DOM confirm that ChatGPT actually stuck on Pro + Extended
    Thinking after the Phase-1 selector ran → 'extended'|'pro'|'downgrade'|'unsure'.

    #759 (2026-06-02): Phase 1 infers Pro+Extended success purely from the CUA
    selector's prose (the "no 'no pro' in the verdict" break). If the picker
    silently reverted to Instant/Auto — or never applied Extended Thinking — the
    brief is generated on a far shallower model with no signal at all. This is
    the post-select DOM cross-check the user asked for.

    FAIL-OPEN by design: only a CONFIRMED downgrade — a non-Pro thinking mode
    active (Instant/Auto/Fast) AND no Pro/Extended marker anywhere — returns
    'downgrade'. 'extended' / 'pro' / 'unsure' all mean "proceed". The caller
    does at most ONE silent re-run on 'downgrade' — never a pro_required card,
    pause, or badge (this is a quality knob like Claude's Effort/Thinking,
    WARN-only). Never raises. Logs the candidate marker text so the next E2E can
    pin the exact 'Extended Pro' pill selector.

    Excludes [role=menu|listbox|dialog] descendants so an OPEN model-picker
    listing 'Instant'/'Pro'/'Auto' OPTIONS can't be misread as the active mode
    (mirrors the Claude model-trigger read)."""
    try:
        res = await page.evaluate("""() => {
            const norm = s => (s || '').replace(/\\s+/g, ' ').trim();
            const vis = el => el.getClientRects().length > 0;
            const inOverlay = el => !!el.closest('[role="menu"], [role="listbox"], [role="dialog"]');
            const verbRe = /\\b(upgrade|subscribe|get|try)\\b/i;
            const extRe = /extended\\s*pro/i;
            // The model / thinking-mode trigger button (NOT the menu items).
            const clickables = [...document.querySelectorAll('button, [role="button"]')]
                .filter(el => vis(el) && !inOverlay(el));
            const mtrig = clickables.find(b => {
                const a = (b.getAttribute('aria-label') || '').toLowerCase();
                const tid = (b.getAttribute('data-testid') || '').toLowerCase();
                return tid.includes('model') || a.includes('model');
            });
            const trigText = mtrig ? norm(mtrig.textContent) : '';
            const trig = trigText.toLowerCase();
            // 'Extended Pro' marker anywhere in the page chrome (a short chip/pill,
            // not a paragraph, not inside an open menu/overlay).
            const extMark = [...document.querySelectorAll('*')]
                .filter(el => vis(el) && !inOverlay(el))
                .find(el => {
                    const t = norm(el.textContent);
                    if (!t || t.length > 24) return false;
                    return extRe.test(t);
                });
            const hasExtended = extRe.test(trigText) || !!extMark;
            const hasPro = /\\b(pro|plus)\\b/.test(trig) && !verbRe.test(trig);
            const hasInstant = /\\b(instant|auto|fast|standard)\\b/.test(trig);
            return { trigText: trigText.slice(0, 50), hasExtended, hasPro, hasInstant,
                     extText: extMark ? norm(extMark.textContent).slice(0, 40) : '',
                     // #766: dump the marker's tag + class so the next E2E can
                     // pin a CSS selector for the 'Extended Pro' pill (the
                     // confirm itself is a text scan, validated working in the
                     // 2026-06-03 E2Es — both workers returned 'extended').
                     extTag: extMark ? (extMark.tagName || '').toLowerCase() : '',
                     extCls: extMark ? norm((extMark.className && extMark.className.toString)
                         ? extMark.className.toString() : '').slice(0, 80) : '' };
        }""")
    except Exception as e:
        log(f"[p1:extended_pro_confirm] DOM read failed: {e}", "INFO")
        return "unsure"
    if not isinstance(res, dict):
        return "unsure"
    log(f"[p1:extended_pro_confirm] trig={res.get('trigText')!r} "
        f"extended={res.get('hasExtended')} ({res.get('extText')!r} "
        f"<{res.get('extTag')} class={res.get('extCls')!r}>) "
        f"pro={res.get('hasPro')} instant={res.get('hasInstant')}", "INFO")
    # Asymmetric: an Extended/Pro marker wins outright (proceed). Only a non-Pro
    # mode active WITH no Pro/Extended marker is a real downgrade.
    if res.get("hasExtended"):
        return "extended"
    if res.get("hasPro"):
        return "pro"
    if res.get("hasInstant"):
        return "downgrade"
    return "unsure"


# Composer detector shared by the clear + verify legs below. DR-active when a
# short 'deep research' pill/chip is visible in the composer FORM, or the
# composer placeholder is the Deep-Research one. NB the DR placeholder is
# "Get a detailed report" (contains 'report', NOT 'research') — user-captured
# 2026-07-08 — so the old placeholder.includes('research') check would MISS it.
# Scoped to `form` so a 'Deep research' badge on an already-SENT message (which
# lives OUTSIDE the composer form) can never false-positive.
_CHATGPT_DR_ACTIVE_JS = r"""() => {
    const norm = s => (s || '').replace(/\s+/g, ' ').trim().toLowerCase();
    const form = document.querySelector('form') || document.body;
    let pillText = '';
    for (const p of form.querySelectorAll('button, [role="button"], span, div')) {
        if (!p.offsetParent) continue;
        const t = norm(p.textContent);
        if (t && t.length <= 30 && t.includes('deep research')) { pillText = t; break; }
    }
    let placeholder = '';
    const ta = document.querySelector('#prompt-textarea, textarea, [contenteditable="true"]');
    if (ta) placeholder = norm(ta.getAttribute('placeholder') || ta.getAttribute('data-placeholder'));
    if (!placeholder) {
        const ph = (form.querySelector('[data-placeholder]') || {});
        placeholder = norm(ph.getAttribute ? ph.getAttribute('data-placeholder') : '');
    }
    const phDR = /detailed report|deep research|research report/.test(placeholder);
    return { active: !!pillText || phDR, pillText, placeholder: placeholder.slice(0, 80) };
}"""


# Focus the P1 composer editable and collapse the caret to the very END of any
# (empty) text — i.e. immediately AFTER the Deep-Research inline token. Backspace
# there deletes the token exactly like a character (the platform's real remove
# affordance — user-directed 2026-07-13). Returns {ok, textLen}: textLen guards
# against ever backspacing over typed prose — the brief is not typed yet so it's
# 0, and a PDF attachment is a separate card row (never an in-text token), so an
# in-composer Backspace can only ever delete the tool token, never the file.
_CHATGPT_FOCUS_COMPOSER_END_JS = r"""() => {
    const ta = document.querySelector('#prompt-textarea')
            || document.querySelector('div[contenteditable="true"]')
            || document.querySelector('textarea');
    if (!ta) return { ok: false, textLen: 0 };
    try { ta.focus(); } catch (e) {}
    let textLen = 0;
    try {
        const ce = ta.isContentEditable || ta.getAttribute('contenteditable') === 'true';
        if (ce) {
            textLen = (ta.innerText || '').replace(/[\u200b\ufeff\s]/g, '').length;
            const sel = window.getSelection();
            const range = document.createRange();
            range.selectNodeContents(ta);
            range.collapse(false);        // caret to the very end (after the token)
            sel.removeAllRanges();
            sel.addRange(range);
        } else {
            const v = ta.value || '';
            textLen = v.replace(/[\u200b\ufeff\s]/g, '').length;
            ta.setSelectionRange(v.length, v.length);
        }
    } catch (e) {}
    return { ok: true, textLen };
}"""


async def _chatgpt_clear_deep_research(browser, cua_client=None, verbose=False) -> str:
    """Phase 1 must write the research brief on ChatGPT Pro + Extended Thinking
    with NO composer tool selected — Deep Research belongs to Phase 2 ONLY.

    ChatGPT persists the last-used composer tool per account, so a PRIOR run's
    Phase-2 'Deep research' selection carries into the next run's Phase-1 (the
    tool stays sticky even on a fresh chat). Submitting the brief prompt while
    Deep Research is active drops P1 into Deep Research mode: instead of a
    Pro-Extended text brief, ChatGPT returns a research-plan card ('… Deep
    Research' with an Edit/Cancel/Start gate) — the wrong output type, gated
    behind a Start click, and it burns a deep-research slot (user-captured
    2026-07-08 screenshot: 'Get a detailed report' placeholder + '📣 Deep
    research' on the sent brief + a 'Golden Retriever Deep Research' Start-46 card).

    Read-first + fully fail-safe. Detects an ACTIVE Deep Research composer tool
    and turns it OFF. #952 (2026-07-13): removal is now BACKSPACE-first — the
    selected tool is an inline token at the start of the empty composer, and
    Backspace deletes it like a character (the platform's real remove). We do
    NOT re-click the tool item: ChatGPT's tools menu no longer TOGGLES DR, so a
    click ADDS a second Deep Research instead of removing it (user-observed).
    Order: Backspace loop → composer-pill ✕ (a genuine remove control only) →
    bounded, Backspace-oriented CUA fallback — re-verifying after each leg.
    Returns 'cleared' | 'absent' | 'unsure'. NEVER enables a tool; swallows
    every error; must never block Phase 1 (a miss just proceeds → worst case is
    today's behaviour and the brief still submits)."""
    page = browser.page
    try:
        st = await page.evaluate(_CHATGPT_DR_ACTIVE_JS)
    except Exception as e:
        log(f"[p1:clear_dr] composer probe failed ({e}) — proceeding without clearing", "INFO")
        return "unsure"
    if not st or not st.get("active"):
        log(f"[p1:clear_dr] Deep Research not active on the P1 composer "
            f"(placeholder={((st or {}).get('placeholder')) or ''!r}) — nothing to clear")
        return "absent"
    log(f"[p1:clear_dr] Deep Research is ACTIVE on the P1 composer "
        f"(pill={st.get('pillText')!r}, placeholder={st.get('placeholder')!r}) — "
        f"clearing it (Deep Research belongs to Phase 2 only)", "WARN")

    async def _still_active() -> bool:
        try:
            s = await page.evaluate(_CHATGPT_DR_ACTIVE_JS)
            return bool(s and s.get("active"))
        except Exception:
            return True  # can't confirm cleared → assume still on, keep trying

    # ── Strategy A: BACKSPACE-delete the composer token — the platform's REAL
    #    remove affordance (user-directed 2026-07-13). ChatGPT's tools menu no
    #    longer TOGGLES Deep Research: clicking the already-selected "Deep
    #    research" item (whether by DOM or a CUA vision click) ADDS a SECOND Deep
    #    Research instead of removing it (user-observed: "trying to click deep
    #    research again adds 2 instead of removing"). The selected tool renders
    #    as an inline token at the START of the composer; with the brief not yet
    #    typed the composer is empty, so Backspace deletes the token exactly like
    #    a character. We NEVER re-click the tool item here. Backspace over an
    #    empty composer is harmless (nothing to delete) and never touches a PDF
    #    attachment (that lives in a separate card row, not the text node). ──
    _BS_TRIES = int(os.environ.get("DG_CHATGPT_DR_BACKSPACE_TRIES", "3"))
    # Prose guard: skip Backspace only when the composer holds clearly-typed
    # PROSE, not merely the tool token. If the pill renders as an INLINE token
    # inside the editable its own label ('Deep research', ≤ 30 chars per the
    # detector) inflates innerText — so a bare-token composer can read up to ~30
    # chars with zero prose. A real brief is hundreds of chars. Guard at > 40 so
    # the token's own label never blocks its removal, while any actual prose
    # (never present at this pre-type call site) is still protected.
    _DR_PROSE_GUARD = 40

    async def _backspace_clear() -> bool:
        """Focus the composer, caret to the end (after the token), Backspace once.
        Refuses to press if the composer already holds typed prose — never eat a
        brief. Returns True iff a Backspace was actually issued."""
        try:
            info = await page.evaluate(_CHATGPT_FOCUS_COMPOSER_END_JS)
        except Exception as e:
            log(f"[p1:clear_dr] composer focus for Backspace failed ({e})", "INFO")
            return False
        if not info or not info.get("ok"):
            log("[p1:clear_dr] composer editable not found — cannot Backspace", "INFO")
            return False
        if int(info.get("textLen") or 0) > _DR_PROSE_GUARD:
            log(f"[p1:clear_dr] composer holds {info.get('textLen')} chars of prose "
                f"(> {_DR_PROSE_GUARD}) — skipping Backspace so no brief is deleted", "INFO")
            return False
        await asyncio.sleep(0.15)
        try:
            await page.keyboard.press("Backspace")
        except Exception as e:
            log(f"[p1:clear_dr] Backspace keypress errored ({e})", "INFO")
            return False
        await asyncio.sleep(0.6)
        return True

    for _bt in range(1, _BS_TRIES + 1):
        if not await _still_active():
            break
        _did = await _backspace_clear()
        log(f"[p1:clear_dr] Strategy A (Backspace delete) attempt {_bt}/{_BS_TRIES} (issued={_did})")
        if not _did:
            break  # couldn't focus / composer had text — don't spin the token

    # ── Strategy B: composer-pill ✕ (click a genuine remove/close control on the
    #    DR chip — never re-clicks the tool item, so it can't add a second DR).
    #    SAFETY (#952 review): the ancestor walk is TIGHTLY scoped to the DR chip
    #    so it can never reach an attached PDF's "Remove file" button and silently
    #    delete the user's source doc. clear_dr runs AFTER PDF attach, and ChatGPT
    #    labels an attachment's delete control "Remove file 1: brief.md" (#950) —
    #    which the old bare `remove` match would have clicked. We now (a) STOP the
    #    walk the moment the container's text stops being (essentially) just the
    #    short 'deep research' label (climbing into shared composer chrome that
    #    holds the file cards), and (b) reject any control whose aria mentions
    #    file/attach. Since the modern DR token has no ✕ of its own (it's removed
    #    by Backspace, Strategy A), this leg is a no-op on the current UI and
    #    exists only for an older pill-✕ variant. ──
    if await _still_active():
        try:
            removed = await page.evaluate(r"""() => {
                const norm = s => (s || '').replace(/\s+/g, ' ').trim().toLowerCase();
                const form = document.querySelector('form') || document.body;
                let pill = null;
                for (const p of form.querySelectorAll('button, [role="button"], span, div')) {
                    if (!p.offsetParent) continue;
                    const t = norm(p.textContent);
                    if (t && t.length <= 30 && t.includes('deep research')) { pill = p; break; }
                }
                if (!pill) return false;
                // Walk up a FEW ancestors, but only within the DR chip itself.
                let chip = pill;
                for (let i = 0; i < 3 && chip; i++) {
                    const ctext = norm(chip.textContent);
                    // Once the container's text is no longer ~just the DR label we
                    // have climbed into shared composer chrome (which holds the
                    // attachment cards) — stop before we can match a file remove.
                    if (!ctext.includes('deep research') || ctext.length > 40) break;
                    const btn = [...chip.querySelectorAll('button, [role="button"]')].find(b => {
                        if (!b.offsetParent) return false;
                        const a = norm(b.getAttribute('aria-label'));
                        const t = norm(b.textContent);
                        if (a.includes('file') || a.includes('attach')) return false;  // never a PDF card
                        return a.includes('remove') || a.includes('close') ||
                               a.includes('turn off') || a.includes('deselect') ||
                               a.includes('deep research') ||
                               t === '×' || t === 'x';
                    });
                    if (btn) { btn.click(); return true; }
                    chip = chip.parentElement;
                }
                return false;
            }""")
            await asyncio.sleep(0.8)
            log(f"[p1:clear_dr] Strategy B (pill ✕): remove clicked={removed}")
        except Exception as e:
            log(f"[p1:clear_dr] Strategy B errored ({e})", "INFO")

    # ── Strategy C: bounded CUA fallback (selectors rotate; DR-off is
    #    correctness-critical for P1, so keep the tier-3 net like setup_*_dr).
    #    Backspace-oriented — the prompt FORBIDS clicking the Deep research tool
    #    (a click adds a second DR), so Vision only presses Backspace. ──
    if cua_client and await _still_active():
        log("[p1:clear_dr] DOM legs left Deep Research active — CUA fallback to disable it", "INFO")
        try:
            async def _disable_dr_cua():
                return await asyncio.wait_for(
                    agent_loop(cua_client, browser, PROMPT_CHATGPT_DISABLE_DR,
                        "Remove Deep Research from the ChatGPT composer by pressing "
                        "Backspace in the empty message box. Do NOT click the 'Deep "
                        "research' tool button (clicking it ADDS a second Deep "
                        "Research). Do not type, do not send, do not enable any tool.",
                        model=CUA_MODEL, max_iterations=10, verbose=verbose),
                    timeout=120.0,
                )

            await _shadow_observed_cua(
                page, hotspot_id="1a-disable-dr", phase=1, platform="chatgpt",
                current_step="disable_deep_research_for_brief",
                context_hint="the composer has Deep Research active (placeholder 'Get a detailed "
                             "report' / a 'Deep research' pill) — REMOVE it by pressing Backspace "
                             "in the empty message box; do NOT click the 'Deep research' tool "
                             "(clicking adds a second one). Don't enable any other tool",
                expected_outcome="the ChatGPT composer is in normal chat mode (no Deep Research)",
                cua_coro_factory=_disable_dr_cua,
                mission_prompt=PROMPT_CHATGPT_DISABLE_DR,
                act_timeout_s=110.0)
        except asyncio.TimeoutError:
            log("[p1:clear_dr] CUA fallback timed out (120s) — proceeding", "WARN")
        except Exception as e:
            log(f"[p1:clear_dr] CUA fallback errored ({e}) — proceeding", "WARN")

    # ── Final verify + one-shot diagnostic dump (pins the real control if a
    #    future relabel breaks every leg — grep 'clear_dr composer dump'). ──
    if await _still_active():
        try:
            dump = await page.evaluate(r"""() => {
                const norm = s => (s || '').replace(/\s+/g, ' ').trim();
                // Document-wide (not form-scoped): a body-level popover node or a
                // testid-based control that broke every leg must be pinnable here.
                const out = [];
                for (const el of document.querySelectorAll(
                        'button, [role="button"], [role="menuitemradio"], [role="menuitem"], span, div')) {
                    if (!el.offsetParent) continue;
                    const t = norm(el.textContent);
                    if (!/research|report/i.test(t) || t.length > 40) continue;
                    out.push({ tag: (el.tagName || '').toLowerCase(),
                               role: el.getAttribute('role') || '',
                               text: t.slice(0, 40),
                               aria: (el.getAttribute('aria-label') || '').slice(0, 40),
                               testid: el.getAttribute('data-testid') || '',
                               checked: el.getAttribute('aria-checked') || el.getAttribute('aria-pressed') || '' });
                }
                return out.slice(0, 20);
            }""")
            log("[p1:clear_dr] composer dump (DR still active — fix selector from this): "
                + json.dumps(dump, ensure_ascii=False), "WARN")
        except Exception:
            pass
        log("[p1:clear_dr] could not confirm Deep Research is OFF — proceeding anyway "
            "(brief may run in DR mode; not fatal)", "WARN")
        return "unsure"
    log("[p1:clear_dr] Deep Research cleared — composer back to normal chat mode ✓")
    return "cleared"


async def _cua_pro_tier_call(page, platform: str, cua_client, heavy: bool = False) -> str:
    """Single-screenshot Pro/Free verdict for ChatGPT/Claude/Gemini.

    Returns 'pro' | 'free' | 'unsure'. UNSURE is a fail-open signal — caller
    treats it as "assume Pro, log INFO" so a transient UI state doesn't
    false-flag.

    Raises CuaUnavailableError on structural Anthropic failures (billing cap,
    invalid key, 529) so the caller can surface the canonical "CUA can't run"
    alert rather than silently degrading.
    """
    pname = platform.lower()
    if pname not in _PRO_TIER_PLATFORMS:
        return "unsure"  # No prompt for this platform — caller should not have called us
    # ChatGPT: skip the cheap "light" (Sonnet) pre-check and read tier directly
    # on the heavy (Opus) model. The light model reliably PREAMBLES ("Looking at
    # the screenshot, I…") and the 8-token cap chops it off before the required
    # one-word verdict, so for ChatGPT the light pass is always 'unsure' and
    # always escalates to heavy anyway — wasting a Sonnet call + a 2s settle and
    # logging a noisy "light verdict unsure … escalating" line every time. Going
    # straight to heavy is cheaper (no wasted light call), faster, and quiet.
    # Claude/Gemini keep the light fast-path (their badges read cleanly on the
    # cheap model, so light usually gives a clean verdict — see triage evidence).
    if pname == "chatgpt":
        heavy = True
    try:
        from prompts import (
            PROMPT_DETECT_CHATGPT_PRO,
            PROMPT_DETECT_CLAUDE_PRO,
            PROMPT_DETECT_GEMINI_PRO,
        )
    except Exception as e:
        log(f"[pro_tier:{pname}] prompt import failed: {e}", "WARN")
        return "unsure"
    prompt_map = {
        "chatgpt": PROMPT_DETECT_CHATGPT_PRO,
        "claude":  PROMPT_DETECT_CLAUDE_PRO,
        "gemini":  PROMPT_DETECT_GEMINI_PRO,
    }
    prompt = prompt_map[pname]
    try:
        buf = await page.screenshot(type="png", timeout=10000, full_page=False)
        b64 = base64.b64encode(buf).decode("ascii")
    except Exception as e:
        log(f"[pro_tier:{pname}] screenshot failed: {e}", "WARN")
        return "unsure"
    try:
        resp = await asyncio.to_thread(
            cua_client.messages.create,
            model=(VISION_HEAVY_MODEL if heavy else VISION_LIGHT_MODEL),
            max_tokens=8,
            messages=[{
                "role": "user",
                "content": [
                    {"type": "image", "source": {"type": "base64", "media_type": "image/png", "data": b64}},
                    {"type": "text", "text": prompt},
                ],
            }],
        )
        raw = ""
        try:
            for blk in resp.content:
                if getattr(blk, "type", None) == "text":
                    raw = (blk.text or "").strip()
                    break
        except Exception:
            raw = ""
        verdict = raw.strip().lower()
        if verdict.startswith("pro"):
            return "pro"
        if verdict.startswith("free"):
            # A vision "free" verdict is NOT trusted on its own for Gemini (#743)
            # OR ChatGPT (#751). The current-plan marker is off-screen — Gemini's
            # Advanced badge lives in the collapsed sidebar; ChatGPT's Pro/Plus
            # marker lives in the top model-selector button — so the composer
            # screenshot the model just judged matches the FREE signals even on a
            # paid account, and a heavy re-read of the SAME blind shot wouldn't
            # help. Cross-check the DOM (which CAN read those off-screen markers)
            # and FAIL OPEN: only a clear upsell CTA confirms genuine free;
            # otherwise assume Pro and DON'T raise the pro_required card. Claude's
            # Opus badge is on-screen and reads reliably, so it still trusts the
            # vision 'free' (logs show "Pro detected ✓").
            if pname in ("gemini", "chatgpt"):
                dom = await (_gemini_dom_tier(page) if pname == "gemini" else _chatgpt_dom_tier(page))
                if dom == "pro":
                    log(f"[pro_tier:{pname}] vision said FREE but DOM shows a current-plan Pro marker — trusting DOM (pro)", "INFO")
                    return "pro"
                if dom == "free":
                    log(f"[pro_tier:{pname}] vision FREE + DOM upsell CTA present — confirmed free", "INFO")
                    return "free"
                log(f"[pro_tier:{pname}] vision said FREE but DOM has no upsell CTA (marker off-screen) — failing open, assuming Pro (no alert)", "INFO")
                return "unsure"
            return "free"
        # #724 item 2: an ambiguous LIGHT-model verdict gets one escalated
        # re-read on the heavy model (Opus 4.8) before we fall back to fail-open
        # "unsure" — mirrors verify_login_cua's attempts>=2 rule (research.py
        # ~9040). A fresh screenshot after a short settle covers the common
        # case where the Pro/Free chrome simply hadn't finished rendering when
        # the first shot was taken. heavy=True passes don't recurse (guard is
        # `not heavy`), so this is at most ONE extra screenshot + Opus call,
        # and only on a genuinely ambiguous verdict (not on infra failures,
        # which return "unsure" above without reaching here).
        if not heavy:
            log(f"[pro_tier:{pname}] light verdict unsure ({raw[:30]!r}) — escalating to heavy re-read", "INFO")
            try:
                await asyncio.sleep(2.0)
            except Exception:
                pass
            return await _cua_pro_tier_call(page, platform, cua_client, heavy=True)
        return "unsure"
    except Exception as e:
        err = str(e)
        if _anthropic_err_kind(err) in ("rate_limit", "key", "overload"):
            raise CuaUnavailableError(err) from e
        log(f"[pro_tier:{pname}] API error: {e}", "WARN")
        return "unsure"


async def verify_login_cua(page, platform: str, cua_client) -> bool:
    """Vision-based login verification with a two-strike retry.

    DOM selectors drift and some platforms show auth-like markers (New chat,
    sidebar nav) even on the logged-out landing page. Vision is the only
    reliable way to tell "modal/login wall" from "authenticated app".

    Strategy: one quick check → if NO, wait 3s (lets Claude.ai / Gemini /
    Google Docs finish hydrating) and re-check once. Only flag as not
    logged in if BOTH checks disagree. Eliminates false positives from
    transient loading states while still catching real logout walls.

    Returns True iff at least one of the checks clearly says YES.
    """
    ok1, raw1 = await _cua_login_call(page, platform, cua_client)
    if ok1:
        log(f"[verify_login_cua:{platform}] LOGGED IN ✓ (Claude: {raw1[:30]})", "INFO")
        return True

    # Second attempt — let the page hydrate a bit more and re-check. Some
    # SPAs (claude.ai/chats, docs.google.com) paint a neutral "loading"
    # state for the first 3-4s that CUA misreads as a login wall.
    log(f"[verify_login_cua:{platform}] first pass said NO ({raw1[:30]}) — re-checking after settle", "INFO")
    try:
        await asyncio.sleep(3.5)
        # Kick a tiny scroll so lazy-hydrated UI paints (harmless if page ignores).
        try:
            await page.evaluate("() => window.scrollBy(0, 0)")
        except Exception:
            pass
    except Exception:
        pass
    # #705: the retry pass escalates the vision verdict to the heavy model
    # (Opus 4.8) — a stronger reader is worth the cost on a hard second look
    # at a possible login wall, matching vision tier-2's attempts>=2 rule.
    # The computer-use loop stays on Sonnet 4.6 (the CUA-recommended model);
    # only the vision VERDICT escalates.
    ok2, raw2 = await _cua_login_call(page, platform, cua_client, heavy=True)
    if ok2:
        log(f"[verify_login_cua:{platform}] LOGGED IN ✓ on retry (Opus: {raw2[:30]})", "INFO")
        return True

    log(f"[verify_login_cua:{platform}] NOT LOGGED IN ✗ (Claude both passes: '{raw1[:20]}' / '{raw2[:20]}')", "INFO")
    return False


# ── Auth check after resume navigation ───────────────────────────────────

async def check_auth(page, platform):
    """Verify page isn't a login wall after navigating to a saved chat URL.
    Returns True if authenticated, raises SessionExpiredError if login detected."""
    try:
        url = page.url.lower()
        # Platform-specific login URL patterns
        login_patterns = {
            "chatgpt": ["auth.openai.com", "/login", "chat.openai.com/auth"],
            "gemini": ["accounts.google.com", "/signin"],
            "claude": ["claude.ai/login", "claude.ai/signup", "/auth"],
            "notebooklm": ["accounts.google.com"],
        }
        patterns = login_patterns.get(platform.lower(), ["/login", "/signin", "/auth"])
        for p in patterns:
            if p in url:
                raise SessionExpiredError(
                    f"{platform} session expired — page redirected to {url[:80]}")
        # Additional DOM check: look for login form / sign-in button
        try:
            has_login = await page.evaluate("""() => {
                const text = document.body.innerText.toLowerCase();
                return (text.includes('sign in') || text.includes('log in')) &&
                       (document.querySelector('input[type="password"]') !== null);
            }""")
            if has_login:
                raise SessionExpiredError(f"{platform} session expired — login form detected")
        except SessionExpiredError:
            raise
        except Exception:
            pass
        return True
    except SessionExpiredError:
        raise
    except Exception as e:
        log(f"[auth-check] {platform}: {e}", "WARN")
        return True  # On generic errors, assume OK to avoid false positives


# ── Paste-as-followup primitive ─────────────────────────────────────────

async def paste_followup(page, text, platform, label="followup"):
    """Paste text into the page's input field and send as a follow-up message.
    Reuses verified_paste_brief's strategies but without brief-level verification."""
    try:
        # Scroll to bottom + focus input
        try:
            await page.keyboard.press("End")
        except Exception:
            pass
        await asyncio.sleep(0.3)
        # Use verified_paste_brief with a lower retry count — it clicks and pastes
        ok = await verified_paste_brief(page, text, platform, label, max_retries=2)
        if not ok:
            return False
        # Click send button
        for sel in ['button[data-testid="send-button"]',
                    'button[aria-label="Send prompt"]',
                    'button[aria-label="Send"]',
                    'button[aria-label="Send message"]',
                    'button[aria-label="Submit"]']:
            try:
                btn = await page.query_selector(sel)
                if btn and await btn.is_enabled():
                    await btn.click()
                    await asyncio.sleep(1)
                    return True
            except Exception:
                continue
        # JS fallback
        try:
            sent = await page.evaluate("""() => {
                const btns = document.querySelectorAll('button');
                for (const b of btns) {
                    const a = (b.getAttribute('aria-label') || '').toLowerCase();
                    if ((a.includes('send') || a.includes('submit')) && !b.disabled) {
                        b.click(); return true;
                    }
                }
                return false;
            }""")
            return bool(sent)
        except Exception:
            return False
    except Exception as e:
        log(f"[paste_followup] {platform}: {e}", "WARN")
        return False


# ── Check if agent is still generating (cheap DOM) ───────────────────────

async def is_agent_generating(page, platform):
    """Cheap DOM check: is the page showing a stop/loading indicator?"""
    try:
        sel_map = {
            "chatgpt": 'button[data-testid="stop-button"], button[aria-label*="Stop"], [data-testid*="loading"]',
            # #897b: Gemini's collapsed composer often shows NO stop button
            # mid-run — without the broader new-UI running signals the
            # dispatcher would read a live DR as "finished" and silently
            # drop the user's mid-run chat (review catch).
            "gemini": ('button[aria-label*="Stop"], [role="button"][aria-label*="stop" i], '
                       '[jsname] [role="progressbar"], [data-is-streaming="true"], '
                       '.loading-indicator, .streaming'),
            "claude": 'button[aria-label*="Stop"], [data-testid*="stop"]',
        }
        sel = sel_map.get(platform.lower(), 'button[aria-label*="Stop"]')
        el = await page.query_selector(sel)
        return el is not None
    except Exception:
        return False  # On error assume not generating


# ── Mid-run Input Dispatcher ──────────────────────────────────────────────

async def run_input_dispatcher(poll_interval=2.0):
    """Background task that watches _controls.extra_context and, if pipeline is
    actively running with live pages, dispatches user input immediately to the
    respective active agent chats as follow-up messages.

    If paused, does nothing — pause/resume flow handles buffered context.
    If between phases (no active pages for that phase), input stays buffered
    for the next phase to consume."""
    log("[dispatcher] Mid-run input dispatcher started")
    try:
        while True:
            await asyncio.sleep(poll_interval)
            # Skip if stopped, paused, or nothing to dispatch
            if _controls.is_stop():
                return
            if _controls.is_pause():
                continue
            if not _controls.peek_extra_context():
                continue
            # Only dispatch to live agent pages
            if not _runtime.active_pages:
                continue  # No active agents — buffer stays for next phase
            text = _controls.pop_extra_context()
            if not text:
                continue
            log(f"[dispatcher] Dispatching {len(text)} chars to {list(_runtime.active_pages.keys())}")
            # Snapshot active pages (avoid mutation during iteration)
            targets = list(_runtime.active_pages.items())
            for platform, page in targets:
                try:
                    # Race guard: re-check status just before paste
                    status_before = _runtime.agent_statuses.get(platform, "generating")
                    if status_before != "generating":
                        continue
                    is_gen = await is_agent_generating(page, platform)
                    if not is_gen and status_before == "generating":
                        # Status flipped to done between registration and now — mark for restart
                        log(f"[dispatcher] {platform} finished before dispatch — skipping (will be handled on next pause/resume)", "WARN")
                        continue
                    ok = await paste_followup(page, text, platform, label=f"dispatcher-{platform}")
                    if ok:
                        emit_event("user_input_dispatched", phase=_runtime.phase,
                                   agent=platform, chars=len(text))
                        log(f"[dispatcher] Sent follow-up to {platform}")
                    else:
                        log(f"[dispatcher] Failed to send follow-up to {platform}", "WARN")
                        # Re-buffer so user input isn't lost
                        _controls.add_context(text)
                        break
                except Exception as e:
                    log(f"[dispatcher] Error dispatching to {platform}: {e}", "WARN")
    except asyncio.CancelledError:
        log("[dispatcher] Cancelled")
        raise


# ── Pause/Resume: Close browser + relaunch ──────────────────────────────

async def pause_and_close_browser(browser, queue_dir, phase, extra_kwargs=None):
    """Save pause checkpoint → close browser → block until resume or stop."""
    _runtime.phase = phase
    # Write checkpoint snapshot
    save_pause_checkpoint(queue_dir, extra=extra_kwargs)
    # Emit paused event with snapshot payload (frontend already shows links)
    try:
        emit_event("pipeline_paused", phase=phase,
                   snapshot=_runtime.snapshot())
    except Exception:
        pass
    # Close browser if active (Phase 0 guard: may be None)
    if browser is not None:
        try:
            if browser.context is not None:
                log("[pause] Closing browser for resource-efficient pause...")
                await browser.close()
        except Exception as e:
            log(f"[pause] Browser close error: {e}", "WARN")
    # Clear active pages — they're dead page refs now
    _runtime.active_pages.clear()
    # Block on pause event
    await _controls.wait_if_paused()
    # On resume, caller handles relaunch
    return _controls.is_stop()  # True if stopped during pause


async def resume_browser_from_checkpoint(browser, queue_dir):
    """Relaunch browser, navigate to saved agent chat URLs, verify auth.
    Returns dict of {platform: page} for recovered agents."""
    cp = load_pause_checkpoint(queue_dir) or {}
    # Restore runtime state from checkpoint
    if cp:
        _runtime.phase = cp.get("phase", _runtime.phase)
        _runtime.sub_state = cp.get("sub_state", "")
        _runtime.agent_chat_urls = dict(cp.get("agent_chat_urls", {}))
        _runtime.agent_statuses = dict(cp.get("agent_statuses", {}))
        _runtime.original_inputs = dict(cp.get("original_inputs", {}))
    log(f"[resume] Relaunching browser for phase {_runtime.phase} ({_runtime.sub_state or 'idle'})")
    await browser.start()
    restored = {}
    for platform, url in list(_runtime.agent_chat_urls.items()):
        status = _runtime.agent_statuses.get(platform, "done")
        if status == "done":
            continue  # Don't reopen completed agents
        if not url:
            continue
        try:
            page = await browser.new_tab(url)
            await asyncio.sleep(3)
            try:
                await check_auth(page, platform)
            except SessionExpiredError as e:
                log(f"[resume] {e}", "ERROR")
                fail_agent(platform,
                           f"{platform.capitalize()} session expired",
                           f"{platform.capitalize()} signed out. Sign back in using the open browser, then Retry — or Skip it.")
                continue
            restored[platform] = page
            _runtime.register_page(platform, page, url)
            log(f"[resume] {platform} restored at {url[:80]}")
        except Exception as e:
            log(f"[resume] {platform} reopen failed: {e}", "WARN")
    # Reset dedup cache
    global _last_progress
    _last_progress = {}
    # C3 (2026-04-28): dropped the `pipeline_recovered` info banner — crash
    # recovery is autonomous-first now (checkpoint enrichment + tier
    # framework handle it without user intervention). Only `pipeline_resumed`
    # is emitted for telemetry / chat narrator.
    emit_event("pipeline_resumed", phase=_runtime.phase,
               restored=list(restored.keys()))
    clear_pause_checkpoint(queue_dir)
    return restored


# ── Link Extraction ──────────────────────────────────────────────────────────

# ── Link Validation — single source of truth for URL correctness ─────────────

# Per-platform patterns that indicate a REAL public/shareable link (not a page URL)
_LINK_VALIDATORS = {
    "chatgpt": lambda u: "chatgpt.com/share/" in u,
    "gemini":  lambda u: ("gemini.google.com/share" in u or "g.co/gemini" in u),
    "claude":  lambda u: ("claude.site/artifacts/" in u or "claude.site/" in u),
    "notebooklm": lambda u: "notebooklm.google.com/notebook/" in u,
    "youtube": lambda u: ("youtu.be/" in u or "youtube.com/watch?v=" in u),
    # Require the `/document/d/` doc-id segment — `/document/` alone
    # matches the home page (`/document/u/0/?usp=docs_home`), the create
    # tab (`/document/create`), and other non-doc surfaces. Without `/d/`
    # the validator was letting through pages that look like docs but
    # have no doc-id, causing P5 to early-return as if creation failed.
    "gdocs":   lambda u: "docs.google.com/document/d/" in u,
}

# Known BAD URLs that must NEVER be emitted as links
_BAD_URL_PATTERNS = [
    "studio.youtube.com",       # YouTube Studio (not a video link)
    "chatgpt.com/c/",           # ChatGPT conversation (not shared)
    "chatgpt.com/?model",       # ChatGPT home
    "gemini.google.com/app",    # Gemini app (not shared)
    "claude.ai/new",            # Claude new chat
    "claude.ai/chat/",          # Claude conversation (not published artifact)
    "mail.google.com",          # Gmail (not a doc)
    "accounts.google.com",      # Auth page
]


# F4 / DGOPS-7451 — security constants for session-inheritance defenses.
# 2026-05-05 incident: Gemini Deep Research running inside the patchright
# profile inherited a persisted @distributedglobal.com Workspace session,
# navigated to dg-security-monitor.web.app, fired onAuthStateChanged
# silently, scraped 25k chars of dashboard data, auto-emailed it, and
# auto-created a public share link. Fix has 4 layers: pair-flow account
# separation (mitigation 2), run-start auth scrub (3), Playwright route
# deny-list (4), public-share visibility event (5).

# Default deny-list — tightened to DG-specific hostnames after PR review
# C5 (Copilot). Previously included blanket suffix entries (`web.app`,
# `firebaseapp.com`) which would block legitimate research sources hosted
# on Firebase Hosting. Operators can extend via DG_SECURITY_DENY_HOSTS
# env var (comma-separated) without code changes — addresses J1's "next
# adjacent leak" concern, where a new internal app deployed to a TLD not
# in the list would silently authenticate again. The audit-log event
# payload (security_blocked_navigation) includes the requesting page's
# referrer so post-hoc audit can answer "which page tried to navigate?"
# — the early-warning signal Jason flagged.
#
# Examples of TLDs to watch when expanding the list: *.web.app /
# *.firebaseapp.com / *.appspot.com / *.run.app / Vercel preview URLs /
# custom DG-owned domains. Add specific known hostnames, not blanket
# suffixes — the latter blocks legitimate research sources.
_SECURITY_DENY_HOSTS_DEFAULT = (
    "distributedglobal.com",        # DG corporate apex (incl. all subdomains)
    "dg-eng.com",                    # DG engineering apex (incl. all subdomains)
    "dg-security-monitor.web.app",  # Specific incident vector (2026-05-05)
)


def _read_security_deny_hosts() -> tuple:
    """Read deny-list at module load. DG_SECURITY_DENY_HOSTS env var
    (comma-separated) overrides the default list entirely. Operators
    can extend without code change. Restart --serve for changes to take
    effect."""
    raw = os.environ.get("DG_SECURITY_DENY_HOSTS", "").strip()
    if raw:
        return tuple(h.strip().lower() for h in raw.split(",") if h.strip())
    return _SECURITY_DENY_HOSTS_DEFAULT


_SECURITY_DENY_HOSTS = _read_security_deny_hosts()

# Emergency rollback (J2 principle preserved after SECURITY_SCRUB_MODE
# was deleted in DGOPS-7451 fix — the route deny-list is now the only
# load-bearing F4 defense, so operators need a kill switch in case it
# ever blocks legit research). Default "1" (active). Set to "0" to
# bypass M4 entirely. Restart --serve for changes to take effect.
DG_SECURITY_DENY_LIST_ENABLED = os.environ.get(
    "DG_SECURITY_DENY_LIST_ENABLED", "1") != "0"

# Google auth cookie names — used by _detect_persisted_google_auth in the
# pair flow to surface a prior Google account that would silently
# authenticate the agent on Workspace-protected resources.
_SECURITY_GOOGLE_AUTH_COOKIE_NAMES = (
    "SAPISID", "APISID",
    "__Secure-1PSID", "__Secure-3PSID",
    "__Secure-1PSIDCC", "__Secure-3PSIDCC",
    "__Secure-1PAPISID", "__Secure-3PAPISID",
    "SID", "HSID", "SSID", "SIDCC", "LSID",
)

# Agent platform domains — used by _detect_persisted_google_auth (M2)
# to distinguish "user intentionally paired this account" from "different
# Google account leaked into profile." Subdomains where Gemini /
# NotebookLM / YouTube store their durable platform sessions are
# exempted from M2's pair-flow auth detection so legitimate re-pair on
# the same account doesn't trigger refusal.
_SECURITY_PRESERVE_PLATFORM_DOMAINS = (
    "gemini.google.com",
    "notebooklm.google.com",
    "studio.youtube.com",
    "chatgpt.com",
    "claude.ai",
    "claude.site",
)

# #898b — scrub-only preserve list. Google/YouTube sessions live in APEX
# cookies (SID / __Secure-1PSID on .google.com, not gemini.google.com), so
# the scrub's "never clear a platform session" guarantee must cover the
# parent domains too. Kept SEPARATE from the tuple above: M2's pair-flow
# second-account detection (_detect_persisted_google_auth) must keep
# flagging apex .google.com auth cookies, so it stays on the narrow list.
# M4's route block makes a deliberate google.com/youtube.com deny entry
# unusable for this pipeline anyway — preserving them here costs nothing.
_SECURITY_SCRUB_PRESERVE_DOMAINS = _SECURITY_PRESERVE_PLATFORM_DOMAINS + (
    "google.com",
    "youtube.com",
)


def _matches_security_deny_host(host: str) -> str | None:
    """Return the matching F4 deny-list pattern if the host endswith any of
    the deny suffixes, else None. Suffix-match catches subdomains
    (e.g. dg-security-monitor.web.app matches "web.app")."""
    if not host:
        return None
    h = host.lower()
    for pat in _SECURITY_DENY_HOSTS:
        if h == pat or h.endswith("." + pat):
            return pat
    return None


async def _detect_persisted_google_auth(context) -> dict | None:
    """Inspect the browser context for a persisted Google account login.
    Returns a redacted summary if any Google auth cookie is present, else
    None. Used by --pair to refuse adding a second account silently
    (F4 mitigation 2 / DGOPS-7451). Read-only — no navigation."""
    try:
        cookies = await context.cookies()
    except Exception as e:
        log(f"[security] cookie read failed during pair preflight: {e}", "WARN")
        return None
    matches: list[dict] = []
    for c in cookies:
        name = c.get("name") or ""
        domain = (c.get("domain") or "").lower()
        if name not in _SECURITY_GOOGLE_AUTH_COOKIE_NAMES:
            continue
        if not (domain.endswith(".google.com") or domain == "google.com"):
            continue
        # Permit platform-session cookies (Gemini/NotebookLM live on
        # subdomains) — distinct from auth-management surfaces.
        if any(domain == d or domain.endswith("." + d) for d in _SECURITY_PRESERVE_PLATFORM_DOMAINS):
            continue
        matches.append({"name": name, "domain": domain, "valueLen": len(c.get("value") or "")})
    if not matches:
        return None
    return {
        "cookieMatches": len(matches),
        "sample": [f"{m['name']}@{m['domain']}=[redacted, {m['valueLen']} chars]" for m in matches[:3]],
    }


async def _scrub_persisted_google_auth(context, *, scope: str = "run", reason: str = "") -> dict:
    """Scrub cookies on internal-infra deny-list hosts BEFORE agents take
    control. F4 mitigation 3 / DGOPS-7451 — defense-in-depth alongside
    M4's network-layer route deny-list installed in Browser.start.
    Never touches Google domains.

    Originally this function also wiped localStorage / sessionStorage /
    IndexedDB on accounts.google.com + myaccount.google.com on every run,
    plus cleared cookies on those auth-management surfaces. Removed
    2026-05-07 — see commit "fix(F4): drop Google-domain auth scrub" —
    after that storage wipe was found to cascade-invalidate Gemini /
    NotebookLM / YouTube / Gmail / GoogleDoc sessions on every pipeline
    run by removing cross-origin sign-in propagation state, even though
    apex .google.com cookies were correctly preserved.

    The load-bearing defense for the 2026-05-05 incident vector is M4
    (network-layer block on web.app / firebaseapp.com /
    distributedglobal.com / dg-eng.com). M3 is now narrow defense-in-
    depth — clears any leftover cookies on those internal-infra hosts so
    state doesn't accumulate even though M4 would block any navigation
    that tried to use them.

    Best-effort throughout — any one cookie clear failing must not break
    the pipeline. Errors logged, not raised."""
    summary = {"scope": scope, "reason": reason,
               "cookiesCleared": 0, "originsCleared": 0, "errors": []}

    try:
        cookies = await context.cookies()
    except Exception as e:
        summary["errors"].append(f"cookie read: {e}")
        cookies = []
    to_clear: list[dict] = []
    for c in cookies:
        domain = (c.get("domain") or "").lower()
        # #898b hard allow-list: platform-session domains can NEVER be
        # scrubbed, even if a misconfigured DG_SECURITY_DENY_HOSTS ever
        # named one (e.g. a bare "google.com" entry). Uses the SCRUB list
        # (platform subdomains + apex google.com/youtube.com — the Google
        # session actually lives in apex SID/__Secure-1PSID cookies).
        # Clearing a platform cookie silently signs a worker out and resets
        # the trust the user built — the invariant is "profiles are never
        # cleared except --unpair --deep". M4's network-layer route block
        # stays the load-bearing F4 defense.
        _bare = domain.lstrip(".")
        if any(_bare == d or _bare.endswith("." + d)
               for d in _SECURITY_SCRUB_PRESERVE_DOMAINS):
            continue
        if _matches_security_deny_host(_bare):
            to_clear.append(c)
    for c in to_clear:
        try:
            await context.clear_cookies(name=c.get("name"), domain=c.get("domain"))
            summary["cookiesCleared"] += 1
        except Exception as e:
            summary["errors"].append(f"cookie clear {c.get('name')}@{c.get('domain')}: {e}")

    log(f"[security] scrub({scope}): cookies={summary['cookiesCleared']}, "
        f"errors={len(summary['errors'])}", "INFO")
    try:
        emit_event("security_scrub", **summary)
    except Exception:
        pass
    return summary


def validate_link(platform: str, url: str) -> bool:
    """Check if a URL is a REAL shareable link for the given platform.
    Returns False for page URLs, studio URLs, and other non-shareable URLs."""
    if not url or not url.startswith("http"):
        return False
    # Reject known bad patterns
    for bad in _BAD_URL_PATTERNS:
        if bad in url:
            return False
    # Check platform-specific validator
    validator = _LINK_VALIDATORS.get(platform.lower().replace(" ", ""))
    if validator:
        return validator(url)
    # Unknown platform — reject to prevent bad URLs from leaking through
    log(f"validate_link: unknown platform '{platform}' — rejecting {url[:60]}", "WARN")
    return False


def emit_validated_link(phase: int, agent: str, url: str, label: str, link_kind: str = ""):
    """Emit a link_extracted event ONLY if the URL passes validation.
    Returns True if emitted, False if rejected. Also writes to the research
    doc's `links.{kind}` aggregate map — P5 reads from there to compose
    the Doc body (single source of truth, no event-log replay needed).

    `link_kind` overrides the Firestore aggregate key when it differs from
    the FE event's `agent` field — e.g. audio-overview emits as
    agent="notebooklm" (FE groups under the NLM dropdown) but stores as
    "audio" in the aggregate so P5 picks it up as a separate URL.
    """
    verified = validate_link(agent, url)
    if not verified:
        log(f"[{label}] Link REJECTED — not a valid public link: {url[:80]}", "WARN")
        return False
    emit_event("link_extracted", phase=phase, agent=agent,
               url=url, label=label, verified=True)
    update_link_in_firestore(link_kind or agent, url, label=label, phase=phase, verified=True)
    log(f"[{label}] Link VERIFIED: {url}")
    return True


class LinkResult:
    """Result of a link extraction attempt.

    cua_attempted: True if the extractor's internal CUA fallback ran. Lets
    callers (extract_and_record_agent Step 4b) skip a SECOND CUA pass on
    the same UI surface when the first already had a turn — avoids
    wonky-modal misclicks on share dialogs (caused Gemini tab spam).
    """
    __slots__ = ("url", "label", "platform", "verified", "error", "cua_attempted")

    def __init__(self, url="", label="", platform="", verified=False, error="", cua_attempted=False):
        self.url = url
        self.label = label
        self.platform = platform
        self.verified = verified
        self.error = error
        self.cua_attempted = cua_attempted

    def to_dict(self):
        return {"url": self.url, "label": self.label, "verified": self.verified}

    @property
    def success(self):
        return bool(self.url) and not self.error


async def extract_share_link_chatgpt(browser, cua_client, label="Research Brief", verbose=False):
    """Extract shareable ChatGPT link: Share button → Create link → copy URL.

    Iframe short-circuit (2026-04): ChatGPT Deep Research renders inside a
    cross-origin sandbox iframe that often intercepts pointer events on the
    host Share button. Default Playwright click retries for 30s per attempt
    and then throws. We use a 3s click timeout so the iframe-intercept path
    fails fast — the caller (extract_and_record_agent) then falls back to
    the chat URL without burning 90s across retries."""
    page = browser.page
    url = await browser.current_url() or ""
    cua_attempted = False
    try:
        # 2026-04-26: close-first preamble — any open citations panel,
        # plan-item drawer, or modal can intercept the Share button click.
        # Mirror of Claude's pattern at the top of extract_share_link_claude.
        try:
            await page.evaluate("""() => {
                const close = document.querySelector(
                    '[role="dialog"] button[aria-label*="Close"], ' +
                    '[role="dialog"] button[aria-label*="close"], ' +
                    'button[aria-label*="Close panel"], ' +
                    'button[aria-label*="Close sources"]'
                );
                if (close) close.click();
            }""")
            await asyncio.sleep(0.5)
        except Exception:
            pass
        # Step 1: Try Playwright — find share button
        share_btn = None
        for sel in ['button[aria-label="Share"]', '[data-testid="share-chat-button"]',
                    'button:has(svg[data-testid="share-icon"])']:
            share_btn = await page.query_selector(sel)
            if share_btn:
                break
        if share_btn:
            # Short-timeout click — iframe intercepts surface as timeout here,
            # and we want to abort the public-share path immediately rather
            # than waste 30s per retry attempt.
            try:
                await share_btn.click(timeout=3000)
            except Exception as _ce:
                log(f"[{label}] Share click short-circuited ({_ce}) — public-link fast-fail", "WARN")
                return LinkResult(url=url, label=label, platform="chatgpt",
                                  verified=False, error=f"share_click_intercept: {_ce}")
            await asyncio.sleep(2)
            # Look for "Create link" or "Copy link" button in modal
            link_btn = None
            for sel in ['button:has-text("Create link")', 'button:has-text("Copy link")',
                        'button:has-text("Share")', '[data-testid="share-link-button"]']:
                link_btn = await page.query_selector(sel)
                if link_btn:
                    break
            if link_btn:
                try:
                    await link_btn.click(timeout=3000)
                except Exception as _ce2:
                    log(f"[{label}] Create/Copy link click short-circuited ({_ce2})", "WARN")
                    return LinkResult(url=url, label=label, platform="chatgpt",
                                      verified=False, error=f"link_click_intercept: {_ce2}")
                await asyncio.sleep(2)
            # PRIMARY — try to get URL from input field in modal
            share_input = await page.query_selector('input[readonly][value*="chatgpt.com/share"]')
            if share_input:
                url = await share_input.get_attribute("value") or url
            # SECONDARY — read the browser's clipboard directly (the "Copy link"
            # button wrote the public /share/ URL into it). This is far more
            # reliable than asking CUA to recover it via screenshots.
            # 2s wait_for: a clipboard permission prompt or a busy clipboard
            # used to hang this evaluate() indefinitely on Windows.
            if "chatgpt.com/share" not in url:
                try:
                    clip_js = await asyncio.wait_for(
                        page.evaluate("navigator.clipboard.readText()"),
                        timeout=2.0,
                    )
                    if clip_js and "chatgpt.com/share" in clip_js:
                        url = clip_js.strip()
                        log(f"[{label}] Share URL recovered from browser clipboard: {url}")
                except (asyncio.TimeoutError, Exception):
                    # clipboard-read permission may be denied / hung; fall through
                    pass
            # TERTIARY — Windows OS clipboard via PowerShell. PowerShell can
            # block on a locked clipboard (antivirus / another process holding
            # it); cap with a 3s deadline so the pipeline doesn't stall.
            if "chatgpt.com/share" not in url:
                try:
                    clip = await asyncio.wait_for(
                        asyncio.to_thread(get_clipboard),
                        timeout=3.0,
                    )
                    if "chatgpt.com/share" in (clip or ""):
                        url = clip
                except (asyncio.TimeoutError, Exception):
                    pass
            # Track-B success-path observe (ChatGPT share). If the DOM produced a
            # public /share/ URL, capture the REAL target bbox from the Share/Copy
            # handle BEFORE the modal Escape (the handles go stale after), then
            # fire-and-forget the Vision observe. Gated so the bounding_box() await
            # only runs when the success-observer is armed.
            if "chatgpt.com/share" in url and _vision is not None and observe_success_enabled():
                try:
                    _box = None
                    _sbtn = link_btn or share_btn
                    if _sbtn is not None:
                        _bb = await _sbtn.bounding_box()
                        _vp = page.viewport_size or {}
                        if _bb and _vp.get("width") and _vp.get("height"):
                            _box = {"cx": _bb["x"] + _bb["width"] / 2,
                                    "cy": _bb["y"] + _bb["height"] / 2,
                                    "vw": _vp["width"], "vh": _vp["height"]}
                    _observe_dom_success(page, hotspot_id="p2-share", phase=2, platform="chatgpt",
                                         current_step="open_share_menu_and_create_link",
                                         dom_ground_truth=_gt_from_box(_box, url=url))
                except Exception as _obe:
                    log(f"[{label}] p2-share observe (chatgpt) skipped: {_obe}", "DEBUG")
            # Close modal
            await page.keyboard.press("Escape")
            await asyncio.sleep(0.5)
        # Step 2: CUA fallback if no share URL yet. Hard-cap at 120s — the
        # agent_loop's max_iterations=6 doesn't bound wall-clock time, so a
        # stuck CUA could loiter for many minutes. The wait_for keeps the
        # share-link path bounded and reachable.
        # Shadow-wrapped (Track A telemetry on the "p2-share" hotspot) so
        # Vision tier-2 observes in parallel and accumulates agreement data
        # for autonomous promotion.
        if "chatgpt.com/share" not in url:
            log(f"[{label}] CUA fallback for share link...")
            cua_attempted = True
            emit_tier_transition(phase=2, agent="chatgpt",
                op="p2_share_extract", from_tier="dom", to_tier="cua",
                reason="iframe_share_intercept")
            async def _chatgpt_share_cua():
                return await asyncio.wait_for(
                    agent_loop(cua_client, browser,
                        "Share this ChatGPT conversation by clicking the Share button.",
                        "Click the Share button at the top of this conversation. If a modal appears, click 'Create link' or 'Copy link'. After clicking Copy link, just STOP — don't try to extract the URL yourself, the code will read it from the clipboard.",
                        model=CUA_MODEL, max_iterations=6, verbose=verbose),
                    timeout=120.0,
                )
            try:
                result = await _shadow_observed_cua(
                    page, hotspot_id="p2-share", phase=2, platform="chatgpt",
                    current_step="open_share_menu_and_create_link",
                    context_hint="P2 ChatGPT share-link extraction (DR iframe path)",
                    expected_outcome="public-share URL on clipboard",
                    cua_coro_factory=_chatgpt_share_cua,
                    mission_prompt=(
                        "Share this ChatGPT conversation by clicking the Share button. "
                        "Click the Share button at the top of this conversation. If a modal "
                        "appears, click 'Create link' or 'Copy link'. After clicking Copy "
                        "link, just STOP — don't try to extract the URL yourself, the code "
                        "will read it from the clipboard."),
                    act_timeout_s=60.0)
            except asyncio.TimeoutError:
                log(f"[{label}] CUA share-link extraction timed out (120s) — using current URL as fallback", "WARN")
                result = {"text": ""}
            text = (result.get("text") or "")
            # Extract URL from CUA response (if it happened to observe one)
            m = re.search(r'https://chatgpt\.com/share/[a-zA-Z0-9-]+', text)
            if m:
                url = m.group(0)
            # After CUA clicked "Copy link", read the browser clipboard directly
            if "chatgpt.com/share" not in url:
                try:
                    clip_js = await asyncio.wait_for(
                        page.evaluate("navigator.clipboard.readText()"),
                        timeout=2.0,
                    )
                    if clip_js and "chatgpt.com/share" in clip_js:
                        url = clip_js.strip()
                        log(f"[{label}] Share URL recovered from clipboard after CUA share click: {url}")
                except (asyncio.TimeoutError, Exception):
                    pass
            if "chatgpt.com/share" not in url:
                try:
                    clip = await asyncio.wait_for(
                        asyncio.to_thread(get_clipboard),
                        timeout=3.0,
                    )
                    if "chatgpt.com/share" in (clip or ""):
                        url = clip
                except (asyncio.TimeoutError, Exception):
                    pass
        verified = "chatgpt.com/share" in url
        return LinkResult(url=url, label=label, platform="chatgpt", verified=verified,
                          cua_attempted=cua_attempted)
    except Exception as e:
        log(f"Link extraction failed (ChatGPT): {e}", "WARN")
        return LinkResult(url=url, label=label, platform="chatgpt", error=str(e),
                          cua_attempted=cua_attempted)


async def _gemini_share_closer(new_page):
    """Per-page event handler for Gemini share-preview tab closure.

    Closes any page that settles to a `gemini.google.com/share/<id>`
    or `g.co/gemini/<id>` URL. Used inside `extract_share_link_gemini`
    to catch preview tabs that Gemini's Share & Export dialog
    spontaneously spawns when the public-link toggle flips. Mirrors
    `_guard_popup`'s URL-settle pattern (8 × 0.5s polls) so timing
    matches the global guard's allowlist evaluation.

    Path-boundary match (`/share/` and `/gemini/` with the trailing
    slash) — prevents false-positives on neighbouring paths like
    `gemini.google.com/sharer` or `gemini.google.com/shared` or a
    foreign URL that contains "g.co/gemini" as a substring (e.g. a
    Reddit/Twitter URL embedding the share-link as a query parameter).

    Top-level (not closure-captured) so unit tests can call it directly
    with a mock page object.
    """
    try:
        url = ""
        for _ in range(8):  # 8 × 0.5s = 4s window (matches _guard_popup)
            try:
                url = new_page.url or ""
            except Exception:
                return
            if url and url != "about:blank":
                break
            await asyncio.sleep(0.5)
        if not url or url == "about:blank":
            return
        # Path-boundary check — `/share/` and `/gemini/` with the
        # trailing slash ensures we match share-PREVIEW URLs only,
        # not legitimate gemini.google.com/app/* or g.co/gemini-app
        # variants that happen to contain "gemini" as a substring.
        try:
            from urllib.parse import urlparse
            parsed = urlparse(url)
            host = (parsed.hostname or "").lower()
            path = parsed.path or ""
        except Exception:
            return
        is_share_preview = (
            (host == "gemini.google.com" and path.startswith("/share/")) or
            (host == "g.co" and path.startswith("/gemini/"))
        )
        if is_share_preview:
            try:
                await new_page.close()
            except Exception:
                pass
    except Exception:
        pass


async def extract_share_link_gemini(browser, cua_client, label="Gemini Deep Research", verbose=False):
    """Extract shareable Gemini conversation link with public visibility.

    Architecture: DOM-once → CUA. Each DOM stage (open dialog, click
    public-link submenu, set visibility, read URL) makes ONE click attempt
    using a selector fallback chain — not multi-attempt. If the URL
    isn't verified after the DOM pass, ONE CUA mission (90 s budget) gets
    a chance. `cua_attempted` flag stops the caller (extract_and_record_agent
    Step 4b) from running a SECOND redundant CUA pass.

    Hardened 2026-04-25:
    - Added "Export & save" label variants (current Gemini Deep Research
      UI sometimes uses this instead of "Share & Export").
    - Wrapped the CUA fallback in a 90 s timeout so a stuck CUA loop can't
      starve the inline 90 s outer budget at the call-site.
    - Structured error attribution: errors are tagged in `LinkResult.error`
      with a short stage tag (`open_dialog` / `public_toggle` / `link_lookup`
      / `cua_fallback`) so operators can see *where* the flow failed.

    Hardened 2026-05-24:
    - Wrapped the body in `_gemini_share_preview_guard` so preview tabs
      Gemini spontaneously spawns when the public-link toggle flips
      are closed in ~ms (instead of accumulating until the finally-block
      snapshot diff fires). Eliminates the visible 5-tab pileup users
      observed during long (50-90s) extraction windows.
    """
    page = browser.page
    url = await browser.current_url() or ""
    last_stage = "init"
    cua_attempted = False
    # 2026-04-29 dup-tabs hardening: snapshot the page set so we can close
    # any *new* gemini.google.com tab that opens during this function. The
    # popup-guard allowlist permits gemini.google.com/share/... so the
    # global guard (BrowserManager._guard_popup) won't catch a duplicate
    # share-page tab on its own. Function-scoped guard runs in the
    # `finally` below.
    try:
        _pages_snapshot = set(getattr(browser.context, "pages", []))
    except Exception:
        _pages_snapshot = set()
    # 2026-05-24: real-time share-preview tab closer. Catches share-URL
    # tabs the instant they spawn (Gemini's dialog spontaneously opens
    # `gemini.google.com/share/...` preview tabs when the public-link
    # toggle flips). Wrap `_gemini_share_closer` in a unique local
    # closure per call so `remove_listener` targets EXACTLY this call's
    # listener — defensive against any future caller running multiple
    # share-extracts in parallel against the same BrowserContext (which
    # would otherwise accumulate duplicate handlers as pyee's
    # EventEmitter allows duplicate registrations and remove_listener
    # only removes one match at a time).
    async def _share_preview_closer(new_page):
        await _gemini_share_closer(new_page)
    _share_preview_listener_attached = False
    try:
        browser.context.on("page", _share_preview_closer)
        _share_preview_listener_attached = True
    except Exception:
        pass
    try:
        # 2026-04-26: close-first preamble — close any open dialog/drawer
        # that could intercept the Share & Export click. Same pattern as
        # Claude (extract_share_link_claude) and ChatGPT.
        try:
            await page.evaluate("""() => {
                const close = document.querySelector(
                    '[role="dialog"] button[aria-label*="Close"], ' +
                    '[role="dialog"] button[aria-label*="close"], ' +
                    'button[aria-label*="Close panel"], ' +
                    'mat-dialog-container button[aria-label*="Close"]'
                );
                if (close) close.click();
            }""")
            await asyncio.sleep(0.5)
        except Exception:
            pass
        # ── Open the share/export dialog ──
        # Current Gemini Deep Research UI variants seen:
        #   - "Share & Export" (post-2025 redesign)
        #   - "Share and export" (a11y-label variant)
        #   - "Export & save"   (newer 2026 redesign — added 2026-04-25)
        #   - "Share"           (legacy)
        # Try aria-label exact matches first, then partial matches, then
        # fall through to a text-content scan for variants without an
        # aria-label at all.
        last_stage = "open_dialog"
        share_opened = False
        for sel in [
            'button[aria-label="Share & Export"]',
            'button[aria-label="Share and export"]',
            'button[aria-label="Export & save"]',
            'button[aria-label="Export and save"]',
            'button[aria-label*="Share & Export"]',
            'button[aria-label*="Share and export"]',
            'button[aria-label*="Export & save"]',
            'button[aria-label*="Export and save"]',
            'button[aria-label="Share"]',
            'button[aria-label*="Share"]',
        ]:
            try:
                btn = await page.query_selector(sel)
                if btn:
                    await btn.click()
                    share_opened = True
                    await asyncio.sleep(2)
                    break
            except Exception:
                continue
        if not share_opened:
            try:
                clicked = await page.evaluate("""() => {
                    const btns = [...document.querySelectorAll('button')].filter(b => b.offsetParent !== null);
                    const target = btns.find(b => {
                        const t = (b.textContent || '').trim().toLowerCase();
                        return t === 'share & export' || t === 'share and export' ||
                               t === 'export & save' || t === 'export and save' ||
                               t === 'share';
                    });
                    if (target) { target.click(); return true; }
                    return false;
                }""")
                if clicked:
                    share_opened = True
                    await asyncio.sleep(2)
            except Exception:
                pass
        if share_opened:
            # "Share & Export" / "Export & save" opens a submenu (Create
            # public link / Export to Docs / Copy). Click the public-link
            # option before the link lookup, otherwise we land on the Export
            # flow.
            last_stage = "public_toggle"
            try:
                await page.evaluate("""() => {
                    const items = [...document.querySelectorAll(
                        '[role="menuitem"], [role="option"], button, li, a'
                    )].filter(el => el.offsetParent !== null);
                    const target = items.find(el => {
                        const t = (el.textContent || '').trim().toLowerCase();
                        return t === 'create public link' ||
                               t === 'public link' ||
                               t.includes('create public link') ||
                               t.includes('create a public link');
                    });
                    if (target) target.click();
                }""")
                await asyncio.sleep(1.5)
            except Exception:
                pass

            # ── Ensure public visibility ("Anyone with the link") ──
            # Gemini share dialog may default to Restricted — click through to public
            try:
                visibility_set = await page.evaluate("""() => {
                    // Strategy 1: Look for dropdown/button showing "Restricted" or "Only people"
                    const btns = document.querySelectorAll(
                        'button, [role="button"], [role="combobox"], [aria-haspopup]'
                    );
                    for (const btn of btns) {
                        const txt = (btn.innerText || btn.textContent || '').toLowerCase();
                        if (txt.includes('restricted') || txt.includes('only people')) {
                            btn.click();
                            return 'opened_dropdown';
                        }
                    }
                    // Strategy 2: Look for "Enable sharing" toggle
                    const toggles = document.querySelectorAll(
                        'input[type="checkbox"], [role="switch"], [aria-checked]'
                    );
                    for (const t of toggles) {
                        const label = (t.closest('label') || t.parentElement);
                        const txt = (label?.innerText || '').toLowerCase();
                        if (txt.includes('share') || txt.includes('public') || txt.includes('anyone')) {
                            if (t.getAttribute('aria-checked') === 'false' || !t.checked) {
                                t.click();
                                return 'toggled_on';
                            }
                            return 'already_on';
                        }
                    }
                    return '';
                }""")
                if visibility_set == 'opened_dropdown':
                    await asyncio.sleep(1)
                    # Select "Anyone with the link" from the dropdown
                    await page.evaluate("""() => {
                        const options = document.querySelectorAll(
                            '[role="option"], [role="menuitem"], [role="menuitemradio"], li'
                        );
                        for (const opt of options) {
                            const txt = (opt.innerText || opt.textContent || '').toLowerCase();
                            if (txt.includes('anyone with the link') || txt.includes('anyone')) {
                                opt.click();
                                return 'selected';
                            }
                        }
                        return '';
                    }""")
                    await asyncio.sleep(1)
                    log(f"[{label}] Set sharing to 'Anyone with the link'")
            except Exception as e:
                log(f"[{label}] Visibility selection attempt: {e}", "WARN")

            # Look for shareable link in modal
            last_stage = "link_lookup"
            link_el = await page.query_selector('input[value*="g.co/gemini"]')
            if not link_el:
                link_el = await page.query_selector('input[value*="gemini.google.com/share"]')
            if link_el:
                url = await link_el.get_attribute("value") or url
            else:
                # 2026-04-29 dup-tabs hardening: scope the copy-link click
                # to inside the share dialog ONLY, and require an exact
                # "Copy link" match. Previously selected ALL document
                # buttons + matched on a loose "copy" substring — that
                # could click a code-block "Copy code" button or a social-
                # share icon, both of which can spawn new tabs that
                # `gemini.google.com` allowlist permits.
                try:
                    await page.evaluate("""() => {
                        const dlg = document.querySelector(
                            '[role="dialog"], mat-dialog-container, [role="menu"], ' +
                            '[class*="cdk-overlay-pane"]'
                        );
                        if (!dlg) return '';
                        const isSocial = (b) => {
                            const cls = (b.className || '').toLowerCase();
                            const lbl = (b.getAttribute('aria-label') || '').toLowerCase();
                            return cls.includes('social') ||
                                   /twitter|facebook|email|reddit|linkedin|whatsapp/i.test(lbl);
                        };
                        // Prefer aria-label exact match.
                        const exact = dlg.querySelector(
                            'button[aria-label="Copy link"], button[aria-label*="Copy link" i]'
                        );
                        if (exact && !isSocial(exact)) { exact.click(); return 'aria'; }
                        // Text-content fallback within the dialog only;
                        // require exact "copy link" (no substring "copy").
                        const buttons = [...dlg.querySelectorAll('button')];
                        const target = buttons.find(b => {
                            if (isSocial(b)) return false;
                            const t = (b.textContent || '').trim().toLowerCase();
                            return t === 'copy link';
                        });
                        if (target) { target.click(); return 'text'; }
                        return '';
                    }""")
                    await asyncio.sleep(0.5)
                except Exception:
                    pass
                clip = get_clipboard()
                if "gemini" in clip and "share" in clip:
                    url = clip
            await page.keyboard.press("Escape")
            await asyncio.sleep(0.5)
        if "share" not in url.lower():
            # CUA fallback — explicit public sharing instructions, capped at
            # 90 s. Without the cap, an outer 90 s budget at the call-site
            # (extract_and_record_agent inline share extraction) could be
            # consumed entirely by a stuck CUA loop and still time out, with
            # the page never getting to even check the clipboard.
            last_stage = "cua_fallback"
            cua_attempted = True
            try:
                result = await asyncio.wait_for(
                    agent_loop(cua_client, browser,
                        PROMPT_SHARE_GEMINI,
                        "Click the Share button for this Gemini conversation. "
                        "IMPORTANT: Change the access to 'Anyone with the link' (not Restricted). "
                        "Then copy the shareable link and tell me the EXACT URL "
                        "(g.co/gemini/... or gemini.google.com/share/...).",
                        model=CUA_MODEL, max_iterations=12, verbose=verbose),
                    timeout=90.0,
                )
                m = re.search(r'https://[^\s]+gemini[^\s]*share[^\s]*', (result.get("text") or ""))
                if not m:
                    m = re.search(r'https://g\.co/gemini/[^\s]+', (result.get("text") or ""))
                if m:
                    url = m.group(0)
                else:
                    clip = get_clipboard()
                    if clip and ("gemini" in clip or "g.co" in clip) and "share" in clip:
                        url = clip
            except asyncio.TimeoutError:
                log(f"[{label}] CUA fallback exceeded 90s — using best-effort URL", "WARN")
                # Salvage: maybe CUA copied to clipboard before the timeout.
                clip = get_clipboard()
                if clip and ("gemini" in clip or "g.co" in clip) and "share" in clip:
                    url = clip
        # Tight public-link gate: Gemini's Share & Export flow produces URLs on
        # gemini.google.com/share/ or g.co/gemini/... — require one of those
        # explicitly so that a stale chat URL (gemini.google.com/app/...) or a
        # share-dialog URL never sneaks through as verified. The Phase 2 outer
        # loop will fall back to the chat URL silently with verified=False when
        # this gate fails.
        _lu = url.lower()
        verified = ("gemini.google.com/share" in _lu) or ("g.co/gemini" in _lu)
        return LinkResult(url=url, label=label, platform="gemini", verified=verified,
                          cua_attempted=cua_attempted)
    except Exception as e:
        return LinkResult(url=url, label=label, platform="gemini",
                          error=f"{last_stage}: {type(e).__name__}: {e}",
                          cua_attempted=cua_attempted)
    finally:
        # 2026-05-24: deregister the real-time share-preview listener
        # FIRST so subsequent (unrelated) page events post-extraction
        # don't accidentally close legitimate Gemini share tabs that
        # might be opened by a later flow. Log removal failures so an
        # operator can detect listener leaks accumulating across runs
        # (pyee's EventEmitter doesn't auto-prune on context teardown).
        if _share_preview_listener_attached:
            try:
                browser.context.remove_listener("page", _share_preview_closer)
            except Exception as _rle:
                log(f"[{label}] Failed to deregister share-preview listener "
                    f"(may accumulate on BrowserContext): {_rle}", "WARN")
        # 2026-04-29 dup-tabs hardening: close any pages that opened during
        # this function. Gemini's share dialog occasionally spawns a
        # `gemini.google.com/share/...` preview tab when the public-link
        # toggle flips, and the popup-guard allowlist permits it (correctly
        # — we don't want to close legitimate agent tabs globally). The
        # function-scoped diff catches duplicate share-page tabs without
        # weakening the global allowlist.
        # Post-2026-05-24: the real-time listener above catches most
        # tabs at spawn — this snapshot diff stays as belt-and-suspenders
        # for any that escape (e.g., if listener removal raced with a
        # late spawn event).
        try:
            _pages_after = set(getattr(browser.context, "pages", []))
            extras = (_pages_after - _pages_snapshot) - {page}
            for _p in extras:
                try:
                    await _p.close()
                except Exception:
                    pass
            if extras:
                log(f"[{label}] Closed {len(extras)} extra tab(s) opened during share extract "
                    f"(scoped guard caught what popup-guard's allowlist permits)", "INFO")
        except Exception as _ge:
            log(f"[{label}] Function-scoped tab guard failed (non-fatal): {_ge}", "DEBUG")


async def extract_share_link_claude(browser, cua_client, label="Claude Deep Research", verbose=False):
    """Extract shareable Claude artifact link.

    Hardened 2026-04-25:
    - **Close first, open last**: Claude conversations with multiple
      artifacts can leave a non-final artifact panel open after content
      extraction (e.g. the early "research plan" artifact, with the real
      deep-research output written to a SECOND artifact below it). The
      `publish_open_claude_artifact` primary path publishes whatever's
      open — if that's the wrong one, the URL we return points at the
      plan, not the report. Explicit close-1st-then-open-last sequence
      forces the correct selection before publishing.
    - **90 s CUA cap**: the CUA fallback is wrapped in asyncio.wait_for so
      a stuck CUA loop can't blow the inline 90 s outer budget.
    - **Stage-tagged errors** for operator visibility.
    """
    page = browser.page
    url = await browser.current_url() or ""
    last_stage = "init"
    cua_attempted = False
    try:
        # Step 1: close any currently-open artifact panel and open the
        # LAST artifact in the conversation (the deep-research output).
        last_stage = "select_last_artifact"
        try:
            # Close any open artifact panel first so the click-last targets
            # a fresh card, not whatever was previously open.
            await page.evaluate("""() => {
                const closeBtn = document.querySelector(
                    'aside button[aria-label*="Close"], aside button[aria-label*="close"]'
                );
                if (closeBtn) closeBtn.click();
            }""")
            await asyncio.sleep(0.5)
            # Use the unified helper instead of duplicating a divergent
            # selector list — this guarantees we click whatever
            # _count_claude_artifacts called the LAST card.
            opened_ok = await _click_claude_artifact(page, index=-1)
            if opened_ok:
                # Let the artifact panel render before publish_open_claude_artifact
                # tries to find its publish/share button.
                await asyncio.sleep(1.5)
            else:
                log(f"[{label}] No clickable artifact cards found via unified helper",
                    "DEBUG")
        except Exception as _ce:
            log(f"[{label}] artifact-select prelude skipped: {_ce}", "DEBUG")

        # Primary: try publishing via the (now correctly-selected) artifact panel
        last_stage = "publish_dom"
        # #735: publish_open_claude_artifact resets browser._claude_publish_cua_used
        # at entry and sets it True iff its own CUA fallback runs — so reading it
        # right after the call tells us whether a CUA pass already happened here
        # (covers the path where it returns a claude.ai URL that fails the
        # claude.site public gate below, which would otherwise let Step 4b fire
        # a redundant second CUA pass).
        published_url = await publish_open_claude_artifact(page, browser, cua_client, verbose=verbose)
        if getattr(browser, "_claude_publish_cua_used", False):
            # #735: publish_open ran its OWN CUA pass — count it so the caller's
            # Step 4b doesn't double it (notably when it returned a claude.ai
            # URL that fails the claude.site public gate below).
            cua_attempted = True
        if published_url and 'claude.' in published_url:
            url = published_url
        else:
            # Fallback: full CUA flow, capped at 90s so a stuck loop doesn't
            # blow the inline 90s outer budget at the call-site.
            last_stage = "cua_fallback"
            cua_attempted = True
            try:
                async def _publish_share_cua():
                    return await asyncio.wait_for(
                        agent_loop(cua_client, browser,
                            PROMPT_PUBLISH_CLAUDE,
                            "Publish the research ARTIFACT in the right panel (not the conversation). "
                            "If two artifacts exist, open the SECOND/bottom one first. "
                            "Click the Publish/Share icon on the artifact. "
                            "Get the published URL (claude.site/artifacts/... or claude.ai/...). "
                            "Tell me the URL.",
                            model=CUA_MODEL, max_iterations=12, verbose=verbose),
                        timeout=90.0,
                    )

                # #839 act tier: the URL must land in the returned text (the
                # mission's "Tell me the URL" → declare_success reason) or on
                # the clipboard — both read below, same as the CUA contract.
                result = await _shadow_observed_cua(
                    page, hotspot_id="publish-claude", phase=2, platform="claude",
                    current_step="publish_share_fallback",
                    context_hint="DOM publish didn't yield a claude.* URL — publish the "
                                 "artifact (SECOND/bottom if two) and read the public URL",
                    expected_outcome="a public claude.site/claude.ai URL is produced",
                    cua_coro_factory=_publish_share_cua,
                    mission_prompt=PROMPT_PUBLISH_CLAUDE,
                    act_timeout_s=40.0)  # bounded; the outer 90s wait_for is act-padded to fit CUA
                text = ((result or {}).get("text") or "")
                m = re.search(r'https://claude\.(?:site|ai)/[^\s]+', text)
                if m:
                    url = m.group(0)
                else:
                    clip = get_clipboard()
                    if clip and "claude." in clip:
                        url = clip
            except asyncio.TimeoutError:
                log(f"[{label}] CUA fallback exceeded 90s — using best-effort URL", "WARN")
                clip = get_clipboard()
                if clip and "claude." in clip:
                    url = clip
        # Tight public-link gate: Claude has a reliable Publish flow, so only a
        # claude.site/ URL counts as verified. A bare claude.ai/chat/... URL is
        # the user's own chat (not a public share) — the Phase 2 outer loop will
        # fall back to it silently with verified=False when this gate fails.
        verified = "claude.site" in url.lower()
        return LinkResult(url=url, label=label, platform="claude", verified=verified,
                          cua_attempted=cua_attempted)
    except Exception as e:
        return LinkResult(url=url, label=label, platform="claude",
                          error=f"{last_stage}: {type(e).__name__}: {e}",
                          cua_attempted=cua_attempted)


async def _set_nlm_public_and_get_link(page, label):
    """Shared helper: inside an open NotebookLM share dialog,
    set Notebook access → 'Anyone with the link', copy/get the link, click Save.

    Returns a tuple (url, public_verified) — `public_verified` is True only
    when the dialog DOM confirms the access dropdown reads "Anyone with the
    link" before save. NotebookLM private and public URLs share the same
    `/notebook/{id}` shape, so URL format alone can't tell them apart — DOM
    verification is the only way to know the link is genuinely shareable.
    Phase 3's caller treats `public_verified=False` as a soft failure (still
    returns the URL so the run can continue, but logs prominently)."""
    url = ""
    public_verified = False
    try:
        # Step 1: Find "Notebook access" section and change to public
        # NLM share dialog shows "Notebook access" with a dropdown (not "Restricted")
        changed = await page.evaluate("""() => {
            // Look for clickable elements near "Notebook access" text
            const allText = document.body.innerText || '';
            // Find dropdown/button that controls access level
            const btns = document.querySelectorAll(
                'button, [role="button"], [role="combobox"], [role="listbox"], select, [aria-haspopup]'
            );
            for (const btn of btns) {
                const txt = (btn.innerText || btn.textContent || '').toLowerCase();
                const parentTxt = (btn.closest('div')?.innerText || '').toLowerCase();
                // NotebookLM uses "Notebook access" section; the dropdown shows current state
                if (txt.includes('restricted') || txt.includes('only people') ||
                    txt.includes('not shared') || txt.includes('private') ||
                    (parentTxt.includes('notebook access') && (txt.includes('off') || txt.length < 30))) {
                    btn.click();
                    return 'opened';
                }
            }
            // Also try: any element labeled "Notebook access" that's clickable
            const labels = document.querySelectorAll('label, span, div, h3, h4');
            for (const lbl of labels) {
                const txt = (lbl.innerText || '').toLowerCase();
                if (txt.includes('notebook access')) {
                    // Click the next sibling or the nearest button
                    const next = lbl.nextElementSibling || lbl.parentElement;
                    const btn = next?.querySelector('button, [role="button"], select');
                    if (btn) { btn.click(); return 'opened'; }
                }
            }
            return '';
        }""")
        if changed == 'opened':
            await asyncio.sleep(1)
            # Select "Anyone with the link" from dropdown/options
            await page.evaluate("""() => {
                const options = document.querySelectorAll(
                    '[role="option"], [role="menuitem"], [role="menuitemradio"], li, label'
                );
                for (const opt of options) {
                    const txt = (opt.innerText || opt.textContent || '').toLowerCase();
                    if (txt.includes('anyone with the link') || txt.includes('anyone')) {
                        opt.click();
                        return 'selected';
                    }
                }
                return '';
            }""")
            await asyncio.sleep(1)
            log(f"[{label}] Set Notebook access to 'Anyone with the link'")

        # Step 2: Get the shareable link
        link = await page.evaluate("""() => {
            // Check input fields for the URL
            const inputs = document.querySelectorAll('input[readonly], input[value*="notebooklm"]');
            for (const inp of inputs) {
                const val = inp.value || '';
                if (val.includes('notebooklm.google.com')) return val;
            }
            // Try clicking "Copy link" button
            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const txt = (b.innerText || '').toLowerCase();
                if (txt.includes('copy link') || (txt.includes('copy') && !txt.includes('copy all'))) {
                    b.click();
                    return 'clipboard';
                }
            }
            return '';
        }""")
        if link == 'clipboard':
            await asyncio.sleep(0.5)
            clip = get_clipboard()
            if clip and "notebooklm.google.com" in clip:
                url = clip
        elif link and "notebooklm.google.com" in link:
            url = link

        # Step 3a: DOM-verify the access dropdown reads "Anyone with the
        # link" BEFORE we save. We require a STRICT signal — either:
        #   (a) the dropdown trigger's *own text node* (not its descendants)
        #       contains "anyone with the link", OR
        #   (b) an aria-selected/aria-checked element inside the dialog
        #       contains "anyone with the link".
        # Why so strict: Material-style dropdowns place the option list as a
        # child of the trigger when open; reading `.innerText` on the trigger
        # captures sibling option labels and would falsely match. Reading the
        # trigger's directly-owned text only (childNodes Text nodes) avoids
        # this. The body-only "soft accept" path was removed — too prone to
        # false positives when the dropdown is left open. Better to undercount
        # public-verifies (fall through to URL-shape recovery in the caller)
        # than to falsely confirm a private link.
        try:
            public_verified = bool(await page.evaluate("""() => {
                const PHRASE = 'anyone with the link';
                // Read only the directly-owned text of an element (no descendants).
                const ownText = (el) => {
                    let s = '';
                    for (const n of el.childNodes) {
                        if (n.nodeType === 3 /* TEXT_NODE */) s += n.nodeValue || '';
                    }
                    return s.toLowerCase();
                };
                // Layer (a): dropdown trigger's own text node only.
                const triggers = document.querySelectorAll(
                    '[role="dialog"] [role="combobox"], [role="dialog"] [aria-haspopup="listbox"], ' +
                    '[role="dialog"] button[aria-expanded]'
                );
                for (const t of triggers) {
                    if (ownText(t).includes(PHRASE)) return true;
                }
                // Layer (b): explicit aria-selected/aria-checked element in the dialog.
                const dlg = document.querySelector('[role="dialog"]');
                if (dlg) {
                    const active = dlg.querySelector(
                        '[aria-selected="true"], [aria-checked="true"], [data-selected="true"]'
                    );
                    if (active && (active.innerText || '').toLowerCase().includes(PHRASE)) {
                        return true;
                    }
                }
                return false;
            }"""))
        except Exception as _ve:
            log(f"[{label}] public-access DOM verify skipped: {_ve}", "DEBUG")

        # Step 3b: Click Save/Done to apply the sharing change.
        await page.evaluate("""() => {
            const btns = document.querySelectorAll('button');
            for (const b of btns) {
                const txt = (b.innerText || '').trim().toLowerCase();
                if (txt === 'save' || txt === 'done' || txt === 'apply') {
                    b.click();
                    return 'saved';
                }
            }
            return '';
        }""")
        await asyncio.sleep(1)
        if public_verified:
            log(f"[{label}] Public share DOM-verified — link is shareable")
        else:
            log(f"[{label}] Public share NOT DOM-verified — returned link may be private", "WARN")
    except Exception as e:
        log(f"[{label}] NLM public share flow: {e}", "WARN")
    return url, public_verified


async def extract_notebooklm_url(browser, cua_client=None, verbose=False, **_):
    """Extract NotebookLM notebook URL after ensuring public sharing is enabled.
    Flow: Share → Notebook access → public → get link → Save.

    `verified=True` requires BOTH a NotebookLM URL shape AND DOM-confirmed
    public-share (Anyone with the link). Without DOM verification, the URL
    could be a private notebook link, which would 404 or "Request access"
    for anyone but the owner downstream in Phase 5's email/Doc.
    """
    page = browser.page
    url = await browser.current_url() or ""
    public_verified = False
    try:
        # Click Share button to open dialog
        share_btn = await page.query_selector(
            'button[aria-label*="Share"], button[aria-label*="share"], '
            '[class*="share"] button'
        )
        if share_btn:
            await share_btn.click()
            await asyncio.sleep(2)
            link, dom_verified = await _set_nlm_public_and_get_link(page, "NotebookLM")
            if link:
                url = link
            public_verified = bool(dom_verified)
            # Close dialog
            await page.keyboard.press("Escape")
            await asyncio.sleep(0.5)
        # CUA fallback if DOM didn't work
        if not url or "notebooklm.google.com/notebook" not in url:
            if cua_client:
                _nlm_share_mission = (
                    "Click the Share button. In the share dialog, change 'Notebook access' to "
                    "'Anyone with the link'. Then click 'Copy link' to get the URL. Click Save. "
                    "Tell me the EXACT URL.")

                async def _nlm_share_cua():
                    return await agent_loop(cua_client, browser,
                        "Share this NotebookLM notebook publicly.",
                        _nlm_share_mission,
                        model=CUA_MODEL, max_iterations=10, verbose=verbose)

                # #839 act tier: DOM-primary already ran; this is the fallback.
                # A Vision success must put the notebook URL in the returned text
                # (mission's "Tell me the EXACT URL" → declare_success reason) or
                # on the clipboard — both read below. public_verified stays False
                # on this path (only the DOM helper can confirm access), same as
                # the CUA contract.
                result = await _shadow_observed_cua(
                    page, hotspot_id="nlm-share", phase=3, platform="notebooklm",
                    current_step="share_set_public_get_link",
                    context_hint="the DOM share attempt didn't yield a public link — click "
                                 "Share, set 'Notebook access' to 'Anyone with the link', Copy "
                                 "link, Save, and report the notebooklm.google.com/notebook URL",
                    expected_outcome="a public notebooklm.google.com/notebook share URL",
                    cua_coro_factory=_nlm_share_cua,
                    mission_prompt=_nlm_share_mission) or {}
                m = re.search(r'https://notebooklm\.google\.com/notebook/[^\s]+', (result.get("text") or ""))
                if m:
                    url = m.group(0)
                else:
                    clip = get_clipboard()
                    if clip and "notebooklm.google.com" in clip:
                        url = clip
                # CUA path doesn't expose the share-state DOM, so we can't
                # DOM-verify. Treat as unverified — the run still emits the
                # link, but downstream consumers know it might be private.
    except Exception as e:
        log(f"[NotebookLM] Share dialog failed: {e}", "WARN")
    # Fallback to current tab URL
    if not url or "notebooklm.google.com/notebook" not in url:
        url = await browser.current_url() or ""
    # verified = NotebookLM URL shape + DOM-confirmed public access. URL
    # alone is not sufficient since private/public share the same shape.
    verified = ("notebooklm.google.com/notebook" in url) and public_verified
    return LinkResult(url=url, label="NotebookLM Notebook", platform="notebooklm", verified=verified)



# ── B1: Link-first phase_complete — retry helpers ────────────────────────────

async def extract_with_retry(
    phase: int,
    agent: str,
    browser,
    cua_client,
    extractor_fn,
    max_retries: int = 3,
    retry_delay: float = 3.0,
    **kwargs,
) -> "LinkResult":
    """Run a link extractor up to `max_retries` times, validating each URL.
    Emits link_extracting / link_extract_retry / link_extracted / link_extraction_failed.
    Returns LinkResult with verified=True on success; otherwise verified=False + error."""
    last_err = ""
    for attempt in range(1, max_retries + 1):
        emit_event("link_extracting", phase=phase, agent=agent,
                   attempt=attempt, maxAttempts=max_retries)
        log(f"[{agent}] Link extract attempt {attempt}/{max_retries}")
        try:
            result = await extractor_fn(browser, cua_client=cua_client, **kwargs)
        except Exception as e:
            last_err = f"{type(e).__name__}: {e}"
            result = LinkResult(url="", label=kwargs.get("label", ""),
                                platform=agent, verified=False, error=last_err)
        # Validate URL against _LINK_VALIDATORS + _BAD_URL_PATTERNS
        if result.success and validate_link(agent, result.url):
            result.verified = True
            label = result.label or kwargs.get("label", f"{agent} link")
            emit_event("link_extracted", phase=phase, agent=agent,
                       url=result.url, label=label, verified=True, attempt=attempt)
            log(f"[{agent}] Link VERIFIED on attempt {attempt}: {result.url}")
            return result
        # Failed this attempt — log and retry
        last_err = result.error or (
            f"URL failed validation: {result.url[:80]}" if result.url else "No URL returned"
        )
        log(f"[{agent}] Attempt {attempt}/{max_retries} failed: {last_err}", "WARN")
        if attempt < max_retries:
            emit_event("link_extract_retry", phase=phase, agent=agent,
                       attempt=attempt, maxAttempts=max_retries, error=last_err)
            await asyncio.sleep(retry_delay)
    # All retries exhausted. Include a human-readable description so the
    # frontend step list shows something meaningful ("Couldn't extract link
    # after N attempts") instead of the raw event name, and so the agent
    # alert panel has content to render if a caller routes this as a
    # terminal failure rather than proceeding to wait_for_agent_decision.
    log(f"[link_extract] {agent}: failed after {max_retries} attempts ({last_err})", "WARN")
    return LinkResult(url="", label=kwargs.get("label", ""),
                      platform=agent, verified=False, error=last_err)


async def wait_for_agent_decision(agent: str, reason: str, phase: int = 2,
                                   options=("retry", "skip")) -> str:
    """Emit agent_link_failed, pause pipeline, wait for user's decision.
    Returns 'retry' | 'skip' — and may return 'stop' if the user hit Stop
    from the chat input bar while the banner was up (caught via
    _controls.is_stop()). The banner itself no longer offers Stop as a
    button; pipeline-level stop lives in the chat bar only (2026-04-19
    design rule applied to AgentAlertPanel)."""
    _controls.pending_agent_decision = None
    _al_alert_id = f"phase{phase}_agent_link_{agent}"
    emit_event("agent_link_failed", phase=phase, agent=agent,
               reason=reason, options=list(options), alert_id=_al_alert_id)
    # DGOPS-7710-followup: pause with explicit reason + target agent so the
    # CLI dispatcher can discriminate (without this, CLI `r` falls through
    # to the generic branch which only calls request_resume, leaving
    # pop_agent_decision() returning None → caller defaults to "skip").
    _controls.pause_target_agent = (agent or "").strip().lower()
    _controls.request_pause("agent_link_failed")
    emit_event("pipeline_paused", phase=phase, reason="agent_link_failed", agent=agent)
    # #710 parity: durable mirror so opening this chat re-surfaces the
    # Retry/Skip card even if it wasn't the viewed tab. Cleared on the
    # pipeline_resumed this gate emits when the user decides.
    _persist_pending_decision({
        "kind": "agent_link_failed",
        "phase": phase,
        "agent": agent,
        "reason": reason,
        "options": list(options),
        "alert_id": _al_alert_id,
    })
    log(f"[{agent}] Waiting for user decision (retry/skip) — reason: {reason}")
    await _controls.wait_if_paused()
    if _controls.is_stop():
        # Stop exits without emitting pipeline_resumed/stopped, so retract the
        # durable mirror here too (#710) rather than relying on the universal
        # emit_event clear.
        _clear_pending_decision()
        return "stop"
    decision = _controls.pop_agent_decision() or "skip"
    emit_event("pipeline_resumed", phase=phase, reason=f"agent_decision:{decision}", agent=agent)
    log(f"[{agent}] User decision: {decision}")
    return decision


# ── Brief Artifact (first-class research brief with verified paste) ──────────

class BriefArtifact:
    """Holds the complete research brief text + metadata for reliable Phase 2 paste."""
    __slots__ = ("text", "url", "chars", "sections", "extracted_at")

    def __init__(self, text, url="", extracted_at=None):
        self.text = text
        self.url = url
        self.chars = len(text)
        self.sections = re.findall(r'^#{1,3}\s+(.+)$', text, re.MULTILINE)
        self.extracted_at = extracted_at or int(time.time() * 1000)


# ─────────────────────────────────────────────────────────────────────
# DOM-tier paste helpers. Single attempt + CUA fallback contract.
# verified_paste_brief returns False on DOM failure → caller runs
# cua_paste_fallback. No internal retries, no reload/restart loops.
# ─────────────────────────────────────────────────────────────────────

# JS that finds the longest visible composer-like element and returns its
# text length. Used for verifying both DOM and CUA-assisted pastes.
_VERIFY_PASTE_JS = """() => {
    const candidates = [
        '#prompt-textarea',
        'rich-textarea div[contenteditable="true"]',
        '.ProseMirror',
        'div[contenteditable="true"][data-placeholder]',
        'div[contenteditable="true"]',
        'textarea[placeholder]',
        'textarea',
    ];
    let best = 0;
    for (const sel of candidates) {
        for (const el of document.querySelectorAll(sel)) {
            if (el.offsetParent === null) continue;  // visible only
            const txt = (el.innerText || el.value || el.textContent || '');
            if (txt.length > best) best = txt.length;
        }
    }
    return best;
}"""

# Claude attachment-count probe — large pastes auto-convert into one tile.
_CLAUDE_ATTACH_COUNT_JS = """() => {
    const tiles = document.querySelectorAll(
        '[data-testid*="attachment"], [data-testid*="file"], [class*="attachment" i]'
    );
    let c = 0;
    for (const t of tiles) if (t.offsetParent !== null) c++;
    return c;
}"""

# ChatGPT pasted-text chip census — ChatGPT ALSO auto-converts brief-sized
# pastes into an attachment chip. Live-probed 2026-07-13: a 74k-char paste
# leaves the composer at exactly 17 chars ("\\ufeff\\nDeep research\\n " — the
# DR-pill scaffolding the 03:41 run's "Paste verify: 17/73309 (0%)" was
# counting) and lands as button[aria-label="Remove file N: <head of the
# pasted text>"] captioned "Pasted text". That chip IS a delivered brief.
_CHATGPT_PASTED_CHIP_JS = """(head) => {
    let n = 0;
    for (const b of document.querySelectorAll('button[aria-label]')) {
        if (b.offsetParent === null) continue;
        const a = b.getAttribute('aria-label') || '';
        if (!/remove file/i.test(a)) continue;
        if ((head && a.includes(head)) || /pasted text/i.test(a)) n++;
    }
    if (n === 0) {
        // caption fallback: the chip card itself says "Pasted text"
        const form = document.querySelector('form');
        if (form && /pasted text/i.test(form.innerText || '')) n = 1;
    }
    return n;
}"""

# Per-platform composer selectors. Each list leads with the platform's
# composer-specific selector; the broad `div[contenteditable="true"]`
# lives last as a fallback. _GENERIC is the unknown-platform default.
_PASTE_SELECTORS = {
    "gemini": ['rich-textarea div[contenteditable="true"]',
               'div[contenteditable="true"][data-placeholder]',
               'div[contenteditable="true"]',
               'textarea', '[aria-label*="prompt"]'],
    "chatgpt": ['#prompt-textarea', 'textarea',
                'div[contenteditable="true"]', '.ProseMirror'],
    "claude": ['.ProseMirror', 'div[contenteditable="true"]', 'textarea'],
}
_PASTE_SELECTORS_GENERIC = ['#prompt-textarea',
                            'rich-textarea div[contenteditable="true"]',
                            '.ProseMirror',
                            'div[contenteditable="true"][data-placeholder]',
                            'div[contenteditable="true"]',
                            'textarea', '[aria-label*="message"]', '[aria-label*="Message"]']


async def _verify_paste_landed(page, brief_text, platform, label, source="dom"):
    """Read the composer's text length and return True iff ≥ 90% of brief.
    Auto-convert is success too: Claude turns large pastes into one
    attachment tile, and ChatGPT turns them into a "Pasted text" chip
    (live 2026-07-13: the composer keeps only 17 chars of DR-pill
    scaffolding, so the char-count alone read 0% on a paste that had in
    fact fully landed — and the run was failed with the brief sitting
    right there in the composer). `source` tags the success log line."""
    plat = platform.lower()
    try:
        content_len = await page.evaluate(_VERIFY_PASTE_JS)
        expected = len(brief_text)
        ratio = content_len / expected if expected > 0 else 0
        if plat == "claude" and ratio < 0.90:
            try:
                attach_count = await page.evaluate(_CLAUDE_ATTACH_COUNT_JS)
                if attach_count == 1:
                    log(f"[{label}] Brief pasted ✓ ({source}, 1 attachment tile, Claude auto-convert)")
                    return True
                if attach_count > 1:
                    log(f"[{label}] Claude shows {attach_count} attachments (duplicate)", "WARN")
            except Exception:
                pass
        if plat == "chatgpt" and ratio < 0.90:
            try:
                _lines = brief_text.strip().splitlines() or [""]
                chips = await page.evaluate(_CHATGPT_PASTED_CHIP_JS, _lines[0][:12])
                if chips >= 1:
                    if chips > 1:
                        log(f"[{label}] ChatGPT shows {chips} pasted-text chips — duplicate "
                            f"paste, the brief may be delivered twice", "WARN")
                    log(f"[{label}] Brief pasted ✓ ({source}, auto-converted to a "
                        f"'Pasted text' attachment chip)")
                    return True
            except Exception:
                pass
        if ratio >= 0.90:
            log(f"[{label}] Brief pasted ✓ ({source}, {content_len}/{expected} chars, {ratio:.0%})")
            return True
        log(f"[{label}] Paste verify ({source}): {content_len}/{expected} chars ({ratio:.0%})", "WARN")
    except Exception as e:
        log(f"[{label}] Paste verify error ({source}): {e}", "WARN")
    return False


async def _grant_clipboard_permission(page) -> bool:
    """Best-effort CDP clipboard permission grant. Returns True on success,
    False on failure (silent — the paste path still has the keyboard-typing
    fallback, so callers that don't care can ignore the result).

    Browser.grantPermissions with no `origin`/`browserContextId` applies to
    the default browser context (the persistent context here) and persists
    for the session, so a single call at browser bootstrap covers every
    agent tab in every phase — see Browser.start()."""
    try:
        cdp = await page.context.new_cdp_session(page)
        await cdp.send("Browser.grantPermissions",
                       {"permissions": ["clipboardReadWrite", "clipboardSanitizedWrite"]})
        await cdp.detach()
        return True
    except Exception:
        return False


async def verified_paste_brief(page, brief_text, platform, label, max_retries=1):
    """Paste the brief into the platform's composer and verify it landed.

    DOM-tier contract (1 attempt by default). Two strategies inside ONE
    attempt: CDP clipboard + Ctrl+V (fast) → real keyboard typing
    (reliable, slower). Returns True on verified paste, False to hand
    off to `cua_paste_fallback` at the call site.

    For Claude, accepts a single attachment tile as success (large pastes
    auto-convert).

    `max_retries` defaults to 1 — multiple DOM retries here amplified the
    risk of side-effects (off-target clicks → tab spam, framework state
    corruption). Callers should escalate to CUA on first DOM failure
    rather than retry DOM.
    """
    is_claude = platform.lower() == "claude"
    platform_key = (platform or "").strip().lower()
    selectors = _PASTE_SELECTORS.get(platform_key, _PASTE_SELECTORS_GENERIC)

    for attempt in range(1, max_retries + 1):
        if attempt > 1:
            log(f"[{label}] paste retry {attempt}/{max_retries}", "INFO")
        # Claude: clear stale attachments before retry
        if is_claude and attempt > 1:
            try:
                removed = await page.evaluate("""() => {
                    const btns = document.querySelectorAll(
                        'button[aria-label*="Remove"], button[aria-label*="Delete"], '
                        + 'button[data-testid*="remove"]'
                    );
                    let n = 0;
                    for (const b of btns) if (b.offsetParent !== null) { b.click(); n++; }
                    return n;
                }""")
                if removed:
                    log(f"[{label}] Cleared {removed} stale attachment(s) before retry")
                    await asyncio.sleep(0.5)
            except Exception:
                pass
        # Page focus is needed for clipboard access in new tabs.
        try:
            await page.bring_to_front()
            await asyncio.sleep(0.5)
        except Exception:
            pass

        # Find composer (first matching selector wins).
        ta = None
        for sel in selectors:
            try:
                ta = await page.wait_for_selector(sel, timeout=1500)
                if ta:
                    break
            except Exception:
                continue
        if not ta:
            log(f"[{label}] Composer not found (attempt {attempt}/{max_retries})", "WARN")
            await asyncio.sleep(0.5)
            continue

        # Strategy A: CDP clipboard + Ctrl+V (fast).
        try:
            await ta.click()
            await asyncio.sleep(0.3)
            await page.keyboard.press("Control+a")
            await asyncio.sleep(0.1)
            await _grant_clipboard_permission(page)
            await page.evaluate("text => navigator.clipboard.writeText(text)", brief_text)
            await asyncio.sleep(0.3)
            await page.keyboard.press("Control+v")
            await asyncio.sleep(2)
        except Exception as e:
            log(f"[{label}] Strategy A (clipboard) raised: {e}", "WARN")

        if await _verify_paste_landed(page, brief_text, platform, label, source="clipboard"):
            return True

        # Strategy A.5 (Gemini-only): CHUNKED clipboard paste. Background:
        # Gemini's Lit/Angular composer truncates a single large paste at
        # ~5-6K chars (observed: 5608/8951 = 62.7%). Splitting the brief
        # into ~2000-char chunks and Ctrl+V'ing each one lets the composer
        # incrementally reflow + commit each chunk to its underlying state
        # before the next paste lands. Avoids the keyboard-type fallback's
        # 60s wall-time penalty when chunked clipboard works fine.
        if platform_key == "gemini" and len(brief_text) > 4000:
            try:
                CHUNK = 2000
                # Reset composer first — Strategy A may have left a
                # truncated paste in there.
                await ta.click()
                await asyncio.sleep(0.2)
                await page.keyboard.press("Control+a")
                await asyncio.sleep(0.1)
                await page.keyboard.press("Delete")
                await asyncio.sleep(0.1)
                # Walk the brief and paste each chunk via clipboard. On a
                # rich-text composer the cursor stays at end-of-content
                # after each Ctrl+V, so successive pastes naturally append.
                _n = (len(brief_text) + CHUNK - 1) // CHUNK
                log(f"[{label}] Chunked paste: {_n} chunks of {CHUNK} chars (total {len(brief_text)})")
                for i in range(0, len(brief_text), CHUNK):
                    chunk = brief_text[i:i + CHUNK]
                    await page.evaluate("text => navigator.clipboard.writeText(text)", chunk)
                    await asyncio.sleep(0.15)
                    await page.keyboard.press("Control+v")
                    # 200ms settle lets Gemini's input handler commit the
                    # chunk to its model layer before the next paste fires.
                    await asyncio.sleep(0.2)
                await asyncio.sleep(1.5)
            except Exception as e:
                log(f"[{label}] Strategy A.5 (chunked clipboard) raised: {e}", "WARN")

            if await _verify_paste_landed(page, brief_text, platform, label, source="chunked-clipboard"):
                return True

        # Strategy B: real keyboard typing (slower — ~60s for a 30K-char
        # brief — but actually dispatches genuine keydown/keypress events
        # that any controlled composer must handle). Gated to Gemini only
        # because that's where clipboard paste leaves the rich-textarea
        # visually empty due to framework-state issues; ChatGPT/Claude
        # accept clipboard reliably, so a failed clipboard verify there
        # is more likely a wrong-element-read problem that escalating to
        # CUA recovers faster than burning 60s on keyboard typing.
        if platform_key == "gemini":
            try:
                await ta.click()
                await asyncio.sleep(0.2)
                await page.keyboard.press("Control+a")
                await asyncio.sleep(0.1)
                await page.keyboard.press("Delete")
                await asyncio.sleep(0.1)
                # insert_text dispatches ONE insertText event with the literal
                # string — newlines stay literal text, never Enter keypresses. A
                # raw keyboard.type() here fires Enter per "\n", and Gemini binds
                # Enter to SUBMIT, so a multi-line brief gets sent one tiny message
                # per line (the "brief in pieces, endlessly" submit-storm that
                # blocks Deep Research). Mirror the proven insert_text -> fill ->
                # type idiom used elsewhere in this file; the newline-stripped
                # type() is a can't-fire-submit last resort.
                try:
                    await page.keyboard.insert_text(brief_text)
                except Exception:
                    try:
                        await ta.fill(brief_text)
                    except Exception:
                        await page.keyboard.type(brief_text.replace("\n", " "), delay=2)
                await asyncio.sleep(1.5)
            except Exception as e:
                log(f"[{label}] Strategy B (keyboard) raised: {e}", "WARN")
                await asyncio.sleep(1)
                continue

            if await _verify_paste_landed(page, brief_text, platform, label, source="keyboard"):
                return True
        await asyncio.sleep(1)

    log(f"[{label}] DOM paste failed after {max_retries} attempt(s) — caller should run CUA fallback", "WARN")
    return False


async def cua_paste_fallback(page, browser, cua_client, brief_text, platform, label, verbose=False):
    """CUA-assisted paste: CUA focuses the composer (one persistent mission
    within budget), Python pastes via clipboard. CUA can't reliably type
    a 30K-char brief, so we delegate ONLY focus to CUA.

    Tier-transition event is emitted so Track-A telemetry sees the DOM→CUA
    handoff. Returns True on verified paste, False otherwise — caller
    fails the agent on False.
    """
    if not cua_client or not browser:
        log(f"[{label}] CUA paste fallback skipped (no client/browser)", "WARN")
        return False
    log(f"[{label}] DOM paste exhausted — handing off to CUA")
    emit_tier_transition(phase=2, agent=platform.lower(),
        op="brief_paste", from_tier="dom", to_tier="cua",
        reason="dom_paste_unverified")

    # CUA focus mission (45s budget, ~4 iterations).
    try:
        await browser.switch_to_page(page)
        await asyncio.wait_for(
            agent_loop(cua_client, browser,
                "You are focusing a chat composer for a paste operation. "
                "Click the chat input area at the bottom of the page so the "
                "cursor lands in it. Stop after focusing — do NOT type or "
                "paste anything. The Python code will handle the actual "
                "paste from the clipboard.",
                f"Click on the message input area at the bottom of this "
                f"{platform} page. The cursor should be in the input. "
                f"Then STOP — do not type or paste.",
                model=CUA_MODEL, max_iterations=4, verbose=verbose,
                target_page=page),
            timeout=45.0,
        )
    except (asyncio.TimeoutError, Exception) as e:
        log(f"[{label}] CUA composer-focus failed: {e}", "WARN")
        return False

    # Python pastes via clipboard.
    try:
        await _grant_clipboard_permission(page)
        await page.evaluate("text => navigator.clipboard.writeText(text)", brief_text)
        await asyncio.sleep(0.3)
        await page.keyboard.press("Control+v")
        await asyncio.sleep(2)
    except Exception as e:
        log(f"[{label}] CUA-assisted clipboard paste raised: {e}", "WARN")

    return await _verify_paste_landed(page, brief_text, platform, label, source="cua-assisted")


# ── Event Emission (Firestore-only — disk mirror removed 2026-04-29) ───────

# T2 narrator ring buffer. Populated by emit_event, read by _narrator_loop.
# Bounded at 50 — wide enough to cover ~2-5 min at typical event density,
# tight enough that the narrator prompt never balloons. Appended AFTER the
# Firestore write so the frontend and the ring-buffer never diverge in
# order. Do NOT rely on this for frontend-observable state — it's a
# backend-only snapshot for narration prompts.
_recent_events: "collections.deque" = collections.deque(maxlen=50)


def _recent_events_window(seconds: float) -> list:
    """Return recent events no older than `seconds`, oldest → newest.
    Filters out `phase_narration` so the narrator doesn't feed on its
    own output (would produce drift + hall-of-mirrors summaries)."""
    cutoff_ms = int((time.time() - seconds) * 1000)
    out = []
    for e in list(_recent_events):
        if e.get("timestamp", 0) < cutoff_ms:
            continue
        if e.get("type") == "phase_narration":
            continue
        out.append(e)
    return out


def emit_event(event_type, phase=None, agent=None, **data):
    """Emit a typed event to Firestore pipeline_events. (events.jsonl
    disk mirror was removed 2026-04-29 — Firestore is the single
    transport.)"""
    if not _tracks_dir:
        return
    event = {
        "type": event_type,
        "timestamp": int(time.time() * 1000),
    }
    if phase is not None:
        event["phase"] = phase
    if agent:
        event["agent"] = agent
    if data:
        event["data"] = data
    # Track last-emitted event id for Phoenix-resume dedup. Cheap monotonic
    # id (timestamp-ms + type) is enough — FE just needs a "have we seen
    # this one?" cursor, not a globally-unique key.
    try:
        _runtime.last_event_id = f"{event['timestamp']}_{event_type}"
    except Exception:
        pass
    # 2026-04-29: events.jsonl disk write removed. The FE reads pipeline
    # events from Firestore (`pipeline_events` subcoll) only — disk mirror
    # was dead weight (no live readers, only legacy /api/runs HTTP
    # endpoints which are themselves stale).
    # Record phase durations for analytics-based ETAs
    if event_type == "phase_complete" and phase is not None:
        dur = data.get("durationSec", 0)
        if dur > 0:
            record_phase_duration(phase, dur, agent=agent or "")
    # Tile/Icon Consistency (2026-05-01, updated 2026-05-06): persist
    # per-phase + per-agent terminal status to root doc so listing tile +
    # chat icons stay correct post-reload. Single point so every
    # phase_complete / phase_skipped / agent_skipped emit auto-persists;
    # no need to touch each call site individually. phase_complete
    # OVERWRITES a prior "errored" — important when user picks Retry on
    # a fail_phase alert and the retry succeeds. ALL agent_skipped emits
    # now carry a `reason` (config-skips emit "Disabled in pipeline
    # config" — research.py:19402, runtime skips emit "user_skip…") and
    # all persist to root doc as dual-source defense-in-depth: the
    # FE-side pipelineConfig snapshot can be missing on legacy docs or
    # overwritten by the Settings cascade mid-run, so we want the icon
    # to reflect the actual run config via persisted runtime status too.
    try:
        if event_type == "phase_complete" and isinstance(phase, int) and phase >= 0:
            _write_phase_terminal_status(phase, "complete")
        elif event_type == "phase_skipped" and isinstance(phase, int) and phase >= 0:
            _write_phase_terminal_status(phase, "skipped")
        elif event_type == "agent_skipped" and agent:
            # All agent_skipped emits carry a `reason` post-2026-05-06.
            # Guard retained as defense in case a future caller forgets
            # to pass reason — without it, persistence would silently
            # drop and we'd regress to the pre-F2 bug.
            if data.get("reason"):
                _write_agent_terminal_status(agent, "skipped")
    except Exception:
        # Status persistence is best-effort — never let it break event
        # emission (which is the critical path for FE state updates).
        pass
    # #710 parity: a Decision pause's durable pendingDecision mirror is
    # retracted on the UNIVERSAL resolve signal — every gate (login, env,
    # pro, human-verify, agent-link) emits pipeline_resumed (retry/skip/ack)
    # or pipeline_stopped when it unblocks, regardless of whether it waited
    # via wait_if_paused or its own poll loop. Clearing here (one chokepoint)
    # covers them all without per-site clears. Best-effort.
    try:
        # Resolution signals that retract a pending decision: resume/stop, AND
        # skip (#715 — a chat_mode/agent gate resolved via Skip emits
        # agent_skipped/phase_skipped but NOT pipeline_resumed, so without these
        # the skipped decision's mirror would re-surface stale on a same-phase
        # cold open). Safe because a decision pause blocks the whole coroutine
        # (single pause_event) — no unrelated skip fires while one is pending;
        # a config-disabled-agent skip at phase start finds no pending decision
        # and is a harmless no-op.
        # #751 (2026-06-02): phase_restart added — a user clicking Retry on a
        # pipeline_error card resolves the decision via await_phase_decision and
        # emits phase_restart, but NOT pipeline_resumed, so the durable
        # pendingDecision mirror was never cleared → the snag card re-surfaced on
        # the next Firestore snapshot even after the run moved on. Decisions are
        # serialized (one pause blocks the coroutine), so a restart can only
        # resolve the single pending decision — clearing here is always correct.
        if event_type in ("pipeline_resumed", "pipeline_stopped",
                          "agent_skipped", "phase_skipped", "phase_restart"):
            # 2026-07-11 review: scope agent_skipped clears to THAT agent so
            # skipping agent A can't retract agent B's still-live Retry/Skip
            # mirror (a setup-failed agent's card is non-blocking and must
            # survive unrelated resolves). The keep-guard in
            # _clear_pending_decision arbitrates; agent-less events (stop,
            # phase-level) keep the unconditional clear exactly as before.
            # 2026-07-14: scope an AGENT-carrying pipeline_resumed the same way.
            # The non-blocking P2 model now emits per-agent pipeline_resumed on
            # auto-skip / chat-mode-skip / retry (agent=<key>); an unconditional
            # clear here would wipe a SIBLING agent's live durable mirror (two
            # agents fail → single pendingDecision holds the later one → resuming
            # the earlier one blanket-deleted the later's card on cold reopen).
            # Existing agent-carrying resumes (login/HV/agent-link/pro gates) are
            # blocking + serialized (only one mirror is ever live) so scoping is
            # a no-op for them; agent-LESS resumes (crash recovery, login-cleared)
            # still pass None → unconditional, exactly as before.
            _clear_pending_decision(
                agent if event_type in ("agent_skipped", "pipeline_resumed") else None)
    except Exception:
        pass
    # #955 Phase 2: disarm the auto-skip deadline registry on the SAME
    # resolution signals — otherwise a resolved card's armed deadline lingers in
    # the module-global registry and _fire_due_autoskips skips a recovered /
    # retried / resumed agent. Agent-scoped for a specific agent_skipped or an
    # agent-carrying pipeline_resumed; clear-ALL for phase-level and whole-run
    # signals (pipeline_stopped, phase_skipped, phase_restart, and the agent-less
    # pipeline_resumed emitted after a whole-run pause — its rebuilt `pending`
    # has no stuck bookkeeping, so a stale deadline would fire on the first
    # post-resume tick). Separate try/except so a registry error can't break
    # mirror clearing and vice-versa.
    try:
        if event_type in ("pipeline_stopped", "phase_skipped", "phase_restart"):
            _disarm_registry("__all__")
        elif event_type in ("agent_skipped", "pipeline_resumed"):
            _disarm_registry(agent if agent else "__all__")
    except Exception:
        pass
    # #715 universal alert persistence: ANY blocking pipeline_error decision
    # card gets a durable pendingDecision mirror so it RE-SURFACES on a cold
    # chat-open (the run is paused waiting on the user — the card must not
    # vanish behind the per-browser pipeline_events seq cursor). One seam here
    # covers every blocking card that funnels through emit_event('pipeline_error',
    # actions=[...]) — cua_unavailable, {platform}_chat_mode, the Anthropic
    # 429/workspace-cap/401 key cards, phase_timeout, and any future
    # fail_phase/fail_agent — with kind='pipeline_error' (FE decisionToCard
    # rebuilds it byte-identically from the persisted actions). GATE: must carry
    # `actions` AND not be `quiet` — this excludes the transient auto-retry infra
    # banners (529/overload sleep+continue never emit actions; quiet-preflight
    # sets quiet=True), which correctly stay non-durable and vanish on recovery.
    # Retracted by the SAME central clear above on pipeline_resumed/stopped +
    # the run-startup wipe. `suppress_generic_mirror` lets a richer kind-specific
    # persist (pro_required) own the mirror without this generic one clobbering it.
    # `force_mirror` (#911) is the inverse override: a QUIET card (no red tile)
    # that must still persist durably + reach the agent-chat watchdog — the
    # login-interrupt card is quiet by design (nothing errored) yet is exactly
    # the kind of "run is waiting on you" state the durable mirror exists for
    # (pre-fix it vanished on cold open and the agent chat posted nothing).
    try:
        _suppress_generic_mirror = bool(data.pop("suppress_generic_mirror", False))
        _force_mirror = bool(data.pop("force_mirror", False))
        if (event_type == "pipeline_error" and data.get("actions")
                and (not data.get("quiet") or _force_mirror)
                and not _suppress_generic_mirror):
            _persist_pending_decision({
                "kind": "pipeline_error",
                "phase": phase if isinstance(phase, int) else 0,
                "agent": (agent.lower() if agent else None),
                "title": data.get("error"),
                "details": data.get("details"),
                "actions": data.get("actions"),
                "dismissible": data.get("dismissible", True),
                "alert_id": data.get("alert_id"),
                # Unified-decision fields (2026-07-14) — carried so the FE
                # countdown + command-ack survive a cold chat-open.
                "recoverability": data.get("recoverability"),
                "auto_skip_deadline": data.get("auto_skip_deadline"),
                "decision_id": data.get("decision_id"),
            })
    except Exception:
        pass
    # Write to Firestore (frontend real-time transport)
    _emit_to_firestore(event)
    # Drop into the narrator ring buffer (after Firestore so ordering
    # cannot drift between what the frontend sees and what the narrator
    # reasons from).
    try:
        _recent_events.append(event)
    except Exception:
        pass
    # B3: keep _runtime.phase in sync with the actual running phase so that
    # rate-limit warnings (and any other `phase` fallback inside agent_loop)
    # land on the correct phase badge instead of drifting to a stale one.
    # Must happen BEFORE narrator start so narrators for a new phase see
    # the updated value. Agnostic of caller — every phase_start site gets
    # the runtime invariant for free.
    if event_type == "phase_start" and isinstance(phase, int) and phase >= 0:
        # 2026-05-25 (queue ETA): publish currentRunPhase +
        # currentRunPhaseStartedAt to the device doc so queued-doc ETA
        # computations + the FE banner's "Current run is in Phase X"
        # line have live source of truth. Worker-1 only (mirrors
        # currentRunId/Title/StartedAt convention at research.py:~29193;
        # multi-worker per-worker tracking is a future schema bump).
        # Fire-and-forget — never block emit_event on a Firestore write.
        try:
            if WORKER_ID == 1 and _firebase_db:
                _did_for_phase = load_device_id()
                if _did_for_phase:
                    _phase_patch = {
                        "currentRunPhase": int(phase),
                        "currentRunPhaseStartedAt": event["timestamp"],
                        # 2026-05-28: fold worker-1's per-sharer phase into
                        # the SAME write so phase_start issues one device-doc
                        # update, not two. Workers >=2 write this in the
                        # block below (they have no currentRunPhase write).
                        f"workers.{WORKER_ID}.phase": int(phase),
                    }
                    _firebase_db.collection("devices").document(_did_for_phase).update(_phase_patch)
                    # Refresh ETA on all deferred docs so the FE banner
                    # countdown stays accurate as the head advances
                    # through phases. _recompute_deferred_queue_positions
                    # reads the device doc ETA inputs we just wrote and
                    # writes updated queueEtaMs to every queued doc.
                    # Fire-and-forget on a thread so emit_event itself
                    # stays sub-ms (the recompute does ≤50 Firestore
                    # reads + ≤450 batch writes — would block the
                    # event loop if synchronous).
                    try:
                        _threading.Thread(
                            target=_recompute_deferred_queue_positions,
                            daemon=True,
                            name="eta-recompute",
                        ).start()
                    except Exception as _eta_t_err:
                        log(f"[device] ETA recompute thread launch failed (non-fatal): {_eta_t_err}", "DEBUG")
        except Exception as _phase_pub_err:
            log(f"[device] currentRunPhase publish failed (non-fatal): {_phase_pub_err}", "DEBUG")
        # 2026-05-28: per-sharer usage — refresh phase on the device-doc
        # `workers.<id>` map for workers >=2 (worker-1 folds this into its
        # _phase_patch above to avoid a second round-trip). Dotted leaf path
        # merges just the phase, leaving the uid/runId/title/totalPhases
        # seeded at claim intact. Fire-and-forget — never block emit_event.
        try:
            if WORKER_ID != 1 and _firebase_db:
                _did_wph = load_device_id()
                if _did_wph:
                    _firebase_db.collection("devices").document(_did_wph).update({
                        f"workers.{WORKER_ID}.phase": int(phase),
                    })
        except Exception as _wph_err:
            log(f"[device] workers phase publish (w{WORKER_ID}) failed (non-fatal): {_wph_err}", "DEBUG")
        try:
            _runtime.phase = phase
        except Exception:
            pass
    # T2 narrator lifecycle — auto-wired to phase boundaries so every
    # phase_start / phase_complete / phase_skipped / pipeline_stopped site
    # doesn't need manual start/stop_narrator calls. Single point of truth.
    try:
        if event_type == "phase_start" and isinstance(phase, int) and phase >= 0:
            start_narrator(phase)
        elif event_type in ("phase_complete", "phase_skipped",
                             "pipeline_stopped", "pipeline_complete"):
            stop_narrator()
    except Exception:
        pass

    # Note: a terminal-event prune of pipeline_events used to live here. It
    # was reverted because completed/stopped runs MUST preserve their full
    # event timeline for replay/post-mortem. Cleanup happens only when the
    # user explicitly deletes a research — see deleteResearch cascade in
    # firestore.ts and the BE orphan-sweep in startup. The FE seq filter at
    # firestore.ts:925 (where("seq", ">", lastSeq) + localStorage) keeps
    # cold-start reads bounded regardless of subcollection size.


def start_narration_ticker(phase, agent, narration, interval=30, expected_minutes=None):
    """Spawn a background task that emits agent_progress every `interval`s
    with `narration` + elapsed time. Returns the (stop_event, task) pair —
    caller must call stop_event.set() and await task to clean up.

    Used to keep P3/P4/P5 dropdowns alive during long CUA agent_loop calls
    so the narration matches P2's ~30s round-robin cadence. Without this,
    long CUA waypoints leave the FE sitting on a stale pre-call string.

    Usage:
        stop, task = start_narration_ticker(3, "notebooklm",
                                            "Uploading sources to NotebookLM")
        try:
            await agent_loop(...)
        finally:
            stop.set()
            await task
    """
    stop = asyncio.Event()

    async def _tick():
        elapsed = 0
        while not stop.is_set():
            try:
                await asyncio.wait_for(stop.wait(), timeout=interval)
                return
            except asyncio.TimeoutError:
                elapsed += interval
                try:
                    mm, ss = divmod(elapsed, 60)
                    label = (f"{narration}… ({mm}m {ss}s elapsed)" if mm
                             else f"{narration}… ({ss}s elapsed)")
                    kw = {"phase": phase, "agent": agent,
                          "status": "working", "progress": label,
                          "elapsedSec": elapsed}
                    if expected_minutes:
                        kw["expectedMinutes"] = expected_minutes
                    emit_event("agent_progress", **kw)
                except Exception:
                    pass

    task = asyncio.create_task(_tick())
    return stop, task


async def stop_narration_ticker(stop, task):
    """Companion to start_narration_ticker — sets the stop event and awaits
    the ticker task. Safe to call when stop/task are None (no-op)."""
    if stop is None or task is None:
        return
    try:
        stop.set()
    except Exception:
        pass
    try:
        await task
    except Exception:
        pass


